/* !
 * \file matmul.asc
 * \brief
 */

#include "acl/acl.h"
#include "kernel_operator.h"
#include "data_utils.h"

#ifdef ASCENDC_CPU_DEBUG
#include "cpu_debug_launch.h"
#endif

// half type, cube block: [16, 16]
constexpr uint32_t CUBE_BLOCK = 16;

template <
    uint32_t M, uint32_t K, uint32_t N, uint32_t singleCoreM, uint32_t singleCoreK, uint32_t singleCoreN,
    uint32_t baseM, uint32_t baseK, uint32_t baseN>
class KernelMatmul {
public:
    __aicore__ inline KernelMatmul() {}
    __aicore__ inline void Init(GM_ADDR a, GM_ADDR b, GM_ADDR c)
    {
        AscendC::InitSocState();
        aGM.SetGlobalBuffer((__gm__ half*)a);
        bGM.SetGlobalBuffer((__gm__ half*)b);
        cGM.SetGlobalBuffer((__gm__ half*)c);
        InitGMOffsets();
    }

    __aicore__ inline void Process()
    {
        AscendC::LocalTensor<half> a1Local(AscendC::TPosition::A1, a1Addr, baseM * baseK);
        AscendC::LocalTensor<half> a2Local(AscendC::TPosition::A2, a2Addr, baseM * baseK);
        AscendC::LocalTensor<half> b1Local(AscendC::TPosition::B1, b1Addr, baseK * baseN);
        AscendC::LocalTensor<half> b2Local(AscendC::TPosition::B2, b2Addr, baseK * baseN);
        AscendC::LocalTensor<float> cLocal(AscendC::TPosition::CO1, cAddr, baseM * baseN);

        constexpr uint32_t kLoopCount = singleCoreK / baseK;
        constexpr uint32_t mLoopCount = singleCoreM / baseM;
        constexpr uint32_t nLoopCount = singleCoreN / baseN;
        for (uint32_t mIndex = 0; mIndex < mLoopCount; mIndex++) {
            for (uint32_t nIndex = 0; nIndex < nLoopCount; nIndex++) {
                for (uint32_t kIndex = 0; kIndex < kLoopCount; kIndex++) {
                    CopyInA(a1Local, kIndex, mIndex);
                    CopyInB(b1Local, kIndex, nIndex);

                    AscendC::SetFlag<AscendC::HardEvent::MTE2_MTE1>(EVENT_ID0);
                    AscendC::WaitFlag<AscendC::HardEvent::MTE2_MTE1>(EVENT_ID0);

                    DataLoadA(a1Local, a2Local, mIndex);
                    DataLoadB(b1Local, b2Local, nIndex);

                    AscendC::SetFlag<AscendC::HardEvent::MTE1_M>(EVENT_ID0);
                    AscendC::WaitFlag<AscendC::HardEvent::MTE1_M>(EVENT_ID0);

                    Compute(cLocal, a2Local, b2Local, kIndex, mIndex, nIndex);

                    AscendC::SetFlag<AscendC::HardEvent::M_MTE2>(EVENT_ID0);
                    AscendC::WaitFlag<AscendC::HardEvent::M_MTE2>(EVENT_ID0);
                }
                AscendC::SetFlag<AscendC::HardEvent::M_FIX>(EVENT_ID0);
                AscendC::WaitFlag<AscendC::HardEvent::M_FIX>(EVENT_ID0);
                CopyOut(cLocal, mIndex, nIndex);
            }
        }
    }

private:
    __aicore__ inline void InitGMOffsets()
    {
        constexpr uint32_t mIter = M / singleCoreM;
        uint32_t mIterIdx = get_block_idx() % mIter;
        uint32_t nIterIdx = get_block_idx() / mIter;

        uint64_t gmOffsetA = mIterIdx * singleCoreM * K;
        uint64_t gmOffsetB = nIterIdx * singleCoreN;
        uint64_t gmOffsetC = mIterIdx * singleCoreM * N + nIterIdx * singleCoreN;
        aGM = aGM[gmOffsetA];
        bGM = bGM[gmOffsetB];
        cGM = cGM[gmOffsetC];
    }

    __aicore__ inline void CopyInA(AscendC::LocalTensor<half> a1Local, uint32_t kIndex, uint32_t mIndex)
    {
        AscendC::Nd2NzParams nd2nzA1Params;
        nd2nzA1Params.ndNum = 1;
        nd2nzA1Params.nValue = baseM;
        nd2nzA1Params.dValue = baseK;
        nd2nzA1Params.srcNdMatrixStride = 0;
        nd2nzA1Params.srcDValue = K;
        nd2nzA1Params.dstNzC0Stride = baseM;
        nd2nzA1Params.dstNzNStride = 1;
        nd2nzA1Params.dstNzMatrixStride = 0;
        AscendC::DataCopy(a1Local, aGM[kIndex * baseK + mIndex * K * baseM], nd2nzA1Params);
    }

    __aicore__ inline void CopyInB(AscendC::LocalTensor<half> b1Local, uint32_t kIndex, uint32_t nIndex)
    {
        AscendC::Nd2NzParams nd2nzB1Params;
        nd2nzB1Params.ndNum = 1;
        nd2nzB1Params.nValue = baseK;
        nd2nzB1Params.dValue = baseN;
        nd2nzB1Params.srcNdMatrixStride = 0;
        nd2nzB1Params.srcDValue = N;
        nd2nzB1Params.dstNzC0Stride = baseK;
        nd2nzB1Params.dstNzNStride = 1;
        nd2nzB1Params.dstNzMatrixStride = 0;
        AscendC::DataCopy(b1Local, bGM[kIndex * baseK * N + nIndex * baseN], nd2nzB1Params);
    }

    __aicore__ inline void DataLoadA(
        AscendC::LocalTensor<half> a1Local, AscendC::LocalTensor<half> a2Local, uint32_t mIndex)
    {
#if defined(__NPU_ARCH__) && (__NPU_ARCH__ == 2201 || __NPU_ARCH__ == 2202)
        constexpr uint32_t dstOffset = baseK * CUBE_BLOCK;
        // 单个分型的大小为512B，对于half类型小分型大小为16*16=256
        constexpr uint32_t srcOffset = 512 / sizeof(half);
        AscendC::LoadData2DParams loadDataParamsA;
        loadDataParamsA.repeatTimes = baseK / CUBE_BLOCK;
        loadDataParamsA.srcStride = baseM / CUBE_BLOCK;
        loadDataParamsA.dstGap = 0;
        loadDataParamsA.ifTranspose = false;
        for (int i = 0; i < baseM / CUBE_BLOCK; ++i) {
            AscendC::LoadData(a2Local[i * dstOffset], a1Local[i * srcOffset], loadDataParamsA);
        }
#elif defined(__NPU_ARCH__) && (__NPU_ARCH__ == 3510)
        AscendC::LoadData2DParamsV2 loadDataParamsA;
        loadDataParamsA.mStartPosition = 0;
        loadDataParamsA.kStartPosition = 0;
        loadDataParamsA.mStep = AscendC::DivCeil(baseM, CUBE_BLOCK);
        loadDataParamsA.kStep = AscendC::DivCeil(baseK * sizeof(half), 32);
        loadDataParamsA.srcStride = AscendC::DivCeil(baseM, CUBE_BLOCK);
        loadDataParamsA.dstStride = AscendC::DivCeil(baseM, CUBE_BLOCK);
        loadDataParamsA.ifTranspose = false;
        AscendC::LoadData(a2Local, a1Local, loadDataParamsA);
#endif
    }

    __aicore__ inline void DataLoadB(
        AscendC::LocalTensor<half> b1Local, AscendC::LocalTensor<half> b2Local, uint32_t nIndex)
    {
#if defined(__NPU_ARCH__) && (__NPU_ARCH__ == 2201 || __NPU_ARCH__ == 2202)
        constexpr uint32_t dstOffset = baseN * CUBE_BLOCK;
        // 单个分型的大小为512B，对于half类型小分型大小为16*16=256
        constexpr uint32_t srcOffset = 512 / sizeof(half);
        AscendC::LoadData2DParams loadDataParamsB;
        loadDataParamsB.repeatTimes = baseN / CUBE_BLOCK;
        loadDataParamsB.srcStride = baseK / CUBE_BLOCK;
        loadDataParamsB.dstGap = 0;
        loadDataParamsB.ifTranspose = true;
        for (int i = 0; i < baseK / CUBE_BLOCK; ++i) {
            AscendC::LoadData(b2Local[i * dstOffset], b1Local[i * srcOffset], loadDataParamsB);
        }
#elif defined(__NPU_ARCH__) && (__NPU_ARCH__ == 3510)
        AscendC::LoadData2DParamsV2 loadDataParamsB;
        loadDataParamsB.mStartPosition = 0;
        loadDataParamsB.kStartPosition = 0;
        loadDataParamsB.mStep = AscendC::DivCeil(baseK, CUBE_BLOCK);
        loadDataParamsB.kStep = AscendC::DivCeil(baseN * sizeof(half), 32);
        loadDataParamsB.srcStride = AscendC::DivCeil(baseK, CUBE_BLOCK);
        loadDataParamsB.dstStride = AscendC::DivCeil(baseN, CUBE_BLOCK);
        loadDataParamsB.ifTranspose = true;
        AscendC::LoadData(b2Local, b1Local, loadDataParamsB);
#endif
    }

    __aicore__ inline void Compute(
        AscendC::LocalTensor<float> cLocal, AscendC::LocalTensor<half> a2Local, AscendC::LocalTensor<half> b2Local,
        uint32_t kIndex, uint32_t mIndex, uint32_t nIndex)
    {
        AscendC::MmadParams mmadParams;
        mmadParams.m = baseM;
        mmadParams.n = baseN;
        mmadParams.k = baseK;
        mmadParams.cmatrixInitVal = (kIndex == 0 ? true : false);
        AscendC::Mmad(cLocal, a2Local, b2Local, mmadParams);
    }

    __aicore__ inline void CopyOut(AscendC::LocalTensor<float> cLocal, uint32_t mIndex, uint32_t nIndex)
    {
        AscendC::FixpipeParamsV220 fixpipeParams;
        fixpipeParams.nSize = baseN;
        fixpipeParams.mSize = baseM;
        fixpipeParams.srcStride = baseM;
        fixpipeParams.dstStride = N;
        fixpipeParams.quantPre = QuantMode_t::F322F16;
        fixpipeParams.ndNum = 1;
        fixpipeParams.srcNdStride = 0;
        fixpipeParams.dstNdStride = 0;
        AscendC::Fixpipe(cGM[mIndex * baseM * N + nIndex * baseN], cLocal, fixpipeParams);
    }

private:
    uint64_t a1Addr = 0;
    uint64_t a2Addr = 0;
    // L1 size = 512KB，将L1的地址从中间分开，分别存储A和B矩阵的数据
    uint64_t b1Addr = 256 * 1024;
    uint64_t b2Addr = 0;
    uint64_t cAddr = 0;
    AscendC::GlobalTensor<half> aGM;
    AscendC::GlobalTensor<half> bGM;
    AscendC::GlobalTensor<half> cGM;
};

template <
    uint32_t M, uint32_t K, uint32_t N, uint32_t singleCoreM, uint32_t singleCoreK, uint32_t singleCoreN,
    uint32_t baseM, uint32_t baseK, uint32_t baseN>
__global__ __cube__ void mmad_custom(GM_ADDR a, GM_ADDR b, GM_ADDR c)
{
    KernelMatmul<M, K, N, singleCoreM, singleCoreK, singleCoreN, baseM, baseK, baseN> op;
    op.Init(a, b, c);
    op.Process();
}

int32_t main(int32_t argc, char* argv[])
{
    // matmul参数
    constexpr uint32_t M = 512;
    constexpr uint32_t K = 512;
    constexpr uint32_t N = 1024;
    // 单核计算量
    constexpr uint32_t singleCoreM = 256;
    constexpr uint32_t singleCoreK = 512;
    constexpr uint32_t singleCoreN = 512;
    // 矩阵乘执行单元Tile参数
    constexpr uint32_t baseM = 128;
    constexpr uint32_t baseK = 64;
    constexpr uint32_t baseN = 256;

    size_t aFileSize = M * K * sizeof(half);
    size_t bFileSize = K * N * sizeof(half);
    size_t cFileSize = M * N * sizeof(half);
    uint32_t numBlocks = 4;

    aclInit(nullptr);
    int32_t deviceId = 0;
    aclrtSetDevice(deviceId);
    aclrtStream stream = nullptr;
    aclrtCreateStream(&stream);

    uint8_t* aHost;
    uint8_t* aDevice;
    aclrtMallocHost((void**)(&aHost), aFileSize);
    aclrtMalloc((void**)&aDevice, aFileSize, ACL_MEM_MALLOC_HUGE_FIRST);
    ReadFile("./input/x1_gm.bin", aFileSize, aHost, aFileSize);
    aclrtMemcpy(aDevice, aFileSize, aHost, aFileSize, ACL_MEMCPY_HOST_TO_DEVICE);

    uint8_t* bHost;
    uint8_t* bDevice;
    aclrtMallocHost((void**)(&bHost), bFileSize);
    aclrtMalloc((void**)&bDevice, bFileSize, ACL_MEM_MALLOC_HUGE_FIRST);
    ReadFile("./input/x2_gm.bin", bFileSize, bHost, bFileSize);
    aclrtMemcpy(bDevice, bFileSize, bHost, bFileSize, ACL_MEMCPY_HOST_TO_DEVICE);

    uint8_t* cHost;
    uint8_t* cDevice;
    aclrtMallocHost((void**)(&cHost), cFileSize);
    aclrtMalloc((void**)&cDevice, cFileSize, ACL_MEM_MALLOC_HUGE_FIRST);

    mmad_custom<M, K, N, singleCoreM, singleCoreK, singleCoreN, baseM, baseK, baseN>
        <<<numBlocks, nullptr, stream>>>(aDevice, bDevice, cDevice);
    aclrtSynchronizeStream(stream);

    aclrtMemcpy(cHost, cFileSize, cDevice, cFileSize, ACL_MEMCPY_DEVICE_TO_HOST);
    WriteFile("./output/output.bin", cHost, cFileSize);

    aclrtFree(aDevice);
    aclrtFreeHost(aHost);
    aclrtFree(bDevice);
    aclrtFreeHost(bHost);
    aclrtFree(cDevice);
    aclrtFreeHost(cHost);

    aclrtDestroyStream(stream);
    aclrtResetDevice(deviceId);
    aclFinalize();
    return 0;
}

