#include <iostream>
#include <vector>
#include <random>
#include <algorithm>
#include <iterator>
#include "half.hpp"
#include "acl/acl.h"
#include "kernel_operator.h"
#include "utils/debug/asc_dump.h"
#include "utils/debug/asc_printf.h"

// float type, cube block: [16, 16]
constexpr uint32_t CUBE_BLOCK = 16;
constexpr uint32_t CUBE_BLOCK_SIZE = 16 * 16;

class KernelMmad {
public:
    __aicore__ inline KernelMmad()
    {
        aSize = m * k;
        bSize = k * n;
        cSize = m * n;
    }

    __aicore__ inline void Init(GM_ADDR a, GM_ADDR b, GM_ADDR bias, GM_ADDR c)
    {
        aGM.SetGlobalBuffer((__gm__ half *)a);
        bGM.SetGlobalBuffer((__gm__ half *)b);
        cGM.SetGlobalBuffer((__gm__ float *)c);
        biasGM.SetGlobalBuffer((__gm__ half *)bias);
        pipe.InitBuffer(inQueueA1, 1, aSize * sizeof(half));
        pipe.InitBuffer(inQueueA2, 1, aSize * sizeof(half));
        pipe.InitBuffer(inQueueB1, 1, bSize * sizeof(half));
        pipe.InitBuffer(inQueueB2, 1, bSize * sizeof(half));
        pipe.InitBuffer(outQueueCO1, 1, cSize * sizeof(float));
        pipe.InitBuffer(inQueueC1, 1, n * sizeof(half));
        pipe.InitBuffer(outQueueC2, 1, n * sizeof(float));
    }

    __aicore__ inline void Process()
    {
        CopyIn();
        SplitA();
        SplitB();
        SplitBias();
        Compute();
        CopyOut();
    }

private:
    __aicore__ inline uint32_t CeilCubeBlock(uint32_t len) {
        return (len + CUBE_BLOCK - 1) / CUBE_BLOCK;
    }

    __aicore__ inline void CopyIn()
    {
        AscendC::LocalTensor<half> a1Local = inQueueA1.AllocTensor<half>();
        AscendC::LocalTensor<half> b1Local = inQueueB1.AllocTensor<half>();
        AscendC::LocalTensor<half> bias1Local = inQueueC1.AllocTensor<half>();
        // 使用printf旧接口调用
        // AscendC::printf(aGM, 1, 32);
        // 当前printf在__asc_aicore命名空间下，在调用时编译器会隐式添加using语句，不需要显式指定命名空间
        printf("%s\n","========== Matrix A in GM ==========");
        printf("%s\n","[ DumpTensor ]");

        // 使用DumpTensor旧接口调用实现, 现已兼容
        // AscendC::DumpTensor(aGM, 1, 32);
        // dump aGm的数据,设置自定义标识符为1，dumpSize = 32
        asc_dump_gm<half>((__gm__ half*)aGM.GetPhyAddr(), 1, 32);

        printf("%s\n","========== Matrix B in GM ==========");
        printf("%s\n","[ DumpTensor ]");

        // 使用DumpTensor旧接口调用实现, 现已兼容
        // AscendC::DumpTensor(bGM, 2, 32);
        // dump bGm的数据,设置自定义标识符为2，dumpSize = 32
        asc_dump_gm<half>((__gm__ half*)bGM.GetPhyAddr(), 2, 32);

        printf("%s\n","========== Matrix Bias in GM ==========");
        printf("%s\n","[ DumpTensor ]");

        // 使用DumpTensor旧接口调用实现, 现已兼容
        // AscendC::DumpTensor(biasGM, 3, 32);
        // dump biasGM的数据,设置自定义标识符为3，dumpSize = 32
        asc_dump_gm<half>((__gm__ half*)biasGM.GetPhyAddr(), 3, 32);
        AscendC::Nd2NzParams nd2nzA1Params;
        nd2nzA1Params.ndNum = 1;
        nd2nzA1Params.nValue = m;
        nd2nzA1Params.dValue = k;
        nd2nzA1Params.srcNdMatrixStride = 0;
        nd2nzA1Params.srcDValue = k;
        nd2nzA1Params.dstNzC0Stride = CeilCubeBlock(m) * CUBE_BLOCK;
        nd2nzA1Params.dstNzNStride = 1;
        nd2nzA1Params.dstNzMatrixStride = 0;
        AscendC::DataCopy(a1Local, aGM, nd2nzA1Params);
#if defined(__NPU_ARCH__) && (__NPU_ARCH__ == 2201 || __NPU_ARCH__ == 2202)
        printf("%s\n","========== Matrix A in L1 ==========");
        printf("%s\n", "[ DumpTensor in a1Local]");
        asc_dump_l1buf<half>((__cbuf__ half*)a1Local.GetPhyAddr(), 4, 32);
#endif
        AscendC::Nd2NzParams nd2nzB1Params;
        nd2nzB1Params.ndNum = 1;
        nd2nzB1Params.nValue = k;
        nd2nzB1Params.dValue = n;
        nd2nzB1Params.srcNdMatrixStride = 0;
        nd2nzB1Params.srcDValue = n;
        nd2nzB1Params.dstNzC0Stride = CeilCubeBlock(k) * CUBE_BLOCK;
        nd2nzB1Params.dstNzNStride = 1;
        nd2nzB1Params.dstNzMatrixStride = 0;
        AscendC::DataCopy(b1Local, bGM, nd2nzB1Params);

        AscendC::DataCopy(bias1Local, biasGM, n);
        inQueueA1.EnQue(a1Local);
        inQueueB1.EnQue(b1Local);
        inQueueC1.EnQue(bias1Local);
    }

    __aicore__ inline void SplitA()
    {
        AscendC::LocalTensor<half> a1Local = inQueueA1.DeQue<half>();
        AscendC::LocalTensor<half> a2Local = inQueueA2.AllocTensor<half>();
#if defined(__NPU_ARCH__) && (__NPU_ARCH__ == 2201 || __NPU_ARCH__ == 2202)
        uint32_t dstOffset = CeilCubeBlock(k) * CUBE_BLOCK_SIZE;
        uint32_t srcOffset = CUBE_BLOCK_SIZE;

        AscendC::LoadData2DParams loadDataParams;
        loadDataParams.repeatTimes = CeilCubeBlock(k);
        loadDataParams.srcStride = CeilCubeBlock(m);
        loadDataParams.dstGap = 0;
        loadDataParams.ifTranspose = false;
        for (int i = 0; i < CeilCubeBlock(m); ++i) {
            AscendC::LoadData(a2Local[i * dstOffset], a1Local[i * srcOffset], loadDataParams);
        }
#elif defined(__NPU_ARCH__) && (__NPU_ARCH__ == 3510)
        // Nz -> Nz
        AscendC::LoadData2DParamsV2 loadDataParams;
        loadDataParams.mStartPosition = 0;
        loadDataParams.kStartPosition = 0;
        loadDataParams.mStep = CeilCubeBlock(m);
        loadDataParams.kStep = CeilCubeBlock(k);
        loadDataParams.srcStride = CeilCubeBlock(m);
        loadDataParams.dstStride = CeilCubeBlock(m);
        loadDataParams.sid = 0;
        loadDataParams.ifTranspose = false;
        AscendC::LoadData(a2Local, a1Local, loadDataParams);
#endif
        inQueueA2.EnQue<half>(a2Local);
        inQueueA1.FreeTensor(a1Local);
    }

    __aicore__ inline void SplitB()
    {
        AscendC::LocalTensor<half> b1Local = inQueueB1.DeQue<half>();
        AscendC::LocalTensor<half> b2Local = inQueueB2.AllocTensor<half>();

        uint32_t dstOffset = CeilCubeBlock(n) * CUBE_BLOCK_SIZE;
        uint32_t srcOffset = CUBE_BLOCK_SIZE;
        // Nz -> Zn
        AscendC::LoadData2DParams loadDataParams;
        loadDataParams.repeatTimes = CeilCubeBlock(n);
        loadDataParams.srcStride = CeilCubeBlock(k);
        loadDataParams.dstGap = 0;
        loadDataParams.ifTranspose = true;
        for (int i = 0; i < CeilCubeBlock(k); ++i) {
            AscendC::LoadData(b2Local[i * dstOffset], b1Local[i * srcOffset], loadDataParams);
        }

        inQueueB1.FreeTensor(b1Local);
        inQueueB2.EnQue<half>(b2Local);
    }

    __aicore__ inline void SplitBias()
    {
        AscendC::LocalTensor<half> bias1Local = inQueueC1.DeQue<half>();
        AscendC::LocalTensor<float> bias2Local = outQueueC2.AllocTensor<float>();
        AscendC::DataCopy(bias2Local, bias1Local, { 1, (uint16_t)(n * sizeof(float) / 64), 0, 0 });
        outQueueC2.EnQue<float>(bias2Local);
        inQueueC1.FreeTensor(bias1Local);
    }

    __aicore__ inline void Compute()
    {
        AscendC::LocalTensor<half> a2Local = inQueueA2.DeQue<half>();
        AscendC::LocalTensor<half> b2Local = inQueueB2.DeQue<half>();
        AscendC::LocalTensor<float> bias2Local = outQueueC2.DeQue<float>();
        AscendC::LocalTensor<float> c1Local = outQueueCO1.AllocTensor<float>();
        AscendC::MmadParams mmadParams;
        mmadParams.m = m;
        mmadParams.n = n;
        mmadParams.k = k;
        mmadParams.cmatrixInitVal = false;
        AscendC::Mmad(c1Local, a2Local, b2Local, bias2Local, mmadParams);
        outQueueCO1.EnQue<float>(c1Local);
        inQueueA2.FreeTensor(a2Local);
        inQueueB2.FreeTensor(b2Local);
        outQueueC2.FreeTensor(bias2Local);
    }

    __aicore__ inline void CopyOut()
    {
        AscendC::LocalTensor<float> c1Local = outQueueCO1.DeQue<float>();
        printf("%s\n","========== Matrix C in L0C ==========");

        // 使用DumpTensor旧接口调用实现, 现已兼容
        // AscendC::DumpTensor(c1Local, 4, 32);
        // dump c1Local的数据，设置标识符为4，dumpSize = 32
        asc_dump_cbuf<float>((__cc__ float*)c1Local.GetPhyAddr(), 4, 32);

        // 带偏移量的DumpAccChkPoint 打印自定义附加信息5, 带OFFSET_LENGTH偏移
        // constexpr int32_t OFFSET_LENGTH = 16;
        // AscendC::DumpAccChkPoint(c1Local, 5, OFFSET_LENGTH, 32);

        AscendC::FixpipeParamsV220 fixpipeParams;
        fixpipeParams.nSize = n;
        fixpipeParams.mSize = m;
        fixpipeParams.srcStride = m;
        fixpipeParams.dstStride = n;

        fixpipeParams.ndNum = 1;
        fixpipeParams.srcNdStride = 0;
        fixpipeParams.dstNdStride = 0;
        AscendC::Fixpipe(cGM, c1Local, fixpipeParams);
        outQueueCO1.FreeTensor(c1Local);
    }

private:
    AscendC::TPipe pipe;
    AscendC::TQue<AscendC::QuePosition::A1, 1> inQueueA1;
    AscendC::TQue<AscendC::QuePosition::A2, 1> inQueueA2;
    AscendC::TQue<AscendC::QuePosition::B1, 1> inQueueB1;
    AscendC::TQue<AscendC::QuePosition::B2, 1> inQueueB2;
    AscendC::TQue<AscendC::QuePosition::CO1, 1> outQueueCO1;
    AscendC::TQue<AscendC::QuePosition::C1, 1> inQueueC1;
    AscendC::TQue<AscendC::QuePosition::C2, 1> outQueueC2;

    AscendC::GlobalTensor<half> aGM;
    AscendC::GlobalTensor<half> bGM;
    AscendC::GlobalTensor<float> cGM;
    AscendC::GlobalTensor<half> biasGM;
    uint16_t m = 32, k = 32, n = 32;
    uint16_t aSize, bSize, cSize;
};

__global__ __cube__ void mmad_custom(GM_ADDR a, GM_ADDR b, GM_ADDR bias, GM_ADDR c)
{
    KERNEL_TASK_TYPE_DEFAULT(KERNEL_TYPE_AIC_ONLY);
    printf("%s\n","========== A x B + Bias = C ==========");
    KernelMmad op;
    op.Init(a, b, bias, c);
    op.Process();
}

template<uint32_t M, uint32_t N, uint32_t K>
std::vector<float> kernel_mmad(const std::vector<fp16::half>& a, const std::vector<fp16::half>& b, const std::vector<fp16::half>& bias)
{
    constexpr size_t aFileSize = M * K * sizeof(fp16::half);
    constexpr size_t bFileSize = K * N * sizeof(fp16::half);
    constexpr size_t biasFileSize = N * sizeof(fp16::half);
    constexpr size_t cFileSize = M * N * sizeof(float);

    constexpr uint32_t blockDim = 1;
    constexpr int32_t deviceId = 0;
    aclrtStream stream = nullptr;

    aclInit(nullptr);
    aclrtSetDevice(deviceId);
    aclrtCreateStream(&stream);

    const uint8_t *aHost = reinterpret_cast<const uint8_t *>(a.data());
    const uint8_t *bHost = reinterpret_cast<const uint8_t *>(b.data());
    const uint8_t *biasHost = reinterpret_cast<const uint8_t *>(bias.data());
    uint8_t *cHost = nullptr;

    uint8_t *aDevice = nullptr;
    uint8_t *bDevice = nullptr;
    uint8_t *biasDevice = nullptr;
    uint8_t *cDevice = nullptr;

    // mem alloc
    aclrtMallocHost((void **)(&cHost), cFileSize);
    aclrtMalloc((void **)&aDevice, aFileSize, ACL_MEM_MALLOC_HUGE_FIRST);
    aclrtMalloc((void **)&bDevice, bFileSize, ACL_MEM_MALLOC_HUGE_FIRST);
    aclrtMalloc((void **)&biasDevice, biasFileSize, ACL_MEM_MALLOC_HUGE_FIRST);
    aclrtMalloc((void **)&cDevice, cFileSize, ACL_MEM_MALLOC_HUGE_FIRST);

    // h to d
    aclrtMemcpy(aDevice, aFileSize, aHost, aFileSize, ACL_MEMCPY_HOST_TO_DEVICE);
    aclrtMemcpy(bDevice, bFileSize, bHost, bFileSize, ACL_MEMCPY_HOST_TO_DEVICE);
    aclrtMemcpy(biasDevice, biasFileSize, biasHost, biasFileSize, ACL_MEMCPY_HOST_TO_DEVICE);

    mmad_custom<<<blockDim, nullptr, stream>>>(aDevice, bDevice, biasDevice, cDevice);
    aclrtSynchronizeStream(stream);

    // d to h
    aclrtMemcpy(cHost, cFileSize, cDevice, cFileSize, ACL_MEMCPY_DEVICE_TO_HOST);

    std::vector<float> c((float *)cHost, (float *)(cHost + cFileSize));

    aclrtFree(aDevice);
    aclrtFree(bDevice);
    aclrtFree(biasDevice);
    aclrtFree(cDevice);
    aclrtFreeHost(cHost);

    aclrtDestroyStream(stream);
    aclrtResetDevice(deviceId);
    aclFinalize();

    return c;
}

template<uint32_t M, uint32_t N, uint32_t K>
std::vector<float> mmad_half_to_float(const std::vector<fp16::half>& A, const std::vector<fp16::half>& B, const std::vector<fp16::half>& Bias)
{
    if (A.size() != size_t(M * K)) {
        throw std::runtime_error("Error: Matrix A dimension mismatch.");
    }
    if (B.size() != size_t(K * N)) {
        throw std::runtime_error("Error: Matrix B dimension mismatch.");
    }
    if (Bias.size() != size_t(N)) {
        throw std::runtime_error("Error: Bias size must match output columns (N).");
    }
    std::vector<float> C;
    C.resize(M * N);

    for (int i = 0; i < M; ++i) {
        for (int j = 0; j < N; ++j) {
            float sum = 0.0f;
            for (int k = 0; k < K; ++k) {
                float val_a = static_cast<float>(A[i * K + k]);
                float val_b = static_cast<float>(B[k * N + j]);
                sum += val_a * val_b;
            }
            sum += static_cast<float>(Bias[j]);
            C[i * N + j] = sum;
        }
    }
    return C;
}

uint32_t VerifyResult(std::vector<float> &output, std::vector<float> &golden)
{
    constexpr float var = 1e-3;
    auto printTensor = [](std::vector<float> &tensor, const char *name) {
        constexpr size_t maxPrintSize = 20;
        std::cout << name << ": ";
        std::copy(tensor.begin(), tensor.begin() + std::min(tensor.size(), maxPrintSize),
            std::ostream_iterator<float>(std::cout, " "));
        if (tensor.size() > maxPrintSize) {
            std::cout << "...";
        }
        std::cout << std::endl;
    };
    printTensor(output, "Output");
    printTensor(golden, "Golden");
    bool res = true;
    for (size_t i = 0; i < output.size(); ++i) {
        if (std::abs(output[i] - golden[i]) > var) {
            std::cout << i << ":" << output[i] << " " << golden[i] << std::endl;
            res = false;
        }
    }
    if (res) {
        std::cout << "[Success] Case accuracy is verification passed." << std::endl;
        return 0;
    } else {
        std::cout << "[Failed] Case accuracy is verification failed!" << std::endl;
        return 1;
    }
    return 0;
}

template<typename T>
std::vector<T> generate_random_vector_generate(const size_t& size) {
    std::vector<float> rdVec(size);
    std::vector<T> res(size);
    std::random_device rd;
    std::mt19937 gen(rd());
    std::uniform_real_distribution<float> dis(0.0f, 5.0f);

    std::generate(rdVec.begin(), rdVec.end(), [&]() { return dis(gen); });

    for (size_t i = 0; i < size; ++i) {
        res[i] = static_cast<T>(rdVec[i]);
    }
    return res;
}

int32_t main(int32_t argc, char *argv[])
{
    constexpr uint32_t M = 32;
    constexpr uint32_t N = 32;
    constexpr uint32_t K = 32;
    std::vector<fp16::half> a = generate_random_vector_generate<fp16::half>(M * K);
    std::vector<fp16::half> b = generate_random_vector_generate<fp16::half>(K * N);
    std::vector<fp16::half> bias = generate_random_vector_generate<fp16::half>(N);

    std::vector<float> c = kernel_mmad<M, N, K>(a, b, bias);

    std::vector<float> golden = mmad_half_to_float<M, N, K>(a, b, bias);

    return VerifyResult(c, golden);
}

