namespace {
    constexpr uint32_t THREAD_COUNT = 32;
}

__simt_vf__ __launch_bounds__(THREAD_COUNT) inline void simt_gather(
    __gm__ float* input,
    __gm__ uint32_t* index,
    __gm__ float* gather_output,
    uint32_t in_shape0,
    uint32_t in_shape1,
    uint32_t index_total_length)
{
    uint64_t t1 = clock();
    // Calculate global thread ID -> maps to the row index of output tensor
    int32_t out_row = blockIdx.x * blockDim.x + threadIdx.x;

    // Calculate global thread ID -> maps to the row index of output tensor
    if (out_row >= index_total_length) {
        return;
    }

    // Single thread processes entire row (all columns) - enables coalesced memory access
    uint32_t in_row = index[out_row];
    for (int32_t col = 0; col < in_shape1; col++) {
        int input_idx = in_row * in_shape1 + col;
        int output_idx = out_row * in_shape1 + col;
        gather_output[output_idx] = input[input_idx];
    }
    uint64_t t2 = clock();
    printf("simt_vf execute cycle : %lu\n", t2 - t1);
}

__global__ __vector__ void gather_kernel(__gm__ float* input, __gm__ uint32_t* index, __gm__ float* output,
    uint32_t in_shape0, uint32_t in_shape1, uint32_t index_total_length)
{
    asc_vf_call<simt_gather>(dim3(THREAD_COUNT), input, index, 
                             output,
                             in_shape0,
                             in_shape1,
                             index_total_length);
}

std::vector<float> gather(std::vector<float>& input, const uint32_t* in_shape, std::vector<uint32_t>& index)
{
    uint32_t input_total_length = input.size();
    size_t input_total_byte_size = input_total_length * sizeof(float);

    uint32_t index_total_length = index.size();
    size_t index_total_byte_size = index_total_length * sizeof(uint32_t);

    uint32_t output_total_length = index.size() * in_shape[1];
    size_t output_total_byte_size = output_total_length * sizeof(float);
    uint32_t num_blocks = (index_total_length + THREAD_COUNT - 1) / THREAD_COUNT;

    int32_t device_id = 0;
    aclrtStream stream = nullptr;

    uint8_t* input_host = reinterpret_cast<uint8_t *>(input.data());
    uint8_t* index_host = reinterpret_cast<uint8_t *>(index.data());
    uint8_t* output_host = nullptr;
    float* input_device = nullptr;
    uint32_t* index_device = nullptr;
    float* output_device = nullptr;

    aclInit(nullptr);
    aclrtSetDevice(device_id);
    aclrtCreateStream(&stream);
    aclrtMallocHost((void **)(&output_host), output_total_byte_size);
    aclrtMalloc((void **)&input_device, input_total_byte_size, ACL_MEM_MALLOC_HUGE_FIRST);
    aclrtMalloc((void **)&index_device, index_total_byte_size, ACL_MEM_MALLOC_HUGE_FIRST);
    aclrtMalloc((void **)&output_device, output_total_byte_size, ACL_MEM_MALLOC_HUGE_FIRST);

    aclrtMemcpy(input_device, input_total_byte_size, input_host, input_total_byte_size, ACL_MEMCPY_HOST_TO_DEVICE);
    aclrtMemcpy(index_device, index_total_byte_size, index_host, index_total_byte_size, ACL_MEMCPY_HOST_TO_DEVICE);

    uint32_t dyn_ubuf_size = 0;  // No need to alloc dynamic memory.
    gather_kernel<<<num_blocks, dyn_ubuf_size, stream>>>(input_device, index_device, output_device,
        in_shape[0], in_shape[1], index_total_length);
    aclrtSynchronizeStream(stream);

    aclrtMemcpy(output_host, output_total_byte_size, output_device, output_total_byte_size, ACL_MEMCPY_DEVICE_TO_HOST);

    std::vector<float> output((float *)output_host, (float *)(output_host + output_total_byte_size));

    aclrtFree(input_device);
    aclrtFree(index_device);
    aclrtFree(output_device);
    aclrtFreeHost(output_host);

    aclrtDestroyStream(stream);
    aclrtResetDevice(device_id);
    aclFinalize();

    return output;
}

uint32_t verify_result(std::vector<float>& output, std::vector<float>& golden)
{
    auto print_tensor = [](std::vector<float>& tensor, const char* name) {
        constexpr size_t max_print_size = 20;
        std::cout << name << ": ";
        std::copy(tensor.begin(), tensor.begin() + std::min(tensor.size(), max_print_size),
            std::ostream_iterator<float>(std::cout, " "));
        if (tensor.size() > max_print_size) {
            std::cout << "...";
        }
        std::cout << std::endl;
    };
    print_tensor(output, "Output");
    print_tensor(golden, "Golden");
    if (std::equal(output.begin(), output.end(), golden.begin())) {
        std::cout << "[Success] Case accuracy is verification passed." << std::endl;
        return 0;
    } else {
        std::cout << "[Failed] Case accuracy is verification failed!" << std::endl;
        return 1;
    }
    return 0;
}

float random_float(float min, float max)
{
    static std::mt19937 engine(std::chrono::system_clock::now().time_since_epoch().count());
    std::uniform_real_distribution<float> dist(min, max);
    return dist(engine);
}

uint32_t random_uint32(uint32_t min, uint32_t max)
{
    static std::mt19937 engine(std::chrono::system_clock::now().time_since_epoch().count());
    std::uniform_int_distribution<uint32_t> dist(min, max);
    return dist(engine);
}

int32_t main(int32_t argc, char* argv[])
{
    constexpr uint32_t in_shape[2] = {48 * 32, 128};
    constexpr uint32_t input_total_length = in_shape[0] * in_shape[1];
    std::vector<float> input(input_total_length);
    for (uint32_t i = 0; i < input_total_length; i++) {
        input[i] = random_float(0.0f, 100.0f);
    }

    constexpr uint32_t index_total_length = 12288;
    std::vector<uint32_t> index(index_total_length);
    for (uint32_t i = 0; i < index_total_length; i++) {
        index[i] = random_uint32(0, in_shape[0] - 1);
    }

    std::vector<float> golden(index_total_length * in_shape[1]);
    for (uint32_t i = 0; i < index_total_length; i++) {
        for (uint32_t j = 0; j < in_shape[1]; j++) {
            golden[i * in_shape[1] + j] = input[index[i] * in_shape[1] + j];
        }
    }

    std::vector<float> output = gather(input, in_shape, index);
    return verify_result(output, golden);
}

class KernelGetRuntimeUBSize {
public:
  __aicore__ inline KernelGetRuntimeUBSize() {}

  __aicore__ inline void Init(GM_ADDR srcGm, GM_ADDR dstGm, AscendC::TPipe* pipeIn, uint32_t totalLength) 
  {
    pipe = pipeIn;
    srcGlobal.SetGlobalBuffer((__gm__ half *)srcGm);
    dstGlobal.SetGlobalBuffer((__gm__ half *)dstGm);
    tileLength = AscendC::GetRuntimeUBSize() / sizeof(half) / 2;
    tileNum = totalLength / tileLength;
    pipe->InitBuffer(inQueue, 1, tileLength * sizeof(half));
    pipe->InitBuffer(outQueue, 1, tileLength * sizeof(half));
  }

  __aicore__ inline void Process() 
  {
    for (int32_t i = 0; i < tileNum; i++) {
      CopyIn(i);
      Compute(i);
      CopyOut(i);
    }
  }

private:
  __aicore__ inline void CopyIn(int32_t progress) 
  {
    AscendC::LocalTensor<half> srcLocal = inQueue.AllocTensor<half>();
    AscendC::DataCopy(srcLocal, srcGlobal[progress * tileLength], tileLength);
    inQueue.EnQue(srcLocal);
  }

  __aicore__ inline void Compute(int32_t progress) 
  {
    AscendC::LocalTensor<half> srcLocal = inQueue.DeQue<half>();
    AscendC::LocalTensor<half> dstLocal = outQueue.AllocTensor<half>();
    AscendC::Abs(dstLocal, srcLocal, tileLength);
    outQueue.EnQue<half>(dstLocal);
    inQueue.FreeTensor(srcLocal);
  }

  __aicore__ inline void CopyOut(int32_t progress) 
  {
    AscendC::LocalTensor<half> dstLocal = outQueue.DeQue<half>();
    AscendC::DataCopy(dstGlobal[progress * tileLength], dstLocal, tileLength);
    outQueue.FreeTensor(dstLocal);
  }

private:
  AscendC::TPipe* pipe;
  AscendC::TQue<AscendC::TPosition::VECIN, 1> inQueue;
  AscendC::TQue<AscendC::TPosition::VECOUT, 1> outQueue;
  AscendC::GlobalTensor<half> srcGlobal;
  AscendC::GlobalTensor<half> dstGlobal;
  uint32_t tileNum;
  uint32_t tileLength;
}

struct GoldenData {
    std::vector<half> src;
    std::vector<half> golden;
}

__global__ __vector__ void kernel_get_runtime_ub_size(GM_ADDR x, GM_ADDR z) 
{
  AscendC::TPipe pipe;
  KernelGetRuntimeUBSize op;
  uint32_t totalLength = 126976;
  op.Init(x, z, &pipe, totalLength);
  op.Process();
}

