class KernelGetUBSizeInBytes {
public:
  __aicore__ inline KernelGetUBSizeInBytes() {}
  __aicore__ inline void Init(GM_ADDR x, GM_ADDR out, AscendC::TPipe* pipeIn, uint32_t totalLength) 
  {
    pipe = pipeIn;
    this->totalLength = totalLength;
    if (totalLength > AscendC::GetUBSizeInBytes() / sizeof(half) / 2) {
      // one input and one output
      this->tileLength = AscendC::GetUBSizeInBytes() / sizeof(half) / 2;
    } else {
      this->tileLength = this->totalLength;
    }
    this->tileNum = this->totalLength / this->tileLength;
    xGm.SetGlobalBuffer((__gm__ half *)x);
    outGm.SetGlobalBuffer((__gm__ half *)out);
    pipe->InitBuffer(inQueueX, 1, this->tileLength * sizeof(half));
    pipe->InitBuffer(outQueueOUT, 1, this->tileLength * sizeof(half));
  }
  __aicore__ inline void Process() 
  {
    int32_t loopCount = this->tileNum;
    for (int32_t i = 0; i < loopCount; i++) {
      CopyIn(i);
      Compute(i);
      CopyOut(i);
    }
  }

private:
  __aicore__ inline void CopyIn(int32_t progress) 
  {
    AscendC::LocalTensor<half> xLocal = inQueueX.AllocTensor<half>();
    AscendC::DataCopy(xLocal, xGm[progress * this->tileLength],
                      this->tileLength);
    inQueueX.EnQue(xLocal);
  }
  __aicore__ inline void Compute(int32_t progress) 
  {
    AscendC::LocalTensor<half> xLocal = inQueueX.DeQue<half>();
    AscendC::LocalTensor<half> outLocal = outQueueOUT.AllocTensor<half>();
    AscendC::Abs(outLocal, xLocal, this->tileLength);
    outQueueOUT.EnQue<half>(outLocal);
    inQueueX.FreeTensor(xLocal);
  }
  __aicore__ inline void CopyOut(int32_t progress) 
  {
    AscendC::LocalTensor<half> outLocal = outQueueOUT.DeQue<half>();
    AscendC::DataCopy(outGm[progress * this->tileLength], outLocal,
                      this->tileLength);
    outQueueOUT.FreeTensor(outLocal);
  }

private:
  AscendC::TPipe* pipe;
  AscendC::TQue<AscendC::QuePosition::VECIN, 1> inQueueX;
  AscendC::TQue<AscendC::QuePosition::VECOUT, 1> outQueueOUT;
  AscendC::GlobalTensor<half> xGm;
  AscendC::GlobalTensor<half> outGm;
  uint32_t totalLength;
  uint32_t tileNum;
  uint32_t tileLength;
};

__vector__ __global__ void get_ub_size_in_bytes_custom(GM_ADDR x, GM_ADDR z) 
{
  AscendC::TPipe pipe;
  KernelGetUBSizeInBytes op;
  uint32_t totalLength = 16384;
  op.Init(x, z, &pipe, totalLength);
  op.Process();
}

int32_t main(int32_t argc, char* argv[]) 
{
  uint32_t numBlocks = 1;
  size_t inputByteSize = 16384 * sizeof(half);
  size_t outputByteSize = 16384 * sizeof(half);

  int32_t deviceId = 0;
  aclrtSetDevice(deviceId);
  aclrtStream stream = nullptr;
  aclrtCreateStream(&stream);

  uint8_t *xHost, *outHost;
  uint8_t *xDevice, *outDevice;

  aclrtMallocHost((void **)(&xHost), inputByteSize);
  aclrtMallocHost((void **)(&outHost), outputByteSize);
  aclrtMalloc((void **)&xDevice, inputByteSize, ACL_MEM_MALLOC_HUGE_FIRST);
  aclrtMalloc((void **)&outDevice, outputByteSize, ACL_MEM_MALLOC_HUGE_FIRST);

  ReadFile("./input/input_x.bin", inputByteSize, xHost, inputByteSize);
  aclrtMemcpy(xDevice, inputByteSize, xHost, inputByteSize,
              ACL_MEMCPY_HOST_TO_DEVICE);
  get_ub_size_in_bytes_custom<<<numBlocks, nullptr, stream>>>(xDevice, outDevice);
  aclrtSynchronizeStream(stream);

  aclrtMemcpy(outHost, outputByteSize, outDevice, outputByteSize,
              ACL_MEMCPY_DEVICE_TO_HOST);
  WriteFile("./output/output.bin", outHost, outputByteSize);

  aclrtFree(xDevice);
  aclrtFree(outDevice);
  aclrtFreeHost(xHost);
  aclrtFreeHost(outHost);

  aclrtDestroyStream(stream);
  aclrtResetDevice(deviceId);
  aclFinalize();

  return 0;
}

ge::graphStatus TilingFunc(gert::TilingContext *context)
{
    AddCustomTilingData *tiling = context->GetTilingData<AddCustomTilingData>();
    uint32_t totalLength = context->GetInputShape(0)->GetOriginShape().GetShapeSize();
    context->SetBlockDim(NUM_BLOCKS);
    tiling->totalLength = totalLength;
    tiling->tileNum = TILE_NUM;
    size_t *currentWorkspace = context->GetWorkspaceSizes(1);
    currentWorkspace[0] = 0;
    return ge::GRAPH_SUCCESS;
}

class AddCustom : public OpDef {
public:
    explicit AddCustom(const char *name) : OpDef(name)
    {
        this->Input("x")
            .ParamType(REQUIRED)
            .DataType({ge::DT_FLOAT16})
            .Format({ge::FORMAT_ND});
        this->Input("y")
            .ParamType(REQUIRED)
            .DataType({ge::DT_FLOAT16})
            .Format({ge::FORMAT_ND});
        this->Output("z")
            .ParamType(REQUIRED)
            .DataType({ge::DT_FLOAT16})
            .Format({ge::FORMAT_ND});

        this->SetInferShape(ge::InferShape).SetInferDataType(ge::InferDataType);
        this->AICore()
            .SetTiling(optiling::TilingFunc)
            // at least one soc version must be configured.
            .AddConfig("ascend310p")
            .AddConfig("ascend310b")
            .AddConfig("ascend910b")
            .AddConfig("ascend910_93")
            .AddConfig("ascend950");
    }
}

ge::graphStatus TilingFunc(gert::TilingContext *context)
{
    uint32_t totalLength = context->GetInputShape(0)->GetOriginShape().GetShapeSize();
    ge::DataType dtype_x = context->GetInputDesc(0)->GetDataType();
    ge::DataType dtype_y = context->GetInputDesc(1)->GetDataType();
    ge::DataType dtype_z = context->GetOutputDesc(0)->GetDataType();
    uint32_t D_T_X = static_cast<uint32_t>(dtype_x);
    uint32_t D_T_Y = static_cast<uint32_t>(dtype_y);
    uint32_t D_T_Z = static_cast<uint32_t>(dtype_z);
    uint32_t TILE_NUM = 1;
    uint32_t IS_SPLIT = 0;
    if (totalLength < MIN_LENGTH_FOR_SPLIT) {
        IS_SPLIT = 0;
        TILE_NUM = 1;
    } else {
        IS_SPLIT = 1;
        TILE_NUM = DEFAULT_TILE_NUM;
    }
    context->SetBlockDim(NUM_BLOCKS);
    TilingDataTemplate *tiling = context->GetTilingData<TilingDataTemplate>();
    tiling->totalLength = totalLength;
    // 模板参数tilingkey配置
    ASCENDC_TPL_SEL_PARAM(context, D_T_X, D_T_Y, D_T_Z, TILE_NUM, IS_SPLIT);
    size_t *currentWorkspace = context->GetWorkspaceSizes(1);
    currentWorkspace[0] = 0;
    return ge::GRAPH_SUCCESS;
}

