class KernelBroadCastVecToMM {
public:
    __aicore__ inline KernelBroadCastVecToMM() {}
    __aicore__ inline void Init(__gm__ uint8_t* srcGm, __gm__ uint8_t* dstGm, AscendC::TPipe* pipeIn)
    {
        pipe = pipeIn;
        srcGlobal.SetGlobalBuffer((__gm__ float*)srcGm);
        dstGlobal.SetGlobalBuffer((__gm__ float*)dstGm);
        pipe->InitBuffer(inQueueSrc, 1, INPUT_LENGTH * sizeof(float));
        pipe->InitBuffer(broadCastQueue, 1, OUTPUT_LENGTH * sizeof(float));
        pipe->InitBuffer(outQueueDst, 1, OUTPUT_LENGTH * sizeof(float));
    }
    __aicore__ inline void Process()
    {
        CopyIn();
        BroadCast();
        Aggregate();
        CopyOut();
    }
private:
    __aicore__ inline void CopyIn()
    {
        AscendC::LocalTensor<float> srcLocal = inQueueSrc.AllocTensor<float>();
        AscendC::DataCopy(srcLocal, srcGlobal, INPUT_LENGTH);
        inQueueSrc.EnQue(srcLocal);
    }
    __aicore__ inline void BroadCast()
    {
        AscendC::LocalTensor<float> srcLocal = inQueueSrc.DeQue<float>();
        AscendC::LocalTensor<float> brcLocal = broadCastQueue.AllocTensor<float>();
        // blockCount = 1, blockLen = 1, 256 elements total
        // srcGap = 0, dstGap = 1
        AscendC::BroadCastVecToMM(brcLocal, srcLocal, 1, 1, 0, 1);
        broadCastQueue.EnQue<float>(brcLocal);
        inQueueSrc.FreeTensor(srcLocal);
    }
    __aicore__ inline void Aggregate()
    {
        AscendC::LocalTensor<float> brcLocal = broadCastQueue.DeQue<float>();
        AscendC::LocalTensor<float> dstLocal = outQueueDst.AllocTensor<float>();

        AscendC::DataCopyParams dataCopyParams;
        dataCopyParams.blockCount = 1;
        dataCopyParams.blockLen = 32;
        AscendC::DataCopyEnhancedParams enhancedParams;
        enhancedParams.blockMode = AscendC::BlockMode::BLOCK_MODE_MATRIX;
        // CO1 -> UB
        AscendC::DataCopy(dstLocal, brcLocal, dataCopyParams, enhancedParams);

        outQueueDst.EnQue<float>(dstLocal);
        broadCastQueue.FreeTensor(brcLocal);
    }
    __aicore__ inline void CopyOut()
    {
        AscendC::LocalTensor<float> dstLocal = outQueueDst.DeQue<float>();
        AscendC::DataCopy(dstGlobal, dstLocal, OUTPUT_LENGTH);
        outQueueDst.FreeTensor(dstLocal);
    }
private:
    AscendC::TPipe* pipe;
    AscendC::TQue<AscendC::TPosition::VECIN, 1> inQueueSrc;
    AscendC::TQueBind<AscendC::TPosition::VECIN, AscendC::TPosition::CO1, 1> broadCastQueue;
    AscendC::TQue<AscendC::TPosition::VECOUT, 1> outQueueDst;
    AscendC::GlobalTensor<float> srcGlobal, dstGlobal;
}

