    {
        AscendC::LocalTensor<int32_t> srcLocal = inQueueSrc.AllocTensor<int32_t>();
        AscendC::DataCopy(srcLocal, srcGlobal, 512);
        inQueueSrc.EnQue(srcLocal);
    }
    __aicore__ inline void Compute()
    {
        AscendC::LocalTensor<int32_t> srcLocal = inQueueSrc.DeQue<int32_t>();
        AscendC::LocalTensor<int32_t> dstLocal = outQueueDst.AllocTensor<int32_t>();

        uint64_t mask = 64;

        // 执行拷贝操作
        // 参数说明：dstLocal-目标张量，srcLocal-源张量，mask-每次迭代内前64个元素参与计算，8-重复次数
        // {1, 1, 8, 8}-块拷贝参数，同一迭代内datablock的地址步长1，相邻迭代间的地址步长8
        AscendC::Copy(dstLocal, srcLocal, mask, 8, { 1, 1, 8, 8 });

        outQueueDst.EnQue<int32_t>(dstLocal);
        inQueueSrc.FreeTensor(srcLocal);
    }
    __aicore__ inline void CopyOut()
    {
        AscendC::LocalTensor<int32_t> dstLocal = outQueueDst.DeQue<int32_t>();
        AscendC::DataCopy(dstGlobal, dstLocal, 512);
        outQueueDst.FreeTensor(dstLocal);
    }
private:
    AscendC::TPipe* pipe;
    AscendC::TQue<AscendC::TPosition::VECIN, 1> inQueueSrc;
    AscendC::TQue<AscendC::TPosition::VECOUT, 1> outQueueDst;
    AscendC::GlobalTensor<int32_t> srcGlobal, dstGlobal;
}

__global__ __vector__ void copy_custom(GM_ADDR x, GM_ADDR z) 
{
    AscendC::TPipe pipe;
    KernelCopy op;
    op.Init(x, z, &pipe);
    op.Process();
}

template <typename T>
class KernelDataCopy {
public:
    __aicore__ inline KernelDataCopy() {}
    __aicore__ inline void Init(GM_ADDR x, GM_ADDR y, uint32_t xCountIn, uint32_t yCountIn, AscendC::TPipe* pipeIn)
    {
        this->pipe = pipeIn;
        this->xCount = xCountIn;
        this->yCount = yCountIn;

        this->xGm.SetGlobalBuffer(reinterpret_cast<__gm__ T*>(x));
        this->yGm.SetGlobalBuffer(reinterpret_cast<__gm__ T*>(y));
        this->pipe->InitBuffer(inQueueX, 1, xCount * sizeof(T));
        this->pipe->InitBuffer(outQueueY, 1, yCount * sizeof(T));
    }
    __aicore__ inline void Process()
    {
        CopyIn();
        Compute();
        CopyOut();
    }

private:
    __aicore__ inline void CopyIn()
    {
        AscendC::LocalTensor<T> xLocal = inQueueX.AllocTensor<T>();
        AscendC::Duplicate<T>(xLocal, 0, xCount);

        // 2D Padding场景，2维数据搬运
        // xGmShape：[2, 8]，搬运8列2行数据，左Padding 3，上Padding 1，右Padding 5，下Padding 1，xLocalShape：[4, 16]
        AscendC::NdDmaLoopInfo<2> loopInfo{{1, 8}, {1, 16}, {8, 2}, {3, 1}, {5, 1}};
        AscendC::NdDmaParams<T, 2> params{loopInfo, 0};  // padding的值为0
        AscendC::NdDmaDci();  // 刷新cache
        static constexpr AscendC::NdDmaConfig dmaConfig;  // // 使用默认参数，也可以不传
        AscendC::DataCopy<T, 2, dmaConfig>(xLocal, xGm, params);

        inQueueX.EnQue(xLocal);
    }
    __aicore__ inline void Compute()
    {
        AscendC::LocalTensor<T> xLocal = inQueueX.DeQue<T>();
        AscendC::LocalTensor<T> yLocal = outQueueY.AllocTensor<T>();
        AscendC::DataCopy(yLocal, xLocal, yCount);
        outQueueY.EnQue<T>(yLocal);
        inQueueX.FreeTensor(xLocal);
    }
    __aicore__ inline void CopyOut()
    {
        AscendC::LocalTensor<T> yLocal = outQueueY.DeQue<T>();
        AscendC::DataCopy(yGm, yLocal, yCount);
        outQueueY.FreeTensor(yLocal);
    }

private:
    AscendC::TPipe* pipe;
    AscendC::TQue<AscendC::TPosition::VECIN, 1> inQueueX;
    AscendC::TQue<AscendC::TPosition::VECOUT, 1> outQueueY;
    AscendC::GlobalTensor<T> xGm, yGm;
    uint32_t xCount, yCount;
}

__global__ __vector__ void datacopy_custom(GM_ADDR x, GM_ADDR y)
{
    AscendC::TPipe pipe;
    KernelDataCopy<float> op;
    // xShape: [2, 8], yShape: [4, 16]
    op.Init(x, y, 2 * 8, 4 * 16, &pipe);
    op.Process();
}

template <typename T>
class SliceData {
public:
    __aicore__ inline SliceData() {}
    __aicore__ inline void Init(__gm__ uint8_t* dstGm, __gm__ uint8_t* srcGm, AscendC::TPipe *pipeIn)
    {
        pipe = pipeIn;
        // startIndex, endIndex, stride, burstLen, shapeValue
        AscendC::SliceInfo srcSliceInfoIn[] = {{16, 70, 7, 3, 87}, {0, 2, 1, 1, 3}};
        AscendC::SliceInfo dstSliceInfoIn[] = {{0, 47, 0, 3, 48}, {0, 1, 0, 1, 2}};
        uint32_t dimValueIn = 2;
        uint32_t dstDataSize = 96; // dst shape[2, 48]
        uint32_t srcDataSize = 261; // src shape[3, 87]
        dimValue = dimValueIn;
        for (uint32_t i = 0; i < dimValueIn; i++) {
            srcSliceInfo[i].startIndex = srcSliceInfoIn[i].startIndex;
            srcSliceInfo[i].endIndex = srcSliceInfoIn[i].endIndex;
            srcSliceInfo[i].stride = srcSliceInfoIn[i].stride;
            srcSliceInfo[i].burstLen = srcSliceInfoIn[i].burstLen;
            srcSliceInfo[i].shapeValue = srcSliceInfoIn[i].shapeValue;
            dstSliceInfo[i].startIndex = dstSliceInfoIn[i].startIndex;
            dstSliceInfo[i].endIndex = dstSliceInfoIn[i].endIndex;
            dstSliceInfo[i].stride = dstSliceInfoIn[i].stride;
            dstSliceInfo[i].burstLen = dstSliceInfoIn[i].burstLen;
            dstSliceInfo[i].shapeValue = dstSliceInfoIn[i].shapeValue;
        }
        srcGlobal.SetGlobalBuffer((__gm__ T *)srcGm);
        dstGlobal.SetGlobalBuffer((__gm__ T *)dstGm);
        pipeIn->InitBuffer(inQueueSrcVecIn, 1, dstDataSize * sizeof(T));
    }
    __aicore__ inline void Process()
    {
        CopyIn();
        CopyOut();
    }
private:
    __aicore__ inline void CopyIn()
    {
        AscendC::LocalTensor<T> srcLocal = inQueueSrcVecIn.AllocTensor<T>();
        // GM -> UB
        AscendC::DataCopy(srcLocal, srcGlobal, dstSliceInfo, srcSliceInfo, dimValue);
        inQueueSrcVecIn.EnQue(srcLocal);
    }
    __aicore__ inline void CopyOut()
    {
        AscendC::LocalTensor<T> srcOutLocal = inQueueSrcVecIn.DeQue<T>();
        int32_t eventID = static_cast<int32_t>(GetTPipePtr()->FetchEventID(AscendC::HardEvent::MTE2_MTE3));
 	    AscendC::SetFlag<AscendC::HardEvent::MTE2_MTE3>(eventID);
 	    AscendC::WaitFlag<AscendC::HardEvent::MTE2_MTE3>(eventID);
        // UB -> GM
        AscendC::DataCopy(dstGlobal, srcOutLocal, dstSliceInfo, dstSliceInfo, dimValue);
        inQueueSrcVecIn.FreeTensor(srcOutLocal);
    }

private:
    AscendC::TPipe *pipe;
    AscendC::TQue<AscendC::TPosition::VECIN, 1> inQueueSrcVecIn;
    AscendC::GlobalTensor<T> srcGlobal;
    AscendC::GlobalTensor<T> dstGlobal;
    AscendC::SliceInfo dstSliceInfo[AscendC::K_MAX_DIM];
    AscendC::SliceInfo srcSliceInfo[AscendC::K_MAX_DIM]; // K_MAX_DIM = 8
    uint32_t dimValue;
}

__global__ __aicore__ void kernel_slice(GM_ADDR dstGm, GM_ADDR srcGm)
{
    AscendC::TPipe pipe;
    SliceData<float> op;
    op.Init(dstGm, srcGm, &pipe);
    op.Process();
}

