static bool CompareResult(const void* outputData, uint32_t outSize)
{
    void* goldenData;
    aclrtMallocHost((void**)(&goldenData), outSize);
    size_t goldenSize = outSize;
    bool ret = ReadFile("./output/golden.bin", goldenSize, goldenData, goldenSize);
    if (ret) {
        printf("ReadFile golden.bin success!\n");
    } else {
        printf("test failed!\n");
        return false;
    }
    constexpr float EPS = 1e-4;
    int64_t wrongNum = 0;

    for (size_t i = 0; i < outSize / sizeof(float); i++) {
        float a = (reinterpret_cast<const float*>(outputData))[i];
        float b = (reinterpret_cast<const float*>(goldenData))[i];
        float ae = std::abs(a - b);
        float re = ae / std::abs(b);
        if (ae > EPS && re > EPS) {
            printf("CompareResult golden.bin failed output is %lf, golden is %lf\n", a, b);
            wrongNum++;
        }
    }
    aclrtFreeHost(goldenData);
    if (wrongNum != 0) {
        return false;
    } else {
        printf("CompareResult golden.bin success!\n");
        return true;
    }
}

int32_t main(int32_t argc, char* argv[])
{
    uint32_t numBlocks = 1;
    aclInit(nullptr);
    int32_t deviceId = 0;
    aclrtSetDevice(deviceId);
    aclrtStream stream = nullptr;
    aclrtCreateStream(&stream);
    int32_t m = 32, n = 32, k = 32;
    size_t aInputByteSize = static_cast<size_t>(1) * m * k * sizeof(half);
    size_t bInputByteSize = static_cast<size_t>(1) * k * n * sizeof(half);
    size_t outputByteSize = static_cast<size_t>(1) * m * n * sizeof(float);
    uint8_t *xHost, *yHost, *zHost;
    uint8_t *xDevice, *yDevice, *zDevice;
    aclrtMallocHost((void**)(&xHost), aInputByteSize);
    aclrtMallocHost((void**)(&yHost), bInputByteSize);
    aclrtMallocHost((void**)(&zHost), outputByteSize);
    aclrtMalloc((void**)&xDevice, aInputByteSize, ACL_MEM_MALLOC_HUGE_FIRST);
    aclrtMalloc((void**)&yDevice, bInputByteSize, ACL_MEM_MALLOC_HUGE_FIRST);
    aclrtMalloc((void**)&zDevice, outputByteSize, ACL_MEM_MALLOC_HUGE_FIRST);
    ReadFile("./input/input_x.bin", aInputByteSize, xHost, aInputByteSize);
    ReadFile("./input/input_y.bin", bInputByteSize, yHost, bInputByteSize);
    aclrtMemcpy(xDevice, aInputByteSize, xHost, aInputByteSize, ACL_MEMCPY_HOST_TO_DEVICE);
    aclrtMemcpy(yDevice, bInputByteSize, yHost, bInputByteSize, ACL_MEMCPY_HOST_TO_DEVICE);
    data_copy_ub2l1<<<numBlocks, nullptr, stream>>>(xDevice, yDevice, zDevice);
    aclrtSynchronizeStream(stream);
    aclrtMemcpy(zHost, outputByteSize, zDevice, outputByteSize, ACL_MEMCPY_DEVICE_TO_HOST);
    WriteFile("./output/output.bin", zHost, outputByteSize);
    bool goldenResult = true;
    goldenResult = CompareResult(zHost, outputByteSize);
    if (goldenResult) {
        printf("test pass!\n");
    } else {
        printf("test failed!\n");
    }
    aclrtFree(xDevice);
    aclrtFree(yDevice);
    aclrtFree(zDevice);
    aclrtFreeHost(xHost);
    aclrtFreeHost(yHost);
    aclrtFreeHost(zHost);
    aclrtDestroyStream(stream);
    aclrtResetDevice(deviceId);
    aclFinalize();
    return 0;
}

template <typename T, CopyMode mode = CopyMode::COPY_SUCCESSIVE>
class Kernel {
public:
    __aicore__ inline void Init(GM_ADDR x, GM_ADDR y, uint32_t count)
    {
        this->count = count;
        this->xGm.SetGlobalBuffer(reinterpret_cast<__gm__ T*>(x));
        this->yGm.SetGlobalBuffer(reinterpret_cast<__gm__ T*>(y));
    }

    __aicore__ inline void Process()
    {
        // 使用 LocalMemAllocator 分配 UB 内存
        AscendC::LocalMemAllocator<AscendC::Hardware::UB> ubAllocator;
        AscendC::LocalTensor<T> xLocal = ubAllocator.Alloc<T>(count);
        AscendC::LocalTensor<T> yLocal = ubAllocator.Alloc<T>(count);

        // CopyIn: GM -> UB
        AscendC::DataCopy(xLocal, xGm, count);

        // 同步：等待 MTE2 完成
        AscendC::SetFlag<AscendC::HardEvent::MTE2_V>(EVENT_ID0);
        AscendC::WaitFlag<AscendC::HardEvent::MTE2_V>(EVENT_ID0);

        // Compute: 使用 VF_CALL 进行数据搬移
        __ubuf__ T* srcAddr = reinterpret_cast<__ubuf__ T*>(xLocal.GetPhyAddr());
        __ubuf__ T* dstAddr = reinterpret_cast<__ubuf__ T*>(yLocal.GetPhyAddr());
        constexpr uint32_t oneRepeatSize = AscendC::GetVecLen() / sizeof(T);
        uint16_t repeatTimes = AscendC::CeilDivision(count, oneRepeatSize);
        if constexpr (mode == CopyMode::COPY_SUCCESSIVE) {
            // 连续搬运
            AscendC::VF_CALL<CopySucceVF<T>>(dstAddr, srcAddr, oneRepeatSize, repeatTimes, count);
        } else if constexpr (mode == CopyMode::COPY_SUCCESSIVE_POST_UPDATE) {
            // 连续搬运(postUpdate模式)
            AscendC::VF_CALL<CopySucceWithPostModeVF<T>>(dstAddr, srcAddr, oneRepeatSize, repeatTimes, count);
        } else if constexpr (mode == CopyMode::COPY_UNSUCCESSIVE) {
            // 非连续搬运
            AscendC::VF_CALL<CopyUnSucceVF<T>>(dstAddr, srcAddr, oneRepeatSize, repeatTimes, count);
        } else if constexpr (mode == CopyMode::COPY_UNSUCCESSIVE_POST_UPDATE) {
            // 非连续搬运(postUpdate模式)
            AscendC::VF_CALL<CopyUnSucceWithPostModeVF<T>>(dstAddr, srcAddr, oneRepeatSize, repeatTimes, count);
        }

        // 同步：等待 V 完成
        AscendC::SetFlag<AscendC::HardEvent::V_MTE3>(EVENT_ID0);
        AscendC::WaitFlag<AscendC::HardEvent::V_MTE3>(EVENT_ID0);

        // CopyOut: UB -> GM
        AscendC::DataCopy(yGm, yLocal, count);
    }

private:
    uint32_t count;
    AscendC::GlobalTensor<T> xGm;
    AscendC::GlobalTensor<T> yGm;
}

