/* !
 * \file fixpipe_co12gm_channelsplit.asc
 * \brief
 */

#include "acl/acl.h"
#include "kernel_operator.h"
#include "data_utils.h"

// IS_CHANNEL_SPLIT = true: mean enable channelsplit;
// USE_DATA_COPY = true: mean use datacopy interface;

// fp16 type, cube block: [16, 16]
constexpr uint32_t CUBE_BLOCK = 16;
constexpr uint32_t C0_SIZE = 16;
constexpr uint32_t CUBE_BLOCK_SIZE = 16 * 16;

// A No Trans, B No Trans
constexpr uint32_t M = 128;
constexpr uint32_t K = 128;
constexpr uint32_t N = 256;
constexpr uint32_t kRound = 2;

constexpr static uint16_t LIMIT_MNSIZE = 10;
constexpr static uint16_t ALIGN_NUM = 16;

template <class inputType, class outputType, class l0cType>
class KernelMmad {
public:
    __aicore__ inline KernelMmad()
    {
        aSingleSize = m * k;
        bSingleSize = k * n;
        cSingleSize = m * n;

        // A 不转置
        aSizeAlignL1 = CeilAlign(m, CUBE_BLOCK) * CeilAlign(k, C0_SIZE);
        aSizeAlignL0 = CeilAlign(m, CUBE_BLOCK) * CeilAlign(k, C0_SIZE);
        // B 不转置
        bSizeAlignL1 = CeilAlign(k, C0_SIZE) * CeilAlign(n, C0_SIZE);
        bSizeAlignL0 = CeilAlign(k, C0_SIZE) * CeilAlign(n, C0_SIZE);
        // C矩阵无视数据类型和a、b是否转置，m,n都向16对齐
        cSizeAlignL0 = CeilAlign(m, CUBE_BLOCK) * CeilAlign(n, CUBE_BLOCK);
    }

    __aicore__ inline void Init(GM_ADDR a, GM_ADDR b, GM_ADDR c, AscendC::TPipe* pipeIn)
    {
        pipe = pipeIn;
        aGM.SetGlobalBuffer((__gm__ inputType *)a);
        bGM.SetGlobalBuffer((__gm__ inputType *)b);
        cGM.SetGlobalBuffer((__gm__ outputType *)c);
        pipe->InitBuffer(inQueueA1, 1, aSizeAlignL1 * sizeof(inputType));
        pipe->InitBuffer(inQueueA2, 1, aSizeAlignL0 * sizeof(inputType));
        pipe->InitBuffer(inQueueB1, 1, bSizeAlignL1 * sizeof(inputType));
        pipe->InitBuffer(inQueueB2, 1, bSizeAlignL0 * sizeof(inputType));
        pipe->InitBuffer(outQueueCO1, 1, cSizeAlignL0 * sizeof(l0cType));
    }

    __aicore__ inline void Process()
    {
        uint32_t chunkSize = kRound;
        AscendC::LocalTensor<l0cType> c;
        c = outQueueCO1.AllocTensor<l0cType>();
        for (uint32_t kIndex = 0; kIndex < chunkSize; kIndex++) {
            CopyIn(kIndex);
            SplitA(kIndex);
            SplitB(kIndex);
            Compute(kIndex, c);
        }

        // use data copy
        if constexpr (USE_DATA_COPY == true) {
            CopyOutUseDataCopy(c);
        } else {
            CopyOut(c);
        }
        outQueueCO1.FreeTensor(c);
    }

private:
    __aicore__ inline uint16_t CeilDivision(uint16_t numerator, uint16_t denominator) 
    {
        return (numerator + denominator - 1) / denominator;
    }

    __aicore__ inline uint16_t CeilAlign(uint16_t numerator, uint16_t denominator) 
    {
        return (numerator + denominator - 1) / denominator * denominator;
    }

    __aicore__ inline void CopyIn(uint32_t kIndex)
    {
        AscendC::LocalTensor<inputType> a1Local = inQueueA1.AllocTensor<inputType>();
        AscendC::LocalTensor<inputType> b1Local = inQueueB1.AllocTensor<inputType>();
        AscendC::Nd2NzParams nd2nzA1Params;
        // 传输ND矩阵的数目
        nd2nzA1Params.ndNum = 1;
        nd2nzA1Params.nValue = m;
        nd2nzA1Params.dValue = k;
        // 源操作数相邻ND矩阵起始地址间的偏移，单位为元素。
        nd2nzA1Params.srcNdMatrixStride = 0;
        nd2nzA1Params.srcDValue = k;
        // 目的NZ矩阵中，来自源操作数同一行的多行数据相邻行起始地址间的偏移，取值范围：dstNzC0Stride∈[1, 16384]，单位：C0_SIZE（32B）。
        nd2nzA1Params.dstNzC0Stride = CeilAlign(m, CUBE_BLOCK);
        // 目的NZ矩阵中，Z型矩阵相邻行起始地址之间的偏移。单位：C0_SIZE（32B）。
        nd2nzA1Params.dstNzNStride = 1;
        // 目的NZ矩阵中，相邻NZ矩阵起始地址间的偏移，单位为元素。
        nd2nzA1Params.dstNzMatrixStride = 0;
        AscendC::DataCopy(a1Local, aGM[kIndex * aSingleSize], nd2nzA1Params);

        AscendC::Nd2NzParams nd2nzB1Params;
        nd2nzB1Params.ndNum = 1;
        nd2nzB1Params.nValue = k;
        nd2nzB1Params.dValue = n;
        nd2nzB1Params.srcNdMatrixStride = 0;
        nd2nzB1Params.srcDValue = n;
        nd2nzB1Params.dstNzC0Stride = CeilAlign(k, C0_SIZE);
        nd2nzB1Params.dstNzNStride = 1;
        nd2nzB1Params.dstNzMatrixStride = 0;
        AscendC::DataCopy(b1Local, bGM[kIndex * bSingleSize], nd2nzB1Params);

        inQueueA1.EnQue(a1Local);
        inQueueB1.EnQue(b1Local);
    }

    __aicore__ inline void SplitA(uint32_t kIndex)
    {
        AscendC::LocalTensor<inputType> a1Local = inQueueA1.DeQue<inputType>();
        AscendC::LocalTensor<inputType> a2Local = inQueueA2.AllocTensor<inputType>();
#if defined(__NPU_ARCH__) && (__NPU_ARCH__ == 2201)
        uint32_t dstOffset = CeilDivision(k, C0_SIZE) * CUBE_BLOCK_SIZE;
        uint32_t srcOffset = CUBE_BLOCK_SIZE;
        // Nz -> Zz
        AscendC::LoadData2DParams loadDataParams;
        loadDataParams.repeatTimes = CeilDivision(k, C0_SIZE);
        loadDataParams.srcStride = CeilDivision(m, CUBE_BLOCK);
        loadDataParams.dstGap = 0;
        loadDataParams.ifTranspose = false;
        for (int i = 0; i < CeilDivision(m, CUBE_BLOCK); ++i) {
            AscendC::LoadData(a2Local[i * dstOffset], a1Local[i * srcOffset], loadDataParams);
        }
#elif defined(__NPU_ARCH__) && (__NPU_ARCH__ == 3510)
        AscendC::LoadData2DParamsV2 loadDataParams;
        loadDataParams.mStep = CeilDivision(m, CUBE_BLOCK);
        loadDataParams.kStep = CeilDivision(k, C0_SIZE);
        loadDataParams.srcStride = CeilDivision(m, CUBE_BLOCK);
        loadDataParams.dstStride = CeilDivision(m, CUBE_BLOCK);
        AscendC::LoadData(a2Local, a1Local, loadDataParams);
#endif
        inQueueA2.EnQue<inputType>(a2Local);
        inQueueA1.FreeTensor(a1Local);
    }

    __aicore__ inline void SplitB(uint32_t kIndex)
    {
        AscendC::LocalTensor<inputType> b1Local = inQueueB1.DeQue<inputType>();
        AscendC::LocalTensor<inputType> b2Local = inQueueB2.AllocTensor<inputType>();

        uint32_t dstOffset = CeilDivision(n, C0_SIZE) * CUBE_BLOCK_SIZE;
        uint32_t srcOffset = CUBE_BLOCK_SIZE;
        // Nz -> Zn
        AscendC::LoadData2DParams loadDataParams;
        loadDataParams.repeatTimes = CeilDivision(n, CUBE_BLOCK);
        loadDataParams.srcStride = CeilDivision(k, CUBE_BLOCK);
        loadDataParams.dstGap = 0;
        loadDataParams.ifTranspose = true;
        for (int i = 0; i < CeilDivision(k, CUBE_BLOCK); ++i) {
            AscendC::LoadData(b2Local[i * dstOffset], b1Local[i * srcOffset], loadDataParams);
        }
        inQueueB2.EnQue<inputType>(b2Local);
        inQueueB1.FreeTensor(b1Local);
    }

    __aicore__ inline void Compute(uint32_t kIndex, AscendC::LocalTensor<l0cType>& c)
    {
        AscendC::LocalTensor<inputType> a = inQueueA2.DeQue<inputType>();
        AscendC::LocalTensor<inputType> b = inQueueB2.DeQue<inputType>();
        AscendC::MmadParams mmadParams;
        mmadParams.m = m;
        // mmad默认n轴向16对齐，但是由于b转置过程n轴向2 * 16对齐，填充了一个全部由无效数据的32 * 16的分形，
        // 如果仍然设置mmadParams.n = n，cube单元会多读入无效数据的分形同时有效数据的分形也未被读入。
        // 此时可以通过设置n向32对齐，让此分形参与计算，搬出时跳过无效分形参与计算的得到的分形即可
        mmadParams.n = CeilAlign(n, C0_SIZE);
        mmadParams.k = k;
        if (kIndex == 0) {
            mmadParams.cmatrixInitVal = true;
        } else {
            mmadParams.cmatrixInitVal = false;
        }

        AscendC::Mmad(c, a, b, mmadParams);
        if ((m / ALIGN_NUM) * (n / ALIGN_NUM) < LIMIT_MNSIZE) {
            AscendC::PipeBarrier<PIPE_M>();
        }

        if (kIndex == kRound - 1) {
            outQueueCO1.EnQue<l0cType>(c);
        }

        inQueueA2.FreeTensor(a);
        inQueueB2.FreeTensor(b);
    }

    __aicore__ inline void CopyOut(AscendC::LocalTensor<l0cType>& c)
    {
        c = outQueueCO1.DeQue<l0cType>();
        // LOC-->GM
        uint16_t c0Size = 16;
        AscendC::FixpipeParamsV220 fixpipeParams;
        if (IS_CHANNEL_SPLIT == true) {
            // fp32 cube block: [16, 8]
            c0Size = 8;
            fixpipeParams.nSize = CeilAlign(n, c0Size);
            fixpipeParams.isChannelSplit = true;
        } else {
            fixpipeParams.nSize = CeilAlign(n, c0Size);
        }
        fixpipeParams.mSize = m;
        fixpipeParams.srcStride = CeilAlign(m, CUBE_BLOCK);
#if defined(__NPU_ARCH__) && (__NPU_ARCH__ == 2201)
        fixpipeParams.dstStride = m * c0Size * sizeof(outputType) / AscendC::ONE_BLK_SIZE;
#elif defined(__NPU_ARCH__) && (__NPU_ARCH__ == 3510)
        fixpipeParams.dstStride = m * c0Size;
#endif

        AscendC::Fixpipe<outputType, l0cType, AscendC::CFG_NZ>(cGM, c, fixpipeParams);
    }

    __aicore__ inline void CopyOutUseDataCopy(AscendC::LocalTensor<l0cType>& c)
    {
        c = outQueueCO1.DeQue<l0cType>();
        uint16_t c0Size = 16;
        AscendC::DataCopyCO12DstParams intriParams;
        if (IS_CHANNEL_SPLIT == true) {
            // fp32 cube block: [16, 8]
            c0Size = 8;
            intriParams.nSize = CeilAlign(n, c0Size);
            intriParams.channelSplit = true;
        } else {
            intriParams.nSize = CeilAlign(n, c0Size);
        }
        intriParams.mSize = m;
        intriParams.srcStride = CeilAlign(m, CUBE_BLOCK);
        intriParams.dstStride = m * c0Size * sizeof(outputType) / AscendC::ONE_BLK_SIZE;

        AscendC::DataCopy(cGM, c, intriParams);      
    }

private:
    AscendC::TPipe* pipe;
    AscendC::TQue<AscendC::TPosition::A1, 1> inQueueA1;
    AscendC::TQue<AscendC::TPosition::A2, 1> inQueueA2;
    AscendC::TQue<AscendC::TPosition::B1, 1> inQueueB1;
    AscendC::TQue<AscendC::TPosition::B2, 1> inQueueB2;
    AscendC::TQue<AscendC::TPosition::CO1, 1> outQueueCO1;

    AscendC::GlobalTensor<half> aGM;
    AscendC::GlobalTensor<half> bGM;
    AscendC::GlobalTensor<float> cGM;

    // 注意沿着K轴切分
    uint16_t m = M, k = K / kRound, n = N;
    uint16_t aSingleSize, bSingleSize, cSingleSize;

    uint16_t aSizeAlignL1, bSizeAlignL1;
    uint16_t aSizeAlignL0, bSizeAlignL0, cSizeAlignL0;
};

extern "C" __global__ __cube__ void fixpipe_co12gm_channelsplit(GM_ADDR a, GM_ADDR b, GM_ADDR c)
{
    AscendC::TPipe pipe;
    KernelMmad<half, float, float> op;
    op.Init(a, b, c, &pipe);
    op.Process();
}

