/* !
 * \file fixpipe_co12gm_quantization_s322s8.asc
 * \brief
 */

#include "acl/acl.h"
#include "kernel_operator.h"
#include "data_utils.h"


// OUTPUT_FORMAT = 1: meam ND output, OUTPUT_FORMAT = 2: mean NZ output
// PRE_QUANT_MODE = 1: mean scalar quant, PRE_QUANT_MODE = 2: mean vector quant
// PRE_RELU_MODE = 0: mean no relu, PRE_RELU_MODE = 1: mean normal relu, leaky relu and prelu not support
// EN_UNIT_FLAG = true: mean enable unitflag
// USE_DATA_COPY = true: mean use datacopy interface

// uint8_t type, cube block: [16, 32]
constexpr uint32_t CUBE_BLOCK = 16;
constexpr uint32_t C0_SIZE = 32;
constexpr uint32_t CUBE_BLOCK_SIZE = 16 * 32;
constexpr uint32_t CUBE_BLOCK_NUM = 2;

// A No Trans, B No Trans
constexpr uint32_t M = 128;
constexpr uint32_t K = 128;
constexpr uint32_t N = 256;
constexpr uint32_t K_ROUND = 2;

constexpr static uint16_t LIMIT_MNSIZE = 10;
constexpr static uint16_t ALIGN_NUM = 16;

template <class inputType, class outputType, class l0cType>
class KernelMmad {
public:
    __aicore__ inline KernelMmad()
    {
        aSingleSize = m * k;
        bSingleSize = k * n;
        cSingleSize = m * n;

        // A 不转置
        aSizeAlignL1 = CeilAlign(m, CUBE_BLOCK) * CeilAlign(k, C0_SIZE);
        aSizeAlignL0 = CeilAlign(m, CUBE_BLOCK) * CeilAlign(k, C0_SIZE);
        // B 不转置
        bSizeAlignL1 = CeilAlign(k, C0_SIZE) * CeilAlign(n, C0_SIZE);
        bSizeAlignL0 = CeilAlign(k, C0_SIZE) * CeilAlign(n, C0_SIZE);
        // C矩阵无视数据类型和a、b是否转置，m,n都向16对齐
        cSizeAlignL0 = CeilAlign(m, CUBE_BLOCK) * CeilAlign(n, CUBE_BLOCK);
    }

    __aicore__ inline void Init(GM_ADDR a, GM_ADDR b, GM_ADDR c, GM_ADDR quantAlpha, AscendC::TPipe* pipeIn)
    {
        pipe = pipeIn;
        aGM.SetGlobalBuffer((__gm__ inputType *)a);
        bGM.SetGlobalBuffer((__gm__ inputType *)b);
        cGM.SetGlobalBuffer((__gm__ outputType *)c);
        quantAlphaGM.SetGlobalBuffer((__gm__ uint64_t *)quantAlpha);
        pipe->InitBuffer(inQueueA1, 1, aSizeAlignL1 * sizeof(inputType));
        pipe->InitBuffer(inQueueA2, 1, aSizeAlignL0 * sizeof(inputType));
        pipe->InitBuffer(inQueueB1, 1, bSizeAlignL1 * sizeof(inputType));
        pipe->InitBuffer(inQueueB2, 1, bSizeAlignL0 * sizeof(inputType));

        if constexpr (PRE_QUANT_MODE == 2) {
            // vector quant的地址需要满足128B对齐
            uint16_t quantAlignSize = CeilAlign(n * sizeof(uint64_t), 128);
            pipe->InitBuffer(inQueueC1, 1, quantAlignSize * sizeof(uint64_t));
            pipe->InitBuffer(inQueueFB, 1, quantAlignSize * sizeof(uint64_t));
        }
        // Tbuf
        if constexpr (EN_UNIT_FLAG == true) {
            pipe->InitBuffer(l0cBuf, cSizeAlignL0 * sizeof(l0cType));
        } else {
            pipe->InitBuffer(outQueueCO1, 1, cSizeAlignL0 * sizeof(l0cType));
        }

    }

    __aicore__ inline void Process()
    {
        uint32_t chunkSize = K_ROUND;
        AscendC::LocalTensor<l0cType> c;
        if constexpr (EN_UNIT_FLAG == true) {
            c = l0cBuf.Get<l0cType>();
        } else {
            c = outQueueCO1.AllocTensor<l0cType>();
        }
        for (uint32_t kIndex = 0; kIndex < chunkSize; kIndex++) {
            CopyIn(kIndex);
            SplitA(kIndex);
            SplitB(kIndex);
            Compute(kIndex, c);
        }

        AscendC::LocalTensor<uint64_t> quantAlphaTensor;
        // vector quant mode
        if constexpr (PRE_QUANT_MODE == 2) {
            quantAlphaTensor = inQueueC1.AllocTensor<uint64_t>();
            CopyQuantAlphaGmToL1(quantAlphaTensor);
        }

        // use data copy
        if constexpr (USE_DATA_COPY == true) {
            CopyOutUseDataCopy(c, quantAlphaTensor);
        } else {
            CopyOut(c, quantAlphaTensor);
        }
        if constexpr (EN_UNIT_FLAG == false) {
            outQueueCO1.FreeTensor(c);
        }
        if constexpr (PRE_QUANT_MODE == 2) {
            inQueueC1.FreeTensor(quantAlphaTensor);
        }
    }

private:
    __aicore__ inline uint16_t CeilDivision(uint16_t numerator, uint16_t denominator) 
    {
        return (numerator + denominator - 1) / denominator;
    }

    __aicore__ inline uint16_t CeilAlign(uint16_t numerator, uint16_t denominator) 
    {
        return (numerator + denominator - 1) / denominator * denominator;
    }

    __aicore__ inline void CopyQuantAlphaGmToL1(AscendC::LocalTensor<uint64_t>& quantAlphaTensor)
    {
        event_t eventIDFixToMte2 = static_cast<event_t>(GetTPipePtr()->FetchEventID(AscendC::HardEvent::FIX_MTE2));
        AscendC::SetFlag<AscendC::HardEvent::FIX_MTE2>(eventIDFixToMte2);
        AscendC::WaitFlag<AscendC::HardEvent::FIX_MTE2>(eventIDFixToMte2);
        uint16_t burstLen = CeilAlign(n * sizeof(uint64_t), 128) / 32;
        AscendC::DataCopyParams intriParams{ 1, burstLen, 0, 0 };
        AscendC::DataCopy(quantAlphaTensor, quantAlphaGM, intriParams);
        event_t eventIDMte2ToFix = static_cast<event_t>(GetTPipePtr()->FetchEventID(AscendC::HardEvent::MTE2_FIX));
        AscendC::SetFlag<AscendC::HardEvent::MTE2_FIX>(eventIDMte2ToFix);
        AscendC::WaitFlag<AscendC::HardEvent::MTE2_FIX>(eventIDMte2ToFix);

        inQueueC1.EnQue(quantAlphaTensor);
        inQueueC1.DeQue();
    }

    __aicore__ inline void CopyIn(uint32_t kIndex)
    {
        AscendC::LocalTensor<inputType> a1Local = inQueueA1.AllocTensor<inputType>();
        AscendC::LocalTensor<inputType> b1Local = inQueueB1.AllocTensor<inputType>();
        AscendC::Nd2NzParams nd2nzA1Params;
        // 传输ND矩阵的数目
        nd2nzA1Params.ndNum = 1;
        nd2nzA1Params.nValue = m;
        nd2nzA1Params.dValue = k;
        // 源操作数相邻ND矩阵起始地址间的偏移，单位为元素。
        nd2nzA1Params.srcNdMatrixStride = 0;
        nd2nzA1Params.srcDValue = k;
        // 目的NZ矩阵中，来自源操作数同一行的多行数据相邻行起始地址间的偏移，取值范围：dstNzC0Stride∈[1, 16384]，单位：C0_SIZE（32B）。
        nd2nzA1Params.dstNzC0Stride = CeilAlign(m, CUBE_BLOCK);
        // 目的NZ矩阵中，Z型矩阵相邻行起始地址之间的偏移。单位：C0_SIZE（32B）。
        nd2nzA1Params.dstNzNStride = 1;
        // 目的NZ矩阵中，相邻NZ矩阵起始地址间的偏移，单位为元素。
        nd2nzA1Params.dstNzMatrixStride = 0;
        AscendC::DataCopy(a1Local, aGM[kIndex * aSingleSize], nd2nzA1Params);

        AscendC::Nd2NzParams nd2nzB1Params;
        nd2nzB1Params.ndNum = 1;
        nd2nzB1Params.nValue = k;
        nd2nzB1Params.dValue = n;
        nd2nzB1Params.srcNdMatrixStride = 0;
        nd2nzB1Params.srcDValue = n;
        nd2nzB1Params.dstNzC0Stride = CeilAlign(k, C0_SIZE);
        nd2nzB1Params.dstNzNStride = 1;
        nd2nzB1Params.dstNzMatrixStride = 0;
        AscendC::DataCopy(b1Local, bGM[kIndex * bSingleSize], nd2nzB1Params);

        inQueueA1.EnQue(a1Local);
        inQueueB1.EnQue(b1Local);
    }

    __aicore__ inline void SplitA(uint32_t kIndex)
    {
        AscendC::LocalTensor<inputType> a1Local = inQueueA1.DeQue<inputType>();
        AscendC::LocalTensor<inputType> a2Local = inQueueA2.AllocTensor<inputType>();
#if defined(__NPU_ARCH__) && (__NPU_ARCH__ == 2201)
        uint32_t dstOffset = CeilDivision(k, C0_SIZE) * CUBE_BLOCK_SIZE;
        uint32_t srcOffset = CUBE_BLOCK_SIZE;
        // Nz -> Zz
        AscendC::LoadData2DParams loadDataParams;
        loadDataParams.repeatTimes = CeilDivision(k, C0_SIZE);
        loadDataParams.srcStride = CeilDivision(m, CUBE_BLOCK);
        loadDataParams.dstGap = 0;
        loadDataParams.ifTranspose = false;
        for (int i = 0; i < CeilDivision(m, CUBE_BLOCK); ++i) {
            AscendC::LoadData(a2Local[i * dstOffset], a1Local[i * srcOffset], loadDataParams);
        }
#elif defined(__NPU_ARCH__) && (__NPU_ARCH__ == 3510)
        AscendC::LoadData2DParamsV2 loadDataParams;
        loadDataParams.mStep = CeilDivision(m, CUBE_BLOCK);
        loadDataParams.kStep = CeilDivision(k, C0_SIZE / sizeof(inputType));
        loadDataParams.srcStride = CeilDivision(m, CUBE_BLOCK);
        loadDataParams.dstStride = CeilDivision(m, CUBE_BLOCK);
        AscendC::LoadData(a2Local, a1Local, loadDataParams);
#endif
        inQueueA2.EnQue<inputType>(a2Local);
        inQueueA1.FreeTensor(a1Local);
    }

    __aicore__ inline void SplitB(uint32_t kIndex)
    {
        AscendC::LocalTensor<inputType> b1Local = inQueueB1.DeQue<inputType>();
        AscendC::LocalTensor<inputType> b2Local = inQueueB2.AllocTensor<inputType>();

        uint32_t dstOffset = CeilDivision(n, C0_SIZE) * CUBE_BLOCK_SIZE * CUBE_BLOCK_NUM;
        uint32_t srcOffset = CUBE_BLOCK_SIZE * CUBE_BLOCK_NUM;
        // Nz -> Zn
        AscendC::LoadData2dTransposeParams loadDataParams;
        loadDataParams.startIndex = 0;
        loadDataParams.repeatTimes = CeilDivision(n, C0_SIZE);
        loadDataParams.srcStride = CeilDivision(k, C0_SIZE);
        loadDataParams.dstGap = 1;
        loadDataParams.dstFracGap = 0;
        for (int i = 0; i < CeilDivision(k, C0_SIZE); ++i) {
            AscendC::LoadDataWithTranspose(b2Local[i * dstOffset], b1Local[i * srcOffset], loadDataParams);
        }
        inQueueB2.EnQue<inputType>(b2Local);
        inQueueB1.FreeTensor(b1Local);
    }

    __aicore__ inline void Compute(uint32_t kIndex, AscendC::LocalTensor<l0cType>& c)
    {
        AscendC::LocalTensor<inputType> a = inQueueA2.DeQue<inputType>();
        AscendC::LocalTensor<inputType> b = inQueueB2.DeQue<inputType>();
        AscendC::MmadParams mmadParams;
        mmadParams.m = m;
        // mmad默认n轴向16对齐，但是由于b转置过程n轴向2 * 16对齐，填充了一个全部由无效数据的32 * 16的分形，
        // 如果仍然设置mmadParams.n = n，cube单元会多读入无效数据的分形同时有效数据的分形也未被读入。
        // 此时可以通过设置n向32对齐，让此分形参与计算，搬出时跳过无效分形参与计算的得到的分形即可
        mmadParams.n = CeilAlign(n, C0_SIZE);
        mmadParams.k = k;
        if (kIndex == 0) {
            mmadParams.cmatrixInitVal = true;
        } else {
            mmadParams.cmatrixInitVal = false;
        }

        if constexpr (EN_UNIT_FLAG == true) {
            // 使能该功能时，Mmad指令的unitFlag在最后1个分形设置为3、其余分形计算设置为2即可。
            // 注： 此功能打开需要确保计算数据量与搬出数据量保持一致
            if (kIndex != K_ROUND - 1) {
                mmadParams.unitFlag = 2;
            } else {
                mmadParams.unitFlag = 3;
            }
        }
        AscendC::Mmad(c, a, b, mmadParams);
        if ((m / ALIGN_NUM) * (n / ALIGN_NUM) < LIMIT_MNSIZE) {
            AscendC::PipeBarrier<PIPE_M>();
        }
        if constexpr (EN_UNIT_FLAG == false) {
            if (kIndex == K_ROUND - 1) {
                outQueueCO1.EnQue<l0cType>(c);
            }
        }

        inQueueA2.FreeTensor(a);
        inQueueB2.FreeTensor(b);
    }

    __aicore__ inline void CopyOut(AscendC::LocalTensor<l0cType>& c, AscendC::LocalTensor<uint64_t>& quantAlphaTensor)
    {
        if constexpr (EN_UNIT_FLAG == false) {
            c = outQueueCO1.DeQue<l0cType>();
        }

        // LOC-->GM
        AscendC::FixpipeParamsV220 fixpipeParams;
        fixpipeParams.nSize = CeilAlign(n, CUBE_BLOCK);
        fixpipeParams.mSize = m;
        fixpipeParams.srcStride = CeilAlign(m, CUBE_BLOCK);
        fixpipeParams.dstStride = m * C0_SIZE * sizeof(outputType) / AscendC::ONE_BLK_SIZE;
        if constexpr (EN_UNIT_FLAG == true) {
            fixpipeParams.unitFlag = 3;
        }

        // scalar quant 
        if constexpr (PRE_QUANT_MODE == 1) {
            fixpipeParams.quantPre = QuantMode_t::REQ8;
            uint64_t deqScalar = static_cast<uint64_t>(*reinterpret_cast<int32_t *>(&quantScalar));
            constexpr bool sign = (AscendC::IsSameType<outputType, int8_t>::value) ? true : false;
            deqScalar = (deqScalar & ~(static_cast<uint64_t>(1) << 46)) | (static_cast<uint64_t>(sign) << 46);
            fixpipeParams.deqScalar = deqScalar;
        } else {
            fixpipeParams.quantPre = QuantMode_t::VREQ8;
        }

        if constexpr (PRE_RELU_MODE == 1) {
            fixpipeParams.reluEn = true;
        }

        // 随路NZ2ND
        if constexpr (OUTPUT_FORMAT == 1) {
            // Orignal nSize
            fixpipeParams.nSize = n;
            fixpipeParams.dstStride = n;
            fixpipeParams.ndNum = 1;
            fixpipeParams.srcNdStride = 0;
            fixpipeParams.dstNdStride = 0;
            if constexpr (PRE_QUANT_MODE == 1) {
                AscendC::Fixpipe<outputType, l0cType, AscendC::CFG_ROW_MAJOR>(cGM, c, fixpipeParams);
            } else {
                AscendC::Fixpipe<outputType, l0cType, AscendC::CFG_ROW_MAJOR>(cGM, c, quantAlphaTensor, fixpipeParams);
            }
        } else {
            // NZ2NZ 默认开启channel merge
            if constexpr (PRE_QUANT_MODE == 1) {
                AscendC::Fixpipe<outputType, l0cType, AscendC::CFG_NZ>(cGM, c, fixpipeParams);
            } else {
                AscendC::Fixpipe<outputType, l0cType, AscendC::CFG_NZ>(cGM, c, quantAlphaTensor, fixpipeParams);
            }
        }
        // unitFlag清空标志位，类型为bool。如果设为true,L0C中所有内存块的单元标志位都会设为0。
        // 旨在消除之前操作中unitFlag产生的多余影响，该操作属于可选项。
        if constexpr (EN_UNIT_FLAG == true) {
            bool isUnitFlag = true;
            AscendC::SetFixPipeConfig<l0cType>(c, isUnitFlag);
        }
    }

    __aicore__ inline void CopyOutUseDataCopy(AscendC::LocalTensor<l0cType>& c, AscendC::LocalTensor<uint64_t>& quantAlphaTensor)
    {
        if constexpr (EN_UNIT_FLAG == false) {
            c = outQueueCO1.DeQue<l0cType>();
        }
        AscendC::DataCopyCO12DstParams intriParams;
        intriParams.nSize = CeilAlign(n, CUBE_BLOCK);
        intriParams.mSize = m;
        intriParams.srcStride = CeilAlign(m, CUBE_BLOCK);
        intriParams.dstStride = m * C0_SIZE * sizeof(outputType) / AscendC::ONE_BLK_SIZE;
        if constexpr (EN_UNIT_FLAG == true) {
            intriParams.unitFlag = 3;
        }

        // scalar quant 
        if constexpr (PRE_QUANT_MODE == 1) {
            intriParams.quantPre = QuantMode_t::REQ8;
            uint64_t deqScalar = static_cast<uint64_t>(*reinterpret_cast<int32_t *>(&quantScalar));
            constexpr bool sign = (AscendC::IsSameType<outputType, int8_t>::value) ? true : false;
            deqScalar = (deqScalar & ~(static_cast<uint64_t>(1) << 46)) | (static_cast<uint64_t>(sign) << 46);
            AscendC::SetFixpipePreQuantFlag(deqScalar);
        } else {
            intriParams.quantPre = QuantMode_t::VREQ8;
            AscendC::LocalTensor<uint64_t> fbTensor = inQueueFB.AllocTensor<uint64_t>();
            inQueueFB.EnQue<uint64_t>(fbTensor);
            fbTensor = inQueueFB.DeQue<uint64_t>();
            uint16_t burstLen = CeilAlign(n * sizeof(uint64_t), 128) / 128;
            AscendC::DataCopyParams dataCopyParams(1, burstLen, 0, 0);
            AscendC::DataCopy(fbTensor, quantAlphaTensor, dataCopyParams);
            AscendC::SetFixPipeConfig(fbTensor);
            inQueueFB.FreeTensor(fbTensor);
        }

        if constexpr (PRE_RELU_MODE == 1) {
            intriParams.reluPre = 1;
        }

        // 随路NZ2ND
        if constexpr (OUTPUT_FORMAT == 1) {
            intriParams.nz2ndEn = true;
            // Orignal nSize
            intriParams.nSize = n;
            intriParams.dstStride = n;
            uint16_t ndNum = 1;
            uint16_t srcNdStride = 0;
            uint16_t dstNdStride = 0;
            AscendC::SetFixpipeNz2ndFlag(ndNum, srcNdStride, dstNdStride);
        }
        AscendC::DataCopy(cGM, c, intriParams);

        // unitFlag清空标志位，类型为bool。如果设为true,L0C中所有内存块的单元标志位都会设为0。
        // 旨在消除之前操作中unitFlag产生的多余影响，该操作属于可选项。
        if constexpr (EN_UNIT_FLAG == true) {
            bool isUnitFlag = true;
            AscendC::SetFixPipeConfig<l0cType>(c, isUnitFlag);
        }
    }

private:
    AscendC::TPipe* pipe;
    AscendC::TQue<AscendC::TPosition::A1, 1> inQueueA1;
    AscendC::TQue<AscendC::TPosition::A2, 1> inQueueA2;
    AscendC::TQue<AscendC::TPosition::B1, 1> inQueueB1;
    AscendC::TQue<AscendC::TPosition::B2, 1> inQueueB2;
    AscendC::TQue<AscendC::TPosition::CO1, 1> outQueueCO1;
    // 注意，开启unitflag功能时，l0c上的tensor应该通过Tbuf获取
    AscendC::TBuf<AscendC::TPosition::CO1> l0cBuf;
    // Vector quant参数 需要从GM拷贝到L1
    AscendC::TQue<AscendC::TPosition::C1, 1> inQueueC1;
    // Vector quant参数 需要再从L1拷贝到FIXP buffer
    AscendC::TQue<AscendC::TPosition::C2PIPE2GM, 1> inQueueFB;

    AscendC::GlobalTensor<int8_t> aGM;
    AscendC::GlobalTensor<int8_t> bGM;
    AscendC::GlobalTensor<int8_t> cGM;
    AscendC::GlobalTensor<uint64_t> quantAlphaGM;

    float quantScalar = 2.0;
    // 注意沿着K轴切分
    uint16_t m = M, k = K / K_ROUND, n = N;
    uint16_t aSingleSize, bSingleSize, cSingleSize;

    uint16_t aSizeAlignL1, bSizeAlignL1;
    uint16_t aSizeAlignL0, bSizeAlignL0, cSizeAlignL0;
};

extern "C" __global__ __cube__ void fixpipe_co12gm_s322s8(GM_ADDR a, GM_ADDR b, GM_ADDR c, GM_ADDR quantAlpha)
{
    AscendC::TPipe pipe;
    KernelMmad<int8_t, int8_t, int32_t> op;
    op.Init(a, b, c, quantAlpha, &pipe);
    op.Process();
}

int32_t main(int32_t argc, char *argv[])
{
    size_t aFileSize = M * K * sizeof(int8_t); 
    size_t bFileSize = K * N * sizeof(int8_t); 
    size_t cFileSize = M * N * sizeof(int8_t);
