    aclrtFree(aDevice);
    aclrtFreeHost(aHost);
    aclrtFree(bDevice);
    aclrtFreeHost(bHost);
    aclrtFree(cDevice);
    aclrtFreeHost(cHost);
    aclrtFree(quantAlphaDevice);
    aclrtFreeHost(quantAlphaHost);    

    aclrtDestroyStream(stream);
    aclrtResetDevice(deviceId);
    aclFinalize();
