#include "data_utils.h"

// int8_t type, cube block: [16, 32]
constexpr uint32_t CUBE_BLOCK = 16;
constexpr uint32_t C0_SIZE = 32;
constexpr uint32_t CUBE_BLOCK_SIZE = 16 * 32;
constexpr uint32_t CUBE_BLOCK_NUM = 2;

class KernelMatmul {
public:
    __aicore__ inline KernelMatmul() {}
    __aicore__ inline void Init(__gm__ uint8_t* a, __gm__ uint8_t* b, __gm__ uint8_t* idx, __gm__ uint8_t* c, uint16_t m, uint16_t k, uint16_t n)
    {
        this->m = m;
        this->k = k;
        this->n = n;

        aSize = m * k;
        bSize = k / 2 * n;
        cSize = m * n;
        mBlocks = m / CUBE_BLOCK;
        nBlocks = n / CUBE_BLOCK;
        kBlocks = k / C0_SIZE;

        aGM.SetGlobalBuffer((__gm__ int8_t*)a);
        bGM.SetGlobalBuffer((__gm__ int8_t*)b);
        idxGM.SetGlobalBuffer((__gm__ uint8_t*)idx);
        cGM.SetGlobalBuffer((__gm__ int32_t*)c);
    }
    __aicore__ inline void Process()
    {
        AscendC::LocalTensor<int8_t> a1Local(AscendC::TPosition::A1, a1Addr, aSize);
 	    AscendC::LocalTensor<int8_t> a2Local(AscendC::TPosition::A2, a2Addr, aSize);
 	    AscendC::LocalTensor<int8_t> b1Local(AscendC::TPosition::B1, b1Addr, bSize);
        AscendC::LocalTensor<uint8_t> idxB1Local(AscendC::TPosition::B1, idxB1Addr, bSize / 4);
 	    AscendC::LocalTensor<int8_t> b2Local(AscendC::TPosition::B2, b2Addr, bSize);
 	    AscendC::LocalTensor<int32_t> cLocal(AscendC::TPosition::CO1, cAddr, cSize);
        CopyIn(a1Local, b1Local, idxB1Local);
        AscendC::SetFlag<AscendC::HardEvent::MTE2_MTE1>(EVENT_ID0);
 	    AscendC::WaitFlag<AscendC::HardEvent::MTE2_MTE1>(EVENT_ID0);    
        SplitA(a1Local, a2Local);
        SplitB(b2Local, b1Local, idxB1Local);
        AscendC::SetFlag<AscendC::HardEvent::MTE1_M>(EVENT_ID0);
 	    AscendC::WaitFlag<AscendC::HardEvent::MTE1_M>(EVENT_ID0);
        Compute(cLocal, a2Local, b2Local);
        AscendC::SetFlag<AscendC::HardEvent::M_FIX>(EVENT_ID0);
 	    AscendC::WaitFlag<AscendC::HardEvent::M_FIX>(EVENT_ID0);
        CopyOut(cLocal);
    }

private:
    __aicore__ inline void CopyIn(AscendC::LocalTensor<int8_t> a1Local, AscendC::LocalTensor<int8_t> b1Local, AscendC::LocalTensor<uint8_t> idxB1Local)
    {
        AscendC::DataCopy(a1Local, aGM, { 1, static_cast<uint16_t>(aSize * sizeof(int8_t) / 32), 0, 0 });
        AscendC::DataCopy(b1Local, bGM, { 1, static_cast<uint16_t>(bSize * sizeof(int8_t) / 32), 0, 0 });
        AscendC::DataCopy(idxB1Local, idxGM, { 1, static_cast<uint16_t>(bSize / 4 * sizeof(int8_t) / 32), 0, 0 });
    }

    __aicore__ inline void SplitA(AscendC::LocalTensor<int8_t> a1Local, AscendC::LocalTensor<int8_t> a2Local)
    {
        uint32_t dstOffset = kBlocks * CUBE_BLOCK_SIZE;
        uint32_t srcOffset = CUBE_BLOCK_SIZE;

        AscendC::LoadData2DParams loadDataParams;
        loadDataParams.repeatTimes = kBlocks;
        loadDataParams.srcStride = mBlocks;
        loadDataParams.dstGap = 0;
        loadDataParams.ifTranspose = false;
        for (int i = 0; i < mBlocks; ++i) {
            AscendC::LoadData(a2Local[i * dstOffset], a1Local[i * srcOffset], loadDataParams);
        }
        AscendC::LoadData(a2Local, a1Local, loadDataParams);
    }

    __aicore__ inline void SplitB(AscendC::LocalTensor<int8_t> b2Local, AscendC::LocalTensor<int8_t> b1Local, AscendC::LocalTensor<uint8_t> idxB1Local)
    {
        //zn to zn
        AscendC::LoadData2DParams loadDataParams;
        loadDataParams.repeatTimes = kBlocks * nBlocks / 2;
        loadDataParams.srcStride = 0;
        loadDataParams.ifTranspose = false;
        AscendC::LoadDataWithSparse(b2Local, b1Local, idxB1Local, loadDataParams);
    }

    __aicore__ inline void Compute(AscendC::LocalTensor<int32_t> cLocal, AscendC::LocalTensor<int8_t> a2Local, AscendC::LocalTensor<int8_t> b2Local)
    {
        AscendC::MmadWithSparse(cLocal, a2Local, b2Local, { m, n, k, false, 0, false, false, false });
    }

    __aicore__ inline void CopyOut(AscendC::LocalTensor<int32_t> cLocal)
    {
        AscendC::FixpipeParamsV220 fixpipeParams;
        fixpipeParams.nSize = n;
        fixpipeParams.mSize = m;
        fixpipeParams.srcStride = m;
        fixpipeParams.dstStride = n;
        fixpipeParams.ndNum = 1;
        fixpipeParams.srcNdStride = 0;
        fixpipeParams.dstNdStride = 0;
        AscendC::Fixpipe(cGM, cLocal, fixpipeParams);
    }

private:
    AscendC::TPipe pipe;

    static constexpr uint32_t a1Addr = 0;
 	static constexpr uint32_t a2Addr = 0;
 	static constexpr uint32_t b1Addr = 128 * 1024;
 	static constexpr uint32_t b2Addr = 0;
    static constexpr uint32_t idxB1Addr = 256 * 1024;
 	static constexpr uint32_t cAddr = 0;

    AscendC::GlobalTensor<int8_t> aGM, bGM;
    AscendC::GlobalTensor<uint8_t> idxGM;
    AscendC::GlobalTensor<int32_t> cGM;

    uint16_t m;
    uint16_t n;
    uint16_t k;

    uint16_t aSize, bSize, cSize, mBlocks, nBlocks, kBlocks;
};


extern "C" __global__ __cube__ void mmad_with_sparse_custom(GM_ADDR a, GM_ADDR b, GM_ADDR idx, GM_ADDR c)
{
    uint16_t m = 128;
    uint16_t n = 128;
    uint16_t k = 64;
    KernelMatmul op;
    op.Init(a, b, idx, c, m, k, n);
    op.Process();
}

