template<typename T>
class KernelReduce {
    static constexpr uint32_t SRC_TOTAL_LENGTH = scenarioNum == 1 ? 256 : scenarioNum == 2 ? 512 : 128;
    static constexpr uint32_t DST_TOTAL_LENGTH = scenarioNum == 2 ? 32 : 16;
public:
    __aicore__ inline KernelReduce() {}
    __aicore__ inline void Init(__gm__ uint8_t* src, __gm__ uint8_t* dstGm, AscendC::TPipe* pipeIn)
    {
        pipe = pipeIn;
        srcGlobal.SetGlobalBuffer((__gm__ T*)src);
        dstGlobal.SetGlobalBuffer((__gm__ T*)dstGm);
        pipe->InitBuffer(inQueueSrc, 1, SRC_TOTAL_LENGTH * sizeof(T));
        pipe->InitBuffer(outQueueDst, 1, DST_TOTAL_LENGTH * sizeof(T));
    }
    __aicore__ inline void Process()
    {
        CopyIn();
        Compute();
        CopyOut();
    }
private:
    __aicore__ inline void CopyIn()
    {
        AscendC::LocalTensor<T> srcLocal = inQueueSrc.AllocTensor<T>();
        AscendC::DataCopy(srcLocal, srcGlobal, SRC_TOTAL_LENGTH);
        inQueueSrc.EnQue(srcLocal);
    }
    __aicore__ inline void Compute()
    {
        AscendC::LocalTensor<T> srcLocal = inQueueSrc.DeQue<T>();
        AscendC::LocalTensor<T> dstLocal = outQueueDst.AllocTensor<T>();
        T zero(0);
        AscendC::Duplicate(dstLocal, zero, DST_TOTAL_LENGTH);
        int32_t mask = 256 / sizeof(T);
        if constexpr (scenarioNum == 1) {
            // 场景1：BlockReduceMax：对每个datablock内所有元素求最大值
            // 每个datablock处理32字节(16个half元素)，256个元素共16个datablock，迭代16/8=2次
            // repeat=2, mask=128(256/sizeof(half)), srcBlkStride=1, srcRepStride=8, dstRepStride=1
            AscendC::BlockReduceMax<T>(dstLocal, srcLocal, 2, mask, 1, 1, 8);
        } else if constexpr (scenarioNum == 2) {
            // 场景2：BlockReduceMin：对每个datablock内所有元素求最小值
            // 每个datablock处理32字节(16个half元素)，512个元素共32个datablock，迭代32/8=4次
            // repeat=4, mask=128(256/sizeof(half)), srcBlkStride=1, srcRepStride=8, dstRepStride=1
            AscendC::BlockReduceMin<T>(dstLocal, srcLocal, 4, mask, 1, 1, 8);
        } else if constexpr (scenarioNum == 3) {
            // 场景3：BlockReduceSum：对每个datablock内所有元素求和
            // 每个datablock处理32字节(8个float元素)，128个元素共16个datablock，迭代16/8=2次
            // repeat=2, mask=64(256/sizeof(float)), srcBlkStride=1, srcRepStride=8, dstRepStride=1
            AscendC::BlockReduceSum<T>(dstLocal, srcLocal, 2, mask, 1, 1, 8);
        }

        outQueueDst.EnQue<T>(dstLocal);
        inQueueSrc.FreeTensor(srcLocal);
    }
    __aicore__ inline void CopyOut()
    {
        AscendC::LocalTensor<T> dstLocal = outQueueDst.DeQue<T>();
        AscendC::DataCopy(dstGlobal, dstLocal, DST_TOTAL_LENGTH);
        outQueueDst.FreeTensor(dstLocal);
    }
private:
    AscendC::TPipe* pipe;
    AscendC::TQue<AscendC::TPosition::VECIN, 1> inQueueSrc;
    AscendC::TQue<AscendC::TPosition::VECOUT, 1> outQueueDst;
    AscendC::GlobalTensor<T> srcGlobal, dstGlobal;
}

__global__ __vector__ void block_reduce_custom(GM_ADDR x, GM_ADDR y)
{
    AscendC::TPipe pipe;
    if constexpr (scenarioNum == 1 || scenarioNum == 2) {
        KernelReduce<half> op;
        op.Init(x, y, &pipe);
        op.Process();
    } else if constexpr (scenarioNum == 3) {
        KernelReduce<float> op;
        op.Init(x, y, &pipe);
        op.Process();
    }
}

class KernelBrcb {
public:
    __aicore__ inline KernelBrcb()
    {}
    __aicore__ inline void Init(__gm__ uint8_t *x, __gm__ uint8_t *y, AscendC::TPipe* pipeIn)
    {
      pipe = pipeIn;
      x_gm.SetGlobalBuffer(reinterpret_cast<__gm__ uint16_t *>(x));
      y_gm.SetGlobalBuffer(reinterpret_cast<__gm__ uint16_t *>(y));
      pipe->InitBuffer(vecIn, 1, 16 * sizeof(uint16_t));
      pipe->InitBuffer(vecOut, 1, 256 * sizeof(uint16_t));
    }
    __aicore__ inline void Process()
    {
      CopyIn();
      Compute();
      CopyOut();
    }
    __aicore__ inline void CopyIn()
    {
      auto x_buf = vecIn.AllocTensor<uint16_t>();
      AscendC::DataCopy(x_buf, x_gm, 16);
      vecIn.EnQue(x_buf);
    }
    __aicore__ inline void Compute()
    {
      auto x_buf = vecIn.DeQue<uint16_t>();
      auto y_buf = vecOut.AllocTensor<uint16_t>();
      /*
      执行广播复制操作参数说明:
      y_buf: 目标张量，用于存储结果
      x_buf: 源张量，要广播的数据
      2: 迭代次数
      {1,8}: 广播参数，1: y_buf迭代内间隔1block，8: y_buf迭代间间隔8block
      */
      AscendC::Brcb(y_buf, x_buf, 2, {1,8});
      vecOut.EnQue(y_buf);
      vecIn.FreeTensor(x_buf);
    }
    __aicore__ inline void CopyOut()
    {
      auto y_buf = vecOut.DeQue<uint16_t>();
      AscendC::DataCopy(y_gm, y_buf, 256);
      vecOut.FreeTensor(y_buf);
    }
private:
    AscendC::GlobalTensor<uint16_t> x_gm;
    AscendC::GlobalTensor<uint16_t> y_gm;
    AscendC::TPipe* pipe;
    AscendC::TQue<AscendC::TPosition::VECIN, 1> vecIn;
    AscendC::TQue<AscendC::TPosition::VECOUT, 1> vecOut;
}

__global__ __vector__ void brcb_custom(GM_ADDR x, GM_ADDR y)
{
  KernelBrcb op;
  AscendC::TPipe pipe;
  op.Init(x, y, &pipe);
  op.Process();
}

class KernelCmp {
public:
    __aicore__ inline KernelCmp() {}
    __aicore__ inline void Init(__gm__ uint8_t* src0Gm, __gm__ uint8_t* src1Gm, __gm__ uint8_t* dstGm, 
                                AscendC::TPipe* pipeIn)
    {
      pipe = pipeIn;
      src0Global.SetGlobalBuffer((__gm__ float*)src0Gm);
      src1Global.SetGlobalBuffer((__gm__ float*)src1Gm);
      dstGlobal.SetGlobalBuffer((__gm__ uint8_t*)dstGm);
      pipe->InitBuffer(inQueueSrc0, 1, srcDataSize * sizeof(float));
      pipe->InitBuffer(inQueueSrc1, 1, srcDataSize * sizeof(float));
      pipe->InitBuffer(outQueueDst, 1, dstDataSize * sizeof(uint8_t));
    }
    __aicore__ inline void Process()
    {
      CopyIn();
      Compute();
      CopyOut();
    }
private:
    __aicore__ inline void CopyIn()
    {
      AscendC::LocalTensor<float> src0Local = inQueueSrc0.AllocTensor<float>();
      AscendC::LocalTensor<float> src1Local = inQueueSrc1.AllocTensor<float>();
      AscendC::DataCopy(src0Local, src0Global, srcDataSize);
      AscendC::DataCopy(src1Local, src1Global, srcDataSize);
      inQueueSrc0.EnQue(src0Local);
      inQueueSrc1.EnQue(src1Local);
    }
    __aicore__ inline void Compute()
    {
      AscendC::LocalTensor<float> src0Local = inQueueSrc0.DeQue<float>();
      AscendC::LocalTensor<float> src1Local = inQueueSrc1.DeQue<float>();
      AscendC::LocalTensor<uint8_t> dstLocal = outQueueDst.AllocTensor<uint8_t>();

      // 可根据实际使用接口Compare进行替换
      AscendC::Compare(dstLocal, src0Local, src1Local, AscendC::CMPMODE::LT, srcDataSize);

      outQueueDst.EnQue<uint8_t>(dstLocal);
      inQueueSrc0.FreeTensor(src0Local);
      inQueueSrc1.FreeTensor(src1Local);
    }
    __aicore__ inline void CopyOut()
    {
      AscendC::LocalTensor<uint8_t> dstLocal = outQueueDst.DeQue<uint8_t>();
      AscendC::DataCopy(dstGlobal, dstLocal, dstDataSize);
      outQueueDst.FreeTensor(dstLocal);
    }
private:
    AscendC::TPipe* pipe;
    AscendC::TQue<AscendC::TPosition::VECIN, 1> inQueueSrc0, inQueueSrc1;
    AscendC::TQue<AscendC::TPosition::VECOUT, 1> outQueueDst;
    AscendC::GlobalTensor<float> src0Global, src1Global;
    AscendC::GlobalTensor<uint8_t> dstGlobal;
    uint32_t srcDataSize = 256;
    uint32_t dstDataSize = srcDataSize / 8;
}

__global__ __vector__ void compare_custom(GM_ADDR x, GM_ADDR y, GM_ADDR z) 
{
  AscendC::TPipe pipe;
  KernelCmp op;
  op.Init(x, y, z, &pipe);
  op.Process();
}

template <typename T> class KernelCmpCmpmask {
