template <typename InputT, typename OutputT>
class KernelCompoundCompute {
public:
    __aicore__ inline KernelCompoundCompute() {}
    __aicore__ inline void Init(GM_ADDR src0_gm, GM_ADDR src1_gm, GM_ADDR dst_gm, AscendC::TPipe* pipeIn)
    {
        pipe = pipeIn;

        if constexpr (scenarioNum == 1) {
            // 场景1：CastDequant - int16_t输入，uint8_t输出
            src0_global.SetGlobalBuffer(reinterpret_cast<__gm__ InputT*>(src0_gm));
            dst_global.SetGlobalBuffer(reinterpret_cast<__gm__ OutputT*>(dst_gm));
            pipe->InitBuffer(inQueueSrc0, 1, DATA_SIZE * sizeof(InputT));
            pipe->InitBuffer(outQueue, 1, DATA_SIZE * 2 * sizeof(OutputT));
        } else {
            // 场景2/3：AddRelu/Axpy - half输入输出
            src0_global.SetGlobalBuffer(reinterpret_cast<__gm__ InputT*>(src0_gm));
            src1_global.SetGlobalBuffer(reinterpret_cast<__gm__ InputT*>(src1_gm));
            dst_global.SetGlobalBuffer(reinterpret_cast<__gm__ OutputT*>(dst_gm));
            pipe->InitBuffer(inQueueSrc0, 1, DATA_SIZE * sizeof(InputT));
            pipe->InitBuffer(inQueueSrc1, 1, DATA_SIZE * sizeof(InputT));
            pipe->InitBuffer(outQueue, 1, DATA_SIZE * sizeof(OutputT));
        }
    }

    __aicore__ inline void Process()
    {
        CopyIn();
        Compute();
        CopyOut();
    }

private:
    __aicore__ inline void CopyIn()
    {
        if constexpr (scenarioNum == 1) {
            // 场景1：CastDequant - 搬入一个int16_t输入
            AscendC::LocalTensor<InputT> src0Local = inQueueSrc0.AllocTensor<InputT>();
            AscendC::DataCopy(src0Local, src0_global, DATA_SIZE);
            inQueueSrc0.EnQue(src0Local);
        } else {
            // 场景2/3：AddRelu/Axpy - 搬入两个half输入
            AscendC::LocalTensor<InputT> src0Local = inQueueSrc0.AllocTensor<InputT>();
            AscendC::LocalTensor<InputT> src1Local = inQueueSrc1.AllocTensor<InputT>();
            AscendC::DataCopy(src0Local, src0_global, DATA_SIZE);
            AscendC::DataCopy(src1Local, src1_global, DATA_SIZE);
            inQueueSrc0.EnQue(src0Local);
            inQueueSrc1.EnQue(src1Local);
        }
    }

    __aicore__ inline void Compute()
    {
        if constexpr (scenarioNum == 1) {
            // 场景1：CastDequant - 反量化与类型转换融合计算
            AscendC::LocalTensor<OutputT> dstLocal = outQueue.AllocTensor<OutputT>();
            AscendC::Duplicate<int32_t>(dstLocal.template ReinterpretCast<int32_t>(), static_cast<int32_t>(0),
                                        DATA_SIZE * 2 / sizeof(int32_t));
            AscendC::PipeBarrier<PIPE_V>();

            AscendC::LocalTensor<InputT> src0Local = inQueueSrc0.DeQue<InputT>();

            // SetDeqScale接口：设置反量化参数，scale为缩放因子，offset为偏移量，signMode控制输出符号
            float scale = 1.0;
            int16_t offset = 0;
            bool signMode = false;
            AscendC::SetDeqScale(scale, offset, signMode);

            // CastDequant接口：完成int16_t到uint8_t的反量化和类型转换
            // 模板参数halfBlock=false表示输出元素存放在上半Block，isVecDeq=false表示标量反量化
            AscendC::CastDequant<OutputT, InputT, false, false>(dstLocal, src0Local, DATA_SIZE);

            outQueue.EnQue<OutputT>(dstLocal);
            inQueueSrc0.FreeTensor(src0Local);
        } else { // 场景2/3：AddRelu/Axpy
            AscendC::LocalTensor<OutputT> dstLocal = outQueue.AllocTensor<OutputT>();
            AscendC::LocalTensor<InputT> src0Local = inQueueSrc0.DeQue<InputT>();
            AscendC::LocalTensor<InputT> src1Local = inQueueSrc1.DeQue<InputT>();

            if constexpr (scenarioNum == 2) {
                // AddRelu接口：完成向量加法与ReLU激活的融合计算
                // 计算公式：dst[i] = max(src0[i] + src1[i], 0)
                AscendC::AddRelu<InputT>(dstLocal, src0Local, src1Local, DATA_SIZE);
            } else if constexpr (scenarioNum == 3) {
                // 先将src1Local（作为初始dst）拷贝到dstLocal
                AscendC::DataCopy(dstLocal, src1Local, DATA_SIZE);
                AscendC::PipeBarrier<PIPE_V>();

                // Axpy接口：完成标量乘法与向量加法的融合计算
                // 计算公式：dstLocal = dstLocal + src0Local * scalar
                // scalar为标量值，此处设为2.0
                half scalar = static_cast<half>(2.0);
                AscendC::Axpy<InputT, InputT>(dstLocal, src0Local, scalar, DATA_SIZE);
            }
            outQueue.EnQue<OutputT>(dstLocal);
            inQueueSrc0.FreeTensor(src0Local);
            inQueueSrc1.FreeTensor(src1Local);
        }
    }

    __aicore__ inline void CopyOut()
    {
        if constexpr (scenarioNum == 1) {
            // 场景1：CastDequant - 输出uint8_t数据
            AscendC::LocalTensor<OutputT> dstLocal = outQueue.DeQue<OutputT>();
            AscendC::DataCopy(dst_global, dstLocal, DATA_SIZE * 2);
            outQueue.FreeTensor(dstLocal);
        } else {
            // 场景2/3：AddRelu/Axpy - 输出half数据
            AscendC::LocalTensor<OutputT> dstLocal = outQueue.DeQue<OutputT>();
            AscendC::DataCopy(dst_global, dstLocal, DATA_SIZE);
            outQueue.FreeTensor(dstLocal);
        }
    }

private:
    AscendC::GlobalTensor<InputT> src0_global;
    AscendC::GlobalTensor<InputT> src1_global;
    AscendC::GlobalTensor<OutputT> dst_global;
    AscendC::TPipe* pipe;
    AscendC::TQue<AscendC::TPosition::VECIN, 1> inQueueSrc0;
    AscendC::TQue<AscendC::TPosition::VECIN, 1> inQueueSrc1;
    AscendC::TQue<AscendC::TPosition::VECOUT, 1> outQueue;
}

__global__ __vector__ void element_wise_compound_compute_custom(GM_ADDR src0_gm, GM_ADDR src1_gm, GM_ADDR dst_gm)
{
    AscendC::TPipe pipe;
