template <typename T>
class KernelGather {
public:
    __aicore__ inline KernelGather() {}
    __aicore__ inline void Init(
        __gm__ uint8_t* src0Gm, __gm__ uint8_t* src1Gm, __gm__ uint8_t* dstGm, AscendC::TPipe* pipeIn)
    {
