        if constexpr (scenarioNum == 2 || scenarioNum == 3 || scenarioNum == 4) {
            src1Global.SetGlobalBuffer((__gm__ uint32_t*)src1Gm);
            pipe->InitBuffer(inQueueSrc1, DEPTH, INPUT_Y_SIZE * sizeof(uint32_t));
            pipe->InitBuffer(outQueueDst, DEPTH, OUTPUT_SIZE * sizeof(T));
        }
    }
    __aicore__ inline void Process()
    {
