        Compute();
        CopyOut();
    }

private:
    __aicore__ inline void CopyIn()
    {
        AscendC::LocalTensor<T> src0Local = inQueueSrc0.AllocTensor<T>();
        AscendC::DataCopy(src0Local, src0Global, INPUT_SIZE);
        inQueueSrc0.EnQue(src0Local);

        if constexpr (scenarioNum == 2 || scenarioNum == 3 || scenarioNum == 4) {
            AscendC::LocalTensor<uint32_t> src1Local = inQueueSrc1.AllocTensor<uint32_t>();
            AscendC::DataCopy(src1Local, src1Global, INPUT_Y_SIZE);
            inQueueSrc1.EnQue(src1Local);
        }
    }
    __aicore__ inline void Compute()
    {
        uint32_t mask;
        uint64_t rsvdCnt = 0; // 用于保存筛选后保留下来的元素个数
        if constexpr (scenarioNum == 1) {
            AscendC::LocalTensor<T> src0Local = inQueueSrc0.DeQue<T>();

            mask = 0;                // normal模式下mask建议设置为0
            uint8_t src1Pattern = 2; // 内置固定模式，取值范围为[1,7]
            // reduceMode = false; 使用normal模式
            // src0BlockStride = 1; 单次迭代内数据间隔1个Block，即数据连续读取和写入
            // repeatTimes = 4; 重复迭代4次
            // src0RepeatStride = 8; 源操作数迭代间数据间隔8个datablock
            // src1RepeatStride = 0; 
            AscendC::GatherMask(src0Local, src0Local, src1Pattern, false, mask, {1, 4, 8, 0}, rsvdCnt);

            inQueueSrc0.EnQue<T>(src0Local);
        } else {
            AscendC::LocalTensor<T> src0Local = inQueueSrc0.DeQue<T>();
            AscendC::LocalTensor<uint32_t> src1Local = inQueueSrc1.DeQue<uint32_t>();
            AscendC::LocalTensor<T> dstLocal = outQueueDst.AllocTensor<T>();
            if constexpr (scenarioNum == 2) {
                AscendC::Duplicate(dstLocal, static_cast<T>(0), OUTPUT_SIZE);

                mask = 70;
                // reduceMode = true;    使用Counter模式
                // src0BlockStride = 1;  单次迭代内数据间隔1个datablock，即数据连续读取和写入
                // repeatTimes = 2;      Counter模式时，仅在部分产品型号下会生效
                // src0RepeatStride = 4; 源操作数迭代间数据间隔4个datablock
                // src1RepeatStride = 0; src1迭代间数据间隔0个datablock，即原位置读取
                AscendC::GatherMask(dstLocal, src0Local, src1Local, true, mask, {1, 2, 4, 0}, rsvdCnt);
            } else if constexpr (scenarioNum == 3) {
                src0Local.SetSize(INPUT_Y_SIZE);
                AscendC::Gather(dstLocal, src0Local, src1Local, (uint32_t)0, INPUT_Y_SIZE);
            } else if constexpr (scenarioNum == 4) {
                AscendC::GatherRepeatParams params{1, 8};
                uint8_t repeatTime = INPUT_SIZE * sizeof(T) / 256; // 重复迭代次数
                AscendC::Gatherb<T>(dstLocal, src0Local, src1Local, repeatTime, params);
            }
            inQueueSrc0.FreeTensor(src0Local);
            inQueueSrc1.FreeTensor(src1Local);
            outQueueDst.EnQue(dstLocal);
        }
    }

    __aicore__ inline void CopyOut()
    {
        if constexpr (scenarioNum == 1) {
            AscendC::LocalTensor<T> dstLocal = inQueueSrc0.DeQue<T>();
            AscendC::DataCopy(dstGlobal, dstLocal, OUTPUT_SIZE);
            inQueueSrc0.FreeTensor(dstLocal);
        } else {
            AscendC::LocalTensor<T> dstLocal = outQueueDst.DeQue<T>();
            AscendC::DataCopy(dstGlobal, dstLocal, OUTPUT_SIZE);
            outQueueDst.FreeTensor(dstLocal);
        } 
    }

private:
    AscendC::TPipe* pipe;
    AscendC::TQue<AscendC::TPosition::VECIN, DEPTH> inQueueSrc0, inQueueSrc1;
    AscendC::TQue<AscendC::TPosition::VECOUT, DEPTH> outQueueDst;
    AscendC::GlobalTensor<T> src0Global, dstGlobal;
    AscendC::GlobalTensor<uint32_t> src1Global;
}

