class KernelMrgSort {
public:
    __aicore__ inline KernelMrgSort() {}
    __aicore__ inline void Init(__gm__ uint8_t* src0Gm, __gm__ uint8_t* src1Gm, __gm__ uint8_t* dstGm)
    {
        srcGlobal0.SetGlobalBuffer((__gm__ float*)src0Gm);
        srcGlobal1.SetGlobalBuffer((__gm__ uint32_t*)src1Gm);
        dstGlobal.SetGlobalBuffer((__gm__ float*)dstGm);

        if constexpr (scenarioNum == 1) {
            srcDataSize = 128;
            repeat = 4;
            workSize = repeat * 32 * 2;
        } else if constexpr (scenarioNum == 2) {
            srcDataSize = 96;
            repeat = 3;
            workSize = repeat * 32 * 2;
        } else if constexpr (scenarioNum == 3) {
            srcDataSize = 1024;
            repeat = 32;
            workSize = repeat * 32 * 6;
        }

        dstDataSize = srcDataSize * 2;

        pipe.InitBuffer(inQueueSrc0, 1, srcDataSize * sizeof(float));
        pipe.InitBuffer(inQueueSrc1, 1, srcDataSize * sizeof(uint32_t));
        pipe.InitBuffer(workQueue, 1, workSize * sizeof(float));
        pipe.InitBuffer(outQueueDst, 1, dstDataSize * sizeof(float));
    }
    __aicore__ inline void Process()
    {
        CopyIn();
        Compute();
        CopyOut();
    }

private:
    __aicore__ inline void CopyIn()
    {
        AscendC::LocalTensor<float> srcLocal0 = inQueueSrc0.AllocTensor<float>();
        AscendC::DataCopy(srcLocal0, srcGlobal0, srcDataSize);
        inQueueSrc0.EnQue(srcLocal0);
        AscendC::LocalTensor<uint32_t> srcLocal1 = inQueueSrc1.AllocTensor<uint32_t>();
        AscendC::DataCopy(srcLocal1, srcGlobal1, srcDataSize);
        inQueueSrc1.EnQue(srcLocal1);
    }
    __aicore__ inline void Compute()
    {
        AscendC::LocalTensor<float> srcLocal0 = inQueueSrc0.DeQue<float>();
        AscendC::LocalTensor<uint32_t> srcLocal1 = inQueueSrc1.DeQue<uint32_t>();
        AscendC::LocalTensor<float> workLocal = workQueue.AllocTensor<float>();
        AscendC::LocalTensor<float> dstLocal = outQueueDst.AllocTensor<float>();

        AscendC::Sort32<float>(workLocal, srcLocal0, srcLocal1, repeat);

        AscendC::PipeBarrier<PIPE_V>();

        if constexpr (scenarioNum == 3) {
            ComputeMrgSortMultiRound(workLocal, dstLocal);
        } else {
            ComputeMrgSort(workLocal, dstLocal);
        }

        outQueueDst.EnQue<float>(dstLocal);
        inQueueSrc0.FreeTensor(srcLocal0);
        inQueueSrc1.FreeTensor(srcLocal1);
        workQueue.FreeTensor(workLocal);
    }

    __aicore__ inline void ComputeMrgSort(AscendC::LocalTensor<float>& workLocal,
        AscendC::LocalTensor<float>& dstLocal)
    {
        uint16_t validBit;
        uint16_t rptTimes;
        if constexpr (scenarioNum == 1) {
            validBit = 0b1111;
            rptTimes = 1;
        } else if constexpr (scenarioNum == 2) {
            // 场景2：3条队列有效，演示非4对齐情况下的合并
            validBit = 0b0111;
            rptTimes = 1;
        }

        // MrgSort合并多条已排序队列，params配置：
        // elementLengths：每条队列元素个数，无效队列设为0
        // ifExhaustedSuspension：false
        // validBit：0b1111表示4条队列均有效，0b0111表示前3条有效
        // repeatTimes：合并操作重复次数

        AscendC::MrgSort4Info params;
        params.elementLengths[0] = 32;
        params.elementLengths[1] = 32;
        params.elementLengths[2] = 32;
        params.elementLengths[3] = (validBit == 0b1111) ? 32 : 0;
        params.ifExhaustedSuspension = false;
        params.validBit = validBit;
        params.repeatTimes = rptTimes;

        AscendC::MrgSortSrcList<float> srcList;
        srcList.src1 = workLocal[0];
        srcList.src2 = workLocal[32 * 1 * 2];
        srcList.src3 = workLocal[32 * 2 * 2];
        srcList.src4 = workLocal[32 * 3 * 2];

        AscendC::MrgSort<float>(dstLocal, srcList, params);
    }

    __aicore__ inline void ComputeMrgSortMultiRound(AscendC::LocalTensor<float>& workLocal,
        AscendC::LocalTensor<float>& dstLocal)
    {
        // workLocal空间划分说明：
        // workLocal[0:2048]：Sort32后存储32条有序队列
        // workLocal[2048:4096]：第一轮归并结果存储区，以及第二轮归并的源数据起始地址
        // workLocal[4096:6144]：第二轮归并结果存储区，以及第三轮归并的源数据起始地址
        AscendC::LocalTensor<float> srcLocal = workLocal[0];
        AscendC::LocalTensor<float> tempLocal1 = workLocal[2048];
        AscendC::LocalTensor<float> tempLocal2 = workLocal[4096];

        // 第一轮归并：32条队列 → 8条队列
        // workLocal：32条有序队列，每条32个元素
        // tempLocal1：输出8条有序队列，每条128个元素（占用256个float空间）
        AscendC::MrgSort4Info params;
        params.elementLengths[0] = 32;
        params.elementLengths[1] = 32;
        params.elementLengths[2] = 32;
        params.elementLengths[3] = 32;
        params.ifExhaustedSuspension = false;
        params.validBit = 0b1111;
        params.repeatTimes = 8;

        AscendC::MrgSortSrcList<float> srcList;
        srcList.src1 = srcLocal[0];
        srcList.src2 = srcLocal[32 * 1 * 2];
        srcList.src3 = srcLocal[32 * 2 * 2];
        srcList.src4 = srcLocal[32 * 3 * 2];

        AscendC::MrgSort<float>(tempLocal1, srcList, params);

        AscendC::PipeBarrier<PIPE_V>();

        // 第二轮归并：8条队列 → 2条队列
        // tempLocal1：8条有序队列，每条128个元素
        // tempLocal2：输出2条有序队列，每条512个元素
        params.elementLengths[0] = 128;
        params.elementLengths[1] = 128;
        params.elementLengths[2] = 128;
        params.elementLengths[3] = 128;
        params.repeatTimes = 2;

        srcList.src1 = tempLocal1[0];
        srcList.src2 = tempLocal1[128 * 1 * 2];
        srcList.src3 = tempLocal1[128 * 2 * 2];
        srcList.src4 = tempLocal1[128 * 3 * 2];

        AscendC::MrgSort<float>(tempLocal2, srcList, params);

        AscendC::PipeBarrier<PIPE_V>();

        // 第三轮归并：2条队列 → 1条全局有序队列
        // tempLocal2：2条有序队列，每条512个元素
        // dstLocal：输出1条全局有序队列，共1024个元素
        srcList.src1 = tempLocal2[0];
        srcList.src2 = tempLocal2[512 * 1 * 2];

        params.elementLengths[0] = 512;
        params.elementLengths[1] = 512;
        params.elementLengths[2] = 0;
        params.elementLengths[3] = 0;
        params.ifExhaustedSuspension = false;
        params.validBit = 0b11;
        params.repeatTimes = 1;

        AscendC::MrgSort<float>(dstLocal, srcList, params);
    }

    __aicore__ inline void CopyOut()
    {
        AscendC::LocalTensor<float> dstLocal = outQueueDst.DeQue<float>();
        AscendC::DataCopy(dstGlobal, dstLocal, dstDataSize);
        outQueueDst.FreeTensor(dstLocal);
    }

private:
    AscendC::TPipe pipe;
    AscendC::TQue<AscendC::TPosition::VECIN, 1> inQueueSrc0;
    AscendC::TQue<AscendC::TPosition::VECIN, 1> inQueueSrc1;
    AscendC::TQue<AscendC::TPosition::VECIN, 1> workQueue;
    AscendC::TQue<AscendC::TPosition::VECOUT, 1> outQueueDst;
    AscendC::GlobalTensor<float> srcGlobal0, dstGlobal;
    AscendC::GlobalTensor<uint32_t> srcGlobal1;
    int srcDataSize = 0;
    int dstDataSize = 0;
    int workSize = 0;
    int repeat = 0;
}

