template <typename T>
class KernelReduce {
public:
    __aicore__ inline KernelReduce() {}
    __aicore__ inline void Init(__gm__ uint8_t* src, __gm__ uint8_t* dstGm, AscendC::TPipe* pipeIn)
    {
        pipe = pipeIn;
        srcGlobal.SetGlobalBuffer((__gm__ T*)src);
        dstGlobal.SetGlobalBuffer((__gm__ T*)dstGm);

        constexpr int elePerRepeat = 256 / sizeof(T);
        constexpr int elePerBlock = 32 / sizeof(T);
        mask = elePerRepeat; // full mask
        // ReduceMax/ReduceMin: 返回value + index; ReduceSum: 返回value
        if constexpr (scenarioNum == 1 || scenarioNum == 3) {
            srcDataSize = 288;
            repeat = RoundUp(srcDataSize, elePerRepeat);
            workSize = RoundUp(repeat * 2, elePerBlock);
        } else if constexpr (scenarioNum == 2 || scenarioNum == 4) {
            srcDataSize = 512;
            repeat = RoundUp(srcDataSize, mask);
            workSize = RoundUp(repeat * 2, elePerBlock);
        } else if constexpr (scenarioNum == 5) {
            srcDataSize = 288;
            repeat = RoundUp(srcDataSize, elePerRepeat);
            workSize = RoundUp(repeat, elePerBlock);
        } else if constexpr (scenarioNum == 6) {
            srcDataSize = 8320;
            repeat = RoundUp(srcDataSize, mask);
            workSize = RoundUp(repeat, elePerBlock);
        }

        pipe->InitBuffer(inQueueSrc, 1, srcDataSize * sizeof(T));
        pipe->InitBuffer(workQueue, 1, workSize * sizeof(T));
        pipe->InitBuffer(outQueueDst, 1, dstDataSize * sizeof(T));
    }

    __aicore__ inline void Process()
    {
        CopyIn();
        Compute();
        CopyOut();
    }

private:
    __aicore__ inline void CopyIn()
    {
        AscendC::LocalTensor<T> srcLocal = inQueueSrc.AllocTensor<T>();
        AscendC::DataCopy(srcLocal, srcGlobal, srcDataSize);
        inQueueSrc.EnQue(srcLocal);
    }

    __aicore__ inline void Compute()
    {
        AscendC::LocalTensor<T> srcLocal = inQueueSrc.DeQue<T>();
        AscendC::LocalTensor<T> dstLocal = outQueueDst.AllocTensor<T>();
        AscendC::LocalTensor<T> sharedTmpBuffer = workQueue.AllocTensor<T>();

        // ReduceMax/ReduceMin, 同时获取最值和最值索引
        if constexpr (scenarioNum == 1) {
            AscendC::ReduceMax<T>(dstLocal, srcLocal, sharedTmpBuffer, srcDataSize, true);
        } else if constexpr (scenarioNum == 2) {
            AscendC::ReduceMax<T>(dstLocal, srcLocal, sharedTmpBuffer, mask, repeat, repStride, true);
        } else if constexpr (scenarioNum == 3) {
            AscendC::ReduceMin<T>(dstLocal, srcLocal, sharedTmpBuffer, srcDataSize, true);
        } else if constexpr (scenarioNum == 4) {
            AscendC::ReduceMin<T>(dstLocal, srcLocal, sharedTmpBuffer, mask, repeat, repStride, true);
        } else if constexpr (scenarioNum == 5) {
            AscendC::ReduceSum<T>(dstLocal, srcLocal, sharedTmpBuffer, srcDataSize);
            int32_t eventID = static_cast<int32_t>(GetTPipePtr()->FetchEventID(AscendC::HardEvent::V_S));
            AscendC::SetFlag<AscendC::HardEvent::V_S>(eventID);
            AscendC::WaitFlag<AscendC::HardEvent::V_S>(eventID);
            // GetReduceRepeatSumSpr: get the sum result
            T val = AscendC::GetReduceRepeatSumSpr<T>();
            dstLocal.SetValue(1, val);
        } else if constexpr (scenarioNum == 6) {
            AscendC::ReduceSum<T>(dstLocal, srcLocal, sharedTmpBuffer, mask, repeat, repStride);
        }

        outQueueDst.EnQue<T>(dstLocal);
        inQueueSrc.FreeTensor(srcLocal);
        workQueue.FreeTensor(sharedTmpBuffer);
    }

    __aicore__ inline void CopyOut()
    {
        AscendC::LocalTensor<T> dstLocal = outQueueDst.DeQue<T>();
        AscendC::DataCopy(dstGlobal, dstLocal, dstDataSize);
        outQueueDst.FreeTensor(dstLocal);
    }

    int RoundUp(int a, int b)
    {
        return (a + b - 1) / b;
    }

private:
    AscendC::TPipe* pipe;
    AscendC::TQue<AscendC::TPosition::VECIN, 1> inQueueSrc;
    AscendC::TQue<AscendC::TPosition::VECOUT, 1> workQueue;
    AscendC::TQue<AscendC::TPosition::VECOUT, 1> outQueueDst;
    AscendC::GlobalTensor<T> srcGlobal, dstGlobal;
    int srcDataSize;
    int dstDataSize = 16; // 32B aligned
    int mask = 0;
    int repStride = 8; // no gap between repeats
    int repeat = 0;
    int workSize = 0;
}

