class KernelRegionProposalSort {
public:
    __aicore__ inline KernelRegionProposalSort() {}
    __aicore__ inline void Init(__gm__ uint8_t* src, __gm__ uint8_t* dstGm, AscendC::TPipe* pipeIn)
    {
        pipe = pipeIn;
        srcGlobal.SetGlobalBuffer(reinterpret_cast<__gm__ half*>(src));
        dstGlobal.SetGlobalBuffer(reinterpret_cast<__gm__ half*>(dstGm));
        pipe->InitBuffer(inQueue, 1, SCORE_COUNT * sizeof(half));
        pipe->InitBuffer(workQueue, 1, WORK_SIZE * sizeof(half));
        pipe->InitBuffer(mrgOutQueue, 1, WORK_SIZE * sizeof(half));
        pipe->InitBuffer(extractQueue, 1, DST_SIZE * sizeof(half));
    }
    __aicore__ inline void Process()
    {
        CopyIn();
        Compute();
        CopyOut();
    }
private:
    __aicore__ inline void CopyIn()
    {
        AscendC::LocalTensor<half> srcLocal = inQueue.AllocTensor<half>();
        AscendC::DataCopy(srcLocal, srcGlobal, SCORE_COUNT);
        inQueue.EnQue(srcLocal);
    }
    __aicore__ inline void Compute()
    {
        AscendC::LocalTensor<half> srcLocal = inQueue.DeQue<half>();
        AscendC::LocalTensor<half> workLocal = workQueue.AllocTensor<half>();
        AscendC::LocalTensor<half> mrgOutLocal = mrgOutQueue.AllocTensor<half>();
        AscendC::LocalTensor<half> extractLocal = extractQueue.AllocTensor<half>();

        constexpr uint32_t singleDataSize = SCORE_COUNT / 4;
        constexpr uint32_t workDataSize = WORK_SIZE / 4;
        constexpr int repeat = SCORE_COUNT / 4 / 16;
        constexpr int mode = 4;

        // Step1: ProposalConcat将连续score合入Region Proposal格式
        // Step2: RpSort16对每组16个RP按score域降序排列
        // 每次迭代将16个score合入16个RP的score域位置(offset=4)
        // 共4组，每组repeat=1
        AscendC::ProposalConcat(workLocal[0], srcLocal[0], repeat, mode);
        AscendC::PipeBarrier<PIPE_V>();
        AscendC::RpSort16(workLocal[0], workLocal[0], repeat);

        AscendC::ProposalConcat(workLocal[workDataSize], srcLocal[singleDataSize], repeat, mode);
        AscendC::PipeBarrier<PIPE_V>();
        AscendC::RpSort16(workLocal[workDataSize], workLocal[workDataSize], repeat);

        AscendC::ProposalConcat(workLocal[workDataSize * 2], srcLocal[singleDataSize * 2], repeat, mode);
        AscendC::PipeBarrier<PIPE_V>();
        AscendC::RpSort16(workLocal[workDataSize * 2], workLocal[workDataSize * 2], repeat);

        AscendC::ProposalConcat(workLocal[workDataSize * 3], srcLocal[singleDataSize * 3], repeat, mode);
        AscendC::PipeBarrier<PIPE_V>();
        AscendC::RpSort16(workLocal[workDataSize * 3], workLocal[workDataSize * 3], repeat);

        // Step3: MrgSort4将4组已排序的RP合并为1组，输出写入独立的mrgOutLocal
        AscendC::MrgSortSrcList<half> srcList(workLocal[0], workLocal[workDataSize],
                                               workLocal[workDataSize * 2], workLocal[workDataSize * 3]);
        uint16_t elementLengths[4] = { singleDataSize, singleDataSize, singleDataSize, singleDataSize };
        AscendC::MrgSort4Info srcInfo(elementLengths, false, 15, 1);
        AscendC::MrgSort4(mrgOutLocal, srcList, srcInfo);
        AscendC::PipeBarrier<PIPE_V>();

        // Step4: ProposalExtract从合并后的RP中提取score域，得到排序后的连续score
        constexpr int extractRepeat = WORK_SIZE / 16;
        AscendC::ProposalExtract(extractLocal, mrgOutLocal, extractRepeat, mode);

        extractQueue.EnQue<half>(extractLocal);
        inQueue.FreeTensor(srcLocal);
        workQueue.FreeTensor(workLocal);
        mrgOutQueue.FreeTensor(mrgOutLocal);
    }
    __aicore__ inline void CopyOut()
    {
        AscendC::LocalTensor<half> dstLocal = extractQueue.DeQue<half>();
        AscendC::DataCopy(dstGlobal, dstLocal, DST_SIZE);
        extractQueue.FreeTensor(dstLocal);
    }
private:
    AscendC::TPipe* pipe;
    AscendC::TQue<AscendC::TPosition::VECIN, 1> inQueue;
    AscendC::TQue<AscendC::TPosition::VECIN, 1> workQueue;
    AscendC::TQue<AscendC::TPosition::VECOUT, 1> mrgOutQueue;
    AscendC::TQue<AscendC::TPosition::VECOUT, 1> extractQueue;
    AscendC::GlobalTensor<half> srcGlobal, dstGlobal;
}

__global__ __vector__ void region_proposal_sort_custom(GM_ADDR x, GM_ADDR y)
