template<typename T = half>
class KernelTranspose {
public:
    __aicore__ inline KernelTranspose() {}
    __aicore__ inline void Init(__gm__ uint8_t* src, __gm__ uint8_t* dstGm, AscendC::TPipe* pipeIn)
    {
        pipe = pipeIn;
        srcGlobal.SetGlobalBuffer((__gm__ T*)src);
        dstGlobal.SetGlobalBuffer((__gm__ T*)dstGm);

       if constexpr (scenarioNum == 1) {
            srcDataSize = 256;
            pipe->InitBuffer(inQueueSrc, 1, srcDataSize * sizeof(T));
            pipe->InitBuffer(outQueueDst, 1, srcDataSize * sizeof(T));
        } else if constexpr (scenarioNum == 2) {
            N = 3;
            C = 3;
            H = 2;
            W = 8;
            srcDataSize = N * C * H * W;
            tmpBufferSize = (C + 2) * 16 * 16;
            transposeType = AscendC::TransposeType::TRANSPOSE_NCHW2NHWC;
            pipe->InitBuffer(inQueueSrc, 1, srcDataSize * sizeof(T));
            pipe->InitBuffer(outQueueDst, 1, srcDataSize * sizeof(T));
            pipe->InitBuffer(tmpQueue, 1, tmpBufferSize * sizeof(T));
        }
    }
    __aicore__ inline void Process()
    {
        CopyIn();
        Compute();
        CopyOut();
    }
private:
    __aicore__ inline void CopyIn()
    {
        AscendC::LocalTensor<T> srcLocal = inQueueSrc.AllocTensor<T>();
        AscendC::DataCopy(srcLocal, srcGlobal, srcDataSize);
        inQueueSrc.EnQue(srcLocal);
    }
    __aicore__ inline void Compute()
    {
        AscendC::LocalTensor<T> srcLocal = inQueueSrc.DeQue<T>();
        AscendC::LocalTensor<T> dstLocal = outQueueDst.AllocTensor<T>();
        if constexpr (scenarioNum == 1) {
            // 场景1：普通转置，[16,16]二维矩阵转置
            AscendC::Transpose<T>(dstLocal, srcLocal);
            outQueueDst.EnQue<T>(dstLocal);
            inQueueSrc.FreeTensor(srcLocal);
        } else if constexpr (scenarioNum == 2) {
            // 场景2：增强转置，[N,C,H,W]转置为[N,H,W,C]
            AscendC::LocalTensor<uint8_t> stackBuffer = tmpQueue.AllocTensor<uint8_t>();
            AscendC::TransposeParamsExt transposeParams;
            transposeParams.nSize = N;
            transposeParams.cSize = C;
            transposeParams.hSize = H;
            transposeParams.wSize = W;
            transposeParams.transposeType = transposeType;
            AscendC::Transpose(dstLocal, srcLocal, stackBuffer, transposeParams);
            outQueueDst.EnQue<T>(dstLocal);
            inQueueSrc.FreeTensor(srcLocal);
            tmpQueue.FreeTensor(stackBuffer);
        }
    }
    __aicore__ inline void CopyOut()
    {
        AscendC::LocalTensor<T> dstLocal = outQueueDst.DeQue<T>();
        AscendC::DataCopy(dstGlobal, dstLocal, srcDataSize);
        outQueueDst.FreeTensor(dstLocal);
    }
private:
    AscendC::TPipe* pipe;
    AscendC::TQue<AscendC::TPosition::VECIN, 1> inQueueSrc;
    AscendC::TQue<AscendC::TPosition::VECOUT, 1> outQueueDst;
    AscendC::TQue<AscendC::TPosition::VECIN, 1> tmpQueue;
    AscendC::GlobalTensor<T> srcGlobal, dstGlobal;

    uint32_t srcDataSize, tmpBufferSize;
    uint32_t N, C, H, W;
    AscendC::TransposeType transposeType;
}

