template<typename T>
class KernelReduce {
    static constexpr uint32_t MASK = (sizeof(T) == 4) ? 64 : 128;
    static constexpr uint32_t BYTE_ALIGN = 32;
    static constexpr uint32_t SRC_TOTAL_LENGTH = (scenarioNum == 3 || scenarioNum == 4) ? 2048 :
                                                  scenarioNum == 7 ? 13 * 57 : 1024;
    static constexpr uint32_t SRC_ROW = (scenarioNum == 7) ? 13 : 1;
    static constexpr uint32_t SRC_COL = (scenarioNum == 7) ? 57 : SRC_TOTAL_LENGTH;
    static constexpr uint32_t DST_TOTAL_LENGTH = (scenarioNum == 3 || scenarioNum == 4) ? (SRC_TOTAL_LENGTH / MASK) :
                                                  scenarioNum == 7 ? SRC_ROW : scenarioNum == 1 ? 8 : 16;
    static constexpr uint32_t COL_ALIGN_BYTES =
        ((SRC_COL * sizeof(T) + BYTE_ALIGN - 1) / BYTE_ALIGN) * BYTE_ALIGN;
    static constexpr uint32_t SRC_BUFFER_LENGTH = SRC_ROW * (COL_ALIGN_BYTES / sizeof(T));
public:
    __aicore__ inline KernelReduce() {}
    __aicore__ inline void Init(__gm__ uint8_t* src, __gm__ uint8_t* dstGm, AscendC::TPipe* pipeIn)
    {
        pipe = pipeIn;
        srcGlobal.SetGlobalBuffer((__gm__ T*)src);
        dstGlobal.SetGlobalBuffer((__gm__ T*)dstGm);
        repeat = SRC_TOTAL_LENGTH / MASK;
        pipe->InitBuffer(inQueueSrc, 1, SRC_BUFFER_LENGTH * sizeof(T));
        pipe->InitBuffer(outQueueDst, 1, DST_TOTAL_LENGTH * sizeof(T));
    }
    __aicore__ inline void Process()
    {
        CopyIn();
        Compute();
        CopyOut();
    }
private:
    __aicore__ inline void CopyIn()
    {
        AscendC::LocalTensor<T> srcLocal = inQueueSrc.AllocTensor<T>();
        uint32_t colBytes = SRC_COL * sizeof(T);
        AscendC::DataCopyExtParams copyParams = {(uint16_t)SRC_ROW, colBytes, 0, 0, 0};
        uint8_t rpad = (COL_ALIGN_BYTES - colBytes) / sizeof(T);
        AscendC::DataCopyPadExtParams<T> padParams = {false, 0, rpad, 0};
        AscendC::DataCopyPad<T>(srcLocal, srcGlobal, copyParams, padParams);
        inQueueSrc.EnQue(srcLocal);
    }
    __aicore__ inline void Compute()
    {
        AscendC::LocalTensor<T> srcLocal = inQueueSrc.DeQue<T>();
        AscendC::LocalTensor<T> dstLocal = outQueueDst.AllocTensor<T>();

        if constexpr (scenarioNum == 1) {
            // 场景1：WholeReduceMax：对每个repeat内所有元素求最大值（不返回索引）
            // mask=128, repeat=srcDataSize/mask, order=ORDER_ONLY_VALUE
            // 输出只存储值：[max0, max1, max2, ...]
            AscendC::WholeReduceMax<T>(dstLocal, srcLocal, MASK, repeat, 1, 1, 8, AscendC::ReduceOrder::ORDER_ONLY_VALUE);
        } else if constexpr (scenarioNum == 2) {
            // 场景2：WholeReduceMin：对每个repeat内所有元素求最小值及其索引
            // mask=128, repeat=srcDataSize/mask, 使用默认order (ReduceOrder::ORDER_VALUE_INDEX)
            // 输出按值和索引交错存储：[min0, idx0, min1, idx1, ...]
            AscendC::WholeReduceMin<T>(dstLocal, srcLocal, MASK, repeat, 1, 1, 8);
        } else if constexpr (scenarioNum == 3) {
            // 场景3：WholeReduceSum：对每个repeat内所有元素求和，输入为float类型
            // mask=64(float类型32位), repeat=srcDataSize/mask, 每个repeat输出一个求和结果
            AscendC::WholeReduceSum<T>(dstLocal, srcLocal, MASK, repeat, 1, 1, 8);
        } else if constexpr (scenarioNum == 4) {
            // 场景4：RepeatReduceSum：对每个repeat内所有元素求和（累加模式），输入为float类型
            // 先将dstLocal初始化为0，再将所有repeat的结果累加
            // mask=64(float类型32位), repeat=srcDataSize/mask
            // dstBlkStride=0表示每个repeat的结果累加到同一个位置
            T zero(0);
            AscendC::Duplicate(dstLocal, zero, DST_TOTAL_LENGTH);
            AscendC::PipeBarrier<PIPE_V>();
            AscendC::RepeatReduceSum<T>(dstLocal, srcLocal, repeat, MASK, 0, 1, 1, 8);
        } else if constexpr (scenarioNum == 5) {
             // 场景5：WholeReduceMax + GetReduceRepeatMaxMinSpr
            // 对1024个half元素求全局最大值及其索引
            // mask逐bit模式, repeat=8(1024/128), srcBlkStride=1, srcRepeatStride=8
            // 8个repeat各自归约得到局部最大值，再通过GetReduceRepeatMaxMinSpr获取全局最大值
            uint64_t mask[2] = { 0xFFFFFFFFFFFFFFFF, 0xFFFFFFFFFFFFFFFF };
            AscendC::WholeReduceMax<T>(dstLocal, srcLocal, mask, repeat, 1, 1, 8);
            AscendC::PipeBarrier<PIPE_V>();
            T val = 0;
            T idx = 0;
            AscendC::GetReduceRepeatMaxMinSpr<T>(val, idx);
            AscendC::PipeBarrier<PIPE_V>();
            T zero{0};
            AscendC::Duplicate(dstLocal, zero, DST_TOTAL_LENGTH);
            int32_t eventIdVToS  = static_cast<int32_t>(GetTPipePtr()->FetchEventID(AscendC::HardEvent::V_S));
            AscendC::SetFlag<AscendC::HardEvent::V_S>(eventIdVToS);
            AscendC::WaitFlag<AscendC::HardEvent::V_S>(eventIdVToS);            
            dstLocal.SetValue(0, val);
            dstLocal.SetValue(1, idx);
        } else if constexpr (scenarioNum == 6) {
            // 场景6：WholeReduceMin + GetReduceRepeatMaxMinSpr
            // 对1024个half元素求全局最小值及其索引
            // mask逐bit模式, repeat=8(1024/128), srcBlkStride=1, srcRepeatStride=8
            // 8个repeat各自归约得到局部最小值，再通过GetReduceRepeatMaxMinSpr获取全局最小值
            uint64_t mask[2] = { 0xFFFFFFFFFFFFFFFF, 0xFFFFFFFFFFFFFFFF };
            AscendC::WholeReduceMin<T>(dstLocal, srcLocal, mask, repeat, 1, 1, 8);
            AscendC::PipeBarrier<PIPE_V>();
            T val = 0;
            T idx = 0;
            AscendC::GetReduceRepeatMaxMinSpr<T>(val, idx);
            AscendC::PipeBarrier<PIPE_V>();
            T zero{0};
            AscendC::Duplicate(dstLocal, zero, DST_TOTAL_LENGTH);
            int32_t eventIdVToS  = static_cast<int32_t>(GetTPipePtr()->FetchEventID(AscendC::HardEvent::V_S));
            AscendC::SetFlag<AscendC::HardEvent::V_S>(eventIdVToS);
            AscendC::WaitFlag<AscendC::HardEvent::V_S>(eventIdVToS);   
            dstLocal.SetValue(0, val);
            dstLocal.SetValue(1, idx);
        } else if constexpr (scenarioNum == 7) {
            // 场景7：WholeReduceSum按行求和非对齐场景，输入为float类型
            // mask=SRC_COL(57)，每行57个元素求和
            // repeat=SRC_ROW(13)，共13行
            // srcRepeatStride=对齐后的步长（COL_ALIGN_BYTES/BYTE_ALIGN个block），即每行在LocalTensor中对齐后占用的block数
            int32_t srcStride = COL_ALIGN_BYTES / BYTE_ALIGN;
            AscendC::WholeReduceSum<T>(dstLocal, srcLocal, SRC_COL, SRC_ROW, 1, 1, srcStride);
        }

        outQueueDst.EnQue<T>(dstLocal);
        inQueueSrc.FreeTensor(srcLocal);
    }
    __aicore__ inline void CopyOut()
    {
        AscendC::LocalTensor<T> dstLocal = outQueueDst.DeQue<T>();
        uint16_t outBytes = DST_TOTAL_LENGTH * sizeof(T);
        AscendC::DataCopyExtParams copyParams = {1, outBytes, 0, 0, 0};
        AscendC::DataCopyPad<T>(dstGlobal, dstLocal, copyParams);
        outQueueDst.FreeTensor(dstLocal);
    }
private:
    AscendC::TPipe* pipe;
    AscendC::TQue<AscendC::TPosition::VECIN, 1> inQueueSrc;
    AscendC::TQue<AscendC::TPosition::VECOUT, 1> outQueueDst;
    AscendC::GlobalTensor<T> srcGlobal, dstGlobal;
    uint32_t repeat = 0;
}

__global__ __vector__ void reduce_custom(GM_ADDR x, GM_ADDR z)
{
    AscendC::TPipe pipe;
    if constexpr (scenarioNum == 3 || scenarioNum == 4 || scenarioNum == 7) {
        KernelReduce<float> op;
        op.Init(x, z, &pipe);
        op.Process();
    } else {
        KernelReduce<half> op;
        op.Init(x, z, &pipe);
        op.Process();
    }
}

template <typename T>
class Kernel {
public:
    __aicore__ inline void Init(GM_ADDR x, GM_ADDR y, uint32_t totalLength)
    {
        this->totalLength = totalLength;
        this->xGm.SetGlobalBuffer(reinterpret_cast<__gm__ T*>(x));
        this->yGm.SetGlobalBuffer(reinterpret_cast<__gm__ T*>(y));
    }
    __aicore__ inline void Process()
    {
        AscendC::LocalMemAllocator<AscendC::Hardware::UB> ubAllocator;
        AscendC::LocalTensor<T> xLocal = ubAllocator.Alloc<T, 256>();
        AscendC::LocalTensor<T> yLocal = ubAllocator.Alloc<T, 256>();

        // CopyIn: GM -> UB
        AscendC::DataCopy(xLocal, xGm, totalLength);
        AscendC::SetFlag<AscendC::HardEvent::MTE2_V>(EVENT_ID0);
        AscendC::WaitFlag<AscendC::HardEvent::MTE2_V>(EVENT_ID0);

        // Compute: RegBase AbsVF y = |x|
        __ubuf__ T* xAddr = reinterpret_cast<__ubuf__ T*>(xLocal.GetPhyAddr());
        __ubuf__ T* yAddr = reinterpret_cast<__ubuf__ T*>(yLocal.GetPhyAddr());
        // 一次repeat计算的数据个数
        constexpr uint32_t oneRepeatSize = AscendC::GetVecLen() / sizeof(T);
        // 总迭代次数
        uint16_t repeatTimes = AscendC::CeilDivision(totalLength, oneRepeatSize);
        AbsVF(xAddr, yAddr, totalLength, repeatTimes, oneRepeatSize);

        AscendC::SetFlag<AscendC::HardEvent::V_MTE3>(EVENT_ID0);
        AscendC::WaitFlag<AscendC::HardEvent::V_MTE3>(EVENT_ID0);

        // CopyOut: UB -> GM
        AscendC::DataCopy(yGm, yLocal, totalLength);
    }

private:
    uint32_t totalLength;
    AscendC::GlobalTensor<T> xGm;
    AscendC::GlobalTensor<T> yGm;
}

__global__ __vector__ void abs(GM_ADDR x, GM_ADDR y)
{
    uint32_t totalLength = 256;
    Kernel<float> kernel;
    kernel.Init(x, y, totalLength);
    kernel.Process();
}

template <typename T>
class Kernel {
public:
    __aicore__ inline void Init(GM_ADDR x, GM_ADDR y, GM_ADDR z, uint32_t totalLength)
    {
        this->totalLength = totalLength;
        this->xGm.SetGlobalBuffer(reinterpret_cast<__gm__ T*>(x));
        this->yGm.SetGlobalBuffer(reinterpret_cast<__gm__ T*>(y));
        this->zGm.SetGlobalBuffer(reinterpret_cast<__gm__ T*>(z));
    }
    __aicore__ inline void Process()
    {
        AscendC::LocalMemAllocator<AscendC::Hardware::UB> ubAllocator;
        AscendC::LocalTensor<T> xLocal = ubAllocator.Alloc<T, 256>();
        AscendC::LocalTensor<T> yLocal = ubAllocator.Alloc<T, 256>();
        AscendC::LocalTensor<T> zLocal = ubAllocator.Alloc<T, 256>();

        // CopyIn: GM -> UB
        AscendC::DataCopy(xLocal, xGm, totalLength);
        AscendC::DataCopy(yLocal, yGm, totalLength);
        AscendC::SetFlag<AscendC::HardEvent::MTE2_V>(EVENT_ID0);
        AscendC::WaitFlag<AscendC::HardEvent::MTE2_V>(EVENT_ID0);

        // Compute: RegBase MulVF z = x * y
        __ubuf__ T* xAddr = reinterpret_cast<__ubuf__ T*>(xLocal.GetPhyAddr());
        __ubuf__ T* yAddr = reinterpret_cast<__ubuf__ T*>(yLocal.GetPhyAddr());
        __ubuf__ T* zAddr = reinterpret_cast<__ubuf__ T*>(zLocal.GetPhyAddr());
        // 一次repeat计算的数据个数
        constexpr uint32_t oneRepeatSize = AscendC::GetVecLen() / sizeof(T);
        // 总迭代次数
        uint16_t repeatTimes = AscendC::CeilDivision(totalLength, oneRepeatSize);
        MulVF(xAddr, yAddr, zAddr, totalLength, repeatTimes, oneRepeatSize);

        AscendC::SetFlag<AscendC::HardEvent::V_MTE3>(EVENT_ID0);
        AscendC::WaitFlag<AscendC::HardEvent::V_MTE3>(EVENT_ID0);

        // CopyOut: UB -> GM
        AscendC::DataCopy(zGm, zLocal, totalLength);
    }

private:
    uint32_t totalLength;
    AscendC::GlobalTensor<T> xGm;
    AscendC::GlobalTensor<T> yGm;
    AscendC::GlobalTensor<T> zGm;
}

