template <typename T>
class Kernel {
public:
    __aicore__ inline void Init(GM_ADDR x, GM_ADDR z, uint32_t totalLength, T scalar)
    {
        this->totalLength = totalLength;
        this->scalar = scalar;
        this->xGm.SetGlobalBuffer(reinterpret_cast<__gm__ T*>(x));
        this->zGm.SetGlobalBuffer(reinterpret_cast<__gm__ T*>(z));
    }
    __aicore__ inline void Process()
    {
        AscendC::LocalMemAllocator<AscendC::Hardware::UB> ubAllocator;
        AscendC::LocalTensor<T> xLocal = ubAllocator.Alloc<T, 256>();
        AscendC::LocalTensor<T> zLocal = ubAllocator.Alloc<T, 256>();

        // CopyIn: GM -> UB
        AscendC::DataCopy(xLocal, xGm, totalLength);
        AscendC::SetFlag<AscendC::HardEvent::MTE2_V>(EVENT_ID0);
        AscendC::WaitFlag<AscendC::HardEvent::MTE2_V>(EVENT_ID0);

        // Compute: RegBase MulsVF z = x * scalar
        __ubuf__ T* xAddr = reinterpret_cast<__ubuf__ T*>(xLocal.GetPhyAddr());
        __ubuf__ T* zAddr = reinterpret_cast<__ubuf__ T*>(zLocal.GetPhyAddr());
        // 一次repeat计算的数据个数
        constexpr uint32_t oneRepeatSize = AscendC::GetVecLen() / sizeof(T);
        // 总迭代次数
        uint16_t repeatTimes = AscendC::CeilDivision(totalLength, oneRepeatSize);
        MulsVF(xAddr, zAddr, scalar, totalLength, repeatTimes, oneRepeatSize);

        AscendC::SetFlag<AscendC::HardEvent::V_MTE3>(EVENT_ID0);
        AscendC::WaitFlag<AscendC::HardEvent::V_MTE3>(EVENT_ID0);

        // CopyOut: UB -> GM
        AscendC::DataCopy(zGm, zLocal, totalLength);
    }

private:
    uint32_t totalLength;
    T scalar;
    AscendC::GlobalTensor<T> xGm;
    AscendC::GlobalTensor<T> zGm;
}

