        GetTPipePtr()->InitBuffer(inQueueX, BUFFER_NUM, this->tileLength * sizeof(float));
        GetTPipePtr()->InitBuffer(inQueueY, BUFFER_NUM, this->tileLength * sizeof(float));
        GetTPipePtr()->InitBuffer(outQueueZ, BUFFER_NUM, this->tileLength * sizeof(float));
