public:
    __aicore__ inline KernelAddV5() = default;
    __aicore__ inline void Init(GM_ADDR x, GM_ADDR y, uint32_t singleCoreLength)
    {
        xGm.SetGlobalBuffer((__gm__ float *)x + AscendC::GetBlockIdx() * singleCoreLength, singleCoreLength);
        yGm.SetGlobalBuffer((__gm__ float *)y + AscendC::GetBlockIdx() * singleCoreLength, singleCoreLength);
        loopCount = singleCoreLength / TILE_LENGTH;
    }

    __aicore__ inline void Process()
    {
        AscendC::LocalTensor<float> xLocal(AscendC::TPosition::VECCALC, xAddr, loopCount * TILE_LENGTH);
        AscendC::LocalTensor<float> yLocal(AscendC::TPosition::VECCALC, yAddr, loopCount * TILE_LENGTH);

        AscendC::Duplicate<float>(yLocal, 0.0, loopCount * TILE_LENGTH);
        AscendC::SetFlag<AscendC::HardEvent::V_MTE2>(EVENT_ID0);
        AscendC::WaitFlag<AscendC::HardEvent::V_MTE2>(EVENT_ID0);

        AscendC::DataCopy(xLocal, xGm[0], loopCount * TILE_LENGTH);
        AscendC::SetFlag<AscendC::HardEvent::MTE2_V>(EVENT_ID0);

