template <typename T>
class KernelDataSyncBarrier {
public:
    __aicore__ inline KernelDataSyncBarrier() {}
    __aicore__ inline void Init(GM_ADDR srcGm, GM_ADDR dstGm, AscendC::TPipe *pipeIn, uint32_t calCount)
    {
        pipe = pipeIn;
        bufferSize = calCount;
        blockIdx = AscendC::GetBlockIdx();

        srcGlobal.SetGlobalBuffer(reinterpret_cast<__gm__ T *>(srcGm));
        dstGlobal.SetGlobalBuffer(reinterpret_cast<__gm__ T *>(dstGm));

        pipe->InitBuffer(inQueue, 1, bufferSize * sizeof(T));
        pipe->InitBuffer(outQueue, 1, bufferSize * sizeof(T));
    }
    __aicore__ inline void Process(GM_ADDR srcGm, GM_ADDR dstGm)
    {
        if (blockIdx == 1) {
            while(true){
                __gm__ T *addr = const_cast<__gm__ T *>(srcGlobal.GetPhyAddr());
                T value = AscendC::ReadGmByPassDCache<T>(addr);
                if(value == 6){
                    __gm__ T *addr = const_cast<__gm__ T *>(srcGlobal.GetPhyAddr());
                    T valueNew = AscendC::ReadGmByPassDCache<T>(addr+1);
                    AscendC::printf("GM上addr+1位置的值：%u\n",valueNew);
                    AscendC::WriteGmByPassDCache<T>(reinterpret_cast<__gm__ T *>(dstGm), 2 * valueNew);
                    return;
                }
            }
        }
        if (blockIdx == 0) {
            AscendC::WriteGmByPassDCache<T>(reinterpret_cast<__gm__ T *>(srcGm)+1, value+1);
            AscendC::DataSyncBarrier<AscendC::MemDsbT::DDR>(); // 三种取值，ALL(包含DDR+UB)、DDR、UB
            AscendC::WriteGmByPassDCache<T>(reinterpret_cast<__gm__ T *>(srcGm), value); // value = 6
        }
    }

private:
    AscendC::GlobalTensor<T> srcGlobal;
    AscendC::GlobalTensor<T> dstGlobal;
    AscendC::TPipe* pipe;
    AscendC::TQue<AscendC::TPosition::VECIN, 1> inQueue;
    AscendC::TQue<AscendC::TPosition::VECOUT, 1> outQueue;
    uint32_t bufferSize = 0;
    int32_t blockIdx = 0;
}

