class KernelGroupBarrier {
public:
    __aicore__ inline KernelGroupBarrier() {}

    __aicore__ inline void Init(GM_ADDR barGm, GM_ADDR dstGm, AscendC::TPipe *pipeIn)
    {
        pipe = pipeIn;
        this->barWorkspace = barGm;
        uint32_t oneBlockNum = 32 / sizeof(int32_t);
        this->totalLength = (SIZE_NUM + oneBlockNum - 1) / oneBlockNum * oneBlockNum;
        dstGlobal.SetGlobalBuffer(reinterpret_cast<__gm__ int32_t *>(dstGm), totalLength);
        pipe->InitBuffer(inQueue, 1, totalLength * sizeof(int32_t));
    }

    __aicore__ inline void Process()
    {
        // apply GroupBarrier
        AscendC::GroupBarrier<AscendC::PipeMode::MTE3_MODE> barA(barWorkspace, ARRIVE_NUM, WAIT_NUM);
        AscendC::InitOutput<int32_t>(dstGlobal, totalLength, 0); // init output zero
        AscendC::SyncAll();
        auto id = AscendC::GetBlockIdx();
        if (id >= 0 && id < ARRIVE_NUM) // arrive realize
        {
            AscendC::LocalTensor<int32_t> srcLocal = inQueue.AllocTensor<int32_t> ();
            AscendC::DisableDmaAtomic();
            srcLocal.SetValue(0, TEMP); // set initial number
            AscendC::SetAtomicAdd<int32_t>(); // add initial number
            AscendC::DataCopy(dstGlobal, srcLocal, totalLength);
            AscendC::DisableDmaAtomic();
            inQueue.FreeTensor(srcLocal);
            barA.Arrive(id); //arrive end
        }
        else if (id >= ARRIVE_NUM && id < ARRIVE_NUM + WAIT_NUM)  // wait realize
        {
            barA.Wait(id - ARRIVE_NUM); // wait end
            int32_t val = dstGlobal.GetValue(0);
            AscendC::printf("[Block (%lu/%lu)]: OUTPUT = %d\n", id - ARRIVE_NUM, WAIT_NUM, val);
        }
    }

private:
    AscendC::TPipe* pipe;
    AscendC::TQue<AscendC::TPosition::VECIN, 1> inQueue;
    AscendC::GlobalTensor<int32_t> dstGlobal;
    uint32_t totalLength;
    GM_ADDR barWorkspace;
}

