template <typename T>
class SyncTest {
public:
    __aicore__ inline SyncTest() {}
    __aicore__ inline void Init(GM_ADDR dstGm, GM_ADDR srcGm, GM_ADDR workGm, AscendC::TPipe *pipeIn)
    {
        pipe = pipeIn;

        elementCount = DATA_SIZE;
        tileNum = TILE_NUM;
        tileCount = elementCount / tileNum;

        dstGlobal.SetGlobalBuffer((__gm__ T*)dstGm);
        srcGlobal.SetGlobalBuffer((__gm__ T*)srcGm);
        gmWorkspace.SetGlobalBuffer((__gm__ int32_t*)workGm);

        pipe->InitBuffer(que, 1, elementCount * sizeof(T));
        pipe->InitBuffer(queTmp, 1, WORKSPACE_SIZE * sizeof(int32_t));
    }

    __aicore__ inline void Process()
    {
        AscendC::LocalTensor<int32_t> ubWorkspace = queTmp.AllocTensor<int32_t>();
        AscendC::InitDetermineComputeWorkspace(gmWorkspace, ubWorkspace);
        for(int64_t i = 0; i < tileNum; i++) {
            // copy in
            AscendC::LocalTensor<T> srcLocal = que.AllocTensor<T>();
            AscendC::DataCopy(srcLocal, srcGlobal[i * tileCount], tileCount);

            // copy out
            AscendC::WaitPreBlock(gmWorkspace, ubWorkspace);
            AscendC::SetAtomicAdd<T>();
            AscendC::DataCopy(dstGlobal[i * tileCount], srcLocal, tileCount);
            AscendC::DisableDmaAtomic();
            AscendC::NotifyNextBlock(gmWorkspace, ubWorkspace);
            que.FreeTensor(srcLocal);
        }
        queTmp.FreeTensor(ubWorkspace);
    }

private:
    AscendC::TPipe* pipe;
    int64_t elementCount;
    int64_t tileNum;
    int64_t tileCount;
    AscendC::GlobalTensor<T> srcGlobal;
    AscendC::GlobalTensor<T> dstGlobal;
    AscendC::GlobalTensor<int32_t> gmWorkspace;
    AscendC::TQue<AscendC::TPosition::VECIN, 1> que;
    AscendC::TQue<AscendC::TPosition::VECIN, 1> queTmp;
}

