class KernelSetNextTaskStart {
public:
    __aicore__ inline KernelSetNextTaskStart() {}
    __aicore__ inline void Init(GM_ADDR src0Gm, GM_ADDR src1Gm, GM_ADDR dstGm, AscendC::TPipe *pipeIn, uint32_t calCount)
    {
        pipe = pipeIn;
        bufferSize = calCount;

        src0Global.SetGlobalBuffer(reinterpret_cast<__gm__ T *>(src0Gm));
        src1Global.SetGlobalBuffer(reinterpret_cast<__gm__ T *>(src1Gm));
        dstGlobal.SetGlobalBuffer(reinterpret_cast<__gm__ T *>(dstGm));

        pipe->InitBuffer(inQueueSrc0, 1, bufferSize * sizeof(T));
        pipe->InitBuffer(inQueueSrc1, 1, bufferSize * sizeof(T));
        pipe->InitBuffer(outQueue, 1, bufferSize * sizeof(T));
    }
    __aicore__ inline void Process()
    {
        CopyIn();
        Compute();
        CopyOut();
    }
private:
    __aicore__ inline void CopyIn()
    {
        AscendC::LocalTensor<T> src0Local = inQueueSrc0.AllocTensor<T>();
        AscendC::LocalTensor<T> src1Local = inQueueSrc1.AllocTensor<T>();
        AscendC::DataCopy(src0Local, src0Global, bufferSize);
        AscendC::DataCopy(src1Local, src1Global, bufferSize);
        inQueueSrc0.EnQue(src0Local);
        inQueueSrc1.EnQue(src1Local);
    }
    __aicore__ inline void Compute()
    {
        AscendC::LocalTensor<T> dstLocal = outQueue.AllocTensor<T>();
        AscendC::LocalTensor<T> src0Local = inQueueSrc0.DeQue<T>();
        AscendC::LocalTensor<T> src1Local = inQueueSrc1.DeQue<T>();

        AscendC::Add(dstLocal, src0Local, src1Local, bufferSize);

        outQueue.EnQue(dstLocal);
        inQueueSrc0.FreeTensor(src0Local);
        inQueueSrc1.FreeTensor(src1Local);
    }
    __aicore__ inline void CopyOut()
    {
        AscendC::LocalTensor<T> dstLocal = outQueue.DeQue<T>();
        AscendC::DataCopy(dstGlobal, dstLocal, bufferSize);
        AscendC::SetNextTaskStart();
        outQueue.FreeTensor(dstLocal);
    }

private:
    AscendC::GlobalTensor<T> src0Global;
    AscendC::GlobalTensor<T> src1Global;
    AscendC::GlobalTensor<T> dstGlobal;
    AscendC::TPipe* pipe;
    AscendC::TQue<AscendC::TPosition::VECIN, 1> inQueueSrc0, inQueueSrc1;
    AscendC::TQue<AscendC::TPosition::VECOUT, 1> outQueue;
    uint32_t bufferSize = 0;
}

