#include <cstdio>
#include "kernel_args.h"
#include "securec.h"
#include "acl/acl.h"

extern __global__ __aicpu__ uint32_t MyAicpuKernel(KernelInfo::KernelArgs);

extern "C" void hello_world_do(uint32_t numBlocks, void *stream, uint8_t*m, uint8_t *ti);

int32_t main(int argc, char const *argv[])
{
    aclInit(nullptr);
    int32_t deviceId = 0;
    aclrtSetDevice(deviceId);

    aclrtStream aicpu_stream = nullptr;
    aclrtStream aicore_stream = nullptr;
    aclrtCreateStream(&aicpu_stream);
    aclrtCreateStream(&aicore_stream);

    aclrtEvent event;
    aclrtCreateEventExWithFlag(&event, ACL_EVENT_SYNC);

    void* zDevice;
    void* ti;
    void* zHost;
    aclrtMalloc((void**)&zDevice, 4096, ACL_MEM_MALLOC_HUGE_FIRST);
    aclrtMalloc((void**)&ti, 4096, ACL_MEM_MALLOC_HUGE_FIRST);
    aclrtMallocHost((void**)&zHost, 4096);

    aclrtMemset((void*)ti, 4096, 0, 4096);
    aclrtMemset((void*)zHost, 4096, 10, 4096);
    aclrtMemcpy(zDevice, 4096, zHost, 4096, ACL_MEMCPY_HOST_TO_DEVICE);

    struct KernelInfo::KernelArgs args = {0};
    args.xDevice = (uint32_t *)zDevice;
    args.yDevice = args.xDevice + 1;
    args.zDevice = args.yDevice + 1;
    args.ti = (KernelInfo::TilingInfo *)ti;

    MyAicpuKernel<<<1, nullptr, aicpu_stream>>>(args);
    aclrtRecordEvent(event, aicpu_stream);
    aclrtStreamWaitEvent(aicore_stream, event);
    hello_world_do(1, aicore_stream, (uint8_t *)zDevice, (uint8_t *)ti);

    aclrtSynchronizeStream(aicpu_stream);
    aclrtSynchronizeStream(aicore_stream);
    aclrtFree(zDevice);
    aclrtFree(ti);
    aclrtFreeHost(zHost);
    aclrtDestroyStream(aicpu_stream);
    aclrtDestroyStream(aicore_stream);
    aclrtResetDevice(deviceId);
    aclFinalize();
    return 0;
}

