constexpr AscendC::Te::LoadDataTrait LOAD_DATA_B_TRAIT{true};

struct LoadData2BTrait {
    using TraitType = AscendC::Te::LoadDataTrait;
    static constexpr const TraitType value = LOAD_DATA_B_TRAIT;
};

// 自定义FixpipeTrait，使能relu激活
// 用于控制量化场景下的舍入模式，仅针对float量化为hifloat8_t场景生效，默认值为RoundMode::DEFAULT
constexpr AscendC::Te::RoundMode roundModeIn = AscendC::Te::RoundMode::DEFAULT;
// 是否使能ReLU的开关
constexpr bool enableReluIn = true;
// 输出到GM场景下，是否使能通道拆分的功能。仅在目的操作数和源操作数都为float，且目的操作数数据格式为NZ时才能使能通道拆分。
constexpr bool enableChannelSplitIn = false;
// 用于输出到UB场景下双目标模式控制，默认值为DualDstMode::DUAL_DST_DISABLE（即不启用双目标模式控制）
constexpr AscendC::Te::DualDstMode dualDstCtlIn = AscendC::Te::DualDstMode::DUAL_DST_DISABLE;

constexpr AscendC::Te::FixpipeTrait fixpipeTrait = {roundModeIn, enableReluIn, enableChannelSplitIn, dualDstCtlIn};
struct FixpipeTraitCustom {
    using TraitType = AscendC::Te::FixpipeTrait;
    static constexpr const TraitType value = fixpipeTrait;
};

template <int32_t m, int32_t n, int32_t k, int32_t singleCoreM, int32_t singleCoreN, int32_t singleCoreK, int32_t baseM,
          int32_t baseN, int32_t baseK, int32_t stepM, int32_t stepN, int32_t stepK>
__cube__ __global__ void matmul_quant_relu_custom(__gm__ half* x, __gm__ half* y, __gm__ int8_t* z,
                                                  __gm__ uint64_t* quant)
{
    using namespace AscendC::Te;

    auto gmPtrA = MakeGMmemPtr(x);
    auto gmPtrB = MakeGMmemPtr(y);
    auto gmPtrC = MakeGMmemPtr(z);
    auto gmPtrQuant = MakeGMmemPtr(quant);

    auto gmA = MakeTensor(gmPtrA, MakeNDLayout<half>(m, k));
    auto gmB = MakeTensor(gmPtrB, MakeNDLayout<half>(k, n));
    auto gmC = MakeTensor(gmPtrC, MakeNDLayout<int8_t>(m, n));
    auto gmQuant = MakeTensor(gmPtrQuant, MakeNDLayout<uint64_t>(AscendC::Std::Int<1>{}, n));

    uint32_t mIter = m / singleCoreM;
    uint32_t mIterIdx = get_block_idx() % mIter;
    uint32_t nIterIdx = get_block_idx() / mIter;

    auto shapeA = MakeShape(singleCoreM, singleCoreK);
    auto globalA = gmA(MakeCoord(mIterIdx * singleCoreM, 0), shapeA);

    auto shapeB = MakeShape(singleCoreK, singleCoreN);
    auto globalB = gmB(MakeCoord(0, nIterIdx * singleCoreN), shapeB);

    auto shapeC = MakeShape(singleCoreM, singleCoreN);
    auto globalC = gmC(MakeCoord(mIterIdx * singleCoreM, nIterIdx * singleCoreN), shapeC);

    auto shapeQuant = MakeShape(AscendC::Std::Int<1>{}, singleCoreN);
    auto globalQuant = gmQuant(MakeCoord(0, nIterIdx * singleCoreN), shapeQuant);

    auto l1ALayout = MakeNzLayout<half>(baseM * stepM, baseK * stepK);
    auto l1BLayout = MakeNzLayout<half>(baseK * stepK, baseN * stepN);
    auto l1QuantLayout = MakeNDLayout<uint64_t>(AscendC::Std::Int<1>{}, baseN * stepN);

    auto l0ALayout = MakeNzLayout<half>(baseM, baseK);
    auto l0BLayout = MakeZnLayout<half>(baseK, baseN);
    auto l0CLayout = MakeL0CLayout(baseM, baseN);

    size_t l1ASize = baseM * stepM * baseK * stepK;
    size_t l1BSize = baseN * stepN * baseK * stepK;

    __cbuf__ half* l1ABuf = (__cbuf__ half*)0;
    __cbuf__ half* l1BBuf = (__cbuf__ half*)0 + l1ASize;
    __cbuf__ uint64_t* l1QuantBuf = (__cbuf__ uint64_t*)0 + l1ASize + l1BSize;
    __ca__ half* l0ABuf = (__ca__ half*)0;
    __cb__ half* l0BBuf = (__cb__ half*)0;
    __cc__ float* l0CBuf = (__cc__ float*)0;

    auto l1APtr = MakeL1memPtr(l1ABuf);
    auto l1BPtr = MakeL1memPtr(l1BBuf);
    auto l1QuantPtr = MakeL1memPtr(l1QuantBuf);
    auto l0APtr = MakeL0AmemPtr(l0ABuf);
    auto l0BPtr = MakeL0BmemPtr(l0BBuf);
    auto l0CPtr = MakeL0CmemPtr(l0CBuf);

    auto l1ATensor = MakeTensor(l1APtr, l1ALayout);
    auto l1BTensor = MakeTensor(l1BPtr, l1BLayout);
    auto l1QuantTensor = MakeTensor(l1QuantPtr, l1QuantLayout);
    auto l0ATensor = MakeTensor(l0APtr, l0ALayout);
    auto l0BTensor = MakeTensor(l0BPtr, l0BLayout);
    auto l0CTensor = MakeTensor(l0CPtr, l0CLayout);

    uint32_t mLoop = singleCoreM / baseM;
    uint32_t nLoop = singleCoreN / baseN;
    uint32_t kLoop = singleCoreK / baseK;

    AscendC::SetFlag<AscendC::HardEvent::MTE1_MTE2>(EVENT_ID0);
    AscendC::SetFlag<AscendC::HardEvent::M_MTE1>(EVENT_ID0);
    AscendC::SetFlag<AscendC::HardEvent::FIX_M>(EVENT_ID0);

    for (uint32_t i = 0; i < mLoop; i++) {
        for (uint32_t j = 0; j < nLoop; j++) {
            for (uint32_t kIter = 0; kIter < kLoop; kIter++) {
                if (kIter % stepK == 0) {
                    AscendC::WaitFlag<AscendC::HardEvent::MTE1_MTE2>(EVENT_ID0);
                    // GM -> L1A
                    Copy(CopyAtom<CopyTraits<CopyGM2L1, DataCopyTraitDefault>>{}, l1ATensor, globalA,
                         MakeCoord(i * stepM * baseM, kIter * baseK));
                    // GM -> L1B
                    Copy(CopyAtom<CopyTraits<CopyGM2L1, DataCopyTraitDefault>>{}, l1BTensor, globalB,
                         MakeCoord(kIter * baseK, j * stepN * baseN));
                    // GM -> L1Quant
                    Copy(CopyAtom<CopyTraits<CopyGM2L1, DataCopyTraitDefault>>{}, l1QuantTensor, globalQuant,
                         MakeCoord(0, j * stepN * baseN));
                    AscendC::SetFlag<AscendC::HardEvent::MTE2_MTE1>(EVENT_ID0);
                }
                if (kIter % stepK == 0) {
                    AscendC::WaitFlag<AscendC::HardEvent::MTE2_MTE1>(EVENT_ID0);
                }
                AscendC::WaitFlag<AscendC::HardEvent::M_MTE1>(EVENT_ID0);
                // L1A -> L0A
                Copy(CopyAtom<CopyTraits<CopyL12L0, LoadDataTraitDefault>>{}, l0ATensor, l1ATensor,
                     MakeCoord(0, kIter % stepK * baseK));
                // L1B -> L0B
                Copy(CopyAtom<CopyTraits<CopyL12L0, LoadData2BTrait>>{}, l0BTensor, l1BTensor,
                     MakeCoord(kIter % stepK * baseK, 0));
                if ((kIter + 1) % stepK == 0) {
                    AscendC::SetFlag<AscendC::HardEvent::MTE1_MTE2>(EVENT_ID0);
                }
                AscendC::SetFlag<AscendC::HardEvent::MTE1_M>(EVENT_ID0);
                AscendC::WaitFlag<AscendC::HardEvent::MTE1_M>(EVENT_ID0);

                if (kIter % stepK == 0) {
                    AscendC::WaitFlag<AscendC::HardEvent::FIX_M>(EVENT_ID0);
                }

                // mmad
                MmadParams para;
                para.m = baseM;
                para.n = baseN;
                para.k = baseK;
                if (kIter == 0) {
                    para.cmatrixInitVal = true;
                    Mad(MmadAtom<MmadTraits<MmadOperation, MmadTraitDefault>>{}, l0CTensor, l0ATensor, l0BTensor, para);
                } else {
                    para.cmatrixInitVal = false;
                    Mad(MmadAtom<MmadTraits<MmadOperation, MmadTraitDefault>>{}, l0CTensor, l0ATensor, l0BTensor, para);
                }
                if (kIter == kLoop - 1) {
                    AscendC::SetFlag<AscendC::HardEvent::M_FIX>(EVENT_ID0);
                }
                AscendC::SetFlag<AscendC::HardEvent::M_MTE1>(EVENT_ID0);
            }
            AscendC::WaitFlag<AscendC::HardEvent::M_FIX>(EVENT_ID0);

            // L0C -> GM
            // 自定义FixpipeTraitCustom以及输入quantTensor，使能随路量化和relu激活
            Copy(CopyAtom<CopyTraits<CopyL0C2GM, FixpipeTraitCustom>>{}, globalC, l0CTensor, l1QuantTensor,
                 MakeCoord(i * baseM, j * baseN));
            AscendC::SetFlag<AscendC::HardEvent::FIX_M>(EVENT_ID0);
        }
    }

    AscendC::WaitFlag<AscendC::HardEvent::M_MTE1>(EVENT_ID0);
    AscendC::WaitFlag<AscendC::HardEvent::MTE1_MTE2>(EVENT_ID0);
    AscendC::WaitFlag<AscendC::HardEvent::FIX_M>(EVENT_ID0);
}

int32_t main(int32_t argc, char* argv[])
{
    constexpr uint32_t M = 128;
    constexpr uint32_t N = 128;
    constexpr uint32_t K = 96;
    constexpr uint32_t NUM_BLOCKS = 32;
    constexpr uint32_t SINGLE_CORE_M = 16;
    constexpr uint32_t SINGLE_CORE_N = 32;
    constexpr uint32_t SINGLE_CORE_K = 96;
    constexpr uint32_t BASE_M = 16;
    constexpr uint32_t BASE_N = 32;
    constexpr uint32_t BASE_K = 16;
    constexpr uint32_t STEP_M = 1;
    constexpr uint32_t STEP_N = 1;
    constexpr uint32_t STEP_K = 6;

    size_t param1FileSize = M * K * sizeof(half);
    size_t param2FileSize = N * K * sizeof(half);
    size_t param3FileSize = M * N * sizeof(int8_t);
    size_t param4FileSize = N * sizeof(uint64_t);

    aclInit(nullptr);
    int32_t deviceId = 0;
    aclrtSetDevice(deviceId);
    aclrtStream stream = nullptr;
    aclrtCreateStream(&stream);

    uint8_t *xHost, *yHost, *zHost, *quantHost;
    half *xDevice, *yDevice;
    int8_t* zDevice;
    uint64_t* quantDevice;

    aclrtMallocHost((void**)(&xHost), param1FileSize);
    aclrtMallocHost((void**)(&yHost), param2FileSize);
    aclrtMallocHost((void**)(&zHost), param3FileSize);
    aclrtMallocHost((void**)(&quantHost), param4FileSize);
    aclrtMalloc((void**)&xDevice, param1FileSize, ACL_MEM_MALLOC_HUGE_FIRST);
    aclrtMalloc((void**)&yDevice, param2FileSize, ACL_MEM_MALLOC_HUGE_FIRST);
    aclrtMalloc((void**)&zDevice, param3FileSize, ACL_MEM_MALLOC_HUGE_FIRST);
    aclrtMalloc((void**)&quantDevice, param4FileSize, ACL_MEM_MALLOC_HUGE_FIRST);

    ReadFile("./input/input_x.bin", param1FileSize, xHost, param1FileSize);
    ReadFile("./input/input_y.bin", param2FileSize, yHost, param2FileSize);
    ReadFile("./input/quant.bin", param4FileSize, quantHost, param4FileSize);

    aclrtMemcpy(xDevice, param1FileSize, xHost, param1FileSize, ACL_MEMCPY_HOST_TO_DEVICE);
    aclrtMemcpy(yDevice, param2FileSize, yHost, param2FileSize, ACL_MEMCPY_HOST_TO_DEVICE);
    aclrtMemcpy(quantDevice, param4FileSize, quantHost, param4FileSize, ACL_MEMCPY_HOST_TO_DEVICE);

    matmul_quant_relu_custom<M, N, K, SINGLE_CORE_M, SINGLE_CORE_N, SINGLE_CORE_K, BASE_M, BASE_N, BASE_K, STEP_M,
                             STEP_N, STEP_K><<<NUM_BLOCKS, nullptr, stream>>>(xDevice, yDevice, zDevice, quantDevice);
    aclrtSynchronizeStream(stream);

    aclrtMemcpy(zHost, param3FileSize, zDevice, param3FileSize, ACL_MEMCPY_DEVICE_TO_HOST);
    WriteFile("./output/output.bin", zHost, param3FileSize);

    aclrtFree(xDevice);
    aclrtFree(yDevice);
    aclrtFree(zDevice);
    aclrtFree(quantDevice);
    aclrtFreeHost(xHost);
    aclrtFreeHost(yHost);
    aclrtFreeHost(zHost);
    aclrtFreeHost(quantHost);

    aclrtDestroyStream(stream);
    aclrtResetDevice(deviceId);
    aclFinalize();

    return 0;
}

template <class A_TYPE, class B_TYPE, class C_TYPE, class BIAS_TYPE>
class BatchMatmulKernel {
    public:
        __aicore__ inline BatchMatmulKernel(){};
        __aicore__ inline void Init(GM_ADDR a, GM_ADDR b, GM_ADDR bias, GM_ADDR c, GM_ADDR workspace, const TCubeTiling& tiling);
        template <bool hasBias = false>
        __aicore__ inline void Process(AscendC::TPipe* pipe, int32_t batchA, int32_t batchB);
        AscendC::Matmul<A_TYPE, B_TYPE, C_TYPE, BIAS_TYPE> matmulObj;
    private:
        __aicore__ inline void CalcOffset(int32_t blockIdx, const TCubeTiling& tiling, int32_t& offsetA, int32_t& offsetB,
                                          int32_t& offsetC, int32_t& offsetBias);
        using aType = typename A_TYPE::T;
        using bType = typename B_TYPE::T;
        using cType = typename C_TYPE::T;
        using biasType = typename BIAS_TYPE::T;
        AscendC::GlobalTensor<aType> aGlobal;
