}

__global__ __aicore__ void batch_matmul_custom(GM_ADDR a, GM_ADDR b, GM_ADDR c, __kfc_workspace__ GM_ADDR workspace,
                                                        GM_ADDR tilingGm)
{
    // prepare tiling
    TCubeTiling tiling;
    CopyTiling(&tiling, tilingGm);
    // define matmul kernel
    typedef AscendC::MatmulType<AscendC::TPosition::GM, CubeFormat::ND, half, false, LayoutMode::BSNGD> A_TYPE;
    typedef AscendC::MatmulType<AscendC::TPosition::GM, CubeFormat::ND, half, true, LayoutMode::BSNGD> B_TYPE;
    typedef AscendC::MatmulType<AscendC::TPosition::GM, CubeFormat::ND, float, false, LayoutMode::BSNGD> C_TYPE;
    typedef AscendC::MatmulType<AscendC::TPosition::GM, CubeFormat::ND, float> BIAS_TYPE;
    BatchMatmulKernel<A_TYPE, B_TYPE, C_TYPE, BIAS_TYPE> batchMatmulKernel;
    AscendC::TPipe pipe;
    tiling.shareMode = 0;             // 0, share mode
    tiling.shareL1Size = FULL_L1_SIZE;  // full L1
    tiling.shareL0CSize = FULL_L0C_SIZE; // full L0C
    tiling.shareUbSize = 0;           // no UB
    REGIST_MATMUL_OBJ(&pipe, GetSysWorkSpacePtr(), batchMatmulKernel.matmulObj, &tiling);
    // init matmul kernel
    batchMatmulKernel.Init(a, b, nullptr, c, workspace, tiling);
    // matmul kernel process
    batchMatmulKernel.Process<false>(&pipe, 3, 3);
}

template <typename AType, typename BType, typename CType, typename BiasType>
class MatmulKernel {
public:
    __aicore__ inline MatmulKernel(){};
    /**
     * @brief  Initialization before process.
     * @param  a: A matrix gm addr.
     * @param  b: B matrix gm addr.
     * @param  bias: Bias matrix gm addr.
     * @param  c: C matrix gm addr.
     * @param  tiling: Matmul tiling struct.
     * @retval None
     */
    __aicore__ inline void Init(GM_ADDR a, GM_ADDR b, GM_ADDR bias, GM_ADDR c, const TCubeTiling& tiling);
    /**
     * @brief  Process matrix calculation.
     * @retval None
     */
    __aicore__ inline void Process();
    AscendC::Matmul<AscendC::MatmulType<AscendC::TPosition::GM, CubeFormat::ND, AType, isTransA, LayoutMode::NORMAL>,
                    AscendC::MatmulType<AscendC::TPosition::GM, CubeFormat::ND, BType, isTransB, LayoutMode::NORMAL>,
                    AscendC::MatmulType<AscendC::TPosition::GM, CubeFormat::ND, CType, false, LayoutMode::NORMAL>,
                    AscendC::MatmulType<AscendC::TPosition::GM, CubeFormat::ND, BiasType>, CFG_MM>
        matmulObj;

private:
    AscendC::GlobalTensor<AType> aGlobal;
    AscendC::GlobalTensor<BType> bGlobal;
    AscendC::GlobalTensor<CType> cGlobal;
    AscendC::GlobalTensor<BiasType> biasGlobal;
    TCubeTiling tiling;
}

__global__ __aicore__ void batch_matmul_bias_reuse_custom(GM_ADDR a, GM_ADDR b, GM_ADDR bias, GM_ADDR c, __kfc_workspace__ GM_ADDR workspace, GM_ADDR tilingGm)
{
    TCubeTiling tiling;
    CopyTiling(&tiling, tilingGm);

    MatmulKernel<half, half, float, float> matmulKernel;
    AscendC::TPipe pipe;
    REGIST_MATMUL_OBJ(&pipe, GetSysWorkSpacePtr(), matmulKernel.matmulObj, &tiling);

    matmulKernel.Init(a, b, bias, c, tiling);
    matmulKernel.Process();
}

