/**
 * @brief  Copy tiling data to TCubeTiling ptr from tiling gm addr.
 * @param  tiling: TCubeTiling ptr which needs to copy tiling data.
 * @param  tilingGM: tiling gm addr.
 * @retval None
 */
__aicore__ inline void CopyTiling(TCubeTiling* tiling, GM_ADDR tilingGM)
{
    uint32_t* ptr = reinterpret_cast<uint32_t*>(tiling);
    auto tiling32 = reinterpret_cast<__gm__ uint32_t*>(tilingGM);

    for (uint32_t i = 0; i < sizeof(TCubeTiling) / sizeof(uint32_t); i++, ptr++) { *ptr = *(tiling32 + i); }
    return;
}

__aicore__ inline void CustomDataCopyInA(const AscendC::LocalTensor<int8_t>& aMatrix, const __gm__ void* gm, int row,
                                         int col, int useM, int useK, const uint64_t tilingPtr, const uint64_t dataPtr)
{
    int tmpRow = row * BLOCK_CUBE;
    int tmpCol = col * BLOCK_CUBE;
    int gCol = tilingPtr;
    int height = useM;
    int width = useK;
    uint64_t curSrcAddr;
    uint64_t srcOffset;

    AscendC::LocalTensor<half> dst = aMatrix.template ReinterpretCast<half>();
    AscendC::GlobalTensor<uint64_t> dataGM;
    dataGM.SetGlobalBuffer(reinterpret_cast<__gm__ uint64_t*>(dataPtr), OFFSET_LIST_SIZE);

    int curBlock = AscendC::GetBlockIdx();
    int curSrcAddrIdx = curBlock * NUMBER_OF_CORES_IN_OFFSET_LIST + 1;
    // calculate whether the current basic block needs an offset address through col and row
    if (col < THIRD_INDEX_OF_COL) {
        curSrcAddr = dataGM.GetValue(curSrcAddrIdx);
    } else {
        curSrcAddr = dataGM.GetValue(curSrcAddrIdx + 1);
    }
    if (col == 0 || col == THIRD_INDEX_OF_COL) {
        srcOffset = 0;
    } else {
        srcOffset = width;
    }

    AscendC::GlobalTensor<half> src;
    src.SetGlobalBuffer(reinterpret_cast<__gm__ half*>(curSrcAddr));

    AscendC::Nd2NzParams nd2nzParams;
    nd2nzParams.ndNum = 1;
    nd2nzParams.nValue = height;
    nd2nzParams.dValue = width;
    nd2nzParams.srcNdMatrixStride = 0;
    nd2nzParams.srcDValue = gCol;
    nd2nzParams.dstNzC0Stride = AscendC::Ceil(height, BLOCK_CUBE) * BLOCK_CUBE;
    nd2nzParams.dstNzNStride = 1;
    nd2nzParams.dstNzMatrixStride = 0;
    DataCopy(dst, src[srcOffset], nd2nzParams);
}

template <typename AType, typename BType, typename CType, typename BiasType>
class MatmulKernel {
public:
    __aicore__ inline MatmulKernel(){};
    /**
     * @brief  Initialization before process.
     * @param  a: A matrix gm addr.
     * @param  b: B matrix gm addr.
     * @param  bias: Bias matrix gm addr.
     * @param  c: C matrix gm addr.
     * @param  offsetList: A matrix offset gm addr list.
     * @param  tiling: Matmul tiling struct.
     * @retval None
     */
    __aicore__ inline void Init(GM_ADDR a, GM_ADDR b, GM_ADDR bias, GM_ADDR c, GM_ADDR offsetList,
                                const TCubeTiling& tiling);
    /**
     * @brief  Process matrix calculation.
     * @retval None
     */
    __aicore__ inline void Process();

    AscendC::Matmul<AscendC::MatmulType<AscendC::TPosition::GM, CubeFormat::ND, AType, IS_TRANS_A>,
                    AscendC::MatmulType<AscendC::TPosition::GM, CubeFormat::ND, BType, IS_TRANS_B>,
                    AscendC::MatmulType<AscendC::TPosition::GM, CubeFormat::ND, CType>,
                    AscendC::MatmulType<AscendC::TPosition::GM, CubeFormat::ND, BiasType>, CFG_NORM,
                    AscendC::MatmulCallBackFunc<nullptr, CustomDataCopyInA, nullptr>>
        matmulObj;

private:
    /**
     * @brief  Calculate the gm offset based on the blockIdx.
     * @param  blockIdx: Current Core blockidx.
     * @param  offsetA: Gm offset of A matrix.
     * @param  offsetB: Gm offset of B matrix.
     * @param  offsetC: Gm offset of C matrix.
     * @param  offsetBias: Gm offset of Bias matrix.
     * @retval None
     */
    __aicore__ inline void CalcOffset(int32_t blockIdx, int32_t& offsetA, int32_t& offsetB, int32_t& offsetC,
                                      int32_t& offsetBias);

    AscendC::GlobalTensor<AType> aGlobal;
    AscendC::GlobalTensor<BType> bGlobal;
    AscendC::GlobalTensor<CType> cGlobal;
    AscendC::GlobalTensor<BiasType> biasGlobal;
    AscendC::GlobalTensor<uint64_t> offsetListGlobal;
    TCubeTiling tiling;
};

template <typename AType, typename BType, typename CType, typename BiasType>
__aicore__ inline void MatmulKernel<AType, BType, CType, BiasType>::Init(GM_ADDR a, GM_ADDR b, GM_ADDR bias, GM_ADDR c,
                                                                         GM_ADDR offsetList, const TCubeTiling& tiling)
{
    this->tiling = tiling;

    aGlobal.SetGlobalBuffer(reinterpret_cast<__gm__ AType*>(a), tiling.M * tiling.Ka);
    bGlobal.SetGlobalBuffer(reinterpret_cast<__gm__ BType*>(b), tiling.Kb * tiling.N);
    cGlobal.SetGlobalBuffer(reinterpret_cast<__gm__ CType*>(c), tiling.M * tiling.N);
    biasGlobal.SetGlobalBuffer(reinterpret_cast<__gm__ BiasType*>(bias), tiling.N);
    offsetListGlobal.SetGlobalBuffer(reinterpret_cast<__gm__ uint64_t*>(offsetList), OFFSET_LIST_SIZE);

    int32_t offsetA = 0;
    int32_t offsetB = 0;
    int32_t offsetC = 0;
    int32_t offsetBias = 0;
    CalcOffset(AscendC::GetBlockIdx(), offsetA, offsetB, offsetC, offsetBias);
    aGlobal = aGlobal[offsetA];
    bGlobal = bGlobal[offsetB];
    cGlobal = cGlobal[offsetC];
    biasGlobal = biasGlobal[offsetBias];

    if (GetSysWorkSpacePtr() == nullptr) {
        return;
    }
}

template <typename AType, typename BType, typename CType, typename BiasType>
__aicore__ inline void MatmulKernel<AType, BType, CType, BiasType>::Process()
{
    if (matmul::GetBlockIdx() >= tiling.usedCoreNum) {
        return;
    }

    int curBlock = AscendC::GetBlockIdx();
    int curBlockIdx = curBlock * NUMBER_OF_CORES_IN_OFFSET_LIST + 1;
    int base_offset = offsetListGlobal.GetValue(0);
    uint64_t srcBaseAddr1 = reinterpret_cast<uint64_t>(aGlobal.GetPhyAddr());
    uint64_t srcBaseAddr2 = reinterpret_cast<uint64_t>(aGlobal.GetPhyAddr(base_offset));

    offsetListGlobal.SetValue(curBlockIdx, srcBaseAddr1);
    offsetListGlobal.SetValue(curBlockIdx + 1, srcBaseAddr2);
    uint64_t offsetListGMPtr = reinterpret_cast<uint64_t>(offsetListGlobal.GetPhyAddr());

    matmulObj.SetUserDefInfo(tiling.Ka);
    matmulObj.SetSelfDefineData(offsetListGMPtr);

    matmulObj.SetTensorA(aGlobal, IS_TRANS_A);
    matmulObj.SetTensorB(bGlobal, IS_TRANS_B);
    if (IS_BIAS) {
        matmulObj.SetBias(biasGlobal);
    }
    matmulObj.IterateAll(cGlobal);
    matmulObj.End();
}

template <typename AType, typename BType, typename CType, typename BiasType>
__aicore__ inline void MatmulKernel<AType, BType, CType, BiasType>::CalcOffset(int32_t blockIdx, int32_t& offsetA,
                                                                               int32_t& offsetB, int32_t& offsetC,
                                                                               int32_t& offsetBias)
{
    const TCubeTiling& param = this->tiling;

    auto temp0 = AscendC::Ceil(param.M, param.singleCoreM);
    auto temp1 = AscendC::Ceil(param.N, param.singleCoreN);
    auto temp2 = AscendC::Ceil(param.Ka, param.singleCoreK);

    auto divideKCoreNum = param.usedCoreNum / temp2;

    auto mCoreIndex = (blockIdx % divideKCoreNum) % temp0;
    auto nCoreIndex = (blockIdx % divideKCoreNum) / temp0;
    auto subKIndex = blockIdx / divideKCoreNum;

    offsetA = mCoreIndex * param.Ka * param.singleCoreM + subKIndex * param.singleCoreK;
    offsetB = subKIndex * param.singleCoreK * param.N + nCoreIndex * param.singleCoreN;
    offsetC = mCoreIndex * param.N * param.singleCoreM + nCoreIndex * param.singleCoreN;
    offsetBias = nCoreIndex * param.singleCoreN;
}

/**
 * @brief  matmul_callback kernel function entry
 * @param  a: A matrix gm addr.
 * @param  b: B matrix gm addr.
 * @param  bias: bias matrix gm addr.
 * @param  c: C matrix gm addr.
 * @param  offsetList: A matrix offset gm addr list.
 * @param  workspace: Temporary gm space addr required by matmul calc.
 * @param  tilingGm: Tiling data addr.
 * @retval None
 */
__global__ __cube__ void matmul_callback_custom(GM_ADDR a, GM_ADDR b, GM_ADDR bias, GM_ADDR c, GM_ADDR offsetlist,
                                         GM_ADDR workspace, GM_ADDR tilingGm)
{

    TCubeTiling tiling;
    CopyTiling(&tiling, tilingGm);
    AscendC::TPipe pipe;

    MatmulKernel<half, half, float, float> matmulKernel;
    REGIST_MATMUL_OBJ(&pipe, GetSysWorkSpacePtr(), matmulKernel.matmulObj, &tiling);
    matmulKernel.Init(a, b, bias, c, offsetlist, tiling);
    matmulKernel.Process();
}

void GenerateTiling(platform_ascendc::PlatformAscendC* ascendcPlatform, uint8_t* tilingBuf)
{
    optiling::TCubeTiling tilingData;
    matmul_tiling::MultiCoreMatmulTiling tilingApi(*ascendcPlatform);

    tilingApi.SetDim(NUM_BLOCKS);
    tilingApi.SetAType(matmul_tiling::TPosition::GM, matmul_tiling::CubeFormat::ND, matmul_tiling::DataType::DT_FLOAT16,
                       IS_TRANS_A);
    tilingApi.SetBType(matmul_tiling::TPosition::GM, matmul_tiling::CubeFormat::ND, matmul_tiling::DataType::DT_FLOAT16,
                       IS_TRANS_B);
    tilingApi.SetCType(matmul_tiling::TPosition::GM, matmul_tiling::CubeFormat::ND, matmul_tiling::DataType::DT_FLOAT);
    tilingApi.SetBiasType(matmul_tiling::TPosition::GM, matmul_tiling::CubeFormat::ND,
                          matmul_tiling::DataType::DT_FLOAT);

    tilingApi.SetOrgShape(M, N, K);
    tilingApi.SetShape(M, N, K);
    tilingApi.SetSingleShape(M / NUM_BLOCKS, N, K);
    tilingApi.EnableBias(IS_BIAS);
    tilingApi.SetBufferSpace(-1, -1, -1);

    int64_t res = tilingApi.GetTiling(tilingData); // Get matmul tiling data.
    if (res == -1) {
        std::cout << "gen tiling failed" << std::endl;
    }
    uint32_t tcubeTilingSize = tilingData.GetDataSize();
    tilingData.SaveToBuffer(tilingBuf, tcubeTilingSize);
}

int32_t main(int32_t argc, char* argv[])
{
    auto ascendcPlatform = platform_ascendc::PlatformAscendCManager::GetInstance();

    size_t aFileSize = static_cast<size_t>(M * K) * sizeof(uint16_t); // uint16_t represent half
    size_t bFileSize = static_cast<size_t>(K * N) * sizeof(uint16_t); // uint16_t represent half
    size_t cFileSize = static_cast<size_t>(M * N) * sizeof(float);
    size_t biasFileSize = static_cast<size_t>(N) * sizeof(float);
    size_t offsetListSize = OFFSET_LIST_SIZE * sizeof(uint64_t);

    // matmul TCubeTiling
    size_t tilingFileSize = sizeof(TCubeTiling);
    uint8_t* tilingBuf = (uint8_t*)malloc(tilingFileSize);
    GenerateTiling(ascendcPlatform, tilingBuf);

    size_t userWorkspaceSize = 0;
    size_t systemWorkspaceSize = static_cast<size_t>(ascendcPlatform->GetLibApiWorkSpaceSize());
    size_t workspaceSize = userWorkspaceSize + systemWorkspaceSize;

    int32_t deviceId = 0;
    aclrtStream stream = nullptr;
    aclrtContext context;

    aclInit(nullptr);
    aclrtSetDevice(deviceId);
    aclrtCreateContext(&context, deviceId);
    aclrtCreateStream(&stream);

    uint8_t* aHost;
    uint8_t* aDevice;
    aclrtMallocHost((void**)(&aHost), aFileSize);
    aclrtMalloc((void**)&aDevice, aFileSize, ACL_MEM_MALLOC_HUGE_FIRST);
    ReadFile("./input/x1_gm.bin", aFileSize, aHost, aFileSize);
    aclrtMemcpy(aDevice, aFileSize, aHost, aFileSize, ACL_MEMCPY_HOST_TO_DEVICE);

    uint8_t* bHost;
    uint8_t* bDevice;
    aclrtMallocHost((void**)(&bHost), bFileSize);
    aclrtMalloc((void**)&bDevice, bFileSize, ACL_MEM_MALLOC_HUGE_FIRST);
    ReadFile("./input/x2_gm.bin", bFileSize, bHost, bFileSize);
    aclrtMemcpy(bDevice, bFileSize, bHost, bFileSize, ACL_MEMCPY_HOST_TO_DEVICE);

    uint8_t* biasHost;
    uint8_t* biasDevice;
    if (IS_BIAS) {
        aclrtMallocHost((void**)(&biasHost), biasFileSize);
        aclrtMalloc((void**)&biasDevice, biasFileSize, ACL_MEM_MALLOC_HUGE_FIRST);
        ReadFile("./input/bias_gm.bin", biasFileSize, biasHost, biasFileSize);
        aclrtMemcpy(biasDevice, biasFileSize, biasHost, biasFileSize, ACL_MEMCPY_HOST_TO_DEVICE);
    }

    uint8_t* offsetListHost;
    uint8_t* offsetListDevice;
    aclrtMallocHost((void**)(&offsetListHost), offsetListSize);
    aclrtMalloc((void**)&offsetListDevice, offsetListSize, ACL_MEM_MALLOC_HUGE_FIRST);
    ReadFile("./input/offset_gm.bin", offsetListSize, offsetListHost, offsetListSize);
    aclrtMemcpy(offsetListDevice, offsetListSize, offsetListHost, offsetListSize, ACL_MEMCPY_HOST_TO_DEVICE);

    uint8_t* cHost;
    uint8_t* cDevice;
    aclrtMallocHost((void**)(&cHost), cFileSize);
    aclrtMalloc((void**)&cDevice, cFileSize, ACL_MEM_MALLOC_HUGE_FIRST);

    uint8_t* workspaceDevice;
    aclrtMalloc((void**)&workspaceDevice, workspaceSize, ACL_MEM_MALLOC_HUGE_FIRST);

    uint8_t* tilingHost;
    uint8_t* tilingDevice;
    aclrtMallocHost((void**)(&tilingHost), tilingFileSize);
    aclrtMalloc((void**)&tilingDevice, tilingFileSize, ACL_MEM_MALLOC_HUGE_FIRST);
    aclrtMemcpy(tilingHost, tilingFileSize, tilingBuf, tilingFileSize, ACL_MEMCPY_HOST_TO_HOST);
    aclrtMemcpy(tilingDevice, tilingFileSize, tilingHost, tilingFileSize, ACL_MEMCPY_HOST_TO_DEVICE);

    matmul_callback_custom<<<NUM_BLOCKS, nullptr, stream>>>(aDevice, bDevice, biasDevice, cDevice, offsetListDevice,
                                                  workspaceDevice, tilingDevice);
    aclrtSynchronizeStream(stream);

    aclrtMemcpy(cHost, cFileSize, cDevice, cFileSize, ACL_MEMCPY_DEVICE_TO_HOST);
    WriteFile("./output/output.bin", cHost, cFileSize);

    aclrtFree(aDevice);
    aclrtFreeHost(aHost);
    aclrtFree(bDevice);
    aclrtFreeHost(bHost);
    if (IS_BIAS) {
        aclrtFree(biasDevice);
        aclrtFreeHost(biasHost);
    }
    aclrtFree(offsetListDevice);
    aclrtFreeHost(offsetListHost);
    aclrtFree(workspaceDevice);
    aclrtFree(tilingDevice);
    aclrtFreeHost(tilingHost);
    aclrtFree(cDevice);
    aclrtFreeHost(cHost);

    aclrtDestroyStream(stream);
    aclrtDestroyContext(context);
    aclrtResetDevice(deviceId);
    aclFinalize();

    free(tilingBuf);
    return 0;
}

