using namespace AscendC;

struct MatmulCaseParams
{
    int32_t usedCoreNum;
    int32_t m;
    int32_t n;
    int32_t k;
    bool isBias;
    bool isATrans;
    bool isBTrans;
    bool isScaleATrans;
    bool isScaleBTrans;
};

TCubeTiling generateTiling(const MatmulCaseParams& testCaseParams)
{
    TCubeTiling tilingData;
    auto ascendcPlatform = platform_ascendc::PlatformAscendCManager::GetInstance();
    matmul_tiling::MultiCoreMatmulTiling cubeTiling(*ascendcPlatform);

    uint32_t M = testCaseParams.m;
    uint32_t N = testCaseParams.n;
    uint32_t K = testCaseParams.k;
    uint32_t blockDim = testCaseParams.usedCoreNum;
    bool isBias = testCaseParams.isBias;
    bool isAtrans = testCaseParams.isATrans;
    bool isBtrans = testCaseParams.isBTrans;
    bool isScaleATrans = testCaseParams.isScaleATrans;
    bool isScaleBTrans = testCaseParams.isScaleBTrans;

    cubeTiling.SetDim(blockDim);
    cubeTiling.SetAType(matmul_tiling::TPosition::VECOUT, matmul_tiling::CubeFormat::NZ,
        matmul_tiling::DataType::DT_FLOAT4_E1M2, isAtrans);
    cubeTiling.SetBType(matmul_tiling::TPosition::VECOUT, matmul_tiling::CubeFormat::NZ,
        matmul_tiling::DataType::DT_FLOAT4_E1M2, isBtrans);
    cubeTiling.SetCType(matmul_tiling::TPosition::GM, matmul_tiling::CubeFormat::ND,
        matmul_tiling::DataType::DT_FLOAT);
    cubeTiling.SetBiasType(matmul_tiling::TPosition::GM, matmul_tiling::CubeFormat::ND,
        matmul_tiling::DataType::DT_FLOAT);

    cubeTiling.SetScaleAType(matmul_tiling::TPosition::TSCM, matmul_tiling::CubeFormat::NZ, isScaleATrans);
    cubeTiling.SetScaleBType(matmul_tiling::TPosition::TSCM, matmul_tiling::CubeFormat::NZ, isScaleBTrans);

    cubeTiling.SetOrgShape(M, N, K);
    cubeTiling.SetShape(M, N, K);
    cubeTiling.EnableBias(isBias);

    uint64_t l1Size = 0;
    uint64_t ubSize = 0;
    ascendcPlatform->GetCoreMemSize(platform_ascendc::CoreMemType::L1, l1Size);
    ascendcPlatform->GetCoreMemSize(platform_ascendc::CoreMemType::UB, ubSize);
    uint64_t usedUb = static_cast<uint64_t>(M * K + K * N);
    uint64_t usedL1 = static_cast<uint64_t>(M * K / 32 + K * N / 32);

    cubeTiling.SetBufferSpace(l1Size - usedL1, -1, ubSize - usedUb);
    cubeTiling.SetMadType(matmul_tiling::MatrixMadType::MXMODE);

    if (cubeTiling.GetTiling(tilingData) == -1) {
        std::cout << "Generate tiling failed." << std::endl;
        return {};
    }

    return tilingData;
}

template <typename ATYPE, typename BType, typename CType, typename BiasType>
class MatmulKernel
{
public:
    __aicore__ inline MatmulKernel() {};

    __aicore__ inline void init(GM_ADDR a, GM_ADDR b, GM_ADDR as, GM_ADDR bs, GM_ADDR bias, GM_ADDR c, 
        const TCubeTiling& tiling, bool isTransA, bool isTransB, bool isTransScaleA, bool isTransScaleB);

    __aicore__ inline void process(TPipe* pipe);

    using aType = AscendC::MatmulTypeWithScale<AscendC::TPosition::VECOUT, AscendC::TPosition::TSCM, 
        CubeFormat::NZ, fp4x2_e1m2_t, false, AscendC::TPosition::GM, CubeFormat::NZ, false, AscendC::TPosition::GM>;
    using bType = AscendC::MatmulTypeWithScale<AscendC::TPosition::VECOUT, AscendC::TPosition::TSCM, 
        CubeFormat::NZ, fp4x2_e1m2_t, false, AscendC::TPosition::GM, CubeFormat::NZ, true, AscendC::TPosition::GM>;
    using cType = AscendC::MatmulType<AscendC::TPosition::GM, CubeFormat::ND, float>;
    using biasType = AscendC::MatmulType<AscendC::TPosition::GM, CubeFormat::ND, float>;

    AscendC::Matmul<aType, bType, cType, biasType, CFG_MDL, 
        AscendC::MatmulCallBackFunc<nullptr, nullptr, nullptr>, 
        AscendC::Impl::Detail::MatmulWithScalePolicy> matmulObj;

private:
    __aicore__ inline void calcOffset(int32_t blockIdx, int32_t& offsetA, int32_t& offsetB, 
        int32_t& offsetAscale, int32_t& offsetBscale, int32_t& offsetC, int32_t& offsetBias);

    AscendC::GlobalTensor<fp4x2_e1m2_t> aGlobal;
    AscendC::GlobalTensor<fp4x2_e1m2_t> bGlobal;
    AscendC::GlobalTensor<fp8_e8m0_t> asGlobal;
    AscendC::GlobalTensor<fp8_e8m0_t> bsGlobal;
    AscendC::GlobalTensor<float> cGlobal;
    AscendC::GlobalTensor<float> biasGlobal;
    TCubeTiling tiling;
    int32_t mCoreIndex;
    int32_t nCoreIndex;
    bool isTransA{false};
    bool isTransB{false};
    bool isTransScaleA{false};
    bool isTransScaleB{true};
};

__aicore__ inline void copyTiling(TCubeTiling* tiling, GM_ADDR tilingGm)
{
    uint32_t* ptr = reinterpret_cast<uint32_t*>(tiling);
    auto tiling32 = reinterpret_cast<__gm__ uint32_t*>(tilingGm);

    for (int i = 0; i < sizeof(TCubeTiling) / sizeof(uint32_t); i++, ptr++) {
        *ptr = *(tiling32 + i);
    }

    return;
}

constexpr int SCALE_CEIL_NUMBER = 64;
constexpr int SCALE_NUMBER = 2;

template <typename AType, typename BType, typename CType, typename BiasType>
__aicore__ inline void MatmulKernel<AType, BType, CType, BiasType>::init(GM_ADDR a, GM_ADDR b, 
    GM_ADDR as, GM_ADDR bs, GM_ADDR bias, GM_ADDR c, const TCubeTiling& tiling, 
    bool isTransA, bool isTransB, bool isTransScaleA, bool isTransScaleB)
{
    this->tiling = tiling;
    this->isTransA = isTransA;
    this->isTransB = isTransB;
    this->isTransScaleA = isTransScaleA;
    this->isTransScaleB = isTransScaleB;

    int sK = (tiling.Ka + SCALE_CEIL_NUMBER - 1) / SCALE_CEIL_NUMBER * SCALE_NUMBER;
    aGlobal.SetGlobalBuffer(reinterpret_cast<__gm__ fp4x2_e1m2_t*>(a), tiling.M * tiling.Ka);
    bGlobal.SetGlobalBuffer(reinterpret_cast<__gm__ fp4x2_e1m2_t*>(b), tiling.Kb * tiling.N);
    cGlobal.SetGlobalBuffer(reinterpret_cast<__gm__ CType*>(c), tiling.M * tiling.N);
    biasGlobal.SetGlobalBuffer(reinterpret_cast<__gm__ BiasType*>(bias), tiling.N);
    asGlobal.SetGlobalBuffer(reinterpret_cast<__gm__ fp8_e8m0_t*>(as), tiling.M * sK);
    bsGlobal.SetGlobalBuffer(reinterpret_cast<__gm__ fp8_e8m0_t*>(bs), sK * tiling.N);

    int32_t offsetA = 0;
    int32_t offsetB = 0;
    int32_t offsetAscale = 0;
    int32_t offsetBscale = 0;
    int32_t offsetC = 0;
    int32_t offsetBias = 0;

    calcOffset(AscendC::GetBlockIdx() / 2, offsetA, offsetB, offsetAscale, offsetBscale, offsetC, offsetBias);

    aGlobal = aGlobal[offsetA];
    bGlobal = bGlobal[offsetB];
    cGlobal = cGlobal[offsetC];
    asGlobal = asGlobal[offsetAscale];
    bsGlobal = bsGlobal[offsetBscale];
    biasGlobal = biasGlobal[offsetBias];

    if (GetSysWorkSpacePtr() == nullptr) {
        return;
    }
}

template <typename AType, typename BType, typename CType, typename BiasType>
__aicore__ inline void MatmulKernel<AType, BType, CType, BiasType>::process(TPipe* pipe)
{
    TQue<TPosition::VECOUT, 1> leftMatrixQue;
    TQue<TPosition::VECOUT, 1> rightMatrixQue;
    TSCM<TPosition::GM, 1, 0x04> qidMxA1;
    TSCM<TPosition::GM, 1, 0x04> qidMxB1;
    LocalTensor<fp4x2_e1m2_t> bufferLeft;
    LocalTensor<fp4x2_e1m2_t> bufferRight;
    LocalTensor<fp8_e8m0_t> bufferLeftScale;
    LocalTensor<fp8_e8m0_t> bufferRightScale;

    int alignSingleCoreM = Ceil(tiling.singleCoreM + BLOCK_CUBE - 1, BLOCK_CUBE) * BLOCK_CUBE;
    int alignSingleCoreN = Ceil(tiling.singleCoreN + BLOCK_CUBE - 1, BLOCK_CUBE) * BLOCK_CUBE;
    int alignSingleCoreK = Ceil(tiling.singleCoreK + SCALE_CEIL_NUMBER - 1, SCALE_CEIL_NUMBER) * SCALE_CEIL_NUMBER;

    pipe->InitBuffer(leftMatrixQue, 1, tiling.singleCoreM * tiling.singleCoreK);
    bufferLeft = leftMatrixQue.AllocTensor<fp4x2_e1m2_t>();
    DataCopy(bufferLeft, aGlobal, tiling.singleCoreM * tiling.singleCoreK);
    PipeBarrier<PIPE_ALL>();
    matmulObj.SetTensorA(bufferLeft, isTransA);

    pipe->InitBuffer(rightMatrixQue, 1, tiling.singleCoreK * tiling.singleCoreN);
    bufferRight = rightMatrixQue.AllocTensor<fp4x2_e1m2_t>();
    DataCopy(bufferRight, bGlobal, tiling.singleCoreK * tiling.singleCoreN);
    PipeBarrier<PIPE_ALL>();
    matmulObj.SetTensorB(bufferRight, isTransB);

    pipe->InitBuffer(qidMxA1, 1, alignSingleCoreM * alignSingleCoreK / 32);
    bufferLeftScale = qidMxA1.AllocTensor<fp8_e8m0_t>();
    DataCopy(bufferLeftScale, asGlobal, tiling.singleCoreM * tiling.singleCoreK / 32);
    PipeBarrier<PIPE_ALL>();
    matmulObj.SetTensorScaleA(bufferLeftScale, isTransScaleA);

    pipe->InitBuffer(qidMxB1, 1, alignSingleCoreN * alignSingleCoreK / 32);
    bufferRightScale = qidMxB1.AllocTensor<fp8_e8m0_t>();
    DataCopy(bufferRightScale, bsGlobal, tiling.singleCoreK * tiling.singleCoreN / 32);
    PipeBarrier<PIPE_ALL>();
    matmulObj.SetTensorScaleB(bufferRightScale, isTransScaleB);

    if (tiling.isBias) {
        matmulObj.SetBias(biasGlobal);
    }

    matmulObj.IterateAll(cGlobal);
    PipeBarrier<PIPE_ALL>();

    leftMatrixQue.FreeTensor(bufferLeft);
    rightMatrixQue.FreeTensor(bufferRight);
    qidMxA1.FreeTensor(bufferLeftScale);
    qidMxB1.FreeTensor(bufferRightScale);

    matmulObj.End();
}

template <typename AType, typename BType, typename CType, typename BiasType>
__aicore__ inline void MatmulKernel<AType, BType, CType, BiasType>::calcOffset(
    int32_t blockIdx, int32_t& offsetA, int32_t& offsetB, int32_t& offsetAscale, 
    int32_t& offsetBscale, int32_t& offsetC, int32_t& offsetBias)
{
    const TCubeTiling& tiling = this->tiling;
    int usedCoreNum = tiling.usedCoreNum;

    auto temp0 = Ceil(tiling.M, tiling.singleCoreM);
    auto temp1 = Ceil(tiling.N, tiling.singleCoreN);
    auto temp2 = Ceil(tiling.Ka, tiling.singleCoreK);
    int singleCoreMxK = (tiling.singleCoreK + SCALE_CEIL_NUMBER - 1) / SCALE_CEIL_NUMBER * SCALE_NUMBER;
    int mxK = (tiling.Ka + SCALE_CEIL_NUMBER - 1) / SCALE_CEIL_NUMBER * SCALE_NUMBER;

    auto divideKcoreNum = usedCoreNum / temp2;
    auto mCoreIndex = (blockIdx % divideKcoreNum) % temp0;
    auto nCoreIndex = (blockIdx % divideKcoreNum) / temp0;
    auto subKindex = blockIdx / divideKcoreNum;

    static constexpr int32_t C0_SIZE_B8 = 32;
    static constexpr int32_t BLOCK_CUBE = 16;

    if (isTransA) {
        offsetA = subKindex * tiling.singleCoreK * C0_SIZE_B8 + mCoreIndex * tiling.singleCoreM * tiling.Ka;
    } else {
        offsetA = subKindex * tiling.singleCoreK * tiling.M + mCoreIndex * tiling.singleCoreM * C0_SIZE_B8;
    }

    offsetAscale = subKindex * BLOCK_CUBE * singleCoreMxK + mCoreIndex * tiling.singleCoreM * singleCoreMxK;

    if (isTransB) {
        offsetB = nCoreIndex * tiling.singleCoreN * C0_SIZE_B8 + subKindex * tiling.singleCoreK * tiling.N;
    } else {
        offsetB = tiling.Kb * nCoreIndex * tiling.singleCoreN + subKindex * tiling.singleCoreK * C0_SIZE_B8;
    }

    offsetBscale = singleCoreMxK * nCoreIndex * tiling.singleCoreN + subKindex * singleCoreMxK * BLOCK_CUBE;
    offsetC = mCoreIndex * tiling.N * tiling.singleCoreM + nCoreIndex * tiling.singleCoreN;
    offsetBias = nCoreIndex * tiling.singleCoreN;
}

__mix__(1, 2) __global__ void matmulMxUbTscmNzCustom(
    GM_ADDR a, GM_ADDR b, GM_ADDR as, GM_ADDR bs, GM_ADDR bias, GM_ADDR c, __kfc_workspace__ GM_ADDR workspace, GM_ADDR tilingGm)
{
    TCubeTiling tiling;
    copyTiling(&tiling, tilingGm);

    MatmulKernel<fp4x2_e1m2_t, fp4x2_e1m2_t, float, float> matmulKernel;
    TPipe pipe;

    REGIST_MATMUL_OBJ(&pipe, GetSysWorkSpacePtr(), matmulKernel.matmulObj, &tiling);

    matmulKernel.init(a, b, as, bs, bias, c, tiling, false, false, false, true);
    matmulKernel.process(&pipe);
}

void matmulMxUbTscmNzCustomDo(uint32_t blockDim, void* stream,
    uint8_t* a, uint8_t* b, uint8_t* as, uint8_t* bs, uint8_t* bias, uint8_t* c, 
    uint8_t* workspace, uint8_t* tilingGm)
{
    matmulMxUbTscmNzCustom<<<blockDim, nullptr, stream>>>(a, b, as, bs, bias, c, workspace, tilingGm);
}

constexpr bool IS_BIAS = false;
constexpr bool IS_A_TRANS = false;
constexpr bool IS_B_TRANS = false;
constexpr bool IS_SCALEA_TRANS = false;
constexpr bool IS_SCALEB_TRANS = true;

struct MatrixFileSize
{
    size_t x1FileSize;
    size_t x2FileSize;
    size_t xs1FileSize;
    size_t xs2FileSize;
    size_t yFileSize;
    size_t biasFileSize;
};

static size_t getSysWorkSpaceSize()
{
    auto ascendcPlatform = platform_ascendc::PlatformAscendCManager::GetInstance();

    if (ascendcPlatform == nullptr) {
        return 0;
    }

    return static_cast<size_t>(ascendcPlatform->GetLibApiWorkSpaceSize());
}

void matmulOp(uint8_t* x1, uint8_t* x2, uint8_t* xs1, uint8_t* xs2, uint8_t* y, uint8_t* bias, 
    int64_t m, int64_t n, int64_t k, void* stream = nullptr)
{
    uint8_t* workspaceDevice;
    size_t workspaceSize = getSysWorkSpaceSize();
    aclrtMalloc((void **)&workspaceDevice, workspaceSize, ACL_MEM_MALLOC_HUGE_FIRST);

    uint8_t* tilingHost;
    uint8_t* tilingDevice;
    size_t tilingFileSize = sizeof(TCubeTiling);

    auto ascendcPlatform = platform_ascendc::PlatformAscendCManager::GetInstance();
    MatmulCaseParams testCaseParams{static_cast<int32_t>(ascendcPlatform->GetCoreNumAic()),
        static_cast<int32_t>(m), static_cast<int32_t>(n), static_cast<int32_t>(k), 
        IS_BIAS, IS_A_TRANS, IS_B_TRANS, IS_SCALEA_TRANS, IS_SCALEB_TRANS};

    const auto tilingData = generateTiling(testCaseParams);

    aclrtMallocHost((void **)(&tilingHost), tilingFileSize);
    aclrtMalloc((void **)&tilingDevice, tilingFileSize, ACL_MEM_MALLOC_HUGE_FIRST);

    aclrtMemcpy(tilingHost, tilingFileSize, &tilingData, tilingFileSize, ACL_MEMCPY_HOST_TO_HOST);
    aclrtMemcpy(tilingDevice, tilingFileSize, tilingHost, tilingFileSize, ACL_MEMCPY_HOST_TO_DEVICE);

    matmulMxUbTscmNzCustomDo(tilingData.usedCoreNum, stream, x1, x2, xs1, xs2, bias, y, 
        workspaceDevice, tilingDevice);

    aclrtFreeHost(tilingHost);
    aclrtFree(workspaceDevice);
    aclrtFree(tilingDevice);
}

void testAclInit(aclrtContext& context, aclrtStream& stream, int64_t& deviceId)
{
    aclInit(nullptr);
    aclrtSetDevice(deviceId);
    aclrtCreateContext(&context, deviceId);
    aclrtCreateStream(&stream);
}

void testAclDeInit(aclrtContext& context, aclrtStream& stream, int64_t& deviceId)
{
    aclrtDestroyStream(stream);
    aclrtDestroyContext(context);
    aclrtResetDevice(deviceId);
    aclFinalize();
}

void testMatmul(int64_t m, int64_t n, int64_t k, const MatrixFileSize& matrixFileSize)
{
    size_t x1FileSize = matrixFileSize.x1FileSize;
