    matmulOp(x1Device, x2Device, xs1Device, xs2Device, yDevice, biasDevice, m, n, k, stream);
    aclrtSynchronizeStream(stream);

    aclrtMemcpy(yHost, yFileSize, yDevice, yFileSize, ACL_MEMCPY_DEVICE_TO_HOST);
