template <typename T, bool isBasicBlock = false, bool isDataFormatNZ = false>
class KernelLogSoftMax {
public:
    __aicore__ inline KernelLogSoftMax() {}
    __aicore__ inline void Init(GM_ADDR srcGm, GM_ADDR dstGm, GM_ADDR shapeInfo, AscendC::TPipe* pipeIn)
    {
        pipe = pipeIn;
        elementNumPerBlk = 32 / sizeof(T);
        AscendC::GlobalTensor<uint32_t> shapeInfoGlobal;
        shapeInfoGlobal.SetGlobalBuffer(reinterpret_cast<__gm__ uint32_t*>(shapeInfo), 8);
        srcGlobal.SetGlobalBuffer(reinterpret_cast<__gm__ T*>(srcGm));
        dstGlobal.SetGlobalBuffer(reinterpret_cast<__gm__ T*>(dstGm));
        pipe->InitBuffer(inQueueX, 1, height * width * sizeof(T));
        pipe->InitBuffer(maxQueue, 1, height * elementNumPerBlk * sizeof(T));
        pipe->InitBuffer(sumQueue, 1, height * elementNumPerBlk * sizeof(T));
        pipe->InitBuffer(outQueue, 1, height * width * sizeof(T));
    }
    __aicore__ inline void Process()
    {
        CopyIn();
        Compute();
        CopyOut();
    }

    __aicore__ inline void CopyIn()
    {
        AscendC::LocalTensor<T> srcLocal = inQueueX.AllocTensor<T>();
        AscendC::DataCopy(srcLocal, srcGlobal, height * width);
        inQueueX.EnQue(srcLocal);
    }
    __aicore__ inline void Compute()
    {
        AscendC::LocalTensor<T> srcLocal = inQueueX.DeQue<T>();
        AscendC::LocalTensor<T> sumTempLocal = sumQueue.AllocTensor<T>();
        AscendC::LocalTensor<T> maxTempLocal = maxQueue.AllocTensor<T>();
        AscendC::LocalTensor<T> dstLocal = outQueue.AllocTensor<T>();

        const uint32_t shapeDim = 2;
        AscendC::DataFormat dataFormat{AscendC::DataFormat::ND};
        if (isDataFormatNZ) {
            dataFormat = AscendC::DataFormat::NZ;
        }
        AscendC::SoftMaxShapeInfo srcShape = {height, width, height, width};
        LogSoftMaxTiling tiling;
        AscendC::LocalTensor<uint8_t> sharedTmpBuffer;
        AscendC::PopStackBuffer<uint8_t, AscendC::TPosition::LCM>(sharedTmpBuffer);
        AscendC::LogSoftMax<T, false, isDataFormatNZ>(dstLocal, sumTempLocal, maxTempLocal, srcLocal, sharedTmpBuffer,
                                                      tiling, srcShape);
        outQueue.EnQue<T>(dstLocal);
        sumQueue.FreeTensor(sumTempLocal);
        maxQueue.FreeTensor(maxTempLocal);
        inQueueX.FreeTensor(srcLocal);
    }
    __aicore__ inline void CopyOut()
    {
        AscendC::LocalTensor<T> dstLocal = outQueue.DeQue<T>();
        AscendC::DataCopy(dstGlobal, dstLocal, height * width);
        outQueue.FreeTensor(dstLocal);
    }

private:
    AscendC::TPipe* pipe;
    AscendC::TQue<AscendC::QuePosition::VECIN, 1> inQueueX;
    AscendC::TQue<AscendC::QuePosition::VECOUT, 1> outQueue;
    AscendC::TQue<AscendC::QuePosition::VECIN, 1> sumQueue;
    AscendC::TQue<AscendC::QuePosition::VECIN, 1> maxQueue;
    AscendC::GlobalTensor<T> srcGlobal;
    AscendC::GlobalTensor<T> dstGlobal;
    uint32_t elementNumPerBlk = 0;
    uint32_t height = 128;
