template <typename T, int32_t apiMode>
class KernelSigmoid {
public:
    __aicore__ inline KernelSigmoid() {}
    __aicore__ inline void Init(GM_ADDR srcGm, GM_ADDR dstGm, uint32_t srcSize, uint32_t calCount,
                                AscendC::TPipe* pipeIn)
    {
        pipe = pipeIn;
        srcGlobal.SetGlobalBuffer(reinterpret_cast<__gm__ T*>(srcGm));
        dstGlobal.SetGlobalBuffer(reinterpret_cast<__gm__ T*>(dstGm));

        bufferSize = srcSize;
        count = calCount;
        alignDataSize = AscendC::DivCeil(srcSize * sizeof(T), 32) * 32;   
        alignDataNum = alignDataSize / sizeof(T);

        pipe->InitBuffer(inQueueX, 1, alignDataSize);
        pipe->InitBuffer(inQueueX2, 1, alignDataNum * sizeof(uint8_t));
        pipe->InitBuffer(outQueue, 1, alignDataSize);
    }
    __aicore__ inline void Process()
    {
        AscendC::AscendCUtils::SetOverflow(1);
        CopyIn();
        Compute();
        CopyOut();
        AscendC::AscendCUtils::SetOverflow(0);
    }

private:
    __aicore__ inline void CopyIn()
    {
        AscendC::LocalTensor<T> srcLocal = inQueueX.AllocTensor<T>();
        AscendC::LocalTensor<uint8_t> src1Local = inQueueX2.AllocTensor<uint8_t>();
        AscendC::DataCopy(srcLocal, srcGlobal, alignDataNum);
        inQueueX.EnQue(srcLocal);
        inQueueX2.EnQue(src1Local);
    }
    __aicore__ inline void Compute()
    {
        AscendC::LocalTensor<T> dstLocal = outQueue.AllocTensor<T>();
        AscendC::LocalTensor<T> srcLocal = inQueueX.DeQue<T>();
        AscendC::LocalTensor<uint8_t> tmpBuf = inQueueX2.DeQue<uint8_t>();
        T zero = 0;
        AscendC::Duplicate(dstLocal, zero, alignDataNum);

        if constexpr (apiMode == 0) {
            AscendC::Sigmoid<T, false>(dstLocal, srcLocal);
        } else if constexpr (apiMode == 1) {
            AscendC::Sigmoid<T, false>(dstLocal, srcLocal, count);
        } else if constexpr (apiMode == 2) {
            AscendC::Sigmoid<T, false>(dstLocal, srcLocal, tmpBuf, count);
        } else {
            AscendC::Sigmoid<T, false>(dstLocal, srcLocal, tmpBuf);
        }

        outQueue.EnQue<T>(dstLocal);
        inQueueX.FreeTensor(srcLocal);
        inQueueX2.FreeTensor(tmpBuf);
    }
    __aicore__ inline void CopyOut()
    {
        AscendC::LocalTensor<T> dstLocal = outQueue.DeQue<T>();
        AscendC::DataCopy(dstGlobal, dstLocal, alignDataNum);
        outQueue.FreeTensor(dstLocal);
    }

private:
    AscendC::GlobalTensor<T> srcGlobal;
    AscendC::GlobalTensor<T> dstGlobal;

    AscendC::TPipe* pipe;
    AscendC::TQue<AscendC::QuePosition::VECIN, 1> inQueueX;
    AscendC::TQue<AscendC::QuePosition::VECIN, 1> inQueueX2;
    AscendC::TQue<AscendC::QuePosition::VECOUT, 1> outQueue;
    uint32_t bufferSize = 0;
    uint32_t alignDataSize = 0;
    uint32_t alignDataNum = 0;
    uint32_t count = 0;
}

