template <typename T>
class KernelSwiGLU {
public:
    __aicore__ inline KernelSwiGLU() {}
    __aicore__ inline void Init(GM_ADDR src0Gm, GM_ADDR src1Gm, GM_ADDR dstGm, uint32_t srcSize, T beta,
                                uint32_t tmpBufSizeIn, uint32_t calCountIn, AscendC::TPipe* pipeIn)
    {
        pipe = pipeIn;
        betaValue = beta;
        dataSize = srcSize;

        src0Global.SetGlobalBuffer(reinterpret_cast<__gm__ T*>(src0Gm), dataSize);
        src1Global.SetGlobalBuffer(reinterpret_cast<__gm__ T*>(src1Gm), dataSize);
        dstGlobal.SetGlobalBuffer(reinterpret_cast<__gm__ T*>(dstGm), dataSize);
        pipe->InitBuffer(inQueue0, 1, dataSize * sizeof(T));
        pipe->InitBuffer(inQueue1, 1, dataSize * sizeof(T));
        pipe->InitBuffer(outQueue, 1, dataSize * sizeof(T));
        tmpBufSize = tmpBufSizeIn;
        if (tmpBufSize) {
            pipe->InitBuffer(bufQueue, (tmpBufSizeIn + 31) / 32 * 32);
        }
        calCount = calCountIn;
    }
    __aicore__ inline void Process()
    {
        CopyIn();
        Compute();
        CopyOut();
    }

    __aicore__ inline void CopyIn()
    {
        AscendC::LocalTensor<T> src0Local = inQueue0.AllocTensor<T>();
        AscendC::LocalTensor<T> src1Local = inQueue1.AllocTensor<T>();
        AscendC::DataCopy(src0Local, src0Global, dataSize);
        AscendC::DataCopy(src1Local, src1Global, dataSize);
        inQueue0.EnQue(src0Local);
        inQueue1.EnQue(src1Local);
    }
    __aicore__ inline void Compute()
    {
        AscendC::LocalTensor<T> dstLocal = outQueue.AllocTensor<T>();
        AscendC::LocalTensor<T> src0Local = inQueue0.DeQue<T>();
        AscendC::LocalTensor<T> src1Local = inQueue1.DeQue<T>();
        AscendC::LocalTensor<uint8_t> tmpLocal;
        if (tmpBufSize > 0) {
            tmpLocal = bufQueue.Get<uint8_t>();
        }
        if ((tmpBufSize > 0) && (calCount > 0)) {
            AscendC::SwiGLU(dstLocal, src0Local, src1Local, betaValue, tmpLocal, calCount);
        } else if (tmpBufSize > 0) {
            AscendC::SwiGLU(dstLocal, src0Local, src1Local, betaValue, tmpLocal);
        } else if (calCount > 0) {
            AscendC::SwiGLU(dstLocal, src0Local, src1Local, betaValue, calCount);
        } else {
            AscendC::SwiGLU(dstLocal, src0Local, src1Local, betaValue);
        }
        outQueue.EnQue<T>(dstLocal);
        inQueue0.FreeTensor(src0Local);
        inQueue1.FreeTensor(src1Local);
    }
    __aicore__ inline void CopyOut()
    {
        AscendC::LocalTensor<T> dstLocal = outQueue.DeQue<T>();
        AscendC::DataCopy(dstGlobal, dstLocal, dataSize);
        outQueue.FreeTensor(dstLocal);
    }

private:
    AscendC::TPipe* pipe;
    AscendC::TQue<AscendC::QuePosition::VECIN, 1> inQueue0;
    AscendC::TQue<AscendC::QuePosition::VECIN, 1> inQueue1;
    AscendC::TQue<AscendC::QuePosition::VECOUT, 1> outQueue;
    AscendC::TBuf<AscendC::TPosition::VECCALC> bufQueue;
    AscendC::GlobalTensor<T> src0Global;
    AscendC::GlobalTensor<T> src1Global;
    AscendC::GlobalTensor<T> dstGlobal;
    uint32_t dataSize = 0;
    T betaValue = 0;
    uint32_t tmpBufSize = 0;
    uint32_t calCount = 0;
}

