    __aicore__ inline void Init(GM_ADDR inputX_gm, GM_ADDR inputmean_gm, GM_ADDR inputvar_gm, GM_ADDR outputMean_gm,
                                GM_ADDR outputVariance_gm, uint32_t rnLength, uint32_t abLength, uint32_t rLength,
                                uint32_t head, uint32_t headLength, uint32_t tail, uint32_t tailLength,
                                AscendC::TPipe* pipeIn)
    {
        pipe = pipeIn;
