        bshLength = rnLength * abLength;
        this->rLength = rLength;
        this->abRec = 1.0f / abLength;
        this->rRec = 1.0f / rLength;
        this->outLength = AscendC::CeilDivision(rnLength, 8) * 8;

        inputX_global.SetGlobalBuffer(reinterpret_cast<__gm__ T*>(inputX_gm), bshLength);
        inputmean_global.SetGlobalBuffer(reinterpret_cast<__gm__ float*>(inputmean_gm), bshLength);
