        outputMean_global.SetGlobalBuffer(reinterpret_cast<__gm__ float*>(outputMean_gm), bshLength);
        outputVariance_global.SetGlobalBuffer(reinterpret_cast<__gm__ float*>(outputVariance_gm), bshLength);

        pipe->InitBuffer(inQueueX, 1, bshLength * sizeof(T));
