        pipe->InitBuffer(inQueueVar, 1, sizeof(float) * bshLength);

        pipe->InitBuffer(outQueueMean, 1, outLength * sizeof(float));
        pipe->InitBuffer(outQueueVariance, 1, outLength * sizeof(float));
    }
    __aicore__ inline void Process()
    {
        CopyIn();
        Compute();
        CopyOut();
    }

private:
    __aicore__ inline void CopyIn()
    {
        AscendC::LocalTensor<T> inputXLocal = inQueueX.AllocTensor<T>();
