                                                            GM_ADDR tiling)
{
    AscendC::TPipe pipe;
    MyCustomKernel::KernelWelfordUpdate<half, float> op;
    MyCustomKernel::VecTiling tilingData;
    CopyTiling(&tilingData, tiling);
    op.Init(srcGm, inMeanGm, inVarGm, outMeanGm, outVarGm, tilingData, &pipe);
    op.Process();
}

