    uint32_t elementCountOfInput;
    uint32_t elementCountOfOffset;
    uint32_t mK;
    uint32_t sharedTmpBufferSize;
}

template <typename T, typename U>
class KernelAntiQuant {
public:
    __aicore__ inline KernelAntiQuant() {}
    __aicore__ inline void Init(GM_ADDR dstGm, GM_ADDR srcGm, GM_ADDR offsetGm, GM_ADDR scaleGm,
                                uint32_t elementCountOfInputIn, uint32_t elementCountOfOffsetIn, uint32_t K,
                                uint32_t sharedTmpBufferSizeIn, AscendC::TPipe* pipeIn)
    {
        pipe = pipeIn;
        elementCountOfInput = elementCountOfInputIn;
        elementCountOfOffset = elementCountOfOffsetIn;
        mK = K;
        sharedTmpBufferSize = sharedTmpBufferSizeIn;

        dstGlobal.SetGlobalBuffer((__gm__ T*)dstGm);
        srcGlobal.SetGlobalBuffer((__gm__ U*)srcGm);
        offsetGlobal.SetGlobalBuffer((__gm__ T*)offsetGm);
        scaleGlobal.SetGlobalBuffer((__gm__ T*)scaleGm);

        pipe->InitBuffer(inQueueSrc, 1, elementCountOfInputIn * sizeof(U));
        pipe->InitBuffer(inQueueOffset, 1, elementCountOfOffsetIn * sizeof(T));
        pipe->InitBuffer(inQueueScale, 1, elementCountOfOffsetIn * sizeof(T));
        pipe->InitBuffer(outQueue, 1, elementCountOfInputIn * sizeof(T));
        pipe->InitBuffer(tmpQueue, 1, sharedTmpBufferSize);
    }
    __aicore__ inline void Process()
    {
        CopyIn();
        Compute();
        CopyOut();
    }

private:
    __aicore__ inline void CopyIn()
    {
        AscendC::LocalTensor<U> srcLocal = inQueueSrc.AllocTensor<U>();
        AscendC::DataCopy(srcLocal, srcGlobal, elementCountOfInput);
        inQueueSrc.EnQue(srcLocal);

        AscendC::LocalTensor<T> offsetLocal = inQueueOffset.AllocTensor<T>();
        AscendC::DataCopy(offsetLocal, offsetGlobal, elementCountOfOffset);
        inQueueOffset.EnQue(offsetLocal);

        AscendC::LocalTensor<T> scaleLocal = inQueueScale.AllocTensor<T>();
        AscendC::DataCopy(scaleLocal, scaleGlobal, elementCountOfOffset);
        inQueueScale.EnQue(scaleLocal);
    }
    __aicore__ inline void Compute()
    {
        AscendC::LocalTensor<U> srcLocal = inQueueSrc.DeQue<U>();
        AscendC::LocalTensor<T> offsetLocal = inQueueOffset.DeQue<T>();
        AscendC::LocalTensor<T> scaleLocal = inQueueScale.DeQue<T>();
        AscendC::LocalTensor<T> dstLocal = outQueue.AllocTensor<T>();
        AscendC::LocalTensor<uint8_t> sharedTmpBuffer = tmpQueue.AllocTensor<uint8_t>();

#if defined(__NPU_ARCH__) && (__NPU_ARCH__ == 2201)

        uint32_t offsetShape[] = {static_cast<uint32_t>(1), static_cast<uint32_t>(elementCountOfOffset)};
        offsetLocal.SetShapeInfo(AscendC::ShapeInfo(2, offsetShape, AscendC::DataFormat::ND));
        // AscendAntiQuant接口：实现伪量化计算，将量化数据还原为浮点数据（用于A2A3）
        // 模板参数：U=输入数据类型(int8_t), T=输出数据类型(half), false=不使能输入转置
        // 参数说明：
        //   dstLocal: 输出Tensor，类型为half，shape为[8, 128]
        //   srcLocal: 输入Tensor，类型为int8_t，shape为[8, 128]
        //   offsetLocal: 偏移量Tensor，类型为half，shape为[1, 128]
        //   scaleLocal: 缩放因子Tensor，类型为half，shape为[1, 128]
        //   sharedTmpBuffer: 临时缓冲区，用于内部计算
        //   mK: K轴大小，值为8，用于PER_CHANNEL场景的分组计算
        AscendC::AscendAntiQuant<U, T, false>(dstLocal, srcLocal, offsetLocal, scaleLocal, sharedTmpBuffer, mK);

#elif defined(__NPU_ARCH__) && (__NPU_ARCH__ == 3510)
        constexpr static AscendC::AntiQuantizePolicy policy = AscendC::AntiQuantizePolicy::PER_CHANNEL;
        constexpr static bool hasOffset = true;
        constexpr static AscendC::AntiQuantizeConfig config = {policy, hasOffset, -1};
        AscendC::AntiQuantizeParams params;
        params.m = 8;
        params.n = 128;
        params.groupSize = 0;
        // AntiQuantize接口：实现伪量化计算，将量化数据还原为浮点数据（950系列推荐接口）
        // 模板参数config：配置结构体，包含policy=PER_CHANNEL（按通道量化）、hasOffset=true（使用偏移量）、groupSize=-1（自动计算）
        // 参数说明：
        //   dstLocal: 输出Tensor，类型为half，shape为[8, 128]
        //   srcLocal: 输入Tensor，类型为int8_t，shape为[8, 128]
        //   scaleLocal: 缩放因子Tensor，类型为half，shape为[1, 128]
        //   offsetLocal: 偏移量Tensor，类型为half，shape为[1, 128]
        //   sharedTmpBuffer: 临时缓冲区，用于内部计算
        //   params: 参数结构体，包含m=8（M轴大小）、n=128（N轴大小）、groupSize=0（自动计算分组大小）
        AscendC::AntiQuantize<config>(dstLocal, srcLocal, scaleLocal, offsetLocal, sharedTmpBuffer, params);
#endif

        inQueueSrc.FreeTensor(srcLocal);
        inQueueOffset.FreeTensor(offsetLocal);
        inQueueScale.FreeTensor(scaleLocal);
        tmpQueue.FreeTensor(sharedTmpBuffer);
        outQueue.EnQue(dstLocal);
    }

    __aicore__ inline void CopyOut()
    {
        AscendC::LocalTensor<T> dstLocal = outQueue.DeQue<T>();
        AscendC::DataCopy(dstGlobal, dstLocal, elementCountOfInput);
        outQueue.FreeTensor(dstLocal);
    }

private:
    AscendC::TPipe* pipe;
    AscendC::TQue<AscendC::QuePosition::VECIN, 1> inQueueSrc;
    AscendC::TQue<AscendC::QuePosition::VECIN, 1> inQueueOffset;
    AscendC::TQue<AscendC::QuePosition::VECIN, 1> inQueueScale;
    AscendC::TQue<AscendC::QuePosition::VECOUT, 1> tmpQueue;
    AscendC::TQue<AscendC::QuePosition::VECOUT, 1> outQueue;

    AscendC::GlobalTensor<T> dstGlobal;
    AscendC::GlobalTensor<U> srcGlobal;
    AscendC::GlobalTensor<T> offsetGlobal;
    AscendC::GlobalTensor<T> scaleGlobal;

    uint32_t elementCountOfInput;
    uint32_t elementCountOfOffset;
    uint32_t mK;
    uint32_t sharedTmpBufferSize;
}

