template <typename srcType>
class KernelQuant {
public:
    __aicore__ inline KernelQuant() {}
    __aicore__ inline void Init(GM_ADDR srcGm, GM_ADDR dstGm, uint32_t inputSize, AscendC::TPipe* pipeIn)
    {
        pipe = pipeIn;
        dataSize = inputSize;

        srcGlobal.SetGlobalBuffer(reinterpret_cast<__gm__ srcType*>(srcGm), dataSize);
        dstGlobal.SetGlobalBuffer(reinterpret_cast<__gm__ int8_t*>(dstGm), dataSize);

        pipe->InitBuffer(inQueueX, 1, dataSize * sizeof(srcType));
        pipe->InitBuffer(outQueue, 1, dataSize * sizeof(int8_t));
    }
    __aicore__ inline void Process()
    {
        CopyIn();
        Compute();
        CopyOut();
    }

private:
    __aicore__ inline void CopyIn()
    {
        AscendC::LocalTensor<srcType> srcLocal = inQueueX.AllocTensor<srcType>();
        AscendC::DataCopy(srcLocal, srcGlobal, dataSize);
        inQueueX.EnQue(srcLocal);
    }
    __aicore__ inline void Compute()
    {
        const float scale = 2.0f;
        const float offset = 0.9f;
        AscendC::LocalTensor<int8_t> dstLocal = outQueue.AllocTensor<int8_t>();
        AscendC::LocalTensor<srcType> srcLocal = inQueueX.DeQue<srcType>();

#if defined(__NPU_ARCH__) && (__NPU_ARCH__ == 3510)
        AscendC::QuantizeConfig quantizeConfig;
        quantizeConfig.policy = AscendC::QuantizePolicy::PER_TENSOR;
        quantizeConfig.hasOffset = true;
        quantizeConfig.roundMode = AscendC::RoundMode::CAST_RINT;
        quantizeConfig.groupSize = 1;

        AscendC::QuantizeParams params;
        params.m = 1;
        params.n = dataSize;
        params.groupSize = 0;

        // Quantize接口：实现量化计算，将高精度数据转换为低精度量化数据（950系列推荐接口）
        // 模板参数quantizeConfig：配置结构体，包含policy=PER_TENSOR（按张量量化）、hasOffset=true（使用偏移量）、roundMode=CAST_RINT（四舍五入）、groupSize=1（分组大小为1）
        // 参数说明：
        //   dstLocal: 输出Tensor，类型为int8_t，shape为[1024]
        //   srcLocal: 输入Tensor，类型为float，shape为[1024]
        //   scale: 缩放因子，值为2.0
        //   offset: 偏移量，值为0.9
        //   params: 参数结构体，包含m=1（M轴大小）、n=1024（N轴大小）、groupSize=0（自动计算分组大小）
        AscendC::Quantize<quantizeConfig>(dstLocal, srcLocal, scale, offset, params);

#elif defined(__NPU_ARCH__) && (__NPU_ARCH__ == 2201)

        // AscendQuant接口：实现量化计算，将高精度数据转换为低精度量化数据（用于A2A3）
        // 模板参数srcType：输入数据类型，为float
        // 参数说明：
        //   dstLocal: 输出Tensor，类型为int8_t，shape为[1024]
        //   srcLocal: 输入Tensor，类型为float，shape为[1024]
        //   scale: 缩放因子，值为2.0
        //   offset: 偏移量，值为0.9
        //   dataSize: 数据元素个数，值为1024
        AscendC::AscendQuant<srcType>(dstLocal, srcLocal, scale, offset, dataSize);
#endif

        outQueue.EnQue<int8_t>(dstLocal);
        inQueueX.FreeTensor(srcLocal);
    }
    __aicore__ inline void CopyOut()
    {
        AscendC::LocalTensor<int8_t> dstLocal = outQueue.DeQue<int8_t>();
        AscendC::DataCopy(dstGlobal, dstLocal, dataSize);
        outQueue.FreeTensor(dstLocal);
    }

private:
    AscendC::GlobalTensor<srcType> srcGlobal;
    AscendC::GlobalTensor<int8_t> dstGlobal;
    AscendC::TPipe* pipe;
    AscendC::TQue<AscendC::TPosition::VECIN, 1> inQueueX;
    AscendC::TQue<AscendC::TPosition::VECOUT, 1> outQueue;
    uint32_t dataSize = 0;
}

