template <class X_TYPE, class Y_TYPE, uint32_t Pattern, uint32_t IsReuseSource>
class KernelReduceMax {
public:
    using T_TYPE = typename X_TYPE::T;

    __aicore__ inline KernelReduceMax() {}

    __aicore__ inline void Init(GM_ADDR x, GM_ADDR y, const uint32_t aLength, const uint32_t rLength,
                                const uint32_t srcInnerPad, AscendC::TPipe* pipeIn)
    {
#if defined(__DAV_c310__)
#ifdef __CCE_KT_TEST__
        g_coreType = 2;
#endif
#endif
        pipe = pipeIn;
        xGm.SetGlobalBuffer((__gm__ T_TYPE*)x, X_TYPE::extent);
        yGm.SetGlobalBuffer((__gm__ T_TYPE*)y, Y_TYPE::extent);
        pipe->InitBuffer(inQueueX, BUFFER_NUM, Align32B<X_TYPE>() * sizeof(T_TYPE));
        pipe->InitBuffer(outQueueY, BUFFER_NUM, Y_TYPE::extent * sizeof(T_TYPE));

        const uint32_t alignSize = 32 / sizeof(T_TYPE);

        this->aLength = aLength;
        this->rLength = rLength;
        this->aLengthAlign = (aLength + alignSize - 1) / alignSize * alignSize;
        this->rLengthAlign = (rLength + alignSize - 1) / alignSize * alignSize;
        this->srcInnerPad = (srcInnerPad == 1) ? true : false;
    }

    __aicore__ inline void Compute()
    {
        AscendC::LocalTensor<T_TYPE> xLocal = inQueueX.DeQue<T_TYPE>();
        AscendC::LocalTensor<T_TYPE> yLocal = outQueueY.AllocTensor<T_TYPE>();

        if constexpr (Pattern == 0) {
            uint32_t srcShape[2] = {aLength, rLength};
            constexpr bool isReuse = (IsReuseSource == 1) ? true : false;
            AscendC::ReduceMax<T_TYPE, AscendC::Pattern::Reduce::AR, isReuse>(yLocal, xLocal, srcShape, srcInnerPad);
        } else if constexpr (Pattern == 1) {
            uint32_t srcShape[2] = {rLength, aLength};
            constexpr bool isReuse = (IsReuseSource == 1) ? true : false;
            AscendC::ReduceMax<T_TYPE, AscendC::Pattern::Reduce::RA, isReuse>(yLocal, xLocal, srcShape, srcInnerPad);
        }

        outQueueY.EnQue<T_TYPE>(yLocal);
        inQueueX.FreeTensor(xLocal);
    }
    __aicore__ inline void Process()
    {
        CopyIn();
        Compute();
        CopyOut();
    }

private:
    __aicore__ inline void CopyIn()
    {
        AscendC::LocalTensor<T_TYPE> xLocal = inQueueX.AllocTensor<T_TYPE>();
        AscendC::DataCopyPadExtParams<T_TYPE> padParams;
        AscendC::DataCopyExtParams copyParams;
        if (srcInnerPad == 0) {
            copyParams.blockCount = 1;
            copyParams.blockLen = X_TYPE::extent * sizeof(T_TYPE);
            copyParams.srcStride = 0;
            copyParams.dstStride = 0;
            padParams.isPad = 0;
            padParams.leftPadding = 0;
            padParams.rightPadding = 0;
            padParams.paddingValue = 0;
            DataCopyPad(xLocal, xGm, copyParams, padParams);
        } else {
            padParams.isPad = 1;
            padParams.leftPadding = 0;
            padParams.paddingValue = 0;
            if constexpr (Pattern == 0) {
                copyParams.blockCount = aLength;
                copyParams.blockLen = rLength * sizeof(T_TYPE);
                copyParams.srcStride = rLength * sizeof(T_TYPE);
                copyParams.dstStride = rLengthAlign * sizeof(T_TYPE) / 32;
                padParams.rightPadding = rLengthAlign - rLength;
            } else {
                padParams.rightPadding = aLengthAlign - aLength;
            }
            DataCopyPad(xLocal, xGm, copyParams, padParams);
        }

        inQueueX.EnQue(xLocal);
    }

    __aicore__ inline void CopyOut()
    {
        AscendC::LocalTensor<T_TYPE> yLocal = outQueueY.DeQue<T_TYPE>();
        AscendC::DataCopyExtParams copyParams;
        if (srcInnerPad == 0) {
            copyParams.blockCount = 1;
            copyParams.blockLen = Y_TYPE::extent * sizeof(T_TYPE);
            copyParams.srcStride = 0;
            copyParams.dstStride = 0;
            DataCopyPad(yGm, yLocal, copyParams);
        } else {
            copyParams.blockCount = aLength;
            copyParams.blockLen = rLength * sizeof(T_TYPE);
            copyParams.srcStride = rLength * sizeof(T_TYPE);
            copyParams.dstStride = rLengthAlign * sizeof(T_TYPE) / 32;
            DataCopyPad(yGm, yLocal, copyParams);
        }
        outQueueY.FreeTensor(yLocal);
    }

private:
    AscendC::TPipe* pipe;
    AscendC::TQue<AscendC::QuePosition::VECIN, BUFFER_NUM> inQueueX;
    AscendC::TQue<AscendC::QuePosition::VECOUT, BUFFER_NUM> outQueueY;
    AscendC::GlobalTensor<T_TYPE> xGm;
    AscendC::GlobalTensor<T_TYPE> yGm;
    uint32_t aLength;
    uint32_t rLength;
    uint32_t aLengthAlign;
    uint32_t rLengthAlign;
    bool srcInnerPad;
}

