template <typename TYPE, int32_t EXTENT>
struct ReduceSumType {
    using T = TYPE;
    constexpr static int32_t extent = EXTENT;
};

template <class Type>
__aicore__ inline constexpr uint32_t Align32B()
{
    const int alginSize = 32 / sizeof(typename Type::T);
    return (Type::extent + alginSize - 1) / alginSize * alginSize;
}

template <class X_TYPE, class Y_TYPE, uint32_t Pattern, uint32_t IsReuseSource>
class KernelReduceSum {
public:
    using T_TYPE = typename X_TYPE::T;
    __aicore__ inline KernelReduceSum() {}
    __aicore__ inline void Init(GM_ADDR srcGm, GM_ADDR dstGm, const uint32_t aLength, const uint32_t rLength,
                                const uint32_t srcInnerPad, AscendC::TPipe* pipeIn)
    {
        pipe = pipeIn;
        srcGlobal.SetGlobalBuffer((__gm__ T_TYPE*)srcGm, X_TYPE::extent);
        dstGlobal.SetGlobalBuffer((__gm__ T_TYPE*)dstGm, Y_TYPE::extent);

        pipe->InitBuffer(inQueueX, BUFFER_NUM, Align32B<X_TYPE>() * sizeof(T_TYPE));
        pipe->InitBuffer(outQueue, BUFFER_NUM, Align32B<Y_TYPE>() * sizeof(T_TYPE));
        this->aLength = aLength;
        this->rLength = rLength;
        this->srcInnerPad = (srcInnerPad == 1) ? true : false;
    }
    __aicore__ inline void Process()
    {
        CopyIn();
        Compute();
        CopyOut();
    }

    __aicore__ inline void CopyIn()
    {
        AscendC::LocalTensor<T_TYPE> srcLocal = inQueueX.AllocTensor<T_TYPE>();
        AscendC::DataCopyPadExtParams<T_TYPE> padParams;
        AscendC::DataCopyExtParams copyParams;
        copyParams.blockCount = 1;
        copyParams.blockLen = X_TYPE::extent * sizeof(T_TYPE);
        copyParams.srcStride = 0;
        copyParams.dstStride = 0;
        padParams.isPad = 0;
        padParams.leftPadding = 0;
        padParams.rightPadding = 0;
        padParams.paddingValue = 0;
        AscendC::DataCopyPad(srcLocal, srcGlobal, copyParams, padParams);
        inQueueX.EnQue(srcLocal);
    }
    __aicore__ inline void Compute()
    {
        AscendC::LocalTensor<T_TYPE> srcLocal = inQueueX.DeQue<T_TYPE>();
        AscendC::LocalTensor<T_TYPE> dstLocal = outQueue.AllocTensor<T_TYPE>();

        if constexpr (Pattern == 0) {
            uint32_t srcShape[2] = {aLength, rLength};
            constexpr bool isReuse = (IsReuseSource == 1) ? true : false;
            AscendC::ReduceSum<T_TYPE, AscendC::Pattern::Reduce::AR, isReuse>(dstLocal, srcLocal, srcShape,
                                                                              srcInnerPad);
        } else if constexpr (Pattern == 1) {
            uint32_t srcShape[2] = {rLength, aLength};
            constexpr bool isReuse = (IsReuseSource == 1) ? true : false;
            AscendC::ReduceSum<T_TYPE, AscendC::Pattern::Reduce::RA, isReuse>(dstLocal, srcLocal, srcShape,
                                                                              srcInnerPad);
        }
        outQueue.EnQue<T_TYPE>(dstLocal);
        inQueueX.FreeTensor(srcLocal);
    }

    __aicore__ inline void CopyOut()
    {
        AscendC::LocalTensor<T_TYPE> dstLocal = outQueue.DeQue<T_TYPE>();
        AscendC::DataCopyPad(dstGlobal, dstLocal, {1, static_cast<uint32_t>(Y_TYPE::extent * sizeof(T_TYPE)), 0, 0});
        outQueue.FreeTensor(dstLocal);
    }

private:
    AscendC::TPipe* pipe;
    AscendC::TQue<AscendC::TPosition::VECIN, BUFFER_NUM> inQueueX;
    AscendC::TQue<AscendC::TPosition::VECOUT, BUFFER_NUM> outQueue;
    AscendC::GlobalTensor<T_TYPE> srcGlobal;
    AscendC::GlobalTensor<T_TYPE> dstGlobal;
    uint32_t aLength;
    uint32_t rLength;
    bool srcInnerPad;
};

