template <typename T, bool isFullSort>
class FullSort {
public:
    __aicore__ inline FullSort() {}
    __aicore__ inline void Init(__gm__ uint8_t* dstValueGm, __gm__ uint8_t* dstIndexGm, __gm__ uint8_t* srcValueGm,
                                __gm__ uint8_t* srcIndexGm, uint32_t elementCount, AscendC::TPipe* pipeIn)
    {
        m_pipe = pipeIn;
        m_elementCount = elementCount;
        m_concatRepeatTimes = m_elementCount / ELEMENT_16;
        m_sortRepeatTimes = m_elementCount / ELEMENT_32;
        m_extractRepeatTimes = m_elementCount / ELEMENT_32;
        m_valueGlobal.SetGlobalBuffer((__gm__ T*)srcValueGm);
        m_indexGlobal.SetGlobalBuffer((__gm__ uint32_t*)srcIndexGm);
        m_dstValueGlobal.SetGlobalBuffer((__gm__ T*)dstValueGm);
        m_dstIndexGlobal.SetGlobalBuffer((__gm__ uint32_t*)dstIndexGm);
        m_pipe->InitBuffer(m_queIn, 2, m_elementCount * sizeof(uint32_t));
        m_pipe->InitBuffer(m_queOut, 2, m_elementCount * sizeof(uint32_t));

        uint32_t sortTmpLocalSize = m_elementCount * 8;
        m_pipe->InitBuffer(m_queCalc, 1, sortTmpLocalSize);
        m_pipe->InitBuffer(m_queTmp, 1, sortTmpLocalSize);
    }
    __aicore__ inline void Process()
    {
        CopyIn();
        Compute();
        CopyOut();
    }

private:
    __aicore__ inline void CopyIn()
    {
        AscendC::LocalTensor<T> valueLocal = m_queIn.AllocTensor<T>();
        AscendC::DataCopy(valueLocal, m_valueGlobal, m_elementCount);
        m_queIn.EnQue(valueLocal);

        AscendC::LocalTensor<uint32_t> indexLocal = m_queIn.AllocTensor<uint32_t>();
        AscendC::DataCopy(indexLocal, m_indexGlobal, m_elementCount);
        m_queIn.EnQue(indexLocal);
    }
    __aicore__ inline void Compute()
    {
        AscendC::LocalTensor<T> valueLocal = m_queIn.DeQue<T>();
        AscendC::LocalTensor<uint32_t> indexLocal = m_queIn.DeQue<uint32_t>();
        AscendC::LocalTensor<T> sortedLocal = m_queCalc.AllocTensor<T>();

        AscendC::LocalTensor<T> sortTmpLocal = m_queTmp.AllocTensor<T>();
        AscendC::LocalTensor<T> dstValueLocal = m_queOut.AllocTensor<T>();
        AscendC::LocalTensor<uint32_t> dstIndexLocal = m_queOut.AllocTensor<uint32_t>();
        AscendC::LocalTensor<T> concatLocal;

        valueLocal.SetSize(m_elementCount);

        AscendC::Sort<T, isFullSort>(sortedLocal, valueLocal, indexLocal, sortTmpLocal, m_sortRepeatTimes);

        if constexpr (!isFullSort) {
            AscendC::PipeBarrier<PIPE_V>();
            int32_t loopTime = AscendC::GetFullSortInnerLoopTimes(m_sortRepeatTimes);
            uint16_t singleMergeTmpElementCount = 32;
            uint32_t dstLocalElementCount = m_elementCount * 8 / sizeof(T);
            int32_t mergeTmpRepeatTimes = m_sortRepeatTimes / AscendC::MRG_SORT_ELEMENT_LEN;

            for (uint32_t loop = 0; loop < loopTime; loop++) {
                uint32_t baseOffset = singleMergeTmpElementCount * 8 / sizeof(T);
                AscendC::MrgSortSrcList sortList = AscendC::MrgSortSrcList(
                    sortedLocal[0], sortedLocal[baseOffset], sortedLocal[2 * baseOffset], sortedLocal[3 * baseOffset]);
                const uint16_t elementCountList[4] = {singleMergeTmpElementCount, singleMergeTmpElementCount,
                                                      singleMergeTmpElementCount, singleMergeTmpElementCount};
                uint32_t sortedNum[AscendC::MRG_SORT_ELEMENT_LEN];
                AscendC::MrgSort<T, false>(sortTmpLocal, sortList, elementCountList, sortedNum, 0b1111,
                                           mergeTmpRepeatTimes);
                AscendC::PipeBarrier<PIPE_V>();
                AscendC::DataCopy(sortedLocal, sortTmpLocal, dstLocalElementCount);
                AscendC::PipeBarrier<PIPE_V>();
                singleMergeTmpElementCount *= AscendC::MRG_SORT_ELEMENT_LEN;
                mergeTmpRepeatTimes = mergeTmpRepeatTimes / AscendC::MRG_SORT_ELEMENT_LEN;
            }
        }

        m_queTmp.FreeTensor(sortTmpLocal);
        m_queIn.FreeTensor(valueLocal);
        m_queIn.FreeTensor(indexLocal);
        Extract(dstValueLocal, dstIndexLocal, sortedLocal, m_extractRepeatTimes);
        m_queCalc.FreeTensor(sortedLocal);
        m_queOut.EnQue(dstValueLocal);
        m_queOut.EnQue(dstIndexLocal);
    }
    __aicore__ inline void CopyOut()
    {
        AscendC::LocalTensor<T> dstValueLocal = m_queOut.DeQue<T>();
        AscendC::LocalTensor<uint32_t> dstIndexLocal = m_queOut.DeQue<uint32_t>();
        AscendC::DataCopy(m_dstValueGlobal, dstValueLocal, m_elementCount);
        AscendC::DataCopy(m_dstIndexGlobal, dstIndexLocal, m_elementCount);
        m_queOut.FreeTensor(dstValueLocal);
        m_queOut.FreeTensor(dstIndexLocal);
    }

private:
    AscendC::TPipe* m_pipe;
    AscendC::TQue<AscendC::QuePosition::VECIN, 2> m_queIn;
    AscendC::TQue<AscendC::QuePosition::VECOUT, 2> m_queOut;
    AscendC::TQue<AscendC::QuePosition::VECIN, 1> m_queTmp;
    AscendC::TQue<AscendC::QuePosition::VECIN, 1> m_queCalc;

    AscendC::GlobalTensor<T> m_valueGlobal;
    AscendC::GlobalTensor<uint32_t> m_indexGlobal;
    AscendC::GlobalTensor<T> m_dstValueGlobal;
    AscendC::GlobalTensor<uint32_t> m_dstIndexGlobal;

    uint32_t m_elementCount;
    uint32_t m_concatRepeatTimes;
    uint32_t m_sortRepeatTimes;
    uint32_t m_extractRepeatTimes;
}

