template <typename T, bool isFullSort>
class KernelSort {
public:
    __aicore__ inline KernelSort() {}
    __aicore__ inline void Init(GM_ADDR dstValueGm, GM_ADDR dstIndexGm, GM_ADDR srcValueGm, GM_ADDR srcIndexGm,
                                VecTiling tilingData, AscendC::TPipe* pipeIn)
    {
        mpipe = pipeIn;
        mElementCount = tilingData.elementCount;
        mConcatRepeatTimes = mElementCount / ELEMENT_16;
        mSortRepeatTimes = mElementCount / ELEMENT_32;
        mExtractRepeatTimes = mElementCount / ELEMENT_32;
        mInBufferSize = mElementCount * sizeof(uint32_t);
        mOutBufferSize = mElementCount * sizeof(uint32_t);
        mCalcBufferSize = mElementCount * BUFFER_SIZE;
        mTmpBufferSize = mElementCount * BUFFER_SIZE;

        mValueGlobal.SetGlobalBuffer((__gm__ T*)srcValueGm);
        mIndexGlobal.SetGlobalBuffer((__gm__ uint32_t*)srcIndexGm);
        mDstValueGlobal.SetGlobalBuffer((__gm__ T*)dstValueGm);
        mDstIndexGlobal.SetGlobalBuffer((__gm__ uint32_t*)dstIndexGm);
        mpipe->InitBuffer(mQueIn, DOUBLE_SIZE, mInBufferSize);
        mpipe->InitBuffer(mQueOut, 1, mOutBufferSize);
        mpipe->InitBuffer(mQueOutIdx, 1, mOutBufferSize);
        mpipe->InitBuffer(mQueCalc, 1, mCalcBufferSize * sizeof(T));
        mpipe->InitBuffer(mQueTmp, 1, mTmpBufferSize * sizeof(T));
        mpipe->InitBuffer(mQueTmpConcat, 1, mTmpBufferSize * sizeof(T));
    }
    __aicore__ inline void Process()
    {
        CopyIn();
        Compute();
        CopyOut();
    }

private:
    __aicore__ inline void CopyIn()
    {
        AscendC::LocalTensor<T> valueLocal = mQueIn.AllocTensor<T>();
        AscendC::DataCopy(valueLocal, mValueGlobal, mElementCount);
        mQueIn.EnQue(valueLocal);

        AscendC::LocalTensor<uint32_t> indexLocal = mQueIn.AllocTensor<uint32_t>();
        AscendC::DataCopy(indexLocal, mIndexGlobal, mElementCount);
        mQueIn.EnQue(indexLocal);
    }
    __aicore__ inline void Compute()
    {
        AscendC::LocalTensor<T> valueLocal = mQueIn.DeQue<T>();
        AscendC::LocalTensor<uint32_t> indexLocal = mQueIn.DeQue<uint32_t>();
        AscendC::LocalTensor<T> sortedLocal = mQueCalc.AllocTensor<T>();
        AscendC::LocalTensor<T> concatTmpLocal = mQueTmpConcat.AllocTensor<T>();
        AscendC::LocalTensor<T> sortTmpLocal = mQueTmp.AllocTensor<T>();
        AscendC::LocalTensor<T> dstValueLocal = mQueOut.AllocTensor<T>();
        AscendC::LocalTensor<uint32_t> dstIndexLocal = mQueOutIdx.AllocTensor<uint32_t>();
        AscendC::LocalTensor<T> concatLocal;
        AscendC::Concat(concatLocal, valueLocal, concatTmpLocal, mConcatRepeatTimes);
        valueLocal.SetSize(mElementCount);
        if (sizeof(T) == sizeof(half)) {
            sortedLocal.SetSize(mElementCount * LOCAL_SIZE_220_HALF);
            sortTmpLocal.SetSize(mElementCount * LOCAL_SIZE_220_HALF);
        } else {
            sortedLocal.SetSize(mElementCount * LOCAL_SIZE_220_FLOAT);
            sortTmpLocal.SetSize(mElementCount * LOCAL_SIZE_220_FLOAT);
        }
        AscendC::Sort<T, isFullSort>(sortedLocal, concatLocal, indexLocal, sortTmpLocal, mSortRepeatTimes);

        AscendC::Extract(dstValueLocal, dstIndexLocal, sortedLocal, mExtractRepeatTimes);
        mQueTmp.FreeTensor(sortTmpLocal);
        mQueTmpConcat.FreeTensor(concatTmpLocal);
        mQueIn.FreeTensor(valueLocal);
        mQueIn.FreeTensor(indexLocal);
        mQueCalc.FreeTensor(sortedLocal);
        mQueOut.EnQue(dstValueLocal);
        mQueOutIdx.EnQue(dstIndexLocal);
    }
    __aicore__ inline void CopyOut()
    {
        AscendC::LocalTensor<T> dstValueLocal = mQueOut.DeQue<T>();
        AscendC::LocalTensor<uint32_t> dstIndexLocal = mQueOutIdx.DeQue<uint32_t>();
        AscendC::DataCopy(mDstValueGlobal, dstValueLocal, mElementCount);
        AscendC::DataCopy(mDstIndexGlobal, dstIndexLocal, mElementCount);
        mQueOut.FreeTensor(dstValueLocal);
        mQueOutIdx.FreeTensor(dstIndexLocal);
    }

private:
    AscendC::TPipe* mpipe;
    AscendC::TQue<AscendC::TPosition::VECIN, DOUBLE_SIZE> mQueIn;
    AscendC::TQue<AscendC::TPosition::VECOUT, 1> mQueOut;
    AscendC::TQue<AscendC::TPosition::VECOUT, 1> mQueOutIdx;
    AscendC::TQue<AscendC::TPosition::VECIN, 1> mQueTmp;
    AscendC::TQue<AscendC::TPosition::VECIN, 1> mQueTmpConcat;
    AscendC::TQue<AscendC::TPosition::VECIN, 1> mQueCalc;
    AscendC::GlobalTensor<T> mValueGlobal;
    AscendC::GlobalTensor<uint32_t> mIndexGlobal;
    AscendC::GlobalTensor<T> mDstValueGlobal;
    AscendC::GlobalTensor<uint32_t> mDstIndexGlobal;
    uint32_t mElementCount = 64;
    uint32_t mConcatRepeatTimes;
    uint32_t mSortRepeatTimes;
    uint32_t mExtractRepeatTimes;
    uint32_t mInBufferSize;
    uint32_t mOutBufferSize;
    uint32_t mCalcBufferSize;
    uint32_t mTmpBufferSize;
}

