template <typename T>
class KernelDropout {
public:
    __aicore__ inline KernelDropout() {}
    __aicore__ inline void Init(GM_ADDR src_gm, GM_ADDR mask_gm, GM_ADDR dst_gm, GM_ADDR tiling_gm, uint32_t firstAxis,
                                uint32_t srcLastAxis, uint32_t maskLastAxis, AscendC::TPipe* pipeIn)
    {
        pipe = pipeIn;
        srcSize = firstAxis * srcLastAxis;
        maskSize = firstAxis * maskLastAxis;

        info.firstAxis = firstAxis;
        info.srcLastAxis = srcLastAxis;
        info.maskLastAxis = maskLastAxis;

        src_global.SetGlobalBuffer(reinterpret_cast<__gm__ T*>(src_gm), srcSize);
        mask_global.SetGlobalBuffer(reinterpret_cast<__gm__ uint8_t*>(mask_gm), maskSize);
        tiling_global.SetGlobalBuffer(reinterpret_cast<__gm__ float*>(tiling_gm), 1);
        dst_global.SetGlobalBuffer(reinterpret_cast<__gm__ T*>(dst_gm), srcSize);

        probValue = tiling_global.GetValue(0);
        int32_t eventID = static_cast<int32_t>(GetTPipePtr()->FetchEventID(AscendC::HardEvent::S_MTE3));
        AscendC::SetFlag<AscendC::HardEvent::S_MTE3>(eventID);
        AscendC::WaitFlag<AscendC::HardEvent::S_MTE3>(eventID);

        pipe->InitBuffer(inQueueX, 1, srcSize * sizeof(T) + 256);
        pipe->InitBuffer(inQueueY, 1, maskSize * sizeof(uint8_t));
        pipe->InitBuffer(outQueue, 1, srcSize * sizeof(T) + 256);
        pipe->InitBuffer(sharedTmpBuffer, 32768);
    }
    __aicore__ inline void Process()
    {
        CopyIn();
        Compute();
        CopyOut();
    }

private:
    __aicore__ inline void CopyIn()
    {
        AscendC::LocalTensor<T> srcLocal = inQueueX.AllocTensor<T>();
        AscendC::LocalTensor<uint8_t> maskLocal = inQueueY.AllocTensor<uint8_t>();

        AscendC::DataCopy(srcLocal, src_global, srcSize);
        AscendC::DataCopy(maskLocal, mask_global, maskSize);

        inQueueX.EnQue(srcLocal);
        inQueueY.EnQue(maskLocal);
    }
    __aicore__ inline void Compute()
    {
        AscendC::LocalTensor<T> dstLocal = outQueue.AllocTensor<T>();

        AscendC::LocalTensor<T> srcLocal = inQueueX.DeQue<T>();
        AscendC::LocalTensor<uint8_t> maskLocal = inQueueY.DeQue<uint8_t>();
        AscendC::LocalTensor<uint8_t> tmpBuffer = sharedTmpBuffer.Get<uint8_t>();
        AscendC::DropOut(dstLocal, srcLocal, maskLocal, tmpBuffer, probValue, info);

        outQueue.EnQue<T>(dstLocal);

        inQueueX.FreeTensor(srcLocal);
        inQueueY.FreeTensor(maskLocal);
    }
    __aicore__ inline void CopyOut()
    {
        AscendC::LocalTensor<T> dstLocal = outQueue.DeQue<T>();
        AscendC::DataCopy(dst_global, dstLocal, srcSize);
        outQueue.FreeTensor(dstLocal);
    }

private:
    AscendC::GlobalTensor<T> src_global;
    AscendC::GlobalTensor<uint8_t> mask_global;
    AscendC::GlobalTensor<float> tiling_global;
    AscendC::GlobalTensor<T> dst_global;

    AscendC::TPipe* pipe;
    AscendC::TQue<AscendC::QuePosition::VECIN, 1> inQueueX;
    AscendC::TQue<AscendC::QuePosition::VECIN, 1> inQueueY;
    AscendC::TQue<AscendC::QuePosition::VECOUT, 1> outQueue;
    AscendC::TBuf<AscendC::QuePosition::VECCALC> sharedTmpBuffer;

    uint32_t srcSize = 0;
    uint32_t maskSize = 0;
    float probValue = 0.75;
    AscendC::DropOutShapeInfo info;
}

