template <typename T, uint32_t mode>
class KernelTransData {
public:
    __aicore__ inline KernelTransData() {}
    __aicore__ inline void Init(GM_ADDR src_gm, GM_ADDR dst_gm, int32_t n, int32_t c, int32_t d, int32_t h, int32_t w,
                                AscendC::TPipe* pipeIn)
    {
        pipe = pipeIn;
        this->n = n;
        this->d = d;
        this->c = c;
        this->h = h;
        this->w = w;
        this->c1 = (c + c0 - 1) / c0;
        this->n1 = (n + n0 - 1) / n0;
        this->hw1 = (h * w + hw0 - 1) / hw0;
        if ((h * w) % 16 != 0) {
            needPad = true;
        }
        uint32_t dstGmSize = 0;

        if constexpr (mode == NCDHW_FractalZ3D) {
            this->srcShapeSize = n * d * c * hw0 * hw1;
            this->dstShapeSize = n1 * n0 * c1 * c0 * d * h * w;
            this->tmpShapeSize = c * d * hw0 * hw1 + n1 * n0 * d * c1 * c0 * hw0 * hw1;
            srcGlobal.SetGlobalBuffer(reinterpret_cast<__gm__ T*>(src_gm), srcShapeSize * sizeof(T));
            dstGlobal.SetGlobalBuffer(reinterpret_cast<__gm__ T*>(dst_gm), dstShapeSize * sizeof(T));
        } else if constexpr (mode == FractalZ3D_NCDHW) {
            this->srcShapeSize = d * c1 * h * w * n1 * n0 * c0;
            this->dstShapeSize = n * c * d * (hw1 * hw0);
            if (c == c1 * c0 && n == n1 * n0) {
                this->tmpShapeSize = d * c1 * (hw1 * hw0) * n1 * n0 * c0;
            } else {
                this->tmpShapeSize = d * c1 * (hw1 * hw0) * n1 * n0 * c0 * 2;
            }
            srcGlobal.SetGlobalBuffer(reinterpret_cast<__gm__ T*>(src_gm), srcShapeSize * sizeof(T));
            dstGlobal.SetGlobalBuffer(reinterpret_cast<__gm__ T*>(dst_gm), dstShapeSize * sizeof(T));
        } else if constexpr (mode == NCDHW_NDC1HWC0) {
            this->srcShapeSize = n * d * c * hw0 * hw1;
            this->dstShapeSize = n * c1 * c0 * d * h * w;
            this->tmpShapeSize = d * hw0 * hw1 + d * c1 * c0 * hw0 * hw1;
            srcGlobal.SetGlobalBuffer(reinterpret_cast<__gm__ T*>(src_gm), srcShapeSize * sizeof(T));
            dstGlobal.SetGlobalBuffer(reinterpret_cast<__gm__ T*>(dst_gm), dstShapeSize * sizeof(T));
        } else if constexpr (mode == NDC1HWC0_NCDHW) {
            this->srcShapeSize = n * c1 * c0 * d * h * w;
            this->dstShapeSize = n * d * c * hw0 * hw1;
            dstGmSize = n * c * d * h * w;
            this->tmpShapeSize = 512 + d * c1 * c0 * hw0 * hw1;
            srcGlobal.SetGlobalBuffer(reinterpret_cast<__gm__ T*>(src_gm), srcShapeSize * sizeof(T));
            dstGlobal.SetGlobalBuffer(reinterpret_cast<__gm__ T*>(dst_gm), dstGmSize * sizeof(T));
        }
        pipe->InitBuffer(inQueue, 1, srcShapeSize * sizeof(T));
        pipe->InitBuffer(outQueue, 1, dstShapeSize * sizeof(T));
        pipe->InitBuffer(tmpBuf, tmpShapeSize * sizeof(T));
    }
    __aicore__ inline void Process()
    {
        CopyIn();
        Compute();
        CopyOut();
    }

private:
    __aicore__ inline void CopyIn()
    {
        AscendC::LocalTensor<T> srcLocal = inQueue.AllocTensor<T>();
        if ((mode == NCDHW_FractalZ3D || mode == NCDHW_NDC1HWC0) && needPad) {
            AscendC::DataCopyExtParams extParam = {static_cast<uint16_t>(n * c * d),
                                                   static_cast<uint32_t>(h * w * sizeof(T)), 0, 0, 0};
            AscendC::DataCopyPadExtParams<T> padParam = {true, 0, 0, static_cast<T>(123)};
            AscendC::DataCopyPad(srcLocal, srcGlobal, extParam, padParam);
        } else {
            AscendC::DataCopy(srcLocal, srcGlobal, srcShapeSize);
        }

        inQueue.EnQue(srcLocal);
    }
    __aicore__ inline void Compute()
    {
        AscendC::LocalTensor<T> dstLocal = outQueue.AllocTensor<T>();
        AscendC::LocalTensor<uint8_t> tmp = tmpBuf.Get<uint8_t>();
        AscendC::LocalTensor<T> srcLocal = inQueue.DeQue<T>();
        AscendC::PipeBarrier<PIPE_V>();

        AscendC::Layout ncdhwLayout = AscendC::MakeLayout(AscendC::MakeShape(n, c, d, h, w), AscendC::MakeStride());
        AscendC::Layout ndc1hwc0Layout = 
            AscendC::MakeLayout(AscendC::MakeShape(n, d, c1, h, w, c0), AscendC::MakeStride());
        AscendC::Layout fractalzLayout = 
            AscendC::MakeLayout(AscendC::MakeShape(d, c1, h, w, n1, n0, c0), AscendC::MakeStride());

        if constexpr (mode == NCDHW_FractalZ3D) {
            AscendC::TransDataParams<decltype(ncdhwLayout), decltype(fractalzLayout)> params = {ncdhwLayout,
                                                                                                fractalzLayout};
            AscendC::TransData<config1>(dstLocal, srcLocal, tmp, params);
        } else if constexpr (mode == FractalZ3D_NCDHW) {
            AscendC::TransDataParams<decltype(fractalzLayout), decltype(ncdhwLayout)> params = {fractalzLayout,
                                                                                                ncdhwLayout};
            AscendC::TransData<config2, T, decltype(fractalzLayout), decltype(ncdhwLayout)>(dstLocal, srcLocal, tmp,
                                                                                            params);
        } else if constexpr (mode == NCDHW_NDC1HWC0) {
            AscendC::TransDataParams<decltype(ncdhwLayout), decltype(ndc1hwc0Layout)> params = {ncdhwLayout,
                                                                                                ndc1hwc0Layout};
            AscendC::TransData<config3>(dstLocal, srcLocal, tmp, params);
        } else if constexpr (mode == NDC1HWC0_NCDHW) {
            AscendC::TransDataParams<decltype(ndc1hwc0Layout), decltype(ncdhwLayout)> params = {ndc1hwc0Layout,
                                                                                                ncdhwLayout};
            AscendC::TransData<config4>(dstLocal, srcLocal, tmp, params);
        }

        outQueue.EnQue<T>(dstLocal);
        inQueue.FreeTensor(srcLocal);
    }
    __aicore__ inline void CopyOut()
    {
        AscendC::LocalTensor<T> dstLocal = outQueue.DeQue<T>();
        if constexpr (mode == NCDHW_FractalZ3D || mode == FractalZ3D_NCDHW || mode == NCDHW_NDC1HWC0) {
            AscendC::DataCopy(dstGlobal, dstLocal, dstShapeSize);
        } else if constexpr (mode == NDC1HWC0_NCDHW) {
            AscendC::DataCopyExtParams extParam = {static_cast<uint16_t>(n * c * d),
                                                   static_cast<uint32_t>(h * w * sizeof(T)), 0, 0, 0};
            AscendC::DataCopyPad(dstGlobal, dstLocal, extParam);
        }
        outQueue.FreeTensor(dstLocal);
    }

private:
    AscendC::GlobalTensor<T> srcGlobal;
    AscendC::GlobalTensor<T> dstGlobal;
    AscendC::TPipe* pipe;
    AscendC::TQue<AscendC::QuePosition::VECIN, 1> inQueue;
    AscendC::TQue<AscendC::QuePosition::VECOUT, 1> outQueue;
    AscendC::TBuf<AscendC::QuePosition::VECIN> tmpBuf;
    bool needPad = false;
    int32_t n;
    int32_t c;
    int32_t d;
    int32_t h;
    int32_t w;
    int32_t hw1;
    int32_t n1;
    int32_t c1;
    int32_t n0 = 16;
    int32_t c0 = 16;
    int32_t hw0 = 16;
    uint32_t srcShapeSize = 0;
    uint32_t dstShapeSize = 0;
    uint32_t tmpShapeSize = 0;
}

