template <typename T>
class KernelAcosh {
public:
    __aicore__ inline KernelAcosh() {}
    __aicore__ inline void Init(GM_ADDR srcGm, GM_ADDR dstGm, uint32_t srcSize, uint32_t tmpBufSizeIn,
                                uint32_t calCountIn, AscendC::TPipe* pipeIn)
    {
        pipe = pipeIn;
        uint32_t oneBlkSize = 32 / sizeof(T);
        uint32_t alignSize = ((srcSize + oneBlkSize - 1) / oneBlkSize) * oneBlkSize;
        dataSize = alignSize;
        srcGlobal.SetGlobalBuffer(reinterpret_cast<__gm__ T*>(srcGm), dataSize);
        dstGlobal.SetGlobalBuffer(reinterpret_cast<__gm__ T*>(dstGm), dataSize);
        tmpBufSize = tmpBufSizeIn;
        calCount = calCountIn;
        pipe->InitBuffer(inQueueX, 1, dataSize * sizeof(T));
        pipe->InitBuffer(outQueue, 1, dataSize * sizeof(T));
        if (tmpBufSize > 0) {
            pipe->InitBuffer(buf, tmpBufSize * sizeof(T));
        }
    }
    __aicore__ inline void Process(uint32_t tmpBufSize)
    {
        AscendC::AscendCUtils::SetOverflow(1);
        CopyIn();
        Compute();
        CopyOut();
        AscendC::AscendCUtils::SetOverflow(0);
    }

    __aicore__ inline void CopyIn()
    {
        AscendC::LocalTensor<T> srcLocal = inQueueX.AllocTensor<T>();
        AscendC::DataCopy(srcLocal, srcGlobal, dataSize);
        inQueueX.EnQue<T>(srcLocal);
    }
    __aicore__ inline void Compute()
    {
        AscendC::LocalTensor<T> srcLocal = inQueueX.DeQue<T>();
        AscendC::LocalTensor<T> dstLocal = outQueue.AllocTensor<T>();
        AscendC::LocalTensor<uint8_t> temp;
        const T zero = 0;
        AscendC::Duplicate<T>(dstLocal, zero, dataSize);
        if (tmpBufSize > 0) {
            temp = buf.Get<uint8_t>();
        }
        if ((tmpBufSize > 0) && calCount > 0) {
            AscendC::Acosh<T>(dstLocal, srcLocal, temp, calCount);
        } else if (tmpBufSize > 0) {
            AscendC::Acosh<T>(dstLocal, srcLocal, temp);
        } else if (calCount > 0) {
            AscendC::Acosh<T>(dstLocal, srcLocal, calCount);
        } else {
            AscendC::Acosh<T>(dstLocal, srcLocal);
        }
        outQueue.EnQue<T>(dstLocal);
        inQueueX.FreeTensor(srcLocal);
    }
    __aicore__ inline void CopyOut()
    {
        AscendC::LocalTensor<T> dstLocal = outQueue.DeQue<T>();
        AscendC::DataCopy(dstGlobal, dstLocal, dataSize);
        outQueue.FreeTensor(dstLocal);
    }

private:
    AscendC::TPipe* pipe;
    AscendC::TQue<AscendC::QuePosition::VECIN, 1> inQueueX;
    AscendC::TQue<AscendC::QuePosition::VECOUT, 1> outQueue;
    AscendC::TBuf<AscendC::TPosition::VECCALC> buf;
    AscendC::GlobalTensor<T> srcGlobal;
    AscendC::GlobalTensor<T> dstGlobal;
    uint32_t dataSize = 0;
    uint32_t calCount = 0;
    uint32_t tmpBufSize = 0;
