class ClampByMinMax {
public:
    __aicore__ inline ClampByMinMax() {}

    __aicore__ inline void Init(GM_ADDR srcGm, GM_ADDR minGm, GM_ADDR maxGm, GM_ADDR dstGm, uint32_t countIn,
                                uint32_t dataSizeIn, uint32_t scalarTypeIn, AscendC::TPipe* pipeIn)
    {
