        pipe->InitBuffer(inQueueX, 1, dataSize * sizeof(T));
        pipe->InitBuffer(inQueueMin, 1, dataSize * sizeof(T));
        pipe->InitBuffer(inQueueMax, 1, dataSize * sizeof(T));
        pipe->InitBuffer(outQueue, 1, dataSize * sizeof(T));
    }
    __aicore__ inline void Process()
    {
        AscendC::AscendCUtils::SetOverflow(1);
        CopyIn();
        Compute();
        CopyOut();
        AscendC::AscendCUtils::SetOverflow(0);
    }
    __aicore__ inline void CopyIn()
    {
        AscendC::LocalTensor<T> srcLocal = inQueueX.AllocTensor<T>();
        AscendC::DataCopy(srcLocal, srcGlobal, dataSize);
        inQueueX.EnQue(srcLocal);

        AscendC::LocalTensor<T> minLocal = inQueueMin.AllocTensor<T>();
        AscendC::DataCopy(minLocal, minGlobal, dataSize);
        inQueueMin.EnQue(minLocal);

        AscendC::LocalTensor<T> maxLocal = inQueueMax.AllocTensor<T>();
        AscendC::DataCopy(maxLocal, maxGlobal, dataSize);
        inQueueMax.EnQue(maxLocal);
    }
    __aicore__ inline void Compute()
    {
        AscendC::LocalTensor<T> srcLocal = inQueueX.DeQue<T>();
        AscendC::LocalTensor<T> minLocal = inQueueMin.DeQue<T>();
        AscendC::LocalTensor<T> maxLocal = inQueueMax.DeQue<T>();
        AscendC::LocalTensor<T> dstLocal = outQueue.AllocTensor<T>();
        Duplicate(dstLocal, (T)0, dataSize);
        if (scalarType == ScalarType::BOTH_TENSOR) {
            AscendC::Clamp(dstLocal, srcLocal, minLocal, maxLocal, count);
        } else if (scalarType == ScalarType::TENSOR_SCALAR) {
            event_t eventIdMte2ToS = static_cast<event_t>(GetTPipePtr()->FetchEventID(AscendC::HardEvent::MTE2_S));
            AscendC::SetFlag<AscendC::HardEvent::MTE2_S>(eventIdMte2ToS);
            AscendC::WaitFlag<AscendC::HardEvent::MTE2_S>(eventIdMte2ToS);
            T maxValue = maxLocal.GetValue(0);
            event_t eventIdSToV = static_cast<event_t>(GetTPipePtr()->FetchEventID(AscendC::HardEvent::S_V));
            AscendC::SetFlag<AscendC::HardEvent::S_V>(eventIdSToV);
            AscendC::WaitFlag<AscendC::HardEvent::S_V>(eventIdSToV);
            AscendC::Clamp(dstLocal, srcLocal, minLocal, maxValue, count);
        } else if (scalarType == ScalarType::SCALAR_TENSOR) {
            event_t eventIdMte2ToS = static_cast<event_t>(GetTPipePtr()->FetchEventID(AscendC::HardEvent::MTE2_S));
            AscendC::SetFlag<AscendC::HardEvent::MTE2_S>(eventIdMte2ToS);
            AscendC::WaitFlag<AscendC::HardEvent::MTE2_S>(eventIdMte2ToS);
            T minValue = minLocal.GetValue(0);
            event_t eventIdSToV = static_cast<event_t>(GetTPipePtr()->FetchEventID(AscendC::HardEvent::S_V));
            AscendC::SetFlag<AscendC::HardEvent::S_V>(eventIdSToV);
            AscendC::WaitFlag<AscendC::HardEvent::S_V>(eventIdSToV);
            AscendC::Clamp(dstLocal, srcLocal, minValue, maxLocal, count);
        } else {
            event_t eventIdMte2ToS = static_cast<event_t>(GetTPipePtr()->FetchEventID(AscendC::HardEvent::MTE2_S));
            AscendC::SetFlag<AscendC::HardEvent::MTE2_S>(eventIdMte2ToS);
            AscendC::WaitFlag<AscendC::HardEvent::MTE2_S>(eventIdMte2ToS);
            T minValue = minLocal.GetValue(0);
