template <typename T, const AscendC::CumSumConfig& CONFIG>
class KernelCumSum {
public:
    __aicore__ inline KernelCumSum() {}
    __aicore__ inline void Init(GM_ADDR srcGm, GM_ADDR dstGm, GM_ADDR lastRowGm, uint32_t outter, uint32_t inner,
                                uint32_t gmOutter, uint32_t gmInner, AscendC::TPipe* tPipe)
    {
        this->outter = outter;
        this->inner = inner;
        this->gmOutter = gmOutter;
        this->gmInner = gmInner;
        this->pipe = tPipe;

        srcGlobal.SetGlobalBuffer(reinterpret_cast<__gm__ T*>(srcGm), this->gmOutter * this->gmInner);
        dstGlobal.SetGlobalBuffer(reinterpret_cast<__gm__ T*>(dstGm), this->gmOutter * this->gmInner);
        lastRowGlobal.SetGlobalBuffer(reinterpret_cast<__gm__ T*>(lastRowGm), this->gmInner);

        this->pipe->InitBuffer(inQueueX, BUFFER_NUM, Align32B<T>(outter * inner) * sizeof(T));
        this->pipe->InitBuffer(outQueue, BUFFER_NUM, Align32B<T>(outter * inner) * sizeof(T));
        this->pipe->InitBuffer(lastRowQueue, BUFFER_NUM, Align32B<T>(inner) * sizeof(T));
    }
    __aicore__ inline void Process()
    {
        CopyIn();
        Compute();
        CopyOut();
    }

private:
    __aicore__ inline void CopyIn()
    {
        AscendC::LocalTensor<T> srcLocal = inQueueX.AllocTensor<T>();
        AscendC::DataCopyPadParams dataCopyPadParams;
        for (int32_t i = 0; i < gmOutter; i++) {
            AscendC::DataCopyPad(srcLocal[i * inner], srcGlobal[i * gmInner],
                                 {1, static_cast<uint16_t>(gmInner * sizeof(T)), 0, 0}, dataCopyPadParams);
        }

        inQueueX.EnQue(srcLocal);
    }
    __aicore__ inline void Compute()
    {
        AscendC::LocalTensor<T> dstLocal = outQueue.AllocTensor<T>();
        AscendC::LocalTensor<T> lastRowLocal = lastRowQueue.AllocTensor<T>();
        AscendC::LocalTensor<T> srcLocal = inQueueX.DeQue<T>();
        const AscendC::CumSumInfo cumSumInfo{outter, inner};
        AscendC::CumSum<T, CONFIG>(dstLocal, lastRowLocal, srcLocal, cumSumInfo);
        outQueue.EnQue<T>(dstLocal);
        lastRowQueue.EnQue<T>(lastRowLocal);
        inQueueX.FreeTensor(srcLocal);
    }
    __aicore__ inline void CopyOut()
    {
        AscendC::LocalTensor<T> dstLocal = outQueue.DeQue<T>();
        for (int32_t i = 0; i < gmOutter; i++) {
            AscendC::DataCopyPad(dstGlobal[i * gmInner], dstLocal[i * inner],
                                 {1, static_cast<uint16_t>(gmInner * sizeof(T)), 0, 0});
        }
        outQueue.FreeTensor(dstLocal);
        AscendC::LocalTensor<T> lastRowLocal = lastRowQueue.DeQue<T>();
        AscendC::DataCopyPad(lastRowGlobal, lastRowLocal, {1, static_cast<uint16_t>(gmInner * sizeof(T)), 0, 0});
        lastRowQueue.FreeTensor(lastRowLocal);
    }

private:
    AscendC::GlobalTensor<T> srcGlobal;
    AscendC::GlobalTensor<T> dstGlobal;
    AscendC::GlobalTensor<T> lastRowGlobal;

    AscendC::TQue<AscendC::QuePosition::VECIN, 1> inQueueX;
    AscendC::TQue<AscendC::QuePosition::VECOUT, 1> outQueue;
    AscendC::TQue<AscendC::QuePosition::VECOUT, 1> lastRowQueue;

    AscendC::TPipe* pipe;

    uint32_t outter{1};
    uint32_t inner{1};
    uint32_t gmOutter{1};
    uint32_t gmInner{1};
}

