template <typename T, bool isReuseSrc = false, bool isHighPreci = false, uint8_t expandLevel = 10>
class KernelExp {
public:
    __aicore__ inline KernelExp() {}
    __aicore__ inline void Init(GM_ADDR srcGm, GM_ADDR dstGm, uint32_t totalLength, uint32_t calCount, uint32_t tmpMode,
                                AscendC::DataFormat dataFormat, AscendC::TPipe* pipeIn)
    {
        pipe = pipeIn;
        this->totalLength = totalLength;
        this->calCount = calCount;
        this->tmpMode = tmpMode;
        this->dataFormat = dataFormat;
        uint32_t oneBlockNum = 32 / sizeof(T);
        totalLength = (totalLength + oneBlockNum - 1) / oneBlockNum * oneBlockNum;
        srcGlobal.SetGlobalBuffer(reinterpret_cast<__gm__ T*>(srcGm), totalLength);
        dstGlobal.SetGlobalBuffer(reinterpret_cast<__gm__ T*>(dstGm), totalLength);
        pipe->InitBuffer(inQueueX, 1, totalLength * sizeof(T));
        pipe->InitBuffer(outQueue, 1, totalLength * sizeof(T));
    }

    __aicore__ inline void Process()
    {
        AscendC::AscendCUtils::SetOverflow(1);
        CopyIn();
        Compute();
        CopyOut();
        AscendC::AscendCUtils::SetOverflow(0);
    }

    __aicore__ inline void CopyIn()
    {
        AscendC::LocalTensor<T> srcLocal = inQueueX.AllocTensor<T>();
        AscendC::DataCopy(srcLocal, srcGlobal, totalLength);
        inQueueX.EnQue(srcLocal);
    }
    __aicore__ inline void Compute()
    {
        AscendC::LocalTensor<T> dstLocal = outQueue.AllocTensor<T>();
        AscendC::LocalTensor<T> srcLocal = inQueueX.DeQue<T>();
        Duplicate(dstLocal, (T)0, totalLength);

        uint32_t inputShape[1] = {totalLength};
        AscendC::ShapeInfo shapeInfo{1, inputShape, 1, inputShape, AscendC::DataFormat::ND};
        uint32_t maxSize = 0;
        uint32_t minSize = 0;
        GetExpMaxMinTmpSizeCur(shapeInfo, sizeof(T), isReuseSrc, isHighPreci, maxSize, minSize);

        AscendC::LocalTensor<uint8_t> stackBuffer;
        bool ans = AscendC::PopStackBuffer<uint8_t, AscendC::TPosition::LCM>(stackBuffer);
        stackBufferSize = stackBuffer.GetSize() * 1;

        for (int i = 0; i < 1; i++) {
            if (tmpMode == 0) {
                AscendC::Exp<T, expandLevel, isReuseSrc>(dstLocal, srcLocal, calCount);
            } else {
                if (tmpMode == 1) {
                    stackBufferSize = minSize;
                } else if (tmpMode == 2) {
                    stackBufferSize = maxSize;
                } else if (tmpMode == 3) {
                    stackBufferSize = (minSize + maxSize) / 2;
                }
                stackBuffer.SetSize(stackBufferSize);
                AscendC::Exp<T, expandLevel, isReuseSrc>(dstLocal, srcLocal, stackBuffer, calCount);
            }
        }
        outQueue.EnQue<T>(dstLocal);
        inQueueX.FreeTensor(srcLocal);
    }
    __aicore__ inline void CopyOut()
    {
        AscendC::LocalTensor<T> dstLocal = outQueue.DeQue<T>();
        AscendC::DataCopy(dstGlobal, dstLocal, totalLength);
        outQueue.FreeTensor(dstLocal);
    }

private:
    AscendC::TPipe* pipe;
    AscendC::TQue<AscendC::QuePosition::VECIN, 1> inQueueX;
    AscendC::TQue<AscendC::QuePosition::VECOUT, 1> outQueue;
    AscendC::GlobalTensor<T> srcGlobal;
    AscendC::GlobalTensor<T> dstGlobal;
    uint32_t totalLength = 0;
    uint32_t calCount = 0;
    uint32_t tmpMode = 0;
    AscendC::DataFormat dataFormat;
    uint32_t stackBufferSize = 0;
}

