template <typename DstT, typename SrcT, int32_t calCount, int32_t dataSize>
class KernelIsFinite {
public:
    __aicore__ inline KernelIsFinite() {}
    __aicore__ inline void Init(GM_ADDR x, GM_ADDR y, AscendC::TPipe* pipeIn)
    {
        ASCENDC_ASSERT(AscendC::GetBlockNum() != 0, { KERNEL_IsFinite(KERNEL_ERROR, "block dim can not be zero!"); });

        xGm.SetGlobalBuffer((__gm__ SrcT*)x);
        yGm.SetGlobalBuffer((__gm__ DstT*)y);

        pipe = pipeIn;
        pipe->InitBuffer(inQueueX, BUFFER_NUM, dataSize * sizeof(SrcT));
        pipe->InitBuffer(outQueueY, BUFFER_NUM, dataSize * sizeof(DstT));
    }
    __aicore__ inline void Process()
    {
        CopyIn();
        Compute();
        CopyOut();
    }

private:
    __aicore__ inline void CopyIn()
    {
        AscendC::LocalTensor<SrcT> xLocal = inQueueX.AllocTensor<SrcT>();
        AscendC::DataCopy(xLocal, xGm, dataSize);
        inQueueX.EnQue(xLocal);
    }
    __aicore__ inline void Compute()
    {
        AscendC::LocalTensor<SrcT> xLocal = inQueueX.DeQue<SrcT>();

        if constexpr (std::is_same_v<DstT, bool>) {
            AscendC::LocalTensor<int8_t> yLocal = outQueueY.AllocTensor<int8_t>();
            AscendC::Duplicate(yLocal, (int8_t)0, dataSize);
            AscendC::IsFinite(yLocal, xLocal, calCount);
            outQueueY.EnQue(yLocal);
        } else {
            AscendC::LocalTensor<DstT> yLocal = outQueueY.AllocTensor<DstT>();
            AscendC::Duplicate(yLocal, (DstT)0, dataSize);
            AscendC::IsFinite(yLocal, xLocal, calCount);
            outQueueY.EnQue(yLocal);
        }
        inQueueX.FreeTensor(xLocal);
    }
    __aicore__ inline void CopyOut()
    {
        AscendC::LocalTensor<DstT> yLocal = outQueueY.DeQue<DstT>();
        AscendC::DataCopy(yGm, yLocal, dataSize);
        outQueueY.FreeTensor(yLocal);
    }

private:
    AscendC::TPipe* pipe;
    AscendC::TQue<AscendC::TPosition::VECIN, BUFFER_NUM> inQueueX;
    AscendC::TQue<AscendC::TPosition::VECOUT, BUFFER_NUM> outQueueY;
    AscendC::GlobalTensor<SrcT> xGm;
    AscendC::GlobalTensor<DstT> yGm;
};
