template <typename DstT, typename SrcT, int32_t calCount, int32_t dataSize, int32_t sharedTmpBufferSize>
class KernelIsInf {
public:
    __aicore__ inline KernelIsInf() {}
    __aicore__ inline void Init(GM_ADDR srcGm, GM_ADDR dstGm, AscendC::TPipe* pipeIn)
    {
        pipe = pipeIn;
        srcGlobal.SetGlobalBuffer(reinterpret_cast<__gm__ SrcT*>(srcGm));
        dstGlobal.SetGlobalBuffer(reinterpret_cast<__gm__ DstT*>(dstGm));
        pipe->InitBuffer(inQueue, 1, dataSize * sizeof(SrcT));
        pipe->InitBuffer(outQueue, 1, dataSize * sizeof(DstT));
        if constexpr (sharedTmpBufferSize > 0) {
            pipe->InitBuffer(bufQueue, sharedTmpBufferSize * sizeof(SrcT));
        }
    }
    __aicore__ inline void Process()
    {
        CopyIn();
        Compute();
        CopyOut();
    }

    __aicore__ inline void CopyIn()
    {
        AscendC::LocalTensor<SrcT> srcLocal = inQueue.AllocTensor<SrcT>();
        AscendC::DataCopy(srcLocal, srcGlobal, dataSize);
        inQueue.EnQue(srcLocal);
    }
    __aicore__ inline void Compute()
    {
        AscendC::LocalTensor<DstT> dstLocal = outQueue.AllocTensor<DstT>();
        AscendC::LocalTensor<SrcT> srcLocal = inQueue.DeQue<SrcT>();
        if constexpr (sharedTmpBufferSize > 0) {
            AscendC::LocalTensor<uint8_t> tmpBuf = bufQueue.Get<uint8_t>();
            if constexpr (std::is_same_v<DstT, bool>) {
                AscendC::Duplicate((AscendC::LocalTensor<int8_t>&)dstLocal, (int8_t)0, dataSize);
                AscendC::IsInf(dstLocal, srcLocal, tmpBuf, calCount);
            } else {
                AscendC::Duplicate(dstLocal, (DstT)0, dataSize);
                AscendC::IsInf(dstLocal, srcLocal, tmpBuf, calCount);
            }
