            }
        } else {
            if constexpr (std::is_same_v<DstT, bool>) {
                AscendC::Duplicate((AscendC::LocalTensor<int8_t>&)dstLocal, (int8_t)0, dataSize);
                AscendC::IsNan(dstLocal, srcLocal, calCount);
            } else {
                AscendC::Duplicate(dstLocal, (DstT)0, dataSize);
                AscendC::IsNan(dstLocal, srcLocal, calCount);
            }
        }
        outQueue.EnQue(dstLocal);
        inQueue.FreeTensor(srcLocal);
    }
    __aicore__ inline void CopyOut()
    {
        AscendC::LocalTensor<DstT> dstLocal = outQueue.DeQue<DstT>();
        AscendC::DataCopy(dstGlobal, dstLocal, dataSize);
