        dstGlobal.SetGlobalBuffer(reinterpret_cast<__gm__ bool*>(dstGm));
        pipe->InitBuffer(inQueueX, 1, dataSize * sizeof(T));
        pipe->InitBuffer(inQueueY, 1, dataSize * sizeof(T));
        pipe->InitBuffer(outQueue, 1, dataSize * sizeof(bool));
    }
