template <typename T, int32_t calCount, int32_t dataSize, int32_t sharedTmpBufferSize>
class KernelRint {
public:
    __aicore__ inline KernelRint() {}
    __aicore__ inline void Init(GM_ADDR srcGm, GM_ADDR dstGm, AscendC::TPipe* pipeIn)
    {
        pipe = pipeIn;
        srcGlobal.SetGlobalBuffer(reinterpret_cast<__gm__ T*>(srcGm));
        dstGlobal.SetGlobalBuffer(reinterpret_cast<__gm__ T*>(dstGm));
        pipe->InitBuffer(inQueue, 1, dataSize * sizeof(T));
        pipe->InitBuffer(outQueue, 1, dataSize * sizeof(T));
        if constexpr (sharedTmpBufferSize > 0) {
            pipe->InitBuffer(bufQueue, sharedTmpBufferSize * sizeof(T));
        }
    }
    __aicore__ inline void Process()
    {
        AscendC::AscendCUtils::SetOverflow(1);
        CopyIn();
        Compute();
        CopyOut();
        AscendC::AscendCUtils::SetOverflow(0);
    }

    __aicore__ inline void CopyIn()
    {
        AscendC::LocalTensor<T> srcLocal = inQueue.AllocTensor<T>();
        AscendC::DataCopy(srcLocal, srcGlobal, dataSize);
        inQueue.EnQue(srcLocal);
    }
    __aicore__ inline void Compute()
    {
        AscendC::LocalTensor<T> dstLocal = outQueue.AllocTensor<T>();
        AscendC::LocalTensor<T> srcLocal = inQueue.DeQue<T>();
        AscendC::Duplicate(dstLocal, (T)0, dataSize);
        if constexpr (sharedTmpBufferSize > 0) {
            AscendC::LocalTensor<uint8_t> tmpBuf = bufQueue.Get<uint8_t>();
            AscendC::Rint(dstLocal, srcLocal, tmpBuf, calCount);
        } else {
            AscendC::Rint(dstLocal, srcLocal, calCount);
        }
        outQueue.EnQue(dstLocal);
        inQueue.FreeTensor(srcLocal);
    }
    __aicore__ inline void CopyOut()
    {
        AscendC::LocalTensor<T> dstLocal = outQueue.DeQue<T>();
        AscendC::DataCopy(dstGlobal, dstLocal, dataSize);
        outQueue.FreeTensor(dstLocal);
    }

private:
    AscendC::TPipe* pipe;
    AscendC::TQue<AscendC::QuePosition::VECIN, 1> inQueue;
    AscendC::TQue<AscendC::QuePosition::VECOUT, 1> outQueue;
    AscendC::TBuf<AscendC::TPosition::VECCALC> bufQueue;
    AscendC::GlobalTensor<T> srcGlobal;
    AscendC::GlobalTensor<T> dstGlobal;
}

