template <typename T>
class KernelTrunc {
public:
    __aicore__ inline KernelTrunc() {}
    __aicore__ inline void Init(GM_ADDR srcGm, GM_ADDR dstGm, uint32_t srcSize, uint32_t tmpBufSize, uint32_t calCount,
                                AscendC::TPipe* pipeIn)
    {
        pipe = pipeIn;
        uint32_t oneBlkSize = 32 / sizeof(T);
        uint32_t alignSize = ((srcSize + oneBlkSize - 1) / oneBlkSize) * oneBlkSize;

        srcGlobal.SetGlobalBuffer(reinterpret_cast<__gm__ T*>(srcGm), alignSize);
        dstGlobal.SetGlobalBuffer(reinterpret_cast<__gm__ T*>(dstGm), alignSize);

        pipe->InitBuffer(inQueueX, 1, alignSize * sizeof(T));
        pipe->InitBuffer(outQueue, 1, alignSize * sizeof(T));
        dataSize = srcSize;
        if (tmpBufSize > 0) {
            pipe->InitBuffer(tempBuffer, tmpBufSize * sizeof(T));
        }
    }
    __aicore__ inline void Process(uint32_t tmpBufSize, uint32_t calCount)
    {
        AscendC::AscendCUtils::SetOverflow(1);
        CopyIn();
        Compute(tmpBufSize, calCount);
        CopyOut();
        AscendC::AscendCUtils::SetOverflow(0);
    }

    __aicore__ inline void CopyIn()
    {
        AscendC::LocalTensor<T> srcLocal = inQueueX.AllocTensor<T>();
        AscendC::DataCopy(srcLocal, srcGlobal, dataSize);
        inQueueX.EnQue(srcLocal);
    }
    __aicore__ inline void Compute(uint32_t tmpBufSize, uint32_t calCount)
    {
        AscendC::LocalTensor<T> dstLocal = outQueue.AllocTensor<T>();
        AscendC::LocalTensor<T> srcLocal = inQueueX.DeQue<T>();
        AscendC::LocalTensor<uint8_t> getTempBuffer;
        const T zero = 0;
        AscendC::Duplicate<T>(dstLocal, zero, dataSize);
        if (tmpBufSize > 0) {
            getTempBuffer = tempBuffer.Get<uint8_t>();
        }

        if ((tmpBufSize > 0) && (calCount > 0)) {
            AscendC::Trunc<T>(dstLocal, srcLocal, getTempBuffer, calCount);
        } else if (tmpBufSize > 0) {
            AscendC::Trunc<T>(dstLocal, srcLocal, getTempBuffer);
        } else if (calCount > 0) {
            AscendC::Trunc<T>(dstLocal, srcLocal, calCount);
        } else {
            AscendC::Trunc<T>(dstLocal, srcLocal);
        }

        outQueue.EnQue<T>(dstLocal);
        inQueueX.FreeTensor(srcLocal);
    }
    __aicore__ inline void CopyOut()
    {
        AscendC::LocalTensor<T> dstLocal = outQueue.DeQue<T>();
        AscendC::DataCopy(dstGlobal, dstLocal, dataSize);
        outQueue.FreeTensor(dstLocal);
    }

private:
    AscendC::TPipe* pipe;
    AscendC::TQue<AscendC::QuePosition::VECIN, 1> inQueueX;
    AscendC::TQue<AscendC::QuePosition::VECOUT, 1> outQueue;
    AscendC::TBuf<AscendC::TPosition::VECCALC> tempBuffer;
    AscendC::GlobalTensor<T> srcGlobal;
    AscendC::GlobalTensor<T> dstGlobal;
    uint32_t dataSize = 0;
}

