class KernelAdd {
public:
    __aicore__ inline KernelAdd() = default;
    __aicore__ inline void Init(GM_ADDR x, GM_ADDR y, GM_ADDR z, 
                                 uint32_t totalM, uint32_t totalN,
                                 uint32_t splitM, uint32_t splitN,
                                 uint32_t singleCoreM, uint32_t singleCoreN,
                                 uint32_t dataCopyLen,
                                 bool enableL2Bypass = false)
    {
        uint32_t blockIdx = AscendC::GetBlockIdx();
        uint32_t blockIdxM = blockIdx / splitN;
        uint32_t blockIdxN = blockIdx % splitN;

        this->totalM = totalM;
        this->totalN = totalN;
        this->dataCopyLen = dataCopyLen;

        uint32_t baseCoreM = totalM / splitM;
        uint32_t remainderM = totalM % splitM;
        uint32_t actualCoreM;
        uint32_t startM;
        if (blockIdxM < remainderM) {
            actualCoreM = baseCoreM + 1;
            startM = blockIdxM * actualCoreM;
        } else {
            actualCoreM = baseCoreM;
            startM = remainderM * (baseCoreM + 1) + (blockIdxM - remainderM) * baseCoreM;
        }
        this->singleCoreM = actualCoreM;

        uint32_t baseCoreN = totalN / splitN;
        uint32_t remainderN = totalN % splitN;
        uint32_t actualCoreN;
        uint32_t startN;
        if (blockIdxN < remainderN) {
            actualCoreN = baseCoreN + 1;
            startN = blockIdxN * actualCoreN;
        } else {
            actualCoreN = baseCoreN;
            startN = remainderN * (baseCoreN + 1) + (blockIdxN - remainderN) * baseCoreN;
        }
        this->singleCoreN = actualCoreN;

        uint32_t bufferSize = singleCoreM * totalN;
        xGm.SetGlobalBuffer((__gm__ half *)x + startM * totalN + startN, bufferSize);
        yGm.SetGlobalBuffer((__gm__ half *)y + startM * totalN + startN, bufferSize);
        zGm.SetGlobalBuffer((__gm__ half *)z + startM * totalN + startN, bufferSize);

        if (enableL2Bypass) {
            xGm.SetL2CacheHint(AscendC::CacheMode::CACHE_MODE_DISABLE);
            yGm.SetL2CacheHint(AscendC::CacheMode::CACHE_MODE_DISABLE);
        }
    }

    __aicore__ inline void Process()
    {
        AscendC::LocalTensor<half> xLocal(AscendC::TPosition::VECCALC, xAddr, MAX_DATA_COPY_LEN);
        AscendC::LocalTensor<half> yLocal(AscendC::TPosition::VECCALC, yAddr, MAX_DATA_COPY_LEN);
        AscendC::LocalTensor<half> zLocal(AscendC::TPosition::VECCALC, zAddr, MAX_DATA_COPY_LEN);

        uint32_t rowsPerBlock = dataCopyLen / singleCoreN;
        uint32_t fullBlocks = singleCoreM / rowsPerBlock;
        uint32_t tailRows = singleCoreM % rowsPerBlock;
        uint32_t totalBlocks = fullBlocks + (tailRows > 0 ? 1 : 0);

        AscendC::SetFlag<AscendC::HardEvent::MTE3_MTE2>(EVENT_ID0);

        for (uint32_t loopIdx = 0; loopIdx < totalBlocks; loopIdx++) {
            uint32_t startM = loopIdx * rowsPerBlock;
            uint32_t curRows = (loopIdx < fullBlocks) ? rowsPerBlock : tailRows;
            uint32_t curLen = curRows * singleCoreN;

            AscendC::WaitFlag<AscendC::HardEvent::MTE3_MTE2>(EVENT_ID0);

            uint32_t blockLen = static_cast<uint32_t>(singleCoreN * sizeof(half));
            uint32_t srcStride = static_cast<uint32_t>((totalN - singleCoreN) * sizeof(half));
            uint32_t dstStride = 0;
            AscendC::DataCopyExtParams copyParams = {static_cast<uint16_t>(curRows), blockLen, srcStride, dstStride, 0};
            AscendC::DataCopyPadExtParams<half> padParams = {false, 0, 0, 0};
            AscendC::DataCopyPad<half>(xLocal, xGm[startM * totalN], copyParams, padParams);
            AscendC::DataCopyPad<half>(yLocal, yGm[startM * totalN], copyParams, padParams);

            AscendC::SetFlag<AscendC::HardEvent::MTE2_V>(EVENT_ID0);
            AscendC::WaitFlag<AscendC::HardEvent::MTE2_V>(EVENT_ID0);

            AscendC::Add(zLocal, xLocal, yLocal, curLen);

            AscendC::SetFlag<AscendC::HardEvent::V_MTE3>(EVENT_ID0);
            AscendC::WaitFlag<AscendC::HardEvent::V_MTE3>(EVENT_ID0);

            copyParams.srcStride = 0;
            copyParams.dstStride = srcStride;
            AscendC::DataCopyPad<half>(zGm[startM * totalN], zLocal, copyParams);

            AscendC::SetFlag<AscendC::HardEvent::MTE3_MTE2>(EVENT_ID0);
        }

        AscendC::WaitFlag<AscendC::HardEvent::MTE3_MTE2>(EVENT_ID0);
    }

    __aicore__ inline void ProcessScalar()
    {
        AscendC::LocalTensor<half> xLocal(AscendC::TPosition::VECCALC, xAddr, MAX_DATA_COPY_LEN);
        AscendC::LocalTensor<half> yLocal(AscendC::TPosition::VECCALC, yAddr, MAX_DATA_COPY_LEN);
        AscendC::LocalTensor<half> zLocal(AscendC::TPosition::VECCALC, zAddr, MAX_DATA_COPY_LEN);

        uint32_t totalLoop = singleCoreM * ((singleCoreN + dataCopyLen - 1) / dataCopyLen);
        uint32_t loopIdx = 0;

        for (uint32_t m = 0; m < singleCoreM; m++) {
            for (uint32_t n = 0; n < singleCoreN; n += dataCopyLen) {
                uint32_t curLen = (singleCoreN - n) > dataCopyLen ? dataCopyLen : (singleCoreN - n);

                if (loopIdx != 0) {
                    AscendC::WaitFlag<AscendC::HardEvent::V_MTE2>(EVENT_ID0);
                }

                AscendC::DataCopy(xLocal, xGm[m * totalN + n], curLen);
                AscendC::DataCopy(yLocal, yGm[m * totalN + n], curLen);
                AscendC::SetFlag<AscendC::HardEvent::MTE2_V>(EVENT_ID0);
                AscendC::WaitFlag<AscendC::HardEvent::MTE2_V>(EVENT_ID0);

                if (loopIdx != 0) {
                    AscendC::WaitFlag<AscendC::HardEvent::MTE3_V>(EVENT_ID0);
                }

                for (uint32_t i = 0; i < curLen; i++) {
                    float xVal = (float)xLocal.GetValue(i);
                    float yVal = (float)yLocal.GetValue(i);
                    zLocal.SetValue(i, (half)(xVal + yVal));
                }

                if (loopIdx != (totalLoop - 1)) {
                    AscendC::SetFlag<AscendC::HardEvent::V_MTE2>(EVENT_ID0);
                }
                AscendC::SetFlag<AscendC::HardEvent::V_MTE3>(EVENT_ID0);
                AscendC::WaitFlag<AscendC::HardEvent::V_MTE3>(EVENT_ID0);

                AscendC::DataCopy(zGm[m * totalN + n], zLocal, curLen);
                if (loopIdx != (totalLoop - 1)) {
                    AscendC::SetFlag<AscendC::HardEvent::MTE3_V>(EVENT_ID0);
                }

                loopIdx++;
            }
        }
    }

    __aicore__ inline void ProcessSingle()
    {
        AscendC::LocalTensor<half> xLocal(AscendC::TPosition::VECCALC, xAddr, MAX_DATA_COPY_LEN);
        AscendC::LocalTensor<half> yLocal(AscendC::TPosition::VECCALC, yAddr, MAX_DATA_COPY_LEN);
        AscendC::LocalTensor<half> zLocal(AscendC::TPosition::VECCALC, zAddr, MAX_DATA_COPY_LEN);

        uint32_t totalLoop = singleCoreM * ((singleCoreN + dataCopyLen - 1) / dataCopyLen);
        uint32_t loopIdx = 0;

        for (uint32_t m = 0; m < singleCoreM; m++) {
            for (uint32_t n = 0; n < singleCoreN; n += dataCopyLen) {
                uint32_t curLen = (singleCoreN - n) > dataCopyLen ? dataCopyLen : (singleCoreN - n);

                if (loopIdx != 0) {
                    AscendC::WaitFlag<AscendC::HardEvent::V_MTE2>(EVENT_ID0);
                }

                AscendC::DataCopy(xLocal, xGm[m * totalN + n], curLen);
                AscendC::DataCopy(yLocal, yGm[m * totalN + n], curLen);
                AscendC::SetFlag<AscendC::HardEvent::MTE2_V>(EVENT_ID0);
                AscendC::WaitFlag<AscendC::HardEvent::MTE2_V>(EVENT_ID0);

                if (loopIdx != 0) {
                    AscendC::WaitFlag<AscendC::HardEvent::MTE3_V>(EVENT_ID0);
                }

                AscendC::Add(zLocal, xLocal, yLocal, curLen);

                if (loopIdx != (totalLoop - 1)) {
                    AscendC::SetFlag<AscendC::HardEvent::V_MTE2>(EVENT_ID0);
                }
                AscendC::SetFlag<AscendC::HardEvent::V_MTE3>(EVENT_ID0);
                AscendC::WaitFlag<AscendC::HardEvent::V_MTE3>(EVENT_ID0);

                AscendC::DataCopy(zGm[m * totalN + n], zLocal, curLen);
                if (loopIdx != (totalLoop - 1)) {
                    AscendC::SetFlag<AscendC::HardEvent::MTE3_V>(EVENT_ID0);
                }

                loopIdx++;
            }
        }
    }

    __aicore__ inline void ProcessDoubleBuffer()
    {
        AscendC::LocalTensor<half> xPing(AscendC::TPosition::VECCALC, xAddrPing, MAX_DATA_COPY_LEN);
        AscendC::LocalTensor<half> yPing(AscendC::TPosition::VECCALC, yAddrPing, MAX_DATA_COPY_LEN);
        AscendC::LocalTensor<half> zPing(AscendC::TPosition::VECCALC, zAddrPing, MAX_DATA_COPY_LEN);
        AscendC::LocalTensor<half> xPong(AscendC::TPosition::VECCALC, xAddrPong, MAX_DATA_COPY_LEN);
        AscendC::LocalTensor<half> yPong(AscendC::TPosition::VECCALC, yAddrPong, MAX_DATA_COPY_LEN);
        AscendC::LocalTensor<half> zPong(AscendC::TPosition::VECCALC, zAddrPong, MAX_DATA_COPY_LEN);

        uint32_t rowsPerBlock = dataCopyLen / singleCoreN;
        uint32_t fullBlocks = singleCoreM / rowsPerBlock;
        uint32_t tailRows = singleCoreM % rowsPerBlock;
        uint32_t totalBlocks = fullBlocks + (tailRows > 0 ? 1 : 0);

        AscendC::SetFlag<AscendC::HardEvent::MTE3_MTE2>(EVENT_ID0);
        AscendC::SetFlag<AscendC::HardEvent::MTE3_MTE2>(EVENT_ID1);

        for (uint32_t loopIdx = 0; loopIdx < totalBlocks; loopIdx++) {
            uint32_t startM = loopIdx * rowsPerBlock;
            uint32_t curRows = (loopIdx < fullBlocks) ? rowsPerBlock : tailRows;
            uint32_t curLen = curRows * singleCoreN;

            int32_t eventID = (loopIdx % 2 == 0 ? EVENT_ID0 : EVENT_ID1);
            AscendC::LocalTensor<half> &xLocal = (loopIdx % 2 == 0 ? xPing : xPong);
            AscendC::LocalTensor<half> &yLocal = (loopIdx % 2 == 0 ? yPing : yPong);
            AscendC::LocalTensor<half> &zLocal = (loopIdx % 2 == 0 ? zPing : zPong);

            AscendC::WaitFlag<AscendC::HardEvent::MTE3_MTE2>(eventID);

            uint32_t blockLen = static_cast<uint32_t>(singleCoreN * sizeof(half));
            uint32_t srcStride = static_cast<uint32_t>((totalN - singleCoreN) * sizeof(half));
            uint32_t dstStride = 0;
            AscendC::DataCopyExtParams copyParams = {static_cast<uint16_t>(curRows), blockLen, srcStride, dstStride, 0};
            AscendC::DataCopyPadExtParams<half> padParams = {false, 0, 0, 0};
            AscendC::DataCopyPad<half>(xLocal, xGm[startM * totalN], copyParams, padParams);
            AscendC::DataCopyPad<half>(yLocal, yGm[startM * totalN], copyParams, padParams);

            AscendC::SetFlag<AscendC::HardEvent::MTE2_V>(eventID);
            AscendC::WaitFlag<AscendC::HardEvent::MTE2_V>(eventID);

            AscendC::Add(zLocal, xLocal, yLocal, curLen);

            AscendC::SetFlag<AscendC::HardEvent::V_MTE3>(eventID);
            AscendC::WaitFlag<AscendC::HardEvent::V_MTE3>(eventID);

            copyParams.srcStride = 0;
            copyParams.dstStride = srcStride;
            AscendC::DataCopyPad<half>(zGm[startM * totalN], zLocal, copyParams);

            AscendC::SetFlag<AscendC::HardEvent::MTE3_MTE2>(eventID);
        }

        AscendC::WaitFlag<AscendC::HardEvent::MTE3_MTE2>(EVENT_ID0);
        AscendC::WaitFlag<AscendC::HardEvent::MTE3_MTE2>(EVENT_ID1);
    }

    __aicore__ inline void ProcessDoubleBufferL2Bypass()
    {
        ProcessDoubleBuffer();
    }

    __aicore__ inline void ProcessDoubleBufferBankConflict()
    {
        xGm.SetL2CacheHint(AscendC::CacheMode::CACHE_MODE_DISABLE);
        yGm.SetL2CacheHint(AscendC::CacheMode::CACHE_MODE_DISABLE);

        AscendC::LocalTensor<half> xPing(AscendC::TPosition::VECCALC, xAddrPingBC, MAX_DATA_COPY_LEN);
        AscendC::LocalTensor<half> yPing(AscendC::TPosition::VECCALC, yAddrPingBC, MAX_DATA_COPY_LEN);
        AscendC::LocalTensor<half> zPing(AscendC::TPosition::VECCALC, zAddrPingBC, MAX_DATA_COPY_LEN);
        AscendC::LocalTensor<half> xPong(AscendC::TPosition::VECCALC, xAddrPongBC, MAX_DATA_COPY_LEN);
        AscendC::LocalTensor<half> yPong(AscendC::TPosition::VECCALC, yAddrPongBC, MAX_DATA_COPY_LEN);
        AscendC::LocalTensor<half> zPong(AscendC::TPosition::VECCALC, zAddrPongBC, MAX_DATA_COPY_LEN);

        uint32_t rowsPerBlock = dataCopyLen / singleCoreN;
        uint32_t fullBlocks = singleCoreM / rowsPerBlock;
        uint32_t tailRows = singleCoreM % rowsPerBlock;
        uint32_t totalBlocks = fullBlocks + (tailRows > 0 ? 1 : 0);

        AscendC::SetFlag<AscendC::HardEvent::MTE3_MTE2>(EVENT_ID0);
        AscendC::SetFlag<AscendC::HardEvent::MTE3_MTE2>(EVENT_ID1);

        for (uint32_t loopIdx = 0; loopIdx < totalBlocks; loopIdx++) {
            uint32_t startM = loopIdx * rowsPerBlock;
            uint32_t curRows = (loopIdx < fullBlocks) ? rowsPerBlock : tailRows;
            uint32_t curLen = curRows * singleCoreN;

            int32_t eventID = (loopIdx % 2 == 0 ? EVENT_ID0 : EVENT_ID1);
            AscendC::LocalTensor<half> &xLocal = (loopIdx % 2 == 0 ? xPing : xPong);
            AscendC::LocalTensor<half> &yLocal = (loopIdx % 2 == 0 ? yPing : yPong);
            AscendC::LocalTensor<half> &zLocal = (loopIdx % 2 == 0 ? zPing : zPong);

            AscendC::WaitFlag<AscendC::HardEvent::MTE3_MTE2>(eventID);

            if (curRows == rowsPerBlock) {
                uint32_t blockLen = static_cast<uint32_t>(singleCoreN * sizeof(half));
                uint32_t srcStride = static_cast<uint32_t>((totalN - singleCoreN) * sizeof(half));
                uint32_t dstStride = 0;
                AscendC::DataCopyExtParams copyParams = {static_cast<uint16_t>(curRows), blockLen, srcStride, dstStride, 0};
                AscendC::DataCopyPadExtParams<half> padParams = {false, 0, 0, 0};
                AscendC::DataCopyPad<half>(xLocal, xGm[startM * totalN], copyParams, padParams);
                AscendC::DataCopyPad<half>(yLocal, yGm[startM * totalN], copyParams, padParams);
            } else {
                for (uint32_t m = 0; m < curRows; m++) {
                    AscendC::DataCopy(xLocal[m * singleCoreN], xGm[(startM + m) * totalN], singleCoreN);
                    AscendC::DataCopy(yLocal[m * singleCoreN], yGm[(startM + m) * totalN], singleCoreN);
                }
            }

            AscendC::SetFlag<AscendC::HardEvent::MTE2_V>(eventID);
            AscendC::WaitFlag<AscendC::HardEvent::MTE2_V>(eventID);

            AscendC::Add(zLocal, xLocal, yLocal, curLen);

            AscendC::SetFlag<AscendC::HardEvent::V_MTE3>(eventID);
            AscendC::WaitFlag<AscendC::HardEvent::V_MTE3>(eventID);

            if (curRows == rowsPerBlock) {
                uint32_t blockLen = static_cast<uint32_t>(singleCoreN * sizeof(half));
                uint32_t srcStride = 0;
                uint32_t dstStride = static_cast<uint32_t>((totalN - singleCoreN) * sizeof(half));
                AscendC::DataCopyExtParams copyParams = {static_cast<uint16_t>(curRows), blockLen, srcStride, dstStride, 0};
                AscendC::DataCopyPad<half>(zGm[startM * totalN], zLocal, copyParams);
            } else {
                for (uint32_t m = 0; m < curRows; m++) {
                    AscendC::DataCopy(zGm[(startM + m) * totalN], zLocal[m * singleCoreN], singleCoreN);
                }
            }

            AscendC::SetFlag<AscendC::HardEvent::MTE3_MTE2>(eventID);
        }

        AscendC::WaitFlag<AscendC::HardEvent::MTE3_MTE2>(EVENT_ID0);
        AscendC::WaitFlag<AscendC::HardEvent::MTE3_MTE2>(EVENT_ID1);
    }

private:
    static constexpr uint32_t xAddr = 0;
    static constexpr uint32_t yAddr = MAX_DATA_COPY_LEN * sizeof(half);
    static constexpr uint32_t zAddr = yAddr + MAX_DATA_COPY_LEN * sizeof(half);

    static constexpr uint32_t xAddrPing = 0;
    static constexpr uint32_t yAddrPing = MAX_DATA_COPY_LEN * sizeof(half);
    static constexpr uint32_t zAddrPing = yAddrPing + MAX_DATA_COPY_LEN * sizeof(half);
    static constexpr uint32_t xAddrPong = zAddrPing + MAX_DATA_COPY_LEN * sizeof(half);
    static constexpr uint32_t yAddrPong = xAddrPong + MAX_DATA_COPY_LEN * sizeof(half);
    static constexpr uint32_t zAddrPong = yAddrPong + MAX_DATA_COPY_LEN * sizeof(half);

    static constexpr uint32_t xAddrPingBC = 0;
    static constexpr uint32_t yAddrPingBC = BANK_CONFLICT_DATA_COPY_LEN * sizeof(half);
    static constexpr uint32_t xAddrPongBC = MAX_DATA_COPY_LEN * sizeof(half) * 2;
    static constexpr uint32_t yAddrPongBC = xAddrPongBC + BANK_CONFLICT_DATA_COPY_LEN * sizeof(half);
    static constexpr uint32_t zAddrPingBC = MAX_DATA_COPY_LEN * sizeof(half) * 4;
    static constexpr uint32_t zAddrPongBC = zAddrPingBC + BANK_CONFLICT_DATA_COPY_LEN * sizeof(half);

    AscendC::GlobalTensor<half> xGm;
    AscendC::GlobalTensor<half> yGm;
    AscendC::GlobalTensor<half> zGm;
    uint32_t totalM;
    uint32_t totalN;
    uint32_t singleCoreM;
    uint32_t singleCoreN;
    uint32_t dataCopyLen;
};

extern "C" __vector__ __global__ void add_custom(GM_ADDR x, GM_ADDR y, GM_ADDR z, GM_ADDR tiling)
{
    AscendC::InitSocState();
    KernelAdd op;
    auto tilingData = (__gm__ AddCustomTilingData *)tiling;

    if constexpr (CASE_TYPE == 5) {
        op.Init(x, y, z, 
                tilingData->totalM, tilingData->totalN,
                tilingData->splitM, tilingData->splitN,
                tilingData->singleCoreM, tilingData->singleCoreN,
                tilingData->dataCopyLen,
                true);
        op.ProcessDoubleBufferL2Bypass();
    } else if constexpr (CASE_TYPE == 6) {
        op.Init(x, y, z, 
                tilingData->totalM, tilingData->totalN,
                tilingData->splitM, tilingData->splitN,
                tilingData->singleCoreM, tilingData->singleCoreN,
                tilingData->dataCopyLen,
                false);
        op.ProcessDoubleBufferBankConflict();
    } else {
        op.Init(x, y, z, 
            tilingData->totalM, tilingData->totalN,
            tilingData->splitM, tilingData->splitN,
            tilingData->singleCoreM, tilingData->singleCoreN,
            tilingData->dataCopyLen,
            false);

        if constexpr (CASE_TYPE == 0) {
            op.ProcessScalar();
        } else if constexpr (CASE_TYPE == 1) {
            op.ProcessSingle();
        } else if constexpr (CASE_TYPE == 4) {
            op.ProcessDoubleBuffer();
        } else {
            op.Process();
        }
    }
}

struct ArgInfo {
    std::string fileName;
    size_t length;
};

int32_t main(int32_t argc, char* argv[])
{
    printf("Usage: %s (compile-time CASE_TYPE=%u)\n", argv[0], (uint32_t)CASE_TYPE);
    printf("Running case %u...\n", (uint32_t)CASE_TYPE);

    uint32_t totalM = 8192;
    uint32_t totalN = 8192;
    uint32_t splitM;
    uint32_t splitN;
    uint32_t dataCopyLen;

    if constexpr (CASE_TYPE == 0) {
        splitM = 1;
        splitN = 1;
        dataCopyLen = 4096;
    } else if constexpr (CASE_TYPE == 1) {
        splitM = 1;
        splitN = 1;
        dataCopyLen = 4096;
    } else if constexpr (CASE_TYPE == 2) {
        splitM = 6;
        splitN = 8;
        dataCopyLen = 4096;
    } else if constexpr (CASE_TYPE == 3) {
        splitM = 6;
        splitN = 8;
        dataCopyLen = 16384;
    } else if constexpr (CASE_TYPE == 4) {
        splitM = 6;
        splitN = 8;
        dataCopyLen = 16384;
    } else if constexpr (CASE_TYPE == 5) {
        splitM = 6;
        splitN = 8;
        dataCopyLen = 16384;
    } else if constexpr (CASE_TYPE == 6) {
        splitM = 6;
        splitN = 8;
        dataCopyLen = 16256;
    } else {
        splitM = 1; splitN = 1; dataCopyLen = 4096;
    }

    uint32_t numBlocks = splitM * splitN;

    uint32_t singleCoreM = totalM / splitM;
    uint32_t singleCoreN = totalN / splitN;
    uint32_t dataLen = totalM * totalN;

    size_t inputByteSize = dataLen * sizeof(uint16_t);
    size_t outputByteSize = dataLen * sizeof(uint16_t);
    AddCustomTilingData tiling;
    tiling.caseType = CASE_TYPE;
    tiling.totalM = totalM;
    tiling.totalN = totalN;
    tiling.splitM = splitM;
    tiling.splitN = splitN;
    tiling.singleCoreM = singleCoreM;
    tiling.singleCoreN = singleCoreN;
    tiling.dataCopyLen = dataCopyLen;

    std::vector<ArgInfo> inputsInfo = {{"./input/input_x.bin", inputByteSize}, {"./input/input_y.bin", inputByteSize}};
    std::vector<ArgInfo> outputsInfo = {{"./output/output.bin", outputByteSize}};

    aclInit(nullptr);
    int32_t deviceId = 0;
    aclrtSetDevice(deviceId);
    aclrtStream stream = nullptr;
    aclrtCreateStream(&stream);

    std::vector<uint8_t *> inputHost(inputsInfo.size());
    std::vector<uint8_t *> inputDevice(inputsInfo.size());
    std::vector<uint8_t *> outputHost(outputsInfo.size());
    std::vector<uint8_t *> outputDevice(outputsInfo.size());
    uint8_t *tilingDevice;

    aclrtMalloc((void **)(&tilingDevice), sizeof(AddCustomTilingData), ACL_MEM_MALLOC_HUGE_FIRST);
    aclrtMemcpy(tilingDevice, sizeof(AddCustomTilingData), (uint8_t *)&tiling, sizeof(AddCustomTilingData), ACL_MEMCPY_HOST_TO_DEVICE);

    for (uint32_t i = 0; i < inputsInfo.size(); i++) {
        aclrtMallocHost((void **)(&inputHost[i]), inputsInfo[i].length);
        aclrtMalloc((void **)(&inputDevice[i]), inputsInfo[i].length, ACL_MEM_MALLOC_HUGE_FIRST);
        ReadFile(inputsInfo[i].fileName, inputsInfo[i].length, inputHost[i], inputsInfo[i].length);
        aclrtMemcpy(inputDevice[i], inputsInfo[i].length, inputHost[i], inputsInfo[i].length, ACL_MEMCPY_HOST_TO_DEVICE);
    }

    for (uint32_t i = 0; i < outputsInfo.size(); i++) {
        aclrtMallocHost((void **)(&outputHost[i]), outputsInfo[i].length);
        aclrtMalloc((void **)(&outputDevice[i]), outputsInfo[i].length, ACL_MEM_MALLOC_HUGE_FIRST);
    }

    add_custom<<<numBlocks, nullptr, stream>>>(inputDevice[0], inputDevice[1], outputDevice[0], tilingDevice);
    aclrtSynchronizeStream(stream);

    aclrtFree(tilingDevice);
    for (uint32_t i = 0; i < outputsInfo.size(); i++) {
        aclrtMemcpy(outputHost[i], outputsInfo[i].length, outputDevice[i], outputsInfo[i].length, ACL_MEMCPY_DEVICE_TO_HOST);
        WriteFile(outputsInfo[i].fileName, outputHost[i], outputsInfo[i].length);
        aclrtFree(outputDevice[i]);
        aclrtFreeHost(outputHost[i]);
    }

    for (uint32_t i = 0; i < inputsInfo.size(); i++) {
        aclrtFree(inputDevice[i]);
        aclrtFreeHost(inputHost[i]);
    }

    aclrtDestroyStream(stream);
    aclrtResetDevice(deviceId);
    aclFinalize();

    printf("Case %u completed.\n", (uint32_t)CASE_TYPE);
    return 0;
}

