template <bool isTiling>
void GenerateTilingSingleCore(platform_ascendc::PlatformAscendC* ascendcPlatform, uint8_t* tilingBuf)
{
    optiling::TCubeTiling tilingData;
    matmul_tiling::MatmulApiTiling tilingApi(*ascendcPlatform);
    SetTilingTypes<matmul_tiling::MatmulApiTiling, isTiling>(tilingApi, tilingData);
    if constexpr (!isTiling) {
        tilingData.set_baseK(64);
    }
    SetL1(tilingData);
    uint32_t tcubeTilingSize = tilingData.GetDataSize();
    tilingData.SaveToBuffer(tilingBuf, tcubeTilingSize);
}
template <bool isSplit, bool isMdl, bool isL1Cache, bool isL2Cache>
void GenerateTilingMultiCore(platform_ascendc::PlatformAscendC* ascendcPlatform, uint8_t* tilingBuf)
{
    optiling::TCubeTiling tilingData;
    matmul_tiling::MultiCoreMatmulTiling tilingApi(*ascendcPlatform);
    tilingApi.SetDim(ascendcPlatform->GetCoreNumAic());
    if constexpr (isSplit && !isL2Cache) {
        tilingApi.SetSingleShape(SINGLE_M_SPLIT, SINGLE_N_SPLIT, K);
    } else if constexpr (!isSplit && !isL2Cache) {
        tilingApi.SetSingleShape(SINGLE_M, SINGLE_N, K);
    } else {
        tilingApi.SetSingleShape(SINGLE_M_L2CACHE, SINGLE_N, K);
    }
    SetTilingTypes<matmul_tiling::MultiCoreMatmulTiling, true>(tilingApi, tilingData);

    if constexpr (!isMdl) {
        SetL1(tilingData);
    } else if constexpr (isMdl && isL1Cache) {
        tilingData.set_depthA1(TILING_DEPTHA1_PARAM);
        tilingData.set_stepKa(TILING_STEPKA_PARAM);
    }
    uint32_t tcubeTilingSize = tilingData.GetDataSize();
    tilingData.SaveToBuffer(tilingBuf, tcubeTilingSize);
}

int32_t main(int32_t argc, char* argv[])
{
    printf("Usage: %s (compile-time CASE_TYPE=%u)\n", argv[0], (uint32_t)CASE_TYPE);
    printf("Running case %u...\n", (uint32_t)CASE_TYPE);

    const char* modeName = "";
    uint32_t numBlocks = 1;
    uint32_t singleM = SINGLE_M;
    uint32_t singleN = SINGLE_N;
    uint32_t singleK = SINGLE_K;
    auto ascendc = platform_ascendc::PlatformAscendCManager::GetInstance();

    if constexpr (CASE_TYPE == 0) {
        modeName = "Single Core Basic";
        numBlocks = 1;
    } else if constexpr (CASE_TYPE == 1) {
        modeName = "Single Core Tiling";
        numBlocks = 1;
    } else if constexpr (CASE_TYPE == 2) {
        modeName = "Multi Core Split 2 12";
        numBlocks = CORE_NUM;
    } else if constexpr (CASE_TYPE == 3) {
        modeName = "Multi Core Split 4 6";
        numBlocks = CORE_NUM;
    } else if constexpr (CASE_TYPE == 4) {
        modeName = "Multi Core MDL";
        numBlocks = CORE_NUM;
    } else if constexpr (CASE_TYPE == 5) {
        modeName = "Multi Core MDL L1Cache";
        numBlocks = CORE_NUM;
    } else if constexpr (CASE_TYPE == 6) {
        modeName = "Multi Core MDL L1Cache L2Cache";
        numBlocks = CORE_NUM;
        singleM = 1024;
    } else if constexpr (CASE_TYPE == 7) {
        modeName = "Multi Core MDL L1Cache L2Cache Constant Tiling";
        numBlocks = CORE_NUM;
        singleM = 1024;
    } else if constexpr (CASE_TYPE == 8) {
        modeName = "Multi Core MDL L1Cache L2Cache Constant Tiling UnitFlag";
        numBlocks = CORE_NUM;
        singleM = 1024;
    } else {
        std::cout << "Invalid CASE_TYPE: " << CASE_TYPE << std::endl;
        return -1;
    }

    std::cout << "Running mode: " << modeName << std::endl;

    size_t aFileSize = static_cast<size_t>(M * K) * sizeof(uint16_t);
    size_t bFileSize = static_cast<size_t>(K * N) * sizeof(uint16_t);
    size_t cFileSize = static_cast<size_t>(M * N) * sizeof(uint16_t);
    size_t biasFileSize = static_cast<size_t>(N) * sizeof(uint16_t);

    size_t tilingFileSize;
    uint8_t* tilingBuf = nullptr;

    if constexpr (CASE_TYPE == 7 || CASE_TYPE == 8) {
        tilingFileSize = sizeof(MatmulProblemShape);
    } else {
        tilingFileSize = sizeof(TCubeTiling);
        tilingBuf = (uint8_t*)malloc(tilingFileSize);

        if constexpr (CASE_TYPE == 0) {
            GenerateTilingSingleCore(ascendc, tilingBuf);
        } else if constexpr (CASE_TYPE == 1) {
            GenerateTilingSingleCore<true>(ascendc, tilingBuf);
        } else if constexpr (CASE_TYPE == 2) {
            GenerateTilingMultiCore<true>(ascendc, tilingBuf);
        } else if constexpr (CASE_TYPE == 3) {
            GenerateTilingMultiCore(ascendc, tilingBuf);
        } else if constexpr (CASE_TYPE == 4) {
            GenerateTilingMultiCore<false, true>(ascendc, tilingBuf);
        } else if constexpr (CASE_TYPE == 5) {
            GenerateTilingMultiCore<false, true, true>(ascendc, tilingBuf);
        } else if constexpr (CASE_TYPE == 6) {
            GenerateTilingMultiCore<false, true, true, true>(ascendc, tilingBuf);
        }
    }

    size_t userWorkspaceSize = 0;
    size_t systemWorkspaceSize = static_cast<size_t>(ascendc->GetLibApiWorkSpaceSize());
    size_t workspaceSize = userWorkspaceSize + systemWorkspaceSize;

    int32_t deviceId = 0;
    aclrtStream stream = nullptr;
    aclrtContext context;

    aclInit(nullptr);
    aclrtSetDevice(deviceId);
    aclrtCreateContext(&context, deviceId);
    aclrtCreateStream(&stream);

    uint8_t* aHost;
    uint8_t* aDevice;
    aclrtMallocHost((void**)(&aHost), aFileSize);
    aclrtMalloc((void**)&aDevice, aFileSize, ACL_MEM_MALLOC_HUGE_FIRST);
    ReadFile("./input/x1_gm.bin", aFileSize, aHost, aFileSize);
    aclrtMemcpy(aDevice, aFileSize, aHost, aFileSize, ACL_MEMCPY_HOST_TO_DEVICE);

    uint8_t* bHost;
    uint8_t* bDevice;
    aclrtMallocHost((void**)(&bHost), bFileSize);
    aclrtMalloc((void**)&bDevice, bFileSize, ACL_MEM_MALLOC_HUGE_FIRST);
    ReadFile("./input/x2_gm.bin", bFileSize, bHost, bFileSize);
    aclrtMemcpy(bDevice, bFileSize, bHost, bFileSize, ACL_MEMCPY_HOST_TO_DEVICE);

    uint8_t* biasHost;
    uint8_t* biasDevice;
    if (IS_BIAS) {
        aclrtMallocHost((void**)(&biasHost), biasFileSize);
        aclrtMalloc((void**)&biasDevice, biasFileSize, ACL_MEM_MALLOC_HUGE_FIRST);
        ReadFile("./input/bias_gm.bin", biasFileSize, biasHost, biasFileSize);
        aclrtMemcpy(biasDevice, biasFileSize, biasHost, biasFileSize, ACL_MEMCPY_HOST_TO_DEVICE);
    }

    uint8_t* cHost;
    uint8_t* cDevice;
    aclrtMallocHost((void**)(&cHost), cFileSize);
    aclrtMalloc((void**)&cDevice, cFileSize, ACL_MEM_MALLOC_HUGE_FIRST);

    uint8_t* workspaceDevice;
    aclrtMalloc((void**)&workspaceDevice, workspaceSize, ACL_MEM_MALLOC_HUGE_FIRST);

    uint8_t* tilingHost;
    uint8_t* tilingDevice;
    aclrtMallocHost((void**)(&tilingHost), tilingFileSize);
    aclrtMalloc((void**)&tilingDevice, tilingFileSize, ACL_MEM_MALLOC_HUGE_FIRST);

    if constexpr (CASE_TYPE == 7 || CASE_TYPE == 8) {
        const MatmulProblemShape shapes{numBlocks, M, N, K, singleM, singleN, singleK, 0};
        aclrtMemcpy(tilingHost, tilingFileSize, &shapes, tilingFileSize, ACL_MEMCPY_HOST_TO_HOST);
    } else {
        aclrtMemcpy(tilingHost, tilingFileSize, tilingBuf, tilingFileSize, ACL_MEMCPY_HOST_TO_HOST);
    }
    aclrtMemcpy(tilingDevice, tilingFileSize, tilingHost, tilingFileSize, ACL_MEMCPY_HOST_TO_DEVICE);

    constexpr auto selectedKernel = []() {
        if constexpr (CASE_TYPE >= 0 && CASE_TYPE <= 3) {
            return matmul_custom;
        } else if constexpr (CASE_TYPE == 4 || CASE_TYPE == 5) {
            return matmul_custom_mdl;
        } else if constexpr (CASE_TYPE == 6) {
            return matmul_custom_mdl_l2cache;
        } else if constexpr (CASE_TYPE == 7) {
            return matmul_custom_mdl_l2cache_constant;
        } else if constexpr (CASE_TYPE == 8) {
            return matmul_custom_mdl_l2cache_constant_unitflag;
        }
    }();
    selectedKernel<<<numBlocks, nullptr, stream>>>(aDevice, bDevice, biasDevice, cDevice, workspaceDevice, tilingDevice);

    aclrtSynchronizeStream(stream);
    aclrtMemcpy(cHost, cFileSize, cDevice, cFileSize, ACL_MEMCPY_DEVICE_TO_HOST);
    WriteFile("./output/output.bin", cHost, cFileSize);
    aclrtFree(aDevice);
    aclrtFreeHost(aHost);
    aclrtFree(bDevice);
    aclrtFreeHost(bHost);
    if (IS_BIAS) {
        aclrtFree(biasDevice);
        aclrtFreeHost(biasHost);
    }
    aclrtFree(workspaceDevice);
    aclrtFree(tilingDevice);
    aclrtFreeHost(tilingHost);
    aclrtFree(cDevice);
    aclrtFreeHost(cHost);

    aclrtDestroyStream(stream);
    aclrtDestroyContext(context);
    aclrtResetDevice(deviceId);
    aclFinalize();

    if (tilingBuf != nullptr) {
        free(tilingBuf);
    }
    return 0;
}

template <typename T>
class Kernel {
public:
    __aicore__ inline void Init(GM_ADDR x, GM_ADDR y, uint32_t count, AscendC::TPipe* pipeIn)
    {
        this->pipe = pipeIn;
        this->count = count;
        this->xGm.SetGlobalBuffer(reinterpret_cast<__gm__ T*>(x));
        this->yGm.SetGlobalBuffer(reinterpret_cast<__gm__ T*>(y));
        this->pipe->InitBuffer(inQueueX, 1, sizeof(T) * count);
        this->pipe->InitBuffer(outQueueY, 1, sizeof(T) * count);
    }
    __aicore__ inline void CopyIn()
    {
        AscendC::LocalTensor<T> xLocal = inQueueX.AllocTensor<T>();
        AscendC::Duplicate<T>(xLocal, 0, count);
        AscendC::DataCopy(xLocal, xGm, count);
        inQueueX.EnQue<T>(xLocal);
    }
    __aicore__ inline void Compute()
    {
        AscendC::LocalTensor<T> xLocal = inQueueX.DeQue<T>();
        AscendC::LocalTensor<T> yLocal = outQueueY.AllocTensor<T>();
        __ubuf__ T* srcAddr = reinterpret_cast<__ubuf__ T*>(xLocal.GetPhyAddr());
        __ubuf__ T* dstAddr = reinterpret_cast<__ubuf__ T*>(yLocal.GetPhyAddr());
        constexpr uint32_t oneRepeatSize = AscendC::GetVecLen() / sizeof(T);
        uint16_t repeatTimes = AscendC::CeilDivision(count, oneRepeatSize);
        AscendC::VF_CALL<LoadVF<T>>(srcAddr, dstAddr, oneRepeatSize, repeatTimes, count);
        outQueueY.EnQue<T>(yLocal);
    }
    __aicore__ inline void CopyOut()
    {
        AscendC::LocalTensor<T> yLocal = outQueueY.DeQue<T>();
        AscendC::DataCopy(yGm, yLocal, count);
    }
    __aicore__ inline void Process()
    {
        CopyIn();
        Compute();
        CopyOut();
    }

private:
    AscendC::TPipe* pipe = nullptr;
    uint32_t count;
    AscendC::GlobalTensor<T> xGm;
    AscendC::GlobalTensor<T> yGm;
    AscendC::TQue<AscendC::TPosition::VECIN, 1> inQueueX;
    AscendC::TQue<AscendC::TPosition::VECOUT, 1> outQueueY;
}

__global__ __vector__ void optimize_vf_continious_align_kernel(GM_ADDR x, GM_ADDR y)
{
    AscendC::TPipe pipe;
    Kernel<float> kernel;
    kernel.Init(x, y, 1024, &pipe);
    kernel.Process();
}

template <typename T>
class Kernel {
public:
    __aicore__ inline void Init(GM_ADDR x, GM_ADDR y, GM_ADDR z, uint32_t count, AscendC::TPipe* pipeIn)
    {
        this->pipe = pipeIn;
        this->count = count;
        this->xGm.SetGlobalBuffer(reinterpret_cast<__gm__ T*>(x));
        this->yGm.SetGlobalBuffer(reinterpret_cast<__gm__ T*>(y));
        this->zGm.SetGlobalBuffer(reinterpret_cast<__gm__ T*>(z));
        this->pipe->InitBuffer(inQueueX, 1, sizeof(T) * count);
        this->pipe->InitBuffer(inQueueY, 1, sizeof(T) * count);
        this->pipe->InitBuffer(outQueueZ, 1, sizeof(T) * count);
    }
    __aicore__ inline void CopyIn()
    {
        AscendC::LocalTensor<T> xLocal = inQueueX.AllocTensor<T>();
        AscendC::LocalTensor<T> yLocal = inQueueY.AllocTensor<T>();
        AscendC::DataCopy(xLocal, xGm, count);
        AscendC::DataCopy(yLocal, yGm, count);
        inQueueX.EnQue<T>(xLocal);
        inQueueY.EnQue<T>(yLocal);
    }
    __aicore__ inline void Compute()
    {
        AscendC::LocalTensor<T> xLocal = inQueueX.DeQue<T>();
        AscendC::LocalTensor<T> yLocal = inQueueY.DeQue<T>();
        AscendC::LocalTensor<T> zLocal = outQueueZ.AllocTensor<T>();
        __ubuf__ T* src0Addr = reinterpret_cast<__ubuf__ T*>(xLocal.GetPhyAddr());
        __ubuf__ T* src1Addr = reinterpret_cast<__ubuf__ T*>(yLocal.GetPhyAddr());
        __ubuf__ T* dstAddr = reinterpret_cast<__ubuf__ T*>(zLocal.GetPhyAddr());
        constexpr uint32_t oneRepeatSize = AscendC::GetVecLen() / sizeof(T);
        uint16_t repeatTimes = AscendC::CeilDivision(count, oneRepeatSize);
        AscendC::VF_CALL<AddVF<T>>(src0Addr, src1Addr, dstAddr, oneRepeatSize, repeatTimes, count * 2);
        outQueueZ.EnQue<T>(zLocal);
    }
    __aicore__ inline void CopyOut()
    {
        AscendC::LocalTensor<T> zLocal = outQueueZ.DeQue<T>();
        AscendC::DataCopy(zGm, zLocal, count);
    }
    __aicore__ inline void Process()
    {
        CopyIn();
        Compute();
        CopyOut();
    }

private:
    AscendC::TPipe* pipe = nullptr;
    uint32_t count;
    AscendC::GlobalTensor<T> xGm;
    AscendC::GlobalTensor<T> yGm;
    AscendC::GlobalTensor<T> zGm;
    AscendC::TQue<AscendC::TPosition::VECIN, 1> inQueueX;
    AscendC::TQue<AscendC::TPosition::VECIN, 1> inQueueY;
    AscendC::TQue<AscendC::TPosition::VECOUT, 1> outQueueZ;
}

