int32_t main(int32_t argc, char *argv[]) {
    uint8_t *tiling = nullptr;
    size_t tilingSize = TILINGDATA_SIZE * sizeof(uint32_t);

    aclInit(nullptr);
    int32_t deviceId = 0;
    aclrtSetDevice(deviceId);
    aclrtStream stream = nullptr;
    aclrtCreateStream(&stream);

    uint8_t *xHost, *yHost;
    uint8_t *xDevice, *yDevice;

    aclrtMallocHost((void **)(&tiling), tilingSize);

    GenerateTiling(tiling);

    auto tilingData = reinterpret_cast<AddsCustomTilingData *>(tiling);

    size_t inputSize = tilingData->m * tilingData->n * sizeof(float);
    size_t outputSize = tilingData->m * tilingData->n * sizeof(float);

    aclrtMallocHost((void **)(&xHost), inputSize);
    aclrtMallocHost((void **)(&yHost), outputSize);

    aclrtMalloc((void **)&xDevice, inputSize, ACL_MEM_MALLOC_HUGE_FIRST);
    aclrtMalloc((void **)&yDevice, outputSize, ACL_MEM_MALLOC_HUGE_FIRST);

    ReadFile("./input/input_x.bin", inputSize, xHost, inputSize);

    // Copy host memory to device memory
    aclrtMemcpy(xDevice, inputSize, xHost, inputSize, ACL_MEMCPY_HOST_TO_DEVICE);

    // Execute the kernel
    AddsCustomTilingData tiling_data;
    aclrtMemcpy(&tiling_data, sizeof(AddsCustomTilingData), tiling, sizeof(AddsCustomTilingData), ACL_MEMCPY_DEVICE_TO_HOST);

    adds_custom_v1<<<USED_CORE_NUM, nullptr, stream>>>(xDevice, yDevice, 0, tiling_data);
    // Wait for the stop event to complete
    aclrtSynchronizeStream(stream);
    // Copy result to host memory and write to output file
    aclrtMemcpy(yHost, outputSize, yDevice, outputSize, ACL_MEMCPY_DEVICE_TO_HOST);
    WriteFile("./output/output_z_1.bin", yHost, outputSize);

    adds_custom_v2<<<USED_CORE_NUM, nullptr, stream>>>(xDevice, yDevice, 0, tiling_data);
    // Wait for the stop event to complete
    aclrtSynchronizeStream(stream);
    // Copy result to host memory and write to output file
    aclrtMemcpy(yHost, outputSize, yDevice, outputSize, ACL_MEMCPY_DEVICE_TO_HOST);
    WriteFile("./output/output_z_2.bin", yHost, outputSize);

    adds_custom_v3<<<USED_CORE_NUM, nullptr, stream>>>(xDevice, yDevice, 0, tiling_data);
    // Wait for the stop event to complete
    aclrtSynchronizeStream(stream);
    // Copy result to host memory and write to output file
    aclrtMemcpy(yHost, outputSize, yDevice, outputSize, ACL_MEMCPY_DEVICE_TO_HOST);
    WriteFile("./output/output_z_3.bin", yHost, outputSize);

    // Clean up memory
    aclrtFree(xDevice);
    aclrtFree(yDevice);
    aclrtFreeHost(xHost);
    aclrtFreeHost(yHost);
    aclrtFreeHost(tiling);

    aclrtDestroyStream(stream);
    aclrtResetDevice(deviceId);
    aclFinalize();

    return 0;
}

template<typename T>
class Kernel {
    public:  
    __aicore__ inline void Init(GM_ADDR x, GM_ADDR y, uint32_t count, AscendC::TPipe* pipeIn)
    {
        this->pipe = pipeIn;
        this->count = count;
        this->xGm.SetGlobalBuffer(reinterpret_cast<__gm__ T*>(x));
        this->yGm.SetGlobalBuffer(reinterpret_cast<__gm__ T*>(y));
        this->pipe->InitBuffer(inQueueX, 1, sizeof(T) * count);
        this->pipe->InitBuffer(outQueueY, 1, sizeof(T) * count);
    }
    __aicore__ inline void CopyIn()
    {
        AscendC::LoopModeParams loopModeParams;
        loopModeParams.loop1Size = 2;
        loopModeParams.loop2Size = 2;
        loopModeParams.loop1SrcStride = 96;
        loopModeParams.loop1DstStride = 128;
        loopModeParams.loop2SrcStride = 192;
        loopModeParams.loop2DstStride = 288;
        AscendC::LocalTensor<T> xLocal = inQueueX.AllocTensor<T>();
        AscendC::Duplicate<T>(xLocal, 0, count);
        AscendC::DataCopyParams dataCopyParams;
        dataCopyParams.blockCount = 2;
        dataCopyParams.blockLen = 48;
        dataCopyParams.srcStride = 0;
        dataCopyParams.dstStride = 0;
        AscendC::DataCopyPadParams dataCopyPadParams;
        dataCopyPadParams.isPad = 0;
        dataCopyPadParams.leftPadding = 0;
        dataCopyPadParams.rightPadding = 0;
        dataCopyPadParams.paddingValue = 0;
        AscendC::SetLoopModePara(loopModeParams, AscendC::DataCopyMVType::OUT_TO_UB);
        AscendC::DataCopyPad<T, AscendC::PaddingMode::Compact>(xLocal, xGm, dataCopyParams, dataCopyPadParams);
        AscendC::ResetLoopModePara(AscendC::DataCopyMVType::OUT_TO_UB);
        inQueueX.EnQue<T>(xLocal);
    }
    __aicore__ inline void Compute()
    {
        AscendC::LocalTensor<T> xLocal = inQueueX.DeQue<T>();
        AscendC::LocalTensor<T> yLocal = outQueueY.AllocTensor<T>();
        AscendC::Duplicate<T>(yLocal, 0, count);
        DataCopy(yLocal, xLocal, count);
        outQueueY.EnQue<T>(yLocal);
    }
    __aicore__ inline void CopyOut()
    {
        AscendC::LocalTensor<T> yLocal = outQueueY.DeQue<T>();
        AscendC::DataCopy(yGm, yLocal, count);
    }
    __aicore__ inline void Process()
    {
        CopyIn();
        Compute();
        CopyOut();
    }
    private: 
    AscendC::TPipe* pipe = nullptr;
    uint32_t count;
    AscendC::GlobalTensor<T> xGm;
    AscendC::GlobalTensor<T> yGm;
    AscendC::TQue<AscendC::TPosition::VECIN, 1> inQueueX;
    AscendC::TQue<AscendC::TPosition::VECOUT, 1> outQueueY;
}

