    {
        this->m = m;
        this->n = n;
        this->k = k;
    }
    __aicore__ inline void Init(GM_ADDR aGm, GM_ADDR cGm, AscendC::TPipe* pipeIn)
    {
        aGlobal.SetGlobalBuffer((__gm__ T*)aGm);
        cGlobal.SetGlobalBuffer((__gm__ T*)cGm);
        pipe = pipeIn;
        pipe->InitBuffer(inQueueA1, 1, m * k * sizeof(T));
    }

    // gm -> A1
    __aicore__ inline void CopyGmToA1()
    {
        AscendC::LocalTensor<T> leftMatrix = inQueueA1.AllocTensor<T>();
        AscendC::DataCopy(leftMatrix, aGlobal, m * k);
        inQueueA1.EnQue(leftMatrix);
    }

    __aicore__ inline void CopyL1ToGm()
    {
        AscendC::LocalTensor<T> leftMatrix = inQueueA1.DeQue<T>();
        AscendC::DataCopy(cGlobal, leftMatrix, m * k);
    }

    __aicore__ inline void IterateAll()
    {
        CopyGmToA1();
        AscendC::SetFlag<AscendC::HardEvent::MTE2_MTE3>(EVENT_ID0);
        AscendC::WaitFlag<AscendC::HardEvent::MTE2_MTE3>(EVENT_ID0);
        CopyL1ToGm();
    }

private:
    AscendC::TPipe* pipe;
    uint32_t m = 0;
    uint32_t n = 0;
    uint32_t k = 0;
    AscendC::TQue<AscendC::TPosition::A1, 1, 1> inQueueA1;
    AscendC::GlobalTensor<T> aGlobal;
    AscendC::GlobalTensor<T> cGlobal;
};

