#include "acl/acl.h"
#include "kernel_operator.h"
#include "data_utils.h"

template <typename T, typename U, typename S, typename V>
class Kernel {
public:
    __aicore__ inline Kernel(uint32_t m, uint32_t n, uint32_t k)
    {
        this->m = m;
        this->n = n;
        this->k = k;
    }
    __aicore__ inline void Init(GM_ADDR aGm, GM_ADDR bGm, GM_ADDR cGm, AscendC::TPipe* pipeIn)
    {
        pipe = pipeIn;
        aGlobal.SetGlobalBuffer((__gm__ T*)aGm);
        bGlobal.SetGlobalBuffer((__gm__ U*)bGm);
        cGlobal.SetGlobalBuffer((__gm__ S*)cGm);
        pipe->InitBuffer(inQueueA1, 1, m * k * sizeof(T));
        pipe->InitBuffer(inQueueB1, 1, n * k * sizeof(U));
        pipe->InitBuffer(inQueueA2, 1, m * k * sizeof(T));
        pipe->InitBuffer(inQueueB2, 1, n * k * sizeof(U));
        pipe->InitBuffer(inQueueCO1, 1, m * n * sizeof(S));
    }

    // gm -> A1
    __aicore__ inline void CopyGmToA1()
    {
        AscendC::LocalTensor<T> leftMatrix = inQueueA1.AllocTensor<T>();
        AscendC::Nd2NzParams intriParams1{1, 64, 128, 0, 128, 64, 1, 0};
        AscendC::DataCopy(leftMatrix, aGlobal, intriParams1);
        inQueueA1.EnQue(leftMatrix);
    }

    // gm -> B1
    __aicore__ inline void CopyGmToB1()
    {
        AscendC::LocalTensor<U> rightMatrix = inQueueB1.AllocTensor<U>();
        AscendC::Nd2NzParams intriParams2{1, 128, 128, 0, 128, 128, 1, 0};
        AscendC::DataCopy(rightMatrix, bGlobal, intriParams2);
        inQueueB1.EnQue(rightMatrix);
    }

    __aicore__ inline void Compute()
    {
        AscendC::MmadParams mmadParams;
        mmadParams.m = m;
        mmadParams.n = n;
        mmadParams.k = k;
        mmadParams.isBias = false;
        AscendC::LocalTensor<S> co1Local = inQueueCO1.AllocTensor<S>();
        AscendC::LocalTensor<T> a2 = inQueueA2.DeQue<T>();
        AscendC::LocalTensor<U> b2 = inQueueB2.DeQue<U>();
        AscendC::Mmad(co1Local, a2, b2, mmadParams);
        inQueueA2.FreeTensor(a2);
        inQueueB2.FreeTensor(b2);
        inQueueCO1.EnQue(co1Local);
    }

    __aicore__ inline void CopyL0CToGm()
    {
        AscendC::LocalTensor<S> co1Local = inQueueCO1.DeQue<S>();
        AscendC::FixpipeParamsV220 fixpipeParams;
        fixpipeParams.nSize = n;
        fixpipeParams.mSize = m;
        fixpipeParams.srcStride = m;
        fixpipeParams.dstStride = n;
        fixpipeParams.ndNum = 1;
        fixpipeParams.srcNdStride = 2;
        fixpipeParams.dstNdStride = m * n;
        fixpipeParams.quantPre = QuantMode_t::NoQuant;
        AscendC::Fixpipe<S, S, AscendC::CFG_ROW_MAJOR>(cGlobal, co1Local, fixpipeParams);
        inQueueCO1.FreeTensor(co1Local);
    }

    __aicore__ inline void Load2DA1ToL0A()
    {
        AscendC::LocalTensor<T> a1 = inQueueA1.DeQue<T>();
        AscendC::LocalTensor<T> a2 = inQueueA2.AllocTensor<T>();
        AscendC::LoadData2DParamsV2 loadDataParams;
        loadDataParams.mStartPosition = 0;
        loadDataParams.kStartPosition = 0;
        loadDataParams.mStep = AscendC::DivCeil(m, 16);
        loadDataParams.kStep = AscendC::DivCeil(k * sizeof(T), 32);
        loadDataParams.srcStride = AscendC::DivCeil(m, 16);
        loadDataParams.dstStride = AscendC::DivCeil(m, 16);
        loadDataParams.sid = 0;
        loadDataParams.ifTranspose = false;
        AscendC::LoadData(a2, a1, loadDataParams);
        inQueueA2.EnQue(a2);
        inQueueA1.FreeTensor(a1);
    }

    __aicore__ inline void Load2DA1ToL0B()
    {
        AscendC::LocalTensor<U> b1 = inQueueB1.DeQue<U>();
        AscendC::LocalTensor<U> b2 = inQueueB2.AllocTensor<U>();
        uint16_t nAlign = AscendC::DivCeil(n * sizeof(U), 32);
        uint16_t kAlign = AscendC::DivCeil(k, 16);
        AscendC::LoadData2DParamsV2 loadDataParams;
        loadDataParams.mStartPosition = 0;
        loadDataParams.kStartPosition = 0;
        loadDataParams.mStep = kAlign;
        loadDataParams.kStep = nAlign;
        loadDataParams.srcStride = kAlign;
        loadDataParams.dstStride = nAlign;
        if (AscendC::IsSameType<U, float>::value) {
            loadDataParams.dstStride = nAlign / 2;
        }
        loadDataParams.sid = 0;
        loadDataParams.ifTranspose = true;
        AscendC::LoadData(b2, b1, loadDataParams);
        inQueueB2.EnQue(b2);
        inQueueB1.FreeTensor(b1);
    }

    __aicore__ inline void IterateAll()
    {
        CopyGmToA1();
        CopyGmToB1();
        AscendC::SetFlag<AscendC::HardEvent::MTE2_MTE1>(EVENT_ID0);
        AscendC::WaitFlag<AscendC::HardEvent::MTE2_MTE1>(EVENT_ID0);
        Load2DA1ToL0A();
        Load2DA1ToL0B();
        AscendC::SetFlag<AscendC::HardEvent::MTE1_M>(EVENT_ID1);
        AscendC::WaitFlag<AscendC::HardEvent::MTE1_M>(EVENT_ID1);
        Compute();
        AscendC::SetFlag<AscendC::HardEvent::M_FIX>(EVENT_ID2);
        AscendC::WaitFlag<AscendC::HardEvent::M_FIX>(EVENT_ID2);
        CopyL0CToGm();
    }

private:
    AscendC::TPipe* pipe = nullptr;
    uint32_t m = 0;
    uint32_t n = 0;
    uint32_t k = 0;
    AscendC::TQue<AscendC::TPosition::A1, 1, 1> inQueueA1;
    AscendC::TQue<AscendC::TPosition::B1, 1, 1> inQueueB1;
    AscendC::TQue<AscendC::TPosition::A2, 1> inQueueA2;
    AscendC::TQue<AscendC::TPosition::B2, 1> inQueueB2;
    AscendC::TQue<AscendC::TPosition::CO1, 1> inQueueCO1;
    AscendC::GlobalTensor<T> aGlobal;
    AscendC::GlobalTensor<U> bGlobal;
    AscendC::GlobalTensor<S> cGlobal;
};

