    }

    __aicore__ inline void CopyGmToB1Nd2Nz()
    {
        AscendC::LocalTensor<U> rightMatrix = inQueueB1.template AllocTensor<U>();
        AscendC::Nd2NzParams nd2nzParams;
        nd2nzParams.ndNum = 1;
        nd2nzParams.nValue = kLength;
        nd2nzParams.dValue = nLength;
        nd2nzParams.srcNdMatrixStride = 0;
        nd2nzParams.srcDValue = nLength;
        nd2nzParams.dstNzC0Stride = kLength;
        nd2nzParams.dstNzNStride = 1;
        nd2nzParams.dstNzMatrixStride = 0;
        AscendC::DataCopy(rightMatrix, bGlobal, nd2nzParams);
        inQueueB1.EnQue(rightMatrix);
    }

    __aicore__ inline void CopyGmToA1()
    {
        AscendC::LocalTensor<T> leftMatrix = inQueueA1.template AllocTensor<T>();
        AscendC::DataCopy(leftMatrix, aGlobal, mLength * kLength);
        inQueueA1.EnQue(leftMatrix);
