    constexpr uint32_t MAX_BLOCK_COUNT = 65535;
}

template <typename type_data, typename type_idx, bool is_batch_dims_zero, bool is_axis_zero>
__global__ __launch_bounds__(MAX_THREAD_COUNT) void gather_custom_v2(
    type_data* input,
    type_idx* indices,
    type_data* gather_output,
    uint32_t outer_size,
    uint32_t gather_dim_size,
    uint32_t indices_size,
    uint32_t slice_size,
    uint32_t output_total_size)
{
    uint32_t begin = blockIdx.x * blockDim.x + threadIdx.x;
    uint32_t stride = gridDim.x * blockDim.x;

    for (uint32_t i = begin; i < output_total_size; i += stride) {
        // Split the flattened output index into: [batch, outer, indices, slice].
        uint32_t slices_count = i / slice_size;
        uint32_t slice_i = i - slices_count * slice_size;

        uint32_t entries_count = slices_count / indices_size;
        uint32_t indices_i = slices_count - entries_count * indices_size;

        uint32_t batch_i = 0;
        uint32_t outer_i = 0;

        if constexpr (!is_batch_dims_zero) {
            batch_i = entries_count / outer_size;
        }
        if constexpr (!is_axis_zero) {
            outer_i = entries_count - batch_i * outer_size;
        }

        const type_idx gather_idx = indices[batch_i * indices_size + indices_i];

        if (gather_idx >= 0 && gather_idx < gather_dim_size) {
            const uint32_t input_i = (
                (batch_i * outer_size + outer_i) * gather_dim_size + gather_idx
            ) * slice_size + slice_i;
            gather_output[i] = input[input_i];
        } else {
            gather_output[i] = static_cast<type_data>(0);
        }
    }
}

bool block_split(uint32_t output_total_size, uint32_t &numBlocks, uint32_t &thread_num_per_block) {
    uint32_t real_core_num = 0;
    const auto& platformInfoMgr = platform_ascendc::PlatformAscendCManager::GetInstance();
    if (platformInfoMgr == nullptr) {
        std::cout << "[ERROR] Get platform info failed, please check device status."<< std::endl;
        return false;
    }
    real_core_num = platformInfoMgr->GetCoreNumAiv();
    thread_num_per_block = std::min(output_total_size, MAX_THREAD_COUNT);
    numBlocks = (output_total_size + thread_num_per_block - 1) / thread_num_per_block;
    if (numBlocks > real_core_num) {
        numBlocks = real_core_num;
        thread_num_per_block = MAX_THREAD_COUNT;
    }
    return true;
}

struct GatherV2Params {
    uint32_t outer_size = 1;       // Product of dimensions before axis (excluding batch)
    uint32_t gather_dim_size = 1;  // Size of axis dimension
    uint32_t indices_size = 1;     // Product of indices dimensions (excluding batch)
    uint32_t slice_size = 1;       // Product of dimensions after axis
    uint32_t output_total_size = 0;// Total output elements
};

bool normalize_gather_dims(
    uint32_t input_rank,
    uint32_t indices_rank,
    int32_t &axis,
    int32_t &batch_dims)
{
    if (axis < 0) {
        axis += input_rank;
    }
    if (batch_dims < 0) {
        batch_dims += indices_rank;
    }

    if (axis < 0 || axis >= static_cast<int32_t>(input_rank)) {
        std::cout << "[ERROR] Invalid axis: " << axis << " for input rank " << input_rank << std::endl;
        return false;
    }
    if (batch_dims < 0 || batch_dims > static_cast<int32_t>(std::min(input_rank, indices_rank))) {
        std::cout << "[ERROR] Invalid batch_dims: " << batch_dims
                  << " for input rank " << input_rank
                  << " and indices rank " << indices_rank << std::endl;
        return false;
    }
    if (batch_dims > axis) {
        std::cout << "[ERROR] batch_dims must be <= axis." << std::endl;
        return false;
    }
    return true;
}

uint32_t compute_shape_size(const std::vector<uint32_t>& shape)
{
    uint32_t total_size = 1;
    for (uint32_t dim : shape) {
        total_size *= dim;
    }
    return total_size;
}

GatherV2Params compute_gather_input(
    const std::vector<uint32_t>& input_shape,
    const std::vector<uint32_t>& indices_shape,
    int32_t axis,
    int32_t batch_dims)
{
    GatherV2Params params;
    uint32_t input_rank = input_shape.size();
    uint32_t indices_rank = indices_shape.size();

    uint32_t batch_size = 1;
    for (uint32_t i = 0; i < batch_dims; ++i) {
        batch_size *= input_shape[i];
    }

    for (uint32_t i = batch_dims; i < axis; ++i) {
        params.outer_size *= input_shape[i];
    }

    params.gather_dim_size = input_shape[axis];

    for (uint32_t i = batch_dims; i < indices_rank; ++i) {
        params.indices_size *= indices_shape[i];
    }

    for (uint32_t i = axis + 1; i < input_rank; ++i) {
        params.slice_size *= input_shape[i];
    }

    params.output_total_size = batch_size * params.outer_size * params.indices_size * params.slice_size;

    return params;
}

template <typename type_data, typename type_idx>
std::vector<type_data> gather_v2(
    std::vector<type_data>& input,
    const std::vector<uint32_t>& input_shape,
    std::vector<type_idx>& indices,
    const std::vector<uint32_t>& indices_shape,
    int32_t axis,
    int32_t batch_dims = 0)
{
    // Validate inputs
    if (input.empty() || indices.empty()) {
        std::cout << "[ERROR] Empty input tensors." << std::endl;
        return {};
    }

    uint32_t input_rank = input_shape.size();
    uint32_t indices_rank = indices_shape.size();

    if (!normalize_gather_dims(input_rank, indices_rank, axis, batch_dims)) {
        return {};
    }

    if (compute_shape_size(input_shape) != input.size()) {
        std::cout << "[ERROR] Input data size does not match input shape." << std::endl;
        return {};
    }
    if (compute_shape_size(indices_shape) != indices.size()) {
        std::cout << "[ERROR] Indices data size does not match indices shape." << std::endl;
        return {};
    }

    // Compute gather parameters
    GatherV2Params params = compute_gather_input(input_shape, indices_shape, axis, batch_dims);

    // Validate batch_dims constraints
    if (batch_dims > 0) {
        for (uint32_t i = 0; i < batch_dims; ++i) {
            if (input_shape[i] != indices_shape[i]) {
                std::cout << "[ERROR] input and indices batch dimensions mismatch at dim " << i 
                        << ": " << input_shape[i] << " vs " << indices_shape[i] << std::endl;
                return {};
            }
        }
    }

    if (params.output_total_size == 0) {
        return {};
    }

    // Calculate launch configuration
    uint32_t num_blocks = 0;
    uint32_t threads_per_block = 0;
    if (!block_split(params.output_total_size, num_blocks, threads_per_block)) {
        return {};
    }

    std::cout << "[INFO] gather_v2: input_shape=[";
    for (auto it = input_shape.begin(); it != input_shape.end(); ++it) {
        if (it != input_shape.begin()) std::cout << ", ";
        std::cout << *it;
    }
    std::cout << "], indices_shape=[";
    for (auto it = indices_shape.begin(); it != indices_shape.end(); ++it) {
        if (it != indices_shape.begin()) std::cout << ", ";
        std::cout << *it;
    }
    std::cout << "], axis=" << axis << ", batch_dims=" << batch_dims << std::endl;
    std::cout << "[INFO] Block number is " << num_blocks << "." << std::endl;
    std::cout << "[INFO] Thread number in a block is " << threads_per_block << "." << std::endl;

    int32_t device_id = 0;
    aclrtStream stream = nullptr;

    aclInit(nullptr);
    aclrtSetDevice(device_id);
    aclrtCreateStream(&stream);

    // Calculate memory sizes
    size_t input_total_byte_size = input.size() * sizeof(type_data);
    size_t indices_total_byte_size = indices.size() * sizeof(type_idx);
    size_t output_total_byte_size = params.output_total_size * sizeof(type_data);

    // Allocate memory
    type_data* input_device = nullptr;
    type_idx* indices_device = nullptr;
    type_data* output_device = nullptr;
    uint8_t* output_host = nullptr;

    aclrtMalloc((void**)&input_device, input_total_byte_size, ACL_MEM_MALLOC_HUGE_FIRST);
    aclrtMalloc((void**)&indices_device, indices_total_byte_size, ACL_MEM_MALLOC_HUGE_FIRST);
    aclrtMalloc((void**)&output_device, output_total_byte_size, ACL_MEM_MALLOC_HUGE_FIRST);
    aclrtMallocHost((void**)&output_host, output_total_byte_size);

    // Copy inputs to device
    aclrtMemcpy(input_device, input_total_byte_size, input.data(), input_total_byte_size, ACL_MEMCPY_HOST_TO_DEVICE);
    aclrtMemcpy(indices_device, indices_total_byte_size, indices.data(), indices_total_byte_size, ACL_MEMCPY_HOST_TO_DEVICE);

    uint32_t dyn_ubuf_size = 0;
    const bool is_batch_dims_zero = (batch_dims == 0);
    const bool is_axis_zero = (axis == 0);
    // Call kernel function with <<<...>>>
    if (is_batch_dims_zero) {
        if (is_axis_zero) {
            gather_custom_v2<type_data, type_idx, true, true><<<num_blocks, threads_per_block, dyn_ubuf_size, stream>>>(
                input_device, indices_device, output_device,
                params.outer_size, params.gather_dim_size,
                params.indices_size, params.slice_size, params.output_total_size);
        } else {
            gather_custom_v2<type_data, type_idx, true, false><<<num_blocks, threads_per_block, dyn_ubuf_size, stream>>>(
                input_device, indices_device, output_device,
                params.outer_size, params.gather_dim_size,
                params.indices_size, params.slice_size, params.output_total_size);
        }
    } else {
        if (is_axis_zero) {
            gather_custom_v2<type_data, type_idx, false, true><<<num_blocks, threads_per_block, dyn_ubuf_size, stream>>>(
                input_device, indices_device, output_device,
                params.outer_size, params.gather_dim_size,
                params.indices_size, params.slice_size, params.output_total_size);
        } else {
            gather_custom_v2<type_data, type_idx, false, false><<<num_blocks, threads_per_block, dyn_ubuf_size, stream>>>(
                input_device, indices_device, output_device,
                params.outer_size, params.gather_dim_size,
                params.indices_size, params.slice_size, params.output_total_size);
        }
    }

    aclrtSynchronizeStream(stream);
    // Copy result from device to host
    aclrtMemcpy(output_host, output_total_byte_size, output_device, output_total_byte_size, ACL_MEMCPY_DEVICE_TO_HOST);
    std::vector<type_data> output(reinterpret_cast<type_data*>(output_host), 
                        reinterpret_cast<type_data*>(output_host + output_total_byte_size));

    // Free memory
    aclrtFree(input_device);
    aclrtFree(indices_device);
    aclrtFree(output_device);
    aclrtFreeHost(output_host);

    // DeInit
    aclrtDestroyStream(stream);
    aclrtResetDevice(device_id);
    aclFinalize();

    return output;
}

template <typename type_data>
void print_tensor(const std::vector<type_data>& tensor, const std::string& name, size_t max_print = 20) {
    std::cout << name << ": [";
    size_t print_count = std::min(tensor.size(), max_print);
    for (size_t i = 0; i < print_count; ++i) {
        if (i > 0) std::cout << ", ";
        std::cout << tensor[i];
    }
    if (tensor.size() > max_print) {
        std::cout << ", ...";
    }
    std::cout << "] (size=" << tensor.size() << ")" << std::endl;
}

template <typename type_data>
uint32_t verify_result(const std::vector<type_data>& output, const std::vector<type_data>& golden) {
    print_tensor(output, "Output");
    print_tensor(golden, "Golden");

    if (output.size() != golden.size()) {
        std::cout << "[Failed] Case accuracy is verification failed!" << std::endl;
        return 1;
    }

    if (std::equal(output.begin(), output.end(), golden.begin())) {
        std::cout << "[Success] Case accuracy is verification passed." << std::endl;
        return 0;
    } else {
        std::cout << "[Failed] Case accuracy is verification failed!" << std::endl;
        return 1;
    }
}

template <typename type_data, typename type_idx>
std::vector<type_data> compute_golden(
    const std::vector<type_data>& input,
    const std::vector<uint32_t>& input_shape,
    const std::vector<type_idx>& indices,
    const std::vector<uint32_t>& indices_shape,
    int32_t axis,
    int32_t batch_dims)
{
    int32_t input_rank = input_shape.size();
    int32_t indices_rank = indices_shape.size();
    if (!normalize_gather_dims(input_rank, indices_rank, axis, batch_dims)) {
        return {};
    }

    GatherV2Params params = compute_gather_input(input_shape, indices_shape, axis, batch_dims);
    std::vector<type_data> golden(params.output_total_size);

    for (uint32_t i = 0; i < params.output_total_size; ++i) {

        uint32_t slices_count = i / params.slice_size;
        uint32_t slice_i = i % params.slice_size;

        uint32_t entries_count = slices_count / params.indices_size;
        uint32_t indices_i = slices_count % params.indices_size;

        uint32_t batch_i = 0;
        uint32_t outer_i = 0;

        if (batch_dims != 0) {
            batch_i = entries_count / params.outer_size;
        }
        if (axis != 0) {
            outer_i = entries_count % params.outer_size;
        }
        const type_idx gather_idx = indices[batch_i * params.indices_size + indices_i];

        if (gather_idx >= 0 && gather_idx < params.gather_dim_size) {
            const uint32_t input_i = (
                (batch_i * params.outer_size + outer_i) * params.gather_dim_size + gather_idx
            ) * params.slice_size + slice_i;
            golden[i] = input[input_i];
        } else {
            golden[i] = static_cast<type_data>(0);
        }
    }

    return golden;
}

int32_t main(int32_t argc, char* argv[])
{
    const std::vector<uint32_t> input_shape = {128, 20000, 512};
    const uint32_t input_size = 128ULL * 20000 * 512;
    std::vector<float> input(input_size);
    for (uint32_t i = 0; i < input_size; ++i) {
        input[i] = static_cast<float>(i) * 1.2f;
    }

    const std::vector<uint32_t> indices_shape = {128, 2048};
    std::vector<uint32_t> indices(128 * 2048);
    for (uint32_t i = 0; i < 128 * 2048; ++i) {
        indices[i] = static_cast<uint32_t>(i % 20000);
    }

    auto golden = compute_golden(input, input_shape, indices, indices_shape, 1, 1);
    auto output = gather_v2(input, input_shape, indices, indices_shape, 1, 1);

    verify_result(output, golden);
    return 0;
}

