#include <cstdint>
#include <cstddef>
#include <cstring>
#include <limits>
#include <random>
#include <cstring>
#include <iostream>
#include <array>
#include <vector>
#include "acl/acl.h"
#include "simt_api/asc_simt.h"

namespace {
constexpr uint32_t VALUE_DIM = 32;
constexpr uint32_t HASH_TABLE_CAPACITY = 16 * 1024; // must be 2^n
constexpr uint32_t ALIGN_BYTES = 8;
constexpr uint32_t KEY_NUM = 8 * 1024;
constexpr uint32_t THREAD_COUNT = 1024;
constexpr uint32_t INT64_TYPE_BYTES = 8;
constexpr uint32_t DEFALUT_FLAG = 0;
constexpr uint32_t HOLD_FLAG = 0x57277275;
constexpr uint32_t WRITE_FLAG = 0x39555593;
} // namespace

// Bucket need 8 bytes align
struct Bucket {
    int64_t key;
    uint32_t state;
    uint32_t flag;
    float value[VALUE_DIM];
};

__aicore__ inline uint32_t rotl32(uint32_t x, uint32_t r)
{
    return (x << r) | (x >> (32 - r));
}

__aicore__ inline uint32_t murmur_hash_3(int64_t key, uint32_t len, uint32_t seed)
{
    constexpr uint32_t c1 = 0xcc9e2d51;
    constexpr uint32_t c2 = 0x1b873593;
    constexpr uint32_t r1 = 15;
    constexpr uint32_t r2 = 13;
    constexpr uint32_t m = 5;
    constexpr uint32_t n = 0xe6546b64;
    uint32_t hash = seed;
    uint32_t k = 0;
    uint32_t* data = reinterpret_cast<uint32_t*>(&key);

    const uint32_t nblocks = len / 4;
#pragma unroll 2
    for (uint32_t i = 0; i < nblocks; i++) {
        k = data[i];
        k *= c1;
        k = rotl32(k, r1);
        k *= c2;
        hash ^= k;
        hash = rotl32(hash, r2);
        hash = hash * m + n;
    }

    hash ^= len;
    hash ^= hash >> 16;
    hash *= 0x85ebca6b;
    hash ^= hash >> 13;
    hash *= 0xc2b2ae35;
    hash ^= hash >> 16;
    return hash;
}

__global__ __launch_bounds__(THREAD_COUNT) void insert_hash_table(uint8_t* table_addr, uint32_t capacity,
                                                                  uint32_t value_dim, int64_t* keys, float* values,
                                                                  uint32_t key_num, uint32_t bucket_size)
{
    uint32_t idx = blockIdx.x * blockDim.x + threadIdx.x;
    idx = idx / warpSize;
    if (idx >= key_num) {
        return;
    }
    int32_t lane_id = threadIdx.x % warpSize;
    Bucket* bucket_addr = nullptr;
    int32_t is_insert_succ = 0;
    uint32_t bucket_idx = 0;

    if (lane_id == 0) {
        int64_t insert_key = keys[idx];
        uint32_t hash = murmur_hash_3(insert_key, INT64_TYPE_BYTES, 0);
        bucket_idx = hash & (capacity - 1);
        uint32_t bucket_offset = 0;
        for (uint32_t i = 0; i < capacity; i++) {
            bucket_offset = bucket_idx * bucket_size;
            bucket_addr = reinterpret_cast<Bucket*>(table_addr + bucket_offset);
            uint32_t old_flag = asc_atomic_cas(&bucket_addr->flag, DEFALUT_FLAG, WRITE_FLAG);
            if (old_flag == DEFALUT_FLAG) {
                bucket_addr->key = insert_key;
                asc_threadfence();
                bucket_addr->state = 1;
                is_insert_succ = 1;
                break;
            } else {
                while (*reinterpret_cast<volatile uint32_t*>(&bucket_addr->state) != 1) {}
                if (insert_key == *reinterpret_cast<volatile int64_t*>(&bucket_addr->key)) {
                    old_flag = asc_atomic_cas(&bucket_addr->flag, HOLD_FLAG, WRITE_FLAG);
                    if (old_flag == HOLD_FLAG) {
                        is_insert_succ = 1;
                    }
                    break;
                } else {
                    bucket_idx = (bucket_idx + 1) & (capacity - 1);
                }
            }
        }
    }

    is_insert_succ = asc_shfl(is_insert_succ, 0, warpSize);
    if (is_insert_succ == 1) {
        bucket_idx = asc_shfl(bucket_idx, 0, warpSize);
        bucket_addr = reinterpret_cast<Bucket*>(table_addr + bucket_idx * bucket_size);
        for (uint32_t j = lane_id; j < value_dim; j += warpSize) {
            bucket_addr->value[j] = values[idx * value_dim + j];
        }
        asc_threadfence();
        if (lane_id == 0) {
            bucket_addr->flag = HOLD_FLAG;
        }
    }
}

int64_t random_key()
{
    static std::random_device rd;
    static std::mt19937_64 gen(rd());
    static std::uniform_int_distribution<int64_t> dist(0, std::numeric_limits<int64_t>::max());
    return dist(gen);
}

float random_value()
{
    static std::random_device rd;
    static std::mt19937_64 gen(rd());
    static std::uniform_real_distribution<float> dist(std::numeric_limits<float>::min(),
                                                      std::numeric_limits<float>::max());
    return dist(gen);
}

void generate_test_data(std::vector<int64_t>& keys, std::vector<std::array<float, VALUE_DIM>>& values, uint32_t num)
{
    for (int32_t i = 0; i < num; i++) {
        keys[i] = random_key();
        values[i] = std::array<float, VALUE_DIM>{random_value(), random_value(), random_value(), random_value()};
    }
}

std::vector<uint8_t> launch_kernel(std::vector<int64_t>& keys, std::vector<std::array<float, VALUE_DIM>>& values)
{
    size_t key_total_byte_size = KEY_NUM * sizeof(int64_t);
    size_t value_total_byte_size = KEY_NUM * sizeof(float) * VALUE_DIM;

    size_t bucket_byte_size = sizeof(Bucket);
    bucket_byte_size = (bucket_byte_size + ALIGN_BYTES - 1) & ~(ALIGN_BYTES - 1);
    size_t hash_map_total_byte_size = bucket_byte_size * HASH_TABLE_CAPACITY;

    uint32_t warp_per_block = THREAD_COUNT / 32;
    uint32_t num_blocks = (KEY_NUM + warp_per_block - 1) / warp_per_block;

    int32_t device_id = 0;
    aclrtStream stream = nullptr;
    void* key_host = reinterpret_cast<void*>(keys.data());
    void* key_device = nullptr;
    void* value_host = reinterpret_cast<void*>(values.data());
    void* value_device = nullptr;
    void* hash_map_host = nullptr;
    void* hash_table_device = nullptr;

    aclInit(nullptr);
    aclrtSetDevice(device_id);
    aclrtCreateStream(&stream);
    aclrtMallocHost(&hash_map_host, hash_map_total_byte_size);
    aclrtMalloc(&key_device, key_total_byte_size, ACL_MEM_MALLOC_HUGE_FIRST);
    aclrtMalloc(&value_device, value_total_byte_size, ACL_MEM_MALLOC_HUGE_FIRST);
    aclrtMalloc(&hash_table_device, hash_map_total_byte_size, ACL_MEM_MALLOC_HUGE_FIRST);

    aclrtMemcpy(key_device, key_total_byte_size, key_host, key_total_byte_size, ACL_MEMCPY_HOST_TO_DEVICE);
    aclrtMemcpy(value_device, value_total_byte_size, value_host, value_total_byte_size, ACL_MEMCPY_HOST_TO_DEVICE);

    insert_hash_table<<<num_blocks, THREAD_COUNT, 0, stream>>>(
        static_cast<uint8_t*>(hash_table_device), HASH_TABLE_CAPACITY, VALUE_DIM, static_cast<int64_t*>(key_device),
        static_cast<float*>(value_device), KEY_NUM, static_cast<uint32_t>(bucket_byte_size));
    aclrtSynchronizeStream(stream);

    aclrtMemcpy(hash_map_host, hash_map_total_byte_size, hash_table_device, hash_map_total_byte_size,
                ACL_MEMCPY_DEVICE_TO_HOST);
    std::vector<uint8_t> output((uint8_t*)hash_map_host, (uint8_t*)hash_map_host + hash_map_total_byte_size);

    aclrtFree(key_device);
    aclrtFree(value_device);
    aclrtFree(hash_table_device);
    aclrtFreeHost(hash_map_host);

    aclrtDestroyStream(stream);
    aclrtResetDevice(device_id);
    aclFinalize();

    return output;
}

inline uint32_t rotl32_cpu(uint32_t x, uint32_t r)
{
    return (x << r) | (x >> (32 - r));
}

uint32_t murmur_hash_3_cpu(int64_t key, uint32_t len, uint32_t seed)
{
    constexpr uint32_t c1 = 0xcc9e2d51;
    constexpr uint32_t c2 = 0x1b873593;
    constexpr uint32_t r1 = 15;
    constexpr uint32_t r2 = 13;
    constexpr uint32_t m = 5;
    constexpr uint32_t n = 0xe6546b64;
    uint32_t hash = seed;
    uint32_t k = 0;
    uint32_t* data = reinterpret_cast<uint32_t*>(&key);

    const uint32_t nblocks = len / 4;
    for (uint32_t i = 0; i < nblocks; i++) {
        k = data[i];
        k *= c1;
        k = rotl32_cpu(k, r1);
        k *= c2;
        hash ^= k;
        hash = rotl32_cpu(hash, r2);
        hash = hash * m + n;
    }

    hash ^= len;
    hash ^= hash >> 16;
    hash *= 0x85ebca6b;
    hash ^= hash >> 13;
    hash *= 0xc2b2ae35;
    hash ^= hash >> 16;
    return hash;
}

void check_result(std::vector<int64_t>& keys, std::vector<std::array<float, VALUE_DIM>>& values,
                  std::vector<uint8_t>& hash_map)
{
    constexpr float epsilon = 1e-5f;
    size_t bucket_byte_size = sizeof(Bucket);
    bucket_byte_size = (bucket_byte_size + ALIGN_BYTES - 1) & ~(ALIGN_BYTES - 1);
    size_t hash_map_total_byte_size = bucket_byte_size * HASH_TABLE_CAPACITY;
    const Bucket* bucket_addr = reinterpret_cast<const Bucket*>(hash_map.data());
    uint32_t count = 0;
    for (int32_t i = 0; i < KEY_NUM; i++) {
        int64_t insert_key = keys[i];
        uint32_t hash = murmur_hash_3_cpu(insert_key, INT64_TYPE_BYTES, 0);
        uint32_t pos = hash % HASH_TABLE_CAPACITY;
        for (uint32_t j = 0; j < HASH_TABLE_CAPACITY; j++) {
            uint32_t idx = (pos + j) % HASH_TABLE_CAPACITY;
            if (bucket_addr[idx].key == insert_key) {
                if (bucket_addr[idx].state != 1 || bucket_addr[idx].flag != HOLD_FLAG) {
                    std::cout << "check value failed, key: " << bucket_addr[idx].key
                              << ", state: " << bucket_addr[idx].state << ", flag" << bucket_addr[idx].flag
                              << std::endl;
                    std::cout << "expect              key: " << insert_key << ", state: 1" << ", flag" << HOLD_FLAG
                              << std::endl;
                    break;
                }
                for (uint32_t k = 0; k < VALUE_DIM; k++) {
                    if (std::abs(values[i][k] - bucket_addr[idx].value[k]) > epsilon) {
                        std::cout << "check value failed, key: " << insert_key
                                  << ", value: " << bucket_addr[idx].value[k] << std::endl;
                        std::cout << "            expect, key: " << insert_key << ", value: " << values[i][k]
                                  << std::endl;
                        count++;
                        break;
                    }
                }
            }
        }
    }
    if (count == 0) {
        std::cout << "[Success] find all key-value in hash table." << std::endl;
    } else {
        std::cout << "[Failed] total: " << count << " not find." << std::endl;
    }
}

int32_t main(int32_t argc, char* argv[])
{
    std::vector<int64_t> keys(KEY_NUM);
    std::vector<std::array<float, VALUE_DIM>> values(KEY_NUM);
    generate_test_data(keys, values, KEY_NUM);
    std::vector<uint8_t> hash_map = launch_kernel(keys, values);
    check_result(keys, values, hash_map);
}
